#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists.
    // A simple solution that works for all n >= 2 is to reverse the permutation.
    // Let p = [p_1, p_2, ..., p_n].
    // The sums are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
    // Let p' be the reversed permutation: p' = [p_n, p_{n-1}, ..., p_1].
    // The sums for p' are [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
    // Due to commutativity of addition, p_i + p_{i+1} = p_{i+1} + p_i.
    // The set of sums for p is {p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n}.
    // The set of sums for p' is {p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1}.
    // These two sets of sums are identical.
    // For example, p_1+p_2 is in the first set, and p_2+p_1 is in the second set.
    // p_2+p_3 is in the first set, and p_3+p_2 is in the second set.
    // And so on.
    // Therefore, sorting these sets will result in the same fingerprint.
    // The reversed permutation p' is different from p unless p is a palindrome.
    // However, the problem statement guarantees a solution exists, and this approach
    // is generally accepted for such problems unless specific constraints prevent it.
    // For n=2, p=[1,2], p'=[2,1]. F(p)=[3], F(p')=[3]. p!=p'.
    // For n=6, p=[2,1,6,5,4,3], p'=[3,4,5,6,1,2].
    // F(p) = sort([3,7,11,9,7]) = [3,7,7,9,11].
    // F(p') = sort([7,9,11,7,3]) = [3,7,7,9,11].
    // This works.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

