    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    long long min_val = k + 1; // Initialize with a value larger than any possible a_i
    int min_idx = -1;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < min_val) {
            min_val = a[i];
            min_idx = i;
        }
    }

    long long total_spells = 0;

    // We iterate through all piles except the one with the minimum value.
    // For each such pile, we calculate how many times we can add the minimum value to it.
    for (int i = 0; i < n; ++i) {
        if (i == min_idx) {
            continue; // Skip the pile that contains the minimum value itself
        }

        // Current pile value is a[i]. We want to add min_val to it repeatedly
        // until it exceeds k.
        // Let x be the number of times we add min_val.
        // a[i] + x * min_val <= k
        // x * min_val <= k - a[i]
        // x <= (k - a[i]) / min_val
        // Since x must be an integer, x = floor((k - a[i]) / min_val)

        if (min_val == 0) { // Should not happen based on constraints (a_i >= 1)
            // If min_val is 0, we can add it infinitely many times without changing a[i].
            // But problem constraints say a_i >= 1.
            // This branch is technically unreachable given a_i >= 1.
            // If it were possible, and k >= a[i], then infinite spells.
            // For competitive programming, it's safer to assume constraints hold.
            continue; 
        }

        long long remaining_capacity = k - a[i];
        if (remaining_capacity < 0) { // Should not happen if initial a_i <= k
            // If a[i] is already > k, this pile is invalid.
            // But problem guarantees a_i <= k.
            continue;
        }

        total_spells += remaining_capacity / min_val;
    }

    std::cout << total_spells << std::endl;
}

