int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    long long total_successful_a = 0;
    long long total_sent_a = 0;
    long long total_successful_b = 0;
    long long total_sent_b = 0;

    for (int i = 0; i < n; ++i) {
        int t, x, y;
        std::cin >> t >> x >> y;
        if (t == 1) {
            total_successful_a += x;
            total_sent_a += (x + y); // Each ping sends 10 packets
        } else { // t == 2
            total_successful_b += x;
            total_sent_b += (x + y); // Each ping sends 10 packets
        }
    }

    // Check server 'a'
    // A server is "alive" if at least half of the packets reached it successfully.
    // This means total_successful_a >= total_sent_a / 2
    // To avoid floating point arithmetic, we can use total_successful_a * 2 >= total_sent_a
    if (total_successful_a * 2 >= total_sent_a) {
        std::cout << "LIVE\n";
    } else {
        std::cout << "DEAD\n";
    }

    // Check server 'b'
    if (total_successful_b * 2 >= total_sent_b) {
        std::cout << "LIVE\n";
    } else {
        std::cout << "DEAD\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <utility> // For std::pair

void solve() {
    int n;
    std::cin >> n;
    std::vector<std::pair<int, int>> a_indexed(n);
    std::vector<std::pair<int, int>> b_indexed(n);

    for (int i = 0; i < n; ++i) {
        std::cin >> a_indexed[i].first;
        a_indexed[i].second = i; // Store original index
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b_indexed[i].first;
        b_indexed[i].second = i; // Store original index
    }

    // Sort both vectors based on brightness values
    std::sort(a_indexed.begin(), a_indexed.end());
    std::sort(b_indexed.begin(), b_indexed.end());

    // Create the output arrays
    std::vector<int> x(n);
    std::vector<int> y(n);

    // Pair the i-th smallest necklace with the i-th largest bracelet
    // This ensures that the sums are distinct.
    // Specifically, a_indexed[i].first + b_indexed[n-1-i].first
    // The problem asks for x_i and y_i to be the brightnesses for the i-th daughter.
    // The example output shows that the order of daughters can be arbitrary.
    // So we can just output the sorted a values and sorted b values in reverse.
    // Or, more simply, we can just output the sorted a values and sorted b values.
    // Let's try the simplest approach: sort both arrays and pair a[i] with b[i].
    // The problem statement guarantees an answer always exists.
    // The example output for the second test case uses a different pairing.
    // Let's re-read: "the i-th daughter receives a necklace with brightness x_i and a bracelet with brightness y_i"
    // This means x_i and y_i are the brightnesses for daughter i.
    // The output format is:
    // x_1 x_2 ... x_n
    // y_1 y_2 ... y_n
    // This implies that x_i and y_i are the items given to the i-th daughter.
    // So we need to construct two arrays, x and y, of size n.

    // A simple strategy that works is to sort both arrays and pair a_i with b_{n-1-i}.
    // This creates sums that are "spread out".
    // For example, if a = [1, 5, 7] and b = [1, 2, 6]
    // a_0=1, b_2=6 -> sum 7
    // a_1=5, b_1=2 -> sum 7 (This fails if we pair a_i with b_{n-1-i} directly)
    // The example output for the second test case:
    // a = [1, 7, 5], b = [6, 1, 2]
    // Output:
    // x = [5, 1, 7]
    // y = [6, 2, 1]
    // Sums: 11, 3, 8. These are distinct.
    // This corresponds to:
    // Daughter 1: a_3 (5) + b_1 (6)
    // Daughter 2: a_1 (1) + b_3 (2)
    // Daughter 3: a_2 (7) + b_2 (1)
    // This is a permutation of a and b.

    // The simplest strategy that is guaranteed to work is to sort both arrays
    // and then pair a_i with b_i.
    // Let's verify this strategy.
    // If a = [1, 5, 7] and b = [1, 2, 6] (sorted)
    // Daughter 1: a_0=1, b_0=1 -> sum 2
    // Daughter 2: a_1=5, b_1=2 -> sum 7
    // Daughter 3: a_2=7, b_2=6 -> sum 13
    // These sums are distinct. This strategy seems to work.
    // The problem statement says "It can be shown that an answer always exists."
    // This often implies a simple construction.

    // So, we just need to output the sorted 'a' values and sorted 'b' values.
    // The problem asks for x_i and y_i to be the brightnesses for the i-th daughter.
    // So, we can just assign x_i = a_indexed[i].first and y_i = b_indexed[i].first.
    // This means daughter i gets the i-th smallest necklace and i-th smallest bracelet.

    for (int i = 0; i < n; ++i) {
        x[i] = a_indexed[i].first;
    }
    for (int i = 0; i < n; ++i) {
        y[i] = b_indexed[i].first;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << x[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << y[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

