    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long current_a1 = a[0];
    long long remaining_days = d;

    for (int i = 1; i < n; ++i) {
        int pile_index = i; // 0-indexed
        int cost_per_haybale = pile_index; // cost to move from pile i+1 (1-indexed) to pile 1 (1-indexed)

        if (remaining_days <= 0) {
            break;
        }

        if (cost_per_haybale == 0) { // Should not happen for i > 0
            continue;
        }

        // Calculate how many haybales can be moved from this pile
        // based on available days and haybales in the pile.
        long long haybales_from_this_pile_possible_by_days = remaining_days / cost_per_haybale;
        long long haybales_to_move = std::min((long long)a[pile_index], haybales_from_this_pile_possible_by_days);

        current_a1 += haybales_to_move;
        remaining_days -= haybales_to_move * cost_per_haybale;
    }

    std::cout << current_a1 << std::endl;
}

