int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        long long current_positive_balance = 0;
        long long coins = 0;
        for (int i = 0; i < n; ++i) {
            long long val;
            std::cin >> val;
            if (val > 0) {
                current_positive_balance += val;
            } else { // val <= 0
                // If current_positive_balance is positive, we can use it to offset val.
                // This is equivalent to performing free operations (i < j) where
                // positive values from earlier indices are moved to this negative index.
                long long amount_to_offset = std::min(current_positive_balance, -val);
                current_positive_balance -= amount_to_offset;
                val += amount_to_offset; // val becomes less negative or 0

                // If val is still negative after offsetting with current_positive_balance,
                // it means we need to move more value into this index.
                // This value must come from indices j > i.
                // Moving value from j > i to i costs 1 coin per unit.
                // So, the remaining negative value of 'val' must be paid for.
                if (val < 0) {
                    coins += -val;
                }
            }
        }
        std::cout << coins << "\n";
    }
    return 0;
}

