int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        if (n == 1) {
            std::cout << -1 << "\n";
        } else {
            // For n >= 2, we can construct a number.
            // The first digit is 2.
            // The remaining n-1 digits are 3.
            // This forms the number 233...3 (n-1 times 3).
            //
            // Let's check the conditions:
            // 1. s > 0: Yes, it's a positive number.
            // 2. s consists of n digits: Yes, we print n digits.
            // 3. No digit in s equals 0: Digits are 2 and 3, neither is 0.
            // 4. s is not divisible by any of its digits:
            //    - Not divisible by 2: The number ends in 3, so it's odd.
            //    - Not divisible by 3: The sum of digits is 2 + (n-1)*3.
            //      If n=2, sum=2+3=5, not div by 3.
            //      If n=3, sum=2+3+3=8, not div by 3.
            //      If n=4, sum=2+3+3+3=11, not div by 3.
            //      In general, 2 + (n-1)*3 = 2 + 3n - 3 = 3n - 1.
            //      3n - 1 is never divisible by 3, because 3n is divisible by 3,
            //      so 3n - 1 leaves a remainder of 2 when divided by 3.
            //      Thus, the number is not divisible by 3.
            //
            // All conditions are satisfied.
            std::cout << 2;
            for (int i = 0; i < n - 1; ++i) {
                std::cout << 3;
            }
            std::cout << "\n";
        }
    }
    return 0;
}

