#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        // This logic is based on the observation that if p[i] is not n,
        // then max_{j!=i} min(p[i], p[j]) = max_{j!=i, p[j]<p[i]} p[j] (if such j exists)
        // or p[i] (if p[i] is smaller than all other p[j]).
        // More simply, max_{j!=i} min(p[i], p[j]) is either p[i] or the largest value smaller than p[i].
        // If p[i] is n, then max_{j!=i} min(n, p[j]) = max_{j!=i} p[j] = n-1.
        // If p[i] is not n, then max_{j!=i} min(p[i], p[j]) = p[i].
        // So, if max_val_in_row == n-1, then p[i] must be n.
        // Otherwise, p[i] must be max_val_in_row.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
