#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_R_pos = 0; // Represents the position of the last 'R' or the starting point (0)
                            // The frog is at cell `last_R_pos`.
                            // It can jump from `last_R_pos` to `last_R_pos + 1`, ..., `last_R_pos + d`.
                            // We need to find the next 'R' or the end `n+1`.
                            // The distance to cover is `next_R_pos - last_R_pos`.
                            // If `s[i-1]` is 'R', then `i` is a cell from which we can jump right.
                            // If `s[i-1]` is 'L', then `i` is a cell from which we can only jump left.
                            // So, we must skip all 'L' cells.
                            // The frog must jump from a cell `p` (where `s[p-1]` is 'R' or `p=0`)
                            // to a cell `q` (where `s[q-1]` is 'R' or `q=n+1`).
                            // The jump distance must be at least `q-p`.
                            // We want to minimize `d`, so `d` must be at least `q-p` for all such jumps.
                            // This means `d` must be at least the maximum `q-p` over all necessary jumps.

        // The frog starts at 0.
        // It needs to jump to the first 'R' cell, or directly to n+1 if no 'R's.
        // Or, more generally, it needs to jump from the current 'R' cell (or 0)
        // to the next 'R' cell, or to n+1.

        // Let's track the positions of 'R's.
        // The frog is at cell 0. It can jump to 1, ..., d.
        // It must land on an 'R' cell or n+1.
        // The first 'R' is at index `i` (cell `i+1`).
        // The distance from 0 to `i+1` is `i+1`.
        // So `d` must be at least `i+1`.
        // If there are no 'R's, the frog must jump from 0 to n+1. Distance is `n+1`.

        // Let's find all 'R' positions.
        std::vector<int> r_positions;
        r_positions.push_back(0); // Start at cell 0
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                r_positions.push_back(i + 1); // Cell i+1 has 'R'
            }
        }
        r_positions.push_back(n + 1); // Target cell n+1

