#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int balance = 0;

    for (char c : s) {
        if (c == '(') {
            if (open_count < k / 2) {
                result += '(';
                open_count++;
                balance++;
            }
        } else { // c == ')'
            if (close_count < k / 2 && balance > 0) {
                result += ')';
                close_count++;
                balance--;
            }
        }
        if (open_count == k / 2 && close_count == k / 2) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

