    // Diffs: |1-4|=3, |4-2|=2, |2-3|=1, |3-5|=2. Distinct: {1,2,3}.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i...n-1] is non-decreasing.
    // This is the start of the potential "right non-decreasing part".
    int i = n - 1;
    while (i > 0 && a[i-1] <= a[i]) {
        i--;
    }
    // After this loop, a[i...n-1] is non-decreasing.
    // If i is 0, the whole array is non-decreasing.

    // Find the rightmost index `j` such that a[j...i-1] is non-increasing.
    // This is the start of the potential "left non-increasing part".
    // We only need to check up to `i-1` because `a[i]` is the start of the non-decreasing suffix.
    // If `i` is 0, then `i-1` is -1, so this loop won't run, which is correct.
    int j = i;
    while (j > 0 && a[j-1] >= a[j]) {
        j--;
    }
    // After this loop, a[j...i-1] is non-increasing.
    // The elements a[j...n-1] form a "good" array.
    // The prefix to erase has length `j`.

    std::cout << j << std::endl;
}

