int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long k = n / m; // Number of multiples of m up to n

        if (k == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // The sequence of last digits (i*m)%10 for i=1, 2, ... is periodic with period 10.
        // Calculate the sum of last digits for one full cycle (i=1 to 10).
        long long sum_cycle = 0;
        for (int i = 1; i <= 10; ++i) {
            sum_cycle += (static_cast<long long>(i) * m) % 10;
        }

        // Number of full cycles
        long long num_full_cycles = k / 10;
        long long total_sum = num_full_cycles * sum_cycle;

        // Remaining multiples after full cycles
        long long remaining_multiples = k % 10;
        for (long long i = 1; i <= remaining_multiples; ++i) {
            total_sum += (i * m) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // current_min_idx and current_max_idx are already initialized to pos[1].
        // The length is 1, which is m. So 1 is always beautiful.
        if (m == 1) {
            result += '1';
            continue;
        }

        // For m > 1, we need to expand the current segment [current_min_idx, current_max_idx]
        // to include 'm'.
        // The number 'm' must be at pos[m].
        // We update current_min_idx and current_max_idx to cover the range from 1 to m.
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number 'm' is beautiful if the subsegment p[current_min_idx ... current_max_idx]
        // contains all numbers from 1 to m, and its length is exactly m.
        // The length of this subsegment is (current_max_idx - current_min_idx + 1).
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int d_int;
        std::cin >> d_int;
        double d = static_cast<double>(d_int);

        if (d == 0.0) {
            std::cout << "Y " << std::fixed << std::setprecision(9) << 0.0 << " " << 0.0 << "\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // Discriminant: d^2 - 4d
            // For d >= 4, d^2 - 4d >= 0, so sqrt is real.
            double sqrt_discriminant = std::sqrt(d * d - 4.0 * d);

            // a = (d + sqrt(d^2 - 4d)) / 2
            // b = (d - sqrt(d^2 - 4d)) / 2
            // Or vice versa.
            // We need a, b >= 0.
            // Since d >= 4, d is positive.
            // sqrt(d^2 - 4d) is real and non-negative.
            // d + sqrt(...) is clearly non-negative.
            // For d - sqrt(...) to be non-negative:
            // d >= sqrt(d^2 - 4d)
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // This is true since d >= 4.
            // So both solutions for a (and thus b) are non-negative.

            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            std::cout << "Y " << std::fixed << std::setprecision(9) << a << " " << b << "\n";
        }
    }
    return 0;
}

#include <iostream>
