#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    std::vector<long long> left_min_val(n);
    left_min_val[0] = 0;
    for (int i = 1; i < n; ++i) {
        left_min_val[i] = std::max(left_min_val[i-1] + 1, 0LL);
    }

    std::vector<long long> right_min_val(n);
    right_min_val[n-1] = 0;
    for (int i = n - 2; i >= 0; --i) {
        right_min_val[i] = std::max(right_min_val[i+1] + 1, 0LL);
    }

    bool possible = false;
    for (int k = 0; k < n; ++k) {
        // For a_k to be the peak, it must satisfy:
        // 1. a_k >= left_min_val[k] (to allow increasing sequence up to k)
        // 2. a_k >= right_min_val[k] (to allow decreasing sequence from k)
        // 3. The peak value itself must be strictly positive if it's not an endpoint
        //    (i.e., if k > 0 and k < n-1, then b_k > b_{k-1} and b_k > b_{k+1})
        //    However, the conditions left_min_val[k] and right_min_val[k] already
        //    ensure this. For example, if k > 0, left_min_val[k] >= 1.
        //    If k < n-1, right_min_val[k] >= 1.
        //    If k=0 and k=n-1, then left_min_val[0]=0 and right_min_val[n-1]=0.
        //    The only case where the peak could be 0 is if n=1, which is handled.
        //    If n > 1, then for k=0, right_min_val[0] >= 1. For k=n-1, left_min_val[n-1] >= 1.
        //    So, the peak must be at least 1 if n > 1.
        //    The conditions `a[k] >= left_min_val[k]` and `a[k] >= right_min_val[k]`
        //    implicitly handle the minimum value for the peak.

        if (a[k] >= left_min_val[k] && a[k] >= right_min_val[k]) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

