// Function to determine if Box 1 can be the special box
bool can_be_box1(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 1) {
        return A == 1;
    }

    // Box 1: Negative, Large magnitude
    // Final product must be negative. This means an odd number of negative factors.
    // Final product must have magnitude >= 1.

    // Case 1: Final product is negative.
    // This requires an odd number of initial negative toys (A+B).
    // If (A+B) is even, we need to make an odd number of negative toys.
    // This can happen if we multiply a positive toy by a negative toy.
    // If (A+B) is odd, we need to make an odd number of negative toys.
    // This can happen if we multiply a positive toy by a negative toy, or negative by negative (becomes positive), etc.

    // Let's simplify: the parity of negative numbers in the final product is the parity of (A+B).
    // So, if (A+B) is even, the final product is positive.
    // If (A+B) is odd, the final product is negative.
    // For Box 1, (A+B) must be odd.
    if ((A + B) % 2 == 0) { // Final product must be positive
        return false;
    }

    // Now we know the final product is negative. We need its magnitude to be >= 1.
    // This means we need at least one "large" toy (from Box 1 or Box 4) to survive or be created.
    // If A+D == 0, all initial toys have magnitude < 1.
    // Then any product of these toys will also have magnitude < 1.
    // So, if A+D == 0, it's impossible to get a magnitude >= 1.
    if (A + D == 0) {
        return false;
    }

    // If A+D > 0 and (A+B) is odd, it's always possible.
    // We can always arrange multiplications such that a large magnitude toy is involved in the final steps.
    // Example: If we have X1, X2, X3, X4.
    // If A+D > 0, there is at least one toy with magnitude >= 1.
    // If A+B is odd, there is an odd number of negative toys.
    // We can always multiply all toys with magnitude < 1 first. This results in a toy with magnitude < 1.
    // Then multiply this with a toy with magnitude >= 1.
    // If we have at least one toy with magnitude >= 1 (A+D > 0), and an odd number of negative toys (A+B is odd),
    // we can always construct a scenario where the final product is negative and has magnitude >= 1.
    // For example, take all toys from B and C. Multiply them. The result is a toy with magnitude < 1.
    // Let this be X_small.
    // Now we have A toys from Box 1, D toys from Box 4, and X_small.
    // We need to combine these to get a negative, large magnitude toy.
    // If A > 0, we can use one toy from Box 1. Multiply it with X_small. The result is negative.
    // We can choose the Box 1 toy to be very negative (e.g., -100) and X_small to be small (e.g., 0.1).
    // Product is -10. This is in Box 1.
    // If A == 0, but D > 0. We have an odd number of negative toys (all from B).
    // Multiply all B toys together. Result is negative, magnitude < 1. Let it be X_neg_small.
    // Multiply all C toys together. Result is positive, magnitude < 1. Let it be X_pos_small.
    // Multiply all D toys together. Result is positive, magnitude >= 1. Let it be X_pos_large.
    // Now we have X_neg_small, X_pos_small, X_pos_large.
    // Multiply X_neg_small * X_pos_small = X_neg_very_small.
    // Multiply X_neg_very_small * X_pos_large. We can choose values such that this is negative and >= 1.
    // E.g., X_neg_very_small = -0.01, X_pos_large = 200. Product = -2. In Box 1.
    return true;
}

// Function to determine if Box 2 can be the special box
bool can_be_box2(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 1) {
        return B == 1;
    }

    // Box 2: Negative, Small magnitude
    // Final product must be negative. This means an odd number of negative factors.
    // Final product must have magnitude < 1.

    // Parity of negative numbers: (A+B) must be odd.
    if ((A + B) % 2 == 0) { // Final product must be positive
        return false;
    }

    // Now we know the final product is negative. We need its magnitude to be < 1.
    // This means we need to be able to make the final product have magnitude < 1.
    // This is always possible unless all toys have magnitude >= 1 (A+D == total_toys).
    // If A+D == total_toys, and total_toys > 0, then all products will have magnitude >= 1.
    // So, if A+D == total_toys, it's impossible to get magnitude < 1.
    if (A + D == total_toys) {
        return false;
    }

    // If (A+B) is odd and A+D < total_toys, it's always possible.
    // We can always arrange multiplications such that the final product is negative and has magnitude < 1.
    // For example, take all toys from A and D. Multiply them. The result is a toy with magnitude >= 1.
    // Let this be X_large.
    // Take all toys from B and C. Multiply them. The result is a toy with magnitude < 1.
    // Let this be X_small.
    // Now we have X_large and X_small.
    // If (A+B) is odd, then either X_large is negative and X_small is positive, or vice versa, or both are negative.
    // We need the final product to be negative.
    // If X_large is positive and X_small is negative, their product is negative.
    // We can choose values such that X_large * X_small is < 1.
    // E.g., X_large = 10, X_small = -0.05. Product = -0.5. In Box 2.
    // This is possible as long as there is at least one toy with magnitude < 1 (i.e., B+C > 0, or A+D < total_toys).
    return true;
}

// Function to determine if Box 3 can be the special box
bool can_be_box3(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 1) {
        return C == 1;
    }

    // Box 3: Positive, Small magnitude
    // Final product must be positive. This means an even number of negative factors.
    // Final product must have magnitude < 1.

    // Parity of negative numbers: (A+B) must be even.
    if ((A + B) % 2 != 0) { // Final product must be negative
        return false;
    }

    // Now we know the final product is positive. We need its magnitude to be < 1.
    // This is impossible if all toys have magnitude >= 1 (A+D == total_toys).
    if (A + D == total_toys) {
        return false;
    }

    // If (A+B) is even and A+D < total_toys, it's always possible.
    // We can always arrange multiplications such that the final product is positive and has magnitude < 1.
    // Similar logic to Box 2, but ensuring positive product.
    // If (A+B) is even, we can multiply all negative toys first to get a positive product.
    // Then multiply all toys with magnitude < 1 to get a small magnitude product.
    // Then multiply this small product with a large product, choosing values to keep it small.
    // E.g., X_large = 10, X_small = 0.05. Product = 0.5. In Box 3.
    return true;
}

// Function to determine if Box 4 can be the special box
bool can_be_box4(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 1) {
        return D == 1;
    }

    // Box 4: Positive, Large magnitude
    // Final product must be positive. This means an even number of negative factors.
    // Final product must have magnitude >= 1.

    // Parity of negative numbers: (A+B) must be even.
    if ((A + B) % 2 != 0) { // Final product must be negative
        return false;
    }

    // Now we know the final product is positive. We need its magnitude to be >= 1.
    // This is impossible if all toys have magnitude < 1 (A+D == 0).
    if (A + D == 0) {
        return false;
    }

    // If (A+B) is even and A+D > 0, it's always possible.
    // Similar logic to Box 1, but ensuring positive product.
    // We can always arrange multiplications such that the final product is positive and has magnitude >= 1.
    // E.g., X_large = 100, X_small = 0.1. Product = 10. In Box 4.
    return true;
}

