    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i; // Not strictly needed for B, but good practice
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in descending order
    // For B, we only care about the value, not the original index for sorting purposes.
    // We need to pair the largest B_j with the largest A_i, second largest B_j with second largest A_i, etc.
    // This means if A is sorted ascending, B should be sorted ascending to pair (A_i, B_i)
    // such that A_i / (B_i + 1) is maximized.
    // The problem states F(n, k) = n / (k+1).
    // We want to maximize sum(A'_i / (B_i + 1)).
    // Let x_i = A'_i and y_i = 1 / (B_i + 1). We want to maximize sum(x_i * y_i).
    // To maximize sum(x_i * y_i) where x_i are elements of A and y_i are elements of {1/(B_j+1)},
    // we should sort x_i and y_i in the same order.
    // If A'_i are sorted ascending, then 1/(B_i+1) should be sorted ascending.
    // This means B_i+1 should be sorted descending, which means B_i should be sorted descending.
    std::sort(b_elements.begin(), b_elements.end(), [](const Element& a, const Element& b) {
        return a.value > b.value; // Sort B values in descending order
    });

    // Create the result array A'
    std::vector<long long> result_a_prime(m);

    // Pair sorted A with sorted B (A ascending, B descending)
    // The i-th smallest A value should be paired with the i-th largest B value.
    // The original index of B_i determines where A'_i goes.
