// Function to check if a subarray is a permutation
// `arr` is the array, `start` is the 0-indexed start, `len` is the length
// Returns true if arr[start...start+len-1] is a permutation of length `len`
bool is_permutation(const std::vector<int>& arr, int start, int len) {
    if (len == 0) {
        return true; // An empty sequence can be considered a permutation of length 0
    }
    if (len > arr.size() - start) {
        return false; // Not enough elements
    }

    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start + i];
        if (val <= 0 || val > len || seen[val]) {
            return false; // Value out of range or duplicate
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == len; // All numbers from 1 to len must be present
}

