        // 1. Max element in p2 must be l2
        // 2. Number of distinct elements in p2 must be l2
        bool p2_is_perm = (suffix_max[l1] == l2) && (suffix_distinct_count[l1] == l2);

        if (p1_is_perm && p2_is_perm) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

