long long solve() {
    long long n;
    std::cin >> n;
    long long chanek_coins = 0;
    long long opponent_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (n % 2 == 1) { // N is odd
            if (chanek_turn) {
                chanek_coins += 1;
            } else {
                opponent_coins += 1;
            }
            n -= 1;
        } else { // N is even
            // Check if N is a power of 2
            // A number is a power of 2 if (n & (n - 1)) == 0
            // And n > 0
            if ((n & (n - 1)) == 0) { // N is a power of 2
                if (chanek_turn) {
                    chanek_coins += n / 2;
                } else {
                    opponent_coins += n / 2;
                }
                n /= 2;
            } else { // N is even but not a power of 2
                // Optimal strategy is to take N/2
                if (chanek_turn) {
                    chanek_coins += n / 2;
                } else {
                    opponent_coins += n / 2;
                }
                n /= 2;
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

