int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let i be the number of items taken from the left (0 <= i <= n)
    // Then n-i items must be taken from the right
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;

        // Add extra energy for consecutive actions
        if (i > j) { // More items from left than right
            // The difference is i - j.
            // If i - j = 1, it means the last item taken was from the left, and it was the (j+1)-th left item.
            // The (j+1)-th left item was taken after j right items and j left items.
            // So, it was taken after a left item.
            // The number of "extra" left items is i - j.
            // Each of these (i-j-1) items (excluding the very first one from the left)
            // would incur Ql if it was taken after another left item.
            // The number of times we take an item from the left when the previous item was also from the left
            // is (i - j - 1).
            current_energy += (i - j - 1) * Ql;
        } else if (j > i) { // More items from right than left
            // The number of "extra" right items is j - i.
            // Each of these (j-i-1) items (excluding the very first one from the right)
            // would incur Qr if it was taken after another right item.
            // The number of times we take an item from the right when the previous item was also from the right
            // is (j - i - 1).
            current_energy += (j - i - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

