void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all 1s

    // If s[i] is '0', then both w[i-x] and w[i+x] must be '0'.
    // This is a necessary condition.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Now, verify if the constructed w can produce s.
    // For each s[i], check if it matches the rule based on our w.
    for (int i = 0; i < n; ++i) {
        bool s_i_should_be_1 = false;
        if (i - x >= 0 && w[i - x] == '1') {
            s_i_should_be_1 = true;
        }
        if (i + x < n && w[i + x] == '1') {
            s_i_should_be_1 = true;
        }

        if ((s[i] == '1' && !s_i_should_be_1) || (s[i] == '0' && s_i_should_be_1)) {
            // Mismatch found:
            // If s[i] is '1' but our w implies s[i] should be '0', then no solution.
            // (This happens if both w[i-x] and w[i+x] were forced to '0' by other s[j]='0' conditions,
            // but s[i] itself is '1'.)
            // If s[i] is '0' but our w implies s[i] should be '1', then no solution.
            // (This should not happen with our construction, as we only set w[j]='0' if s[k]='0' forced it.
            // If s[i]='0', then w[i-x] and w[i+x] would have been set to '0' if they exist,
            // making s_i_should_be_1 false. So this case implies an error in logic or problem statement.)
            std::cout << -1 << std::endl;
            return;
        }
    }

    std::cout << w << std::endl;
}

