                if (d[i] < last2) {
                    possible_for_pivot = false;
                    break;
                }
                colors[i] = '2';
                last2 = d[i];
            } else { // d[i] == pivot_digit
                // Can be color 1 or 2. Prefer color 2 if possible.
                if (d[i] < last2) { // Cannot be color 2
                    if (d[i] < last1) { // Cannot be color 1 either
                        possible_for_pivot = false;
                        break;
                    }
                    colors[i] = '1';
                    last1 = d[i];
                } else { // Can be color 2
