// Function to find prime factors of a number
// Returns a vector of unique prime factors
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
        // Let q = f1^a1 * f2^a2 * ... * fk^ak be the prime factorization of q.
        // If x is divisible by q, then x must be divisible by all f_j^a_j.
        // To make x not divisible by q, we must remove at least one prime factor f_j
        // from p enough times such that x is no longer divisible by f_j^a_j.
        // We want to maximize x, so we should remove the minimum necessary factors.
        // This means for each prime factor f_j of q, we try to divide p by f_j
        // until p is no longer divisible by q.
        // The largest x will be p / (f_j raised to some power).

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 1;

        for (long long factor : q_prime_factors) {
            long long current_p = p;
            // Divide current_p by 'factor' until it's no longer divisible by q
            while (current_p % q == 0) {
                current_p /= factor;
            }
            // current_p is now a divisor of original p, and current_p % q != 0.
            // This current_p is a candidate for max_x.
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    long long sum_r_val;
    if (b == 1) { // If b=1, then b-1=0, sum is 0.
        sum_r_val = 0;
    } else {
        long long b_minus_1 = b - 1;
        long long b_val = b;

        // One of b_minus_1 or b_val must be even.
        // Divide by 2 first to avoid overflow before modulo, then multiply.
        // (X * Y / 2) % MOD = ((X % (2*MOD)) * (Y % (2*MOD)) / 2) % MOD
        // Or, more simply, if X is even, (X/2 * Y) % MOD. If Y is even, (X * Y/2) % MOD.
        if (b_minus_1 % 2 == 0) {
            sum_r_val = (b_minus_1 / 2) % MOD;
            sum_r_val = (sum_r_val * b_val) % MOD;
        } else { // b_val must be even
            sum_r_val = (b_val / 2) % MOD;
            sum_r_val = (sum_r_val * b_minus_1) % MOD;
        }
    }

    // Calculate sum_k_term = sum_{k=1 to a} (k * b + 1)
    // sum_k_term = sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    // sum_k_term = b * (sum_{k=1 to a} k) + a
    // sum_{k=1 to a} k = a * (a + 1) / 2
    long long sum_k_val;
    long long a_val = a;
    long long a_plus_1 = a + 1;

    long long sum_k_arith; // a * (a+1) / 2
    if (a_val % 2 == 0) {
        sum_k_arith = (a_val / 2) % MOD;
        sum_k_arith = (sum_k_arith * a_plus_1) % MOD;
    } else { // a_plus_1 must be even
        sum_k_arith = (a_plus_1 / 2) % MOD;
        sum_k_arith = (sum_k_arith * a_val) % MOD;
    }

    long long term1 = (b % MOD * sum_k_arith) % MOD;
    long long term2 = a % MOD;
    sum_k_val = (term1 + term2) % MOD;

    // Total sum = sum_r_val * sum_k_val
    long long total_sum = (sum_r_val * sum_k_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

