int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> pos_by_char(26);
    for (int i = 0; i < L; ++i) {
        pos_by_char[s[i] - 'a'].push_back(i);
    }

    double total_prob = 0.0;

    for (int k_val = 0; k_val < L; ++k_val) {
        char first_char_t = s[k_val];
        int char_idx = first_char_t - 'a';

        const std::vector<int>& possible_k_indices = pos_by_char[char_idx];

        if (possible_k_indices.size() == 1) {
            total_prob += 1.0; // Unique k_val determined by t[0] alone
            continue;
        }

        // Vasya needs to choose an optimal position p (1 to L-1)
        // to maximize the probability of winning for this specific first_char_t.
        // This is equivalent to maximizing the number of k's that would be uniquely determined.

        // For each possible p, count how many k's from possible_k_indices
        // would be uniquely determined.
        int max_unique_count_for_this_char = 0;

        for (int p = 1; p < L; ++p) {
            std::vector<int> counts(26, 0); // Counts of t[p] for each char
            int current_unique_count = 0;

            for (int current_k : possible_k_indices) {
                // t[p] = s[(current_k + p) % L]
                char char_at_p = s[(current_k + p) % L];
                counts[char_at_p - 'a']++;
            }

            for (int count : counts) {
                if (count == 1) {
                    current_unique_count++;
                }
            }
            max_unique_count_for_this_char = std::max(max_unique_count_for_this_char, current_unique_count);
        }

        total_prob += static_cast<double>(max_unique_count_for_this_char) / possible_k_indices.size();
    }

    std::cout << std::fixed << std::setprecision(15) << total_prob / L << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << 1 << std::endl;
        return 0;
    }

    int k = static_cast<int>(std::ceil(std::sqrt(n)));

    std::vector<int> p(n);
    int current_val = n;
    for (int i = 0; i < n; i += k) {
        int block_start_val = std::max(1, current_val - k + 1);
        for (int j = 0; j < k && (i + j) < n; ++j) {
            p[i + j] = block_start_val + j;
        }
        current_val = block_start_val - 1;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

