void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    int min_suffix_price = a[n - 1]; // Initialize with the last element's price

    // Iterate from the second to last element backwards
    for (int i = n - 2; i >= 0; --i) {
        // If the current price is greater than the minimum price found so far to its right
        if (a[i] > min_suffix_price) {
            bad_prices_count++;
        } else {
            // If the current price is not bad, it might become the new minimum for elements to its left
            min_suffix_price = a[i];
        }
    }

    std::cout << bad_prices_count << "\n";
}

