    for (int i = 0; i < n; ++i) {
        current_balance += (a[i] == 1 ? 1 : -1);
        if (left_balances_map.find(current_balance) == left_balances_map.end()) {
            left_balances_map[current_balance] = i + 1;
        }
    }

    // Balances for the right side (jars n+1 to 2n)
    // right_balances[k] stores the balance of jars 2n-k+1 to 2n.
    // right_balances[0] = 0 (empty suffix)
    // right_balances[k] = balance of jars 2n-k+1...2n
    std::map<int, int> right_balances_map; // balance -> min_jars_removed
    right_balances_map[0] = 0; // 0 jars removed, balance 0

    current_balance = 0;
    for (int i = 2 * n - 1; i >= n; --i) {
        current_balance += (a[i] == 1 ? 1 : -1);
        if (right_balances_map.find(current_balance) == right_balances_map.end()) {
            right_balances_map[current_balance] = (2 * n - 1) - i + 1;
        }
    }

    // Calculate the total balance of all 2n jars
    int total_balance_all_jars = 0;
    for (int x : a) {
        total_balance_all_jars += (x == 1 ? 1 : -1);
    }

    int min_removed_jars = 2 * n; // Initialize with max possible

    // Iterate through all possible balances from the left side
    // For each left_balance, we need a right_balance such that:
    // (total_balance_all_jars - left_balance - right_balance) = 0
    // This means left_balance + right_balance = total_balance_all_jars
    // So, right_balance = total_balance_all_jars - left_balance
    for (auto const& [l_bal, l_removed] : left_balances_map) {
        int target_r_bal = total_balance_all_jars - l_bal;
        if (right_balances_map.count(target_r_bal)) {
            int r_removed = right_balances_map[target_r_bal];
            min_removed_jars = std::min(min_removed_jars, l_removed + r_removed);
        }
    }

    std::cout << min_removed_jars << std::endl;
}

