    // So, the max_k calculation for i=0 and i=n-1 should be ignored.
    // The values at indices 0 and n-1 are fixed.
    // The max_k should only consider changes for i from 1 to n-2.

    // Recalculate max_k considering only internal elements
    max_k = 0;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) {
