// Structure to store the result of a state (x, y)
// next_x: the x value after one full cycle (step 2 then step 3)
// delta_y: the change in y after one full cycle
// is_terminal: true if this state leads to termination within one cycle
// final_y_if_terminal: the y value if it terminates within one cycle
struct StateInfo {
    long long next_x;
    long long delta_y;
    bool is_terminal;
    long long final_y_if_terminal;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // a_values stores a_2, ..., a_n.
    // a_values[0] corresponds to a_2, a_values[n-2] corresponds to a_n.
    std::vector<long long> a_values(n - 1);
    for (int i = 0; i < n - 1; ++i) {
        std::cin >> a_values[i];
    }

    // dp[i] will store StateInfo for starting x = i+1 (0-indexed)
    // dp[0] for x=1, dp[1] for x=2, ..., dp[n-1] for x=n
    std::vector<StateInfo> dp(n + 1);

    // Calculate DP states from n down to 2
    // For x = n, n-1, ..., 2
    for (int x_curr_idx = n - 1; x_curr_idx >= 1; --x_curr_idx) {
        long long a_x = a_values[x_curr_idx - 1]; // a_values is 0-indexed, a_x is for x_curr_idx+1
                                                  // a_values[0] is a_2, so a_values[x_curr_idx-1] is a_{x_curr_idx+1}
                                                  // No, a_values[x_curr_idx-1] is a_{x_curr_idx}
                                                  // Example: x_curr_idx = 2, a_x = a_values[1] (which is a_3)
                                                  // This is correct. a_values[k] stores a_{k+2}.
                                                  // So a_values[x_curr_idx-1] stores a_{x_curr_idx+1}.
                                                  // This is confusing. Let's use a_values[k] for a_{k+2}.
                                                  // So a_values[x_curr_idx-2] is a_{x_curr_idx}.
                                                  // For x_curr_idx = 2, a_values[0] is a_2.
                                                  // For x_curr_idx = 3, a_values[1] is a_3.
                                                  // So a_x = a_values[x_curr_idx - 2] for x_curr_idx >= 2.

        // Let's re-index a_values to be 1-indexed for a_2 to a_n
        // a_values[k] stores a_{k+1} for k=1 to n-1.
        // So a_values[x_curr_idx-1] stores a_{x_curr_idx+1}.
        // This is still confusing. Let's just use a_values[x_curr_idx-2] for a_{x_curr_idx} for x_curr_idx >= 2.
        // The input is a_2, a_3, ..., a_n.
        // So a_values[0] is a_2, a_values[1] is a_3, ..., a_values[n-2] is a_n.
        // If current x is `x_curr_idx`, then `a_x` is `a_values[x_curr_idx - 2]`.
        // This is for x_curr_idx >= 2.
        // For the loop, x_curr_idx goes from n-1 down to 1.
        // When x_curr_idx is 1, a_x is not from a_values.
        // When x_curr_idx is 2, a_x is a_values[0].
        // When x_curr_idx is k, a_x is a_values[k-2].
        // This is correct for x_curr_idx >= 2.

        long long current_a_x = a_values[x_curr_idx - 2]; // This is a_{x_curr_idx}

        long long x_after_step2 = x_curr_idx + current_a_x;
        long long y_after_step2 = current_a_x; // y starts at 0 for this cycle

        long long x_after_step3 = x_after_step2 - current_a_x; // This is x_curr_idx
        long long y_after_step3 = y_after_step2 + current_a_x; // This is 2 * current_a_x

        // Check termination after step 2
        if (x_after_step2 <= 0 || x_after_step2 > n) {
            dp[x_curr_idx].is_terminal = true;
            dp[x_curr_idx].final_y_if_terminal = y_after_step2;
            dp[x_curr_idx].next_x = -1; // Not used
            dp[x_curr_idx].delta_y = -1; // Not used
        }
        // Check termination after step 3
        else if (x_after_step3 <= 0 || x_after_step3 > n) {
            dp[x_curr_idx].is_terminal = true;
            dp[x_curr_idx].final_y_if_terminal = y_after_step3;
            dp[x_curr_idx].next_x = -1; // Not used
            dp[x_curr_idx].delta_y = -1; // Not used
        }
