struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n, 0); // b_j = -A_j
    std::vector<long long> current_delta(n, 0);

    // Process operations in reverse to determine constraints on b_j
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // Type 1: a_j = a_j + d
            // This means A_j + current_delta_j becomes A_j + current_delta_j + d
            // So, current_delta_j effectively increases by d.
            // When processing in reverse, this means current_delta_j was d less before this operation.
            // So, we subtract d from current_delta for affected range.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] -= ops[i].val;
            }
        } else { // ops[i].type == 2
            // Type 2: max_{j=l}^{r} a_j = m
            // max_{j=l}^{r} (A_j + current_delta_j) = m
            // max_{j=l}^{r} (-b_j + current_delta_j) = m
            // max_{j=l}^{r} (-b_j) = m - min_{j=l}^{r} current_delta_j
            // min_{j=l}^{r} b_j = -(m - min_{j=l}^{r} current_delta_j)
            // min_{j=l}^{r} b_j = min_{j=l}^{r} current_delta_j - m

            long long min_delta_in_range = LLONG_MAX;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                min_delta_in_range = std::min(min_delta_in_range, current_delta[j]);
            }
            long long required_min_b = min_delta_in_range - ops[i].val;

            // Update b_j for elements in the range [l, r]
            // b_j must be at least required_min_b.
            // To satisfy this, we set b_j = max(b_j, required_min_b)
            // However, we also know that one of the b_j in the range must be exactly required_min_b.
            // To satisfy this, we set b_j to required_min_b for all j in the range.
            // This is because if we set b_k to required_min_b for some k, and b_j > required_min_b for j != k,
            // then min b_j in range is required_min_b.
            // If we set all b_j to required_min_b, then min b_j in range is required_min_b.
            // This greedy approach works because we want to find *any* valid array.
            // By setting b_j to required_min_b, we satisfy the constraint for this operation
            // and potentially make it easier to satisfy future constraints (by making b_j as small as possible).
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::max(b[j], required_min_b);
            }
        }
    }

    // Construct initial array A from b
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        a[i] = -b[i];
    }

    // Verify the solution
    std::vector<long long> current_a = a;
    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_a[j] += op.val;
            }
        } else { // op.type == 2
            long long max_val = LLONG_MIN;
            for (int j = op.l; j <= op.r; ++j) {
                max_val = std::max(max_val, current_a[j]);
            }
            if (max_val != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check absolute value constraint for initial array elements
    for (int i = 0; i < n; ++i) {
        if (std::abs(a[i]) > 1000000000LL) {
            std::cout << "NO\n"; // Should not happen with the current constraints and logic, but good to check.
            return 0;
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
