struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    long long current_d_sum = 0; // Sum of d_j from children who left due to chain reaction

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // Child i is now cured

        long long current_v_effect = children[i].v;
        current_d_sum = 0; // Reset for the new round of chain reactions

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply effects from the child being cured
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect--;
            }

            // Apply effects from previous chain reactions
            children[j].p -= current_d_sum;

            // Check for new chain reaction
            if (children[j].p < 0) {
                children[j].in_line = false;
                current_d_sum += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

