    std::cin >> a >> b;

    int count1_a = 0;
    for (char c : a) {
        if (c == '1') {
            count1_a++;
        }
    }

    int count1_b = 0;
    for (char c : b) {
        if (c == '1') {
            count1_b++;
        }
    }

    // If count1_a is odd, we can append a '1'.
    // If count1_a is even, we can append a '0'.
    // After appending a '1', count1_a increases by 1.
    // After appending a '0', count1_a remains the same.
    // So, if count1_a is odd, it becomes even. If count1_a is even, it remains even.
    // This means we can always make count1_a even by appending a '1' if it's odd.
    // Or, we can always keep count1_a even by appending a '0' if it's even.
    // The maximum number of '1's we can achieve in string 'a' is count1_a + (length_a - length_b) if length_a < length_b.
    // More generally, we can always increase the count of '1's by 1 if it's odd, or keep it the same if it's even.
    // The maximum number of '1's we can have in 'a' after any number of operations
    // (assuming we can make 'a' long enough) is `count1_a` if `count1_a` is even,
