#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all in S1)
    // min_f = a_1 + a_2
    // max_f = a_{n-1} + a_n
    // goodness = (a_{n-1} + a_n) - (a_1 + a_2)
    long long goodness_all_same = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);
    std::vector<int> partition_all_same(n, 1); // All in subsequence 1

    // Case 2: Partition into two non-empty subsequences
    // The optimal strategy for non-empty subsequences is to put a_1 in one, and a_2, ..., a_n in the other.
    // Or, more generally, to put a_1, a_2, ..., a_{k-1} in one and a_k, ..., a_n in the other.
    // However, the problem statement implies that the minimum goodness is achieved when the range of sums is minimized.
    // The critical observation is that if we have elements in both subsequences,
    // the minimum possible sum is a_1 + a_2 (if a_1, a_2 are in the same group) OR a_1 + a_2 + h (if a_1, a_2 are in different groups).
    // The maximum possible sum is a_{n-1} + a_n (if a_{n-1}, a_n are in the same group) OR a_{n-1} + a_n + h (if a_{n-1}, a_n are in different groups).
    //
    // Consider the partition where elements[0] is in S1 and elements[1] is in S2.
    // And all other elements elements[2]...elements[n-1] are in S2.
    // S1 = {elements[0]}
    // S2 = {elements[1], elements[2], ..., elements[n-1]}
    //
    // Pairs within S1: None (if n=1, but n>=2)
    // Pairs within S2:
    //   min_sum_S2 = elements[1].value + elements[2].value
    //   max_sum_S2 = elements[n-1].value + elements[n-2].value
    // Pairs across S1 and S2:
    //   min_sum_cross = elements[0].value + elements[1].value + h
    //   max_sum_cross = elements[0].value + elements[n-1].value + h
    //
    // Overall min_f = min(min_sum_S2, min_sum_cross)
    // Overall max_f = max(max_sum_S2, max_sum_cross)
    //
    // This specific partition (S1={a_1}, S2={a_2, ..., a_n}) is often optimal when h is large.
    // Let's calculate goodness for this partition.
    //
    // min_f_val:
    //   If n=2: S1={a_1}, S2={a_2}. Only cross pair (a_1, a_2). min_f = a_1 + a_2 + h. max_f = a_1 + a_2 + h. Goodness = 0.
    //   If n > 2:
    //     Pairs within S2: elements[1].value + elements[2].value
    //     Pairs across S1-S2: elements[0].value + elements[1].value + h
    //     min_f = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    //
    // max_f_val:
    //   If n=2: max_f = a_1 + a_2 + h.
    //   If n > 2:
    //     Pairs within S2: elements[n-1].value + elements[n-2].value
    //     Pairs across S1-S2: elements[0].value + elements[n-1].value + h
    //     max_f = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)
    //
    // Goodness for this partition: max_f_val - min_f_val

    long long min_f_val_split, max_f_val_split;
    if (n == 2) {
        min_f_val_split = elements[0].value + elements[1].value + h;
        max_f_val_split = elements[0].value + elements[1].value + h;
    } else {
        min_f_val_split = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
        max_f_val_split = std::max(elements[n - 1].value + elements[n - 2].value, elements[0].value + elements[n - 1].value + h);
    }
    long long goodness_split = max_f_val_split - min_f_val_split;

    if (goodness_split < goodness_all_same) {
        std::cout << goodness_split << "\n";
        std::vector<int> result_partition(n);
        result_partition[elements[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            result_partition[elements[i].original_index] = 2;
        }
        for (int i = 0; i < n; ++i) {
            std::cout << result_partition[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness_all_same << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition_all_same[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

