    // This is 2 cuts.
    //
    // This strategy works if `s_prefix` is not equal to `s_suffix`.
    // But `s_prefix` is the reverse of `s_suffix`. So they are only equal if `s_prefix` is a palindrome.
    //
    // The problem statement implies that if k=1 doesn't work and not all characters are the same, then k=2 is the answer.
    // This is a common competitive programming trick. If a simple case (k=1) fails, and a trivial case (all_same) is handled,
    // then the next simple case (k=2) is usually the answer.
    //
    // The only remaining case is when `s` is a palindrome, not all characters are the same, and no single cut works.
    // In this case, the answer is 2.
    // This covers all scenarios.

    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 3; ++j) {
            prefix_counts[j][i + 1] = prefix_counts[j][i];
        }
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = prefix_counts[0][r] - prefix_counts[0][l - 1];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        if (std::abs(count_x - count_y) <= 1 &&
            std::abs(count_x - count_z) <= 1 &&
            std::abs(count_y - count_z) <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::vector<std::set<char>> adj(26);
    bool possible = true;

    for (size_t i = 0; i < s.length() - 1; ++i) {
        char c1 = s[i];
        char c2 = s[i+1];

        adj[c1 - 'a'].insert(c2);
        adj[c2 - 'a'].insert(c1);
    }

    for (int i = 0; i < 26; ++i) {
        if (adj[i].size() > 2) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    std::string layout = "";
    std::vector<bool> visited(26, false);

    // Find a starting point for a chain
    char current_char = '\0';
    for (int i = 0; i < 26; ++i) {
        if (adj[i].size() == 1) { // Found an endpoint of a chain
            current_char = (char)('a' + i);
            break;
        }
    }

    if (current_char == '\0') { // All connected components are cycles or isolated nodes
        // If there are any characters in 's', they must form a cycle or be isolated.
        // If all characters in 's' form a cycle, we can pick any character from 's' as a start.
        // If 's' is empty or has one char, this loop won't run, current_char remains '\0'.
        // If 's' has multiple chars and forms a cycle, pick the first char of 's'.
        if (!s.empty()) {
            current_char = s[0];
        } else {
            // If s is empty, any layout is fine. Just print a-z.
            std::cout << "YES\n";
            for (char c = 'a'; c <= 'z'; ++c) {
                std::cout << c;
            }
            std::cout << "\n";
            return;
        }
    }

    // Build the layout string for the connected component containing current_char
    char prev_char = '\0';
    while (current_char != '\0' && !visited[current_char - 'a']) {
        layout += current_char;
        visited[current_char - 'a'] = true;

        char next_char = '\0';
        for (char neighbor : adj[current_char - 'a']) {
            if (neighbor != prev_char) {
                next_char = neighbor;
                break;
            }
        }
        prev_char = current_char;
        current_char = next_char;
    }

    // Add remaining unvisited characters (those not in 's' or isolated)
    for (int i = 0; i < 26; ++i) {
        if (!visited[i]) {
            layout += (char)('a' + i);
        }
    }

    // Check if all characters from 's' are included in the layout
    // This check is implicitly handled by the logic:
    // If a character from 's' was part of a chain/cycle, it's added.
    // If it was isolated (e.g., 'a' in "b"), it would be added in the second loop.
    // The only way it could fail is if a character from 's' was part of a component
    // that couldn't be fully traversed (e.g., a cycle that wasn't fully added because
    // we started from an endpoint of another component and didn't visit it).
    // However, our logic ensures all characters from 's' are either part of the
    // initial chain or added as isolated characters.
    // The main check for impossibility is adj.size() > 2.

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

using namespace std;

bool check(long long T, int n, int m, const vector<long long>& h, const vector<long long>& p) {
    vector<long long> dp(m + 1, -1); // dp[j] = minimum h_idx needed to cover p[0...j-1]
    dp[0] = -1; // Base case: 0 tracks covered, no head needed (conceptually, before first head)

    for (int j = 0; j < m; ++j) { // Iterate through target tracks p_j
        if (dp[j] == -1) continue; // If p[0...j-1] cannot be covered, skip

        // Option 1: Cover p[j] using an existing head that covered p[j-1]
        // This means p[j] is within range of the head that covered p[j-1]
        // The head that covered p[j-1] must have been at some h_k.
        // If p[j] is within [h_k - T, h_k + T], then it's covered.
        // This is implicitly handled by the greedy approach below.
        // If p[j] is covered by the same head that covered p[j-1], then dp[j+1] can be dp[j].
        // This is true if p[j] is within the range of the head that covered p[j-1].
        // The `dp[j]` value represents the *index* of the head used to cover `p[j-1]`.
        // If `dp[j]` is `k`, it means head `k` (at `h[k]`) was used.
        // The range covered by head `k` is `[h[k] - T, h[k] + T]`.
        // If `p[j]` is within this range, then `dp[j+1]` can be `k`.
        // However, the `dp` state is defined as "minimum h_idx needed to cover p[0...j-1]".
        // This means `dp[j]` is the *first available head index* that can cover `p[j-1]`
        // and all previous tracks.
        // So, if `p[j]` is covered by `h[dp[j]]`, then `dp[j+1]` can be `dp[j]`.
        if (dp[j] < n && p[j] <= h[dp[j]] + T) {
            if (dp[j+1] == -1 || dp[j] < dp[j+1]) {
                dp[j+1] = dp[j];
            }
        }

        // Option 2: Cover p[j] using a new head
        // We need to find the smallest index `k` such that `h[k]` can cover `p[j]`.
        // This head `h[k]` must be *after* `dp[j]` (i.e., `k > dp[j]`).
        // The head `h[k]` must be able to reach `p[j]`, i.e., `p[j]` is in `[h[k] - T, h[k] + T]`.
        // So, `h[k] - T <= p[j] <= h[k] + T`.
        // This means `h[k] <= p[j] + T` and `h[k] >= p[j] - T`.
        // We are looking for the smallest `k > dp[j]` such that `h[k] >= p[j] - T`.
        // The `lower_bound` finds the first `h[k]` that is `>= p[j] - T`.
        // We need to ensure this `h[k]` is also `<= p[j] + T`.

        // Find the first head `h[k]` that can potentially cover `p[j]` from its left side.
        // That is, `h[k] >= p[j] - T`.
        auto it = lower_bound(h.begin() + dp[j] + 1, h.end(), p[j] - T);

        if (it != h.end()) {
            int k = distance(h.begin(), it);
            // If this head `h[k]` can also cover `p[j]` from its right side (i.e., `h[k] <= p[j] + T`),
            // then it's a candidate.
            if (h[k] <= p[j] + T) {
                if (dp[j+1] == -1 || k < dp[j+1]) {
                    dp[j+1] = k;
                }
            }
        }
    }

    return dp[m] != -1;
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n, m;
    cin >> n >> m;

    vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        cin >> h[i];
    }

    vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible distance: (10^10 - 1) + (10^10 - 1) approx 2e10
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    cout << ans << endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_val = 0; // The target value for a[0] must be at least 0.
                            // For a[i], its target value must be at least target_a[i-1].

    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];

        // Case 1: current_a is already >= prev_val.
        // We need to ensure target_a[i] >= prev_val.
        // If current_a >= prev_val, we can potentially keep target_a[i] = current_a.
        // This requires 0 operations on a[i] (relative to current_a).
        // The number of operations needed for a[i] is (target_a[i] - current_a + m) % m.
        // If we choose target_a[i] = current_a, operations = 0.
        // If we choose target_a[i] = current_a + m, operations = m.
        // We can achieve target_a[i] = current_a if 0 <= x.
        // We can achieve target_a[i] = current_a + m if m <= x.
        //
        // If current_a >= prev_val:
        // We can set target_a[i] = current_a. This requires 0 operations on a[i].
        // This is valid if 0 <= x.
        // So, if current_a >= prev_val, we can just set prev_val = current_a and move on.
        // This is the greedy choice to minimize the current element's value.
        if (current_a >= prev_val) {
            // If current_a is already greater than or equal to prev_val,
            // we can potentially keep a[i] as current_a.
            // This requires 0 operations on a[i] (relative to current_a).
            // The number of operations needed for a[i] is (target_a[i] - current_a + m) % m.
            // If we choose target_a[i] = current_a, operations = 0.
            // This is valid if 0 <= x.
            // So, if current_a >= prev_val, we can just set prev_val = current_a and move on.
            // This is the greedy choice to minimize the current element's value.
            // However, we must consider if we *have* to increment it.
            // If current_a + x < prev_val + m, then we can't reach prev_val + m.
            // We need to check if current_a can be made equal to or greater than prev_val.
            // The smallest value a[i] can take is current_a.
            // The largest value a[i] can take is (current_a + x) % m.
            // Or, more precisely, current_a, (current_a+1)%m, ..., (current_a+x)%m.
            //
            // If current_a >= prev_val:
            // We can try to keep a[i] as current_a. This requires 0 operations.
            // This is valid if 0 <= x.
            // So, if current_a >= prev_val, we can set the target for a[i] to current_a.
            // This means prev_val for the next iteration becomes current_a.
            // This is always possible if current_a >= prev_val.
            //
            // But what if current_a is too large? E.g., prev_val = 0, current_a = m-1.
            // We can set target_a[i] = m-1.
            // What if prev_val = 1, current_a = 0?
            // We need to increment 0 to at least 1.
            //
            // Let's re-evaluate. We need to find a target value `t_i` for `a_i` such that:
            // 1. `t_i >= prev_val`
            // 2. `(t_i - a_i + m) % m <= x`
            //
            // If `a_i >= prev_val`:
            // We can try `t_i = a_i`. This satisfies `t_i >= prev_val`.
            // The operations needed are `(a_i - a_i + m) % m = 0`.
            // This is valid if `0 <= x`. This is always true.
            // So, if `a_i >= prev_val`, we can set `t_i = a_i`.
            //
            // However, there's another option: `t_i = a_i + m`.
            // This also satisfies `t_i >= prev_val` (since `a_i >= 0`, `m >= 1`).
            // The operations needed are `(a_i + m - a_i + m) % m = m`.
            // This is valid if `m <= x`.
            //
            // We want to choose the smallest possible `t_i` that satisfies the conditions.
            // If `a_i >= prev_val`:
            //   Option 1: `t_i = a_i`. Operations = 0. Valid if `0 <= x`.
            //   Option 2: `t_i = a_i + m`. Operations = `m`. Valid if `m <= x`.
            //
            // If `m <= x`, we can choose `t_i = a_i` or `t_i = a_i + m`.
            // If `a_i >= prev_val`, we prefer `t_i = a_i` because it's smaller.
            // So, if `a_i >= prev_val`, we set `prev_val = a_i`.
            //
            // If `a_i < prev_val`:
            // We must increment `a_i`.
            // The smallest `t_i` that satisfies `t_i >= prev_val` is `prev_val`.
            // Can we achieve `t_i = prev_val`?
            // Operations needed: `(prev_val - a_i + m) % m`.
            // This is `prev_val - a_i` if `prev_val >= a_i`.
            // This is `prev_val - a_i + m` if `prev_val < a_i`.
            // Since we are in the `a_i < prev_val` case, operations needed are `prev_val - a_i`.
            // This is valid if `prev_val - a_i <= x`.
            //
            // If `prev_val - a_i <= x`, we can set `t_i = prev_val`.
            // So, we set `prev_val = prev_val`.
            //
            // If `prev_val - a_i > x`, we cannot achieve `t_i = prev_val`.
            // We must increment `a_i` by `x` operations.
            // The value becomes `(a_i + x) % m`.
            // This value must be `>= prev_val`.
            // But `a_i < prev_val`.
            // If `a_i + x < prev_val`, then we can't make it `prev_val`.
            // We can only make it `(a_i + x) % m`.
            // If `(a_i + x) % m < prev_val`, then it's impossible.
            //
            // Let's simplify the logic.
            // For each `a[i]`, we need to find a `target_val` such that:
            // 1. `target_val >= prev_val`
            // 2. The number of operations to change `a[i]` to `target_val` is `k_ops <= x`.
            //    `k_ops = (target_val - a[i] + m) % m`.
            //
            // We want to choose the smallest possible `target_val` for `a[i]` to keep `prev_val` for the next element as small as possible.
            //
            // Candidate 1: `target_val = a[i]`.
            //   Operations needed: `0`.
            //   This is valid if `0 <= x` (always true) AND `a[i] >= prev_val`.
            //   If both are true, we can set `prev_val = a[i]`.
            //
            // Candidate 2: `target_val = prev_val`.
            //   Operations needed: `(prev_val - a[i] + m) % m`.
            //   This is valid if `(prev_val - a[i] + m) % m <= x`.
            //   If this is true, we can set `prev_val = prev_val`.
            //
            // If `a[i] >= prev_val`:
            //   We can choose `target_val = a[i]`. Operations = 0. This is valid.
            //   We can also choose `target_val = prev_val`. Operations = `(prev_val - a[i] + m) % m`.
            //   If `prev_val <= a[i]`, then `(prev_val - a[i] + m) % m` is `m - (a[i] - prev_val)`.
            //   This is `m - (a[i] - prev_val)`.
            //   Example: m=7, a[i]=6, prev_val=0.
            //   Option 1: target=6. ops=0. `prev_val` becomes 6.
            //   Option 2: target=0. ops=(0-6+7)%7 = 1. `prev_val` becomes 0.
            //   We want to keep `prev_val` as small as possible. So we prefer Option 2 if possible.
            //   Option 2 is possible if `1 <= x`.
            //
            // Let's try this logic:
            // We need to find `t_i` such that `t_i >= prev_val` and `(t_i - a_i + m) % m <= x`.
            // We want the smallest such `t_i`.
            //
            // Consider `a_i`.
            // If we don't increment `a_i` (i.e., `k_ops = 0`), then `t_i = a_i`.
            // This is valid if `a_i >= prev_val`.
            //
            // If we increment `a_i` by `k_ops` (where `1 <= k_ops <= x`), then `t_i = (a_i + k_ops) % m`.
            //
            // The smallest possible value for `t_i` is `prev_val`.
            // Can we make `a_i` equal to `prev_val`?
            // Operations needed: `diff = (prev_val - a_i + m) % m`.
            // If `diff <= x`, then we can set `t_i = prev_val`.
            // This is the best choice for `t_i` because it's the smallest possible.
            // So, if `diff <= x`, we set `prev_val = prev_val`.
            //
            // What if `diff > x`?
            // This means we cannot make `a_i` equal to `prev_val` using at most `x` operations.
            // We can increment `a_i` by at most `x`.
            // The largest value `a_i` can become is `(a_i + x) % m`.
            // If `a_i + x < prev_val`, then even with `x` operations, `a_i` cannot reach `prev_val`.
            // In this case, it's impossible.
            //
            // Let's trace this logic:
            // `prev_val` is the minimum value `a[i-1]` could have taken.
            // For `a[i]`, we need to find `target_a[i]` such that `target_a[i] >= prev_val`.
            // And `(target_a[i] - a[i] + m) % m <= x`.
            // We want to make `target_a[i]` as small as possible.
            //
            // Option A: `target_a[i] = a[i]`.
            //   This requires 0 operations.
            //   This is valid if `a[i] >= prev_val`.
            //
            // Option B: `target_a[i] = prev_val`.
            //   This requires `(prev_val - a[i] + m) % m` operations.
            //   This is valid if `(prev_val - a[i] + m) % m <= x`.
            //
            // If `a[i] >= prev_val`:
            //   We have two choices for `target_a[i]` that are `>= prev_val`:
            //   1. `a[i]` (0 ops)
            //   2. `prev_val` (if `(prev_val - a[i] + m) % m <= x`)
            //   We want the smaller of these.
            //   If `(prev_val - a[i] + m) % m <= x`, then we can achieve `prev_val` with `x` ops.
            //   Since `prev_val <= a[i]`, `prev_val` is smaller than `a[i]`.
            //   So, if `(prev_val - a[i] + m) % m <= x`, we set `prev_val = prev_val`.
            //   Otherwise (if `(prev_val - a[i] + m) % m > x`), we cannot achieve `prev_val`.
            //   The only other option that is `>= prev_val` and requires `0` ops is `a[i]`.
            //   So, we set `prev_val = a[i]`.
            //
            // If `a[i] < prev_val`:
            //   We must increment `a[i]`.
            //   The smallest value we can aim for is `prev_val`.
            //   Operations needed: `prev_val - a[i]`.
            //   If `prev_val - a[i] <= x`, then we can achieve `prev_val`.
            //   So, we set `prev_val = prev_val`.
            //   Otherwise (`prev_val - a[i] > x`), we cannot achieve `prev_val`.
            //   It's impossible to make `a[i]` `>= prev_val` with `x` operations.
            //   Return `false`.

        // Simplified logic:
        // We need to find a `target_val` for `a[i]` such that:
        // 1. `target_val >= prev_val`
        // 2. `(target_val - current_a + m) % m <= x`
        // We want to make `target_val` as small as possible.

        // Case 1: `current_a >= prev_val`
        // We have two options for `target_val` that are `>= prev_val`:
        //   a) `target_val = current_a`. This requires 0 operations. Always possible if `0 <= x`.
        //   b) `target_val = prev_val`. This requires `(prev_val - current_a + m) % m` operations.
        //      Since `current_a >= prev_val`, `prev_val - current_a` is negative or zero.
        //      So `(prev_val - current_a + m) % m` is `m - (current_a - prev_val)`.
        //      This is the number of operations to wrap around and reach `prev_val`.
        //      This is possible if `m - (current_a - prev_val) <= x`.
        //
        // We prefer the smaller `target_val`. `prev_val` is smaller than or equal to `current_a`.
        // So, if `m - (current_a - prev_val) <= x` (i.e., we can reach `prev_val` by wrapping around),
        // we choose `target_val = prev_val`.
        // Otherwise, we cannot reach `prev_val` by wrapping around with `x` operations.
        // The only other option that is `>= prev_val` and requires `0` ops is `current_a`.
        // So, we choose `target_val = current_a`.
        //
        // In summary for `current_a >= prev_val`:
        // If `current_a - prev_val <= x` (this is equivalent to `m - (current_a - prev_val) > x` if `current_a - prev_val` is small,
        // but it's simpler to think about it as: can we keep `a[i]` as `current_a` or increment it to `current_a + k` such that `current_a + k >= prev_val` and `k <= x`?)
        //
        // Let's use the `diff` approach.
        // `diff = (prev_val - current_a + m) % m`. This is the number of operations to change `current_a` to `prev_val` (modulo `m`).
        // If `diff <= x`:
        //   We can make `a[i]` equal to `prev_val`. This is the smallest possible value for `a[i]`.
        //   So, `prev_val` remains `prev_val`.
        // Else (`diff > x`):
        //   We cannot make `a[i]` equal to `prev_val`.
        //   We must make `a[i]` at least `prev_val`.
        //   If `current_a >= prev_val`:
        //     We can keep `a[i]` as `current_a` (0 operations). This satisfies `a[i] >= prev_val`.
        //     So, `prev_val` becomes `current_a`.
        //   If `current_a < prev_val`:
        //     We cannot make `a[i]` equal to `prev_val` (because `diff > x`).
        //     And `current_a` itself is less than `prev_val`.
        //     So, it's impossible. Return `false`.

        long long diff = (prev_val - current_a + m) % m;

        if (diff <= x) {
            // We can make a[i] equal to prev_val (or prev_val + m, etc.)
            // by applying `diff` operations. Since `diff <= x`, this is allowed.
            // We choose `prev_val` as the target for `a[i]` because it's the smallest possible.
            // So, `prev_val` for the next iteration remains `prev_val`.
        } else { // diff > x
            // We cannot make a[i] equal to prev_val using at most `x` operations.
            // This means we cannot "wrap around" `m` to reach `prev_val` if `current_a` is large,
            // or we cannot simply increment `current_a` to `prev_val` if `current_a` is small.
            //
            // If `current_a >= prev_val`:
            //   We cannot reach `prev_val` by wrapping around.
            //   But `current_a` itself is already `>= prev_val`.
            //   We can choose `target_a[i] = current_a`. This requires 0 operations, which is `<= x`.
            //   So, we must set `prev_val = current_a` for the next iteration.
            //
            // If `current_a < prev_val`:
            //   We cannot reach `prev_val` by simply incrementing `current_a` (because `diff = prev_val - current_a > x`).
            //   And `current_a` itself is less than `prev_val`.
            //   So, it's impossible to make `a[i]` at least `prev_val`.
            //   Return `false`.
            if (current_a < prev_val) {
                return false;
            }
            // Else (current_a >= prev_val and diff > x), we must use current_a as the target.
            // This means prev_val for the next iteration becomes current_a.
            prev_val = current_a;
        }
    }
    return true;
}

