}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // dp[i] stores the maximum length of a suffix of s[0...i] that does NOT contain a triple.
    // This is equivalent to the minimum l such that s[l...i] contains a triple.
    // If s[l...i] contains a triple, then l must be <= i - max_len_no_triple.
    // So, max_len_no_triple = i - min_l_with_triple + 1.
    // Or, min_l_with_triple = i - max_len_no_triple + 1.
    // Let's define dp[i] as the smallest starting index `l` such that the substring s[l...i]
    // contains a triple. If no such `l` exists, dp[i] = 0 (or 1, depending on 0- or 1-indexing).
    // Let's use 1-based indexing for dp values to match problem statement.
    // dp[i] = minimum l such that s[l...i] contains a triple.
    // If s[1...i] does not contain a triple, dp[i] = 0.
    // The problem uses 1-based indexing for string characters, so s_x means s[x-1].
    // Let's convert s to 1-based indexing for easier mapping.
    // Or, just use 0-based indexing for string and adjust.
    // s[i] is char at index i.
    // s_x = s[x-1].
    // s_x = s_{x+k} = s_{x+2k} means s[x-1] = s[x+k-1] = s[x+2k-1].
    // Let current_idx = i. We are looking for s[i-1] = s[i-1-k] = s[i-1-2k].
    // The indices are i-1, i-1-k, i-1-2k.
    // The largest index is i-1. The smallest is i-1-2k.
    // The length of this pattern is 2k+1.
    // The starting index is i-1-2k. The ending index is i-1.

    // Let dp[i] be the smallest starting index `l` (1-based) such that s[l-1...i-1] contains a triple.
    // If no such `l` exists, dp[i] = 1 (meaning the whole prefix s[0...i-1] is good).
    // We want to find the number of pairs (l, r) such that s[l-1...r-1] does NOT contain a triple.
    // For a fixed r, we need to find the number of l's such that s[l-1...r-1] does not contain a triple.
    // This means l must be greater than dp[r].
    // So for a fixed r, the valid l's are dp[r]+1, dp[r]+2, ..., r.
    // The number of such l's is r - (dp[r]+1) + 1 = r - dp[r].
    // If dp[r] = 1, then l can be 1, ..., r. Number of l's is r.
    // This means dp[r] should be the *last* index that *must* be included to form a triple.
    // Let's redefine dp[i] as the maximum starting index `l` (1-based) such that s[l-1...i-1] does NOT contain a triple.
    // This is equivalent to saying that for any $l' \le l$, $s[l'-1 \dots i-1]$ contains a triple.
    // So, for a fixed `r` (current index `i`), `l` can range from `dp[i]` to `i`.
    // The number of good `l` values for this `r` is `i - dp[i] + 1`.
    // `dp[i]` is the smallest `l` such that `s[l-1...i-1]` contains a triple.
    // If `s[0...i-1]` does not contain a triple, `dp[i]` is `0`.
    // Then for a fixed `r` (current index `i`), the number of `l`'s such that `s[l-1...i-1]` does not contain a triple is `i - dp[i]`.
    // If `dp[i]` is `0`, then `i` such `l`'s (1 to `i`).
    // Let `dp[i]` be the smallest `l` (1-based) such that `s[l-1...i-1]` contains a triple.
    // If no such `l` exists, `dp[i] = 0`.
    // Then for a fixed `r` (current index `i`), the number of `l`'s (1-based) such that `s[l-1...i-1]` does NOT contain a triple is `i - dp[i]`.
    // This is because `l` must be in `[1, i]`. If `s[l-1...i-1]` contains a triple, then `l >= dp[i]`.
    // So `l` must be in `[1, dp[i]-1]`. The count is `dp[i]-1`.
    // This is the number of good `l`'s for a fixed `r`.
    // Let's use `min_l_bad[i]` to denote the minimum `l` (1-based) such that `s[l-1...i-1]` contains a triple.
    // If no such `l` exists, `min_l_bad[i] = i+1`.
    // Then for a fixed `r` (current index `i`), the number of `l`'s such that `s[l-1...i-1]` does NOT contain a triple is `min_l_bad[i] - 1`.

    std::vector<int> min_l_bad(n + 1, n + 1); // min_l_bad[i] for substring ending at index i-1 (0-based)
                                            // min_l_bad[i] = smallest l (1-based) such that s[l-1...i-1] contains a triple.
                                            // Initialize to n+1, meaning no triple found yet.

    for (int i = 1; i <= n; ++i) { // i is the current right endpoint (1-based)
        // Inherit from previous:
        min_l_bad[i] = min_l_bad[i-1]; // A triple ending at i-2 is also a triple in s[...i-1]

        // Check for new triples ending at i-1:
        // s[x-1] = s[x+k-1] = s[x+2k-1]
        // The rightmost character is s[i-1].
        // So, i-1 = x+2k-1 => x+2k = i.
        // We need to check for k=1, 2, ..., max_k.
        // Max k: x >= 1 => 1+2k <= i => 2k <= i-1 => k <= (i-1)/2.
        // For k=1: check s[i-3] = s[i-2] = s[i-1].
        // If i-1 >= 2, i-2 >= 1, i-3 >= 0.
        // Indices are i-1, i-2, i-3.
        if (i - 3 >= 0 && s[i-3] == s[i-2] && s[i-2] == s[i-1]) {
            min_l_bad[i] = std::min(min_l_bad[i], i - 2); // x = i-2, so l = i-2
        }
        // For k=2: check s[i-5] = s[i-3] = s[i-1].
        // Indices are i-1, i-3, i-5.
        if (i - 5 >= 0 && s[i-5] == s[i-3] && s[i-3] == s[i-1]) {
            min_l_bad[i] = std::min(min_l_bad[i], i - 4); // x = i-4, so l = i-4
        }
        // For k=3: check s[i-7] = s[i-4] = s[i-1].
        // Indices are i-1, i-4, i-7.
        if (i - 7 >= 0 && s[i-7] == s[i-4] && s[i-4] == s[i-1]) {
            min_l_bad[i] = std::min(min_l_bad[i], i - 6); // x = i-6, so l = i-6
        }
        // For k=4: check s[i-9] = s[i-5] = s[i-1].
        // Indices are i-1, i-5, i-9.
        if (i - 9 >= 0 && s[i-9] == s[i-5] && s[i-5] == s[i-1]) {
            min_l_bad[i] = std::min(min_l_bad[i], i - 8); // x = i-8, so l = i-8
        }
        // For k=5: check s[i-11] = s[i-6] = s[i-1].
        // Indices are i-1, i-6, i-11.
        if (i - 11 >= 0 && s[i-11] == s[i-6] && s[i-6] == s[i-1]) {
            min_l_bad[i] = std::min(min_l_bad[i], i - 10); // x = i-10, so l = i-10
        }
        // For k=6: check s[i-13] = s[i-7] = s[i-1].
        // Indices are i-1, i-7, i-13.
        if (i - 13 >= 0 && s[i-13] == s[i-7] && s[i-7] == s[i-1]) {
            min_l_bad[i] = std::min(min_l_bad[i], i - 12); // x = i-12, so l = i-12
        }
        // For k=7: check s[i-15] = s[i-8] = s[i-1].
        // Indices are i-1, i-8, i-15.
        if (i - 15 >= 0 && s[i-15] == s[i-8] && s[i-8] == s[i-1]) {
            min_l_bad[i] = std::min(min_l_bad[i], i - 14); // x = i-14, so l = i-14
        }
        // For k=8: check s[i-17] = s[i-9] = s[i-1].
        // Indices are i-1, i-9, i-17.
        if (i - 17 >= 0 && s[i-17] == s[i-9] && s[i-9] == s[i-1]) {
            min_l_bad[i] = std::min(min_l_bad[i], i - 16); // x = i-16, so l = i-16
        }

        // The maximum k we need to check is small.
        // If k is large, say k=100, then 2k=200.
        // The pattern s_x s_{x+k} s_{x+2k} has length 2k+1.
        // If a substring s[l...r] contains this pattern, then r-l+1 >= 2k+1.
        // If r-l+1 is small, say <= 18, then 2k+1 <= 18 => 2k <= 17 => k <= 8.
        // If a substring s[l...r] does NOT contain any triple, then its length must be small.
        // The maximum length of a binary string without a triple is 18.
        // For example, 001100110011001100 (length 18) has no triple.
        // Any string of length 19 must contain a triple.
        // This means that if i - (min_l_bad[i]-1) + 1 > 18, then min_l_bad[i] must be updated.
        // So, we only need to check k up to 8.
        // The maximum length of a substring without a triple is 18.
        // If a substring s[l-1...i-1] has length > 18, it must contain a triple.
        // So, min_l_bad[i] cannot be greater than i - 18.
        // This means min_l_bad[i] = std::min(min_l_bad[i], i - 18).
        // This is implicitly handled by the k checks.
        // If min_l_bad[i] is still n+1, it means no triple ending at or before i-1 has been found.
        // In this case, all substrings s[l-1...i-1] are good.
        // The number of good l's for this r (i) is i.
        // If min_l_bad[i] is some value L, then substrings s[l-1...i-1] for l < L are good.
        // The number of good l's is L-1.
        bad_pairs += (min_l_bad[i] - 1);
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

