#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists.
    // Reversing the permutation always produces a permutation with the same fingerprint.
    // F(p) = sort([p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n])
    // Let p' be the reversed permutation: p' = [p_n, p_{n-1}, ..., p_1]
    // F(p') = sort([p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1])
    // The set of sums {p_i + p_{i+1}} is the same as {p_{n-i} + p_{n-i-1}}.
    // For example, p_1+p_2 is in both sets. p_2+p_3 is in both sets, etc.
    // The only case where p' might be equal to p is if p is a palindrome.
    // However, the problem guarantees that p' must be different from p.
    // If p is a palindrome, e.g., [1,2,1] (not a permutation), or [1,3,2,3,1] (not a permutation).
    // A permutation cannot be a palindrome unless n=1 (not allowed, n>=2) or n=0.
    // For n >= 2, a permutation [p_1, ..., p_n] cannot be a palindrome because if p_i = p_{n-i+1} for all i,
    // then if n is odd, the middle element p_{(n+1)/2} would be equal to itself.
    // If n is even, say n=4, p=[p_1,p_2,p_3,p_4]. If p is a palindrome, p_1=p_4, p_2=p_3.
    // This means p_1, p_2, p_3, p_4 are distinct. But if p_1=p_4 and p_2=p_3, then we have only two distinct values.
    // This is only possible if n=2, p=[1,2] -> p'=[2,1]. Here p != p'.
    // If p=[1,2,3,4], p'=[4,3,2,1]. p != p'.
    // If p=[1,3,2,4], p'=[4,2,3,1]. p != p'.
    // In general, for any permutation p of length n >= 2, its reverse p_rev will be different from p.
    // If p == p_rev, then p_i == p_{n-i+1} for all i.
    // Since all elements p_i are distinct, this implies that if p_i == p_{n-i+1}, then i must be equal to n-i+1.
    // This can only happen for the middle element if n is odd.
    // For example, if n=3, p=[1,2,3]. p_rev=[3,2,1]. p!=p_rev.
    // If p=[1,2,1], this is not a permutation.
    // So, reversing the permutation always works.

    for (int i = n - 1; i >= 0; --i) {
        std::cout << p[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;
}

