#include <numeric>
#include <algorithm>

void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    int current_a1 = a[0];
    int remaining_days = d;

    for (int i = 1; i < n; ++i) {
        int pile_index = i; // 0-indexed pile index
        int haybales_in_pile = a[pile_index];
        int days_to_move_one = pile_index; // days to move from pile_index+1 to pile 1

        if (days_to_move_one == 0) { // This should only happen for pile 0, which is a[0]
            continue;
        }

        if (remaining_days >= days_to_move_one) {
            // Calculate how many haybales can be moved from this pile
            int max_haybales_can_move = remaining_days / days_to_move_one;

            // Move min of available haybales and haybales that can be moved within days
            int haybales_to_move = std::min(haybales_in_pile, max_haybales_can_move);

            current_a1 += haybales_to_move;
            remaining_days -= haybales_to_move * days_to_move_one;
        } else {
            // Not enough days to move even one haybale from this pile
            break; 
        }
    }

    std::cout << current_a1 << std::endl;
}

