    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) { // Only consider off-diagonal elements for max_val_in_row
                if (a[i][j] > max_val_in_row) {
                    max_val_in_row = a[i][j];
                }
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is n-1. If so, it should be n.
    // This happens if the original permutation contained n, and its row's max was n-1.
    // Or if n was not present in the off-diagonal elements of any row.
    bool n_found = false;
    for (int i = 0; i < n; ++i) {
        if (p[i] == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        // If n was not found in any p[i], it means that the true value n
        // was always the larger element in min(p_i, p_j) for all j.
        // This implies that the element p_k = n was never the minimum.
        // So, for the row k where p_k = n, all a[k][j] (j!=k) would be p_j.
        // The maximum of these p_j values would be n-1.
        // So, p[k] would be set to n-1 by our logic.
        // We need to find one such p[i] that is n-1 and change it to n.
        // Any p[i] that is n-1 can be chosen, as long as it's unique.
        // Since the problem guarantees a solution, there must be exactly one such p[i]
        // that should be n but was calculated as n-1.
        // Or, more generally, if n is not found, it means one of the n-1s should be n.
        // We can just pick the first one we find and increment it.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; 
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
