    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_dist = 0;
        int last_R_pos = 0; // Represents the last position where an 'R' was encountered, or 0 for the start.
                            // The distance from last_R_pos to the current 'R' or n+1 must be covered.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // If we are at an 'R' cell (index i, which is cell i+1),
                // we need to be able to jump from the last 'R' cell (or 0)
                // to this 'R' cell.
                // The distance to cover is (i+1) - last_R_pos.
                max_dist = std::max(max_dist, (i + 1) - last_R_pos);
                last_R_pos = i + 1; // Update last_R_pos to the current 'R' cell's position.
            }
        }

        // After iterating through all cells, we need to cover the distance
        // from the last 'R' cell (or 0 if no 'R's) to the target n+1.
        max_dist = std::max(max_dist, (n + 1) - last_R_pos);

        std::cout << max_dist << "\n";
    }
    return 0;
}

