        // Therefore, c + m + x - 2k >= k is always true.
        //
        // So, we can always fill the remaining 'k' slots using the available c_rem, m_rem, and x_rem students.
        // For example, we can prioritize using students with no specialization (x_rem), then remaining coders (c_rem), then remaining mathematicians (m_rem).
        // The exact composition of the third member doesn't matter as long as the team has at least one coder and one mathematician, which is already satisfied by the first two members.

        std::cout << max_possible_k << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the triangle from the apex to the i-th cut (x_i)
        // should be i times the area of one piece.
        // Area of one piece = (Total Area) / n = (h/2) / n = h / (2n)
        // Area of triangle up to x_i = i * (h / (2n)) = (i * h) / (2n)
        // Also, Area of triangle up to x_i = x_i^2 / (2h)
        // So, x_i^2 / (2h) = (i * h) / (2n)
        // x_i^2 = (i * h * 2h) / (2n)
        // x_i^2 = (i * h^2) / n
        // x_i = sqrt((i * h^2) / n)
        // x_i = h * sqrt(i / n)
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

