int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number to use for generating k distinct differences
    bool use_left = true;

    for (int i = 0; i < k + 1; ++i) {
        if (use_left) {
            std::cout << left++;
        } else {
            std::cout << right--;
        }
        use_left = !use_left;
        if (i < n - 1) {
            std::cout << " ";
        }
    }

    // After generating k distinct differences using numbers from 1 to k+1,
    // the remaining numbers (k+2 to n) can be appended in increasing order
    // to generate only difference 1.
    // The last number printed was either left-1 or right+1.
    // If use_left is true, it means the last number printed was right+1.
    // If use_left is false, it means the last number printed was left-1.
    // In either case, the next number to append should be the one that
    // continues the sequence of 1s.
    // The numbers used so far are 1, ..., left-1 and right+1, ..., k+1.
    // The next available number is either left or right.
    // Since we want to append in increasing order, we should append from
    // the smallest available number upwards.
    // The numbers from k+2 to n have not been used yet.
    // We can just append them in increasing order.
    // The last number printed was either left-1 or right+1.
    // The smallest unused number is min(left, right+1) if right+1 is still <= k+1.
    // But we are done with the k distinct differences.
    // The numbers 1 to k+1 have been used to generate k distinct differences.
    // The remaining numbers are k+2, k+3, ..., n.
    // We can just append them in increasing order.
    // The last number printed was either left-1 or right+1.
    // The next number to print is k+2.
    // The difference will be |(last_printed) - (k+2)|.
    // If we append k+2, k+3, ..., n, the differences will be 1.
    // This will not introduce new distinct differences if 1 is already present.
    // If k=1, the first two numbers are 1, 2. Then we append 3, 4, ..., n.
    // Differences: |1-2|=1, |2-3|=1, ..., |(n-1)-n|=1. Only 1 distinct difference.
    // This strategy works.

    for (int i = k + 2; i <= n; ++i) {
        std::cout << " " << i;
    }
    std::cout << std::endl;

    return 0;
}

