    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long k = n / m;

        if (k == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Precompute the sum of last digits for the first 10 multiples
        // (m % 10), (2m % 10), ..., (10m % 10)
        std::vector<long long> last_digits_sum_prefix(11, 0);
        for (int i = 1; i <= 10; ++i) {
            last_digits_sum_prefix[i] = last_digits_sum_prefix[i-1] + ((static_cast<long long>(i) * m) % 10);
        }

        long long sum_of_first_10_last_digits = last_digits_sum_prefix[10];

        long long num_full_cycles = k / 10;
        long long remaining_multiples = k % 10;

        long long total_sum = num_full_cycles * sum_of_first_10_last_digits;
        total_sum += last_digits_sum_prefix[remaining_multiples];

        std::cout << total_sum << "\n";
    }
    return 0;
}

