bool is_good(const std::vector<int>& b) {
    int m = b.size();
    if (m <= 1) {
        return true;
    }

    // Find the first peak from the left
    int p1 = 0;
    while (p1 + 1 < m && b[p1] <= b[p1+1]) {
        p1++;
    }

    // Find the first peak from the right (which is the last valley from the left)
    int p2 = m - 1;
    while (p2 - 1 >= 0 && b[p2-1] >= b[p2]) {
        p2--;
    }

    return p1 >= p2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        if (n <= 1) {
            std::cout << 0 << "\n";
            continue;
        }

        // Find the first peak from the right (which is the last valley from the left)
        // This is the index `i` such that a[i] is the start of the non-increasing suffix
        // e.g., [1, 2, 3, 4, 4, 2, 1] -> p2_idx = 4 (value 4)
        // e.g., [4, 3, 3, 8, 4, 5, 2] -> p2_idx = 3 (value 8)
        int p2_idx = n - 1;
        while (p2_idx - 1 >= 0 && a[p2_idx - 1] >= a[p2_idx]) {
            p2_idx--;
        }

        // Find the first valley from the right (which is the last peak from the left)
        // This is the index `i` such that a[i] is the start of the non-decreasing suffix
        // e.g., [1, 2, 3, 4, 4, 2, 1] -> p1_idx = 2 (value 3)
        // e.g., [4, 3, 3, 8, 4, 5, 2] -> p1_idx = 0 (value 4)
        int p1_idx = p2_idx; // Start search from p2_idx
        while (p1_idx - 1 >= 0 && a[p1_idx - 1] <= a[p1_idx]) {
            p1_idx--;
        }

        std::cout << p1_idx << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result(n, '0');

    // For m=1, the segment is just [1]. Its length is 1, min is 1, max is 1.
    // This is always possible by taking l=r=pos[1].
    result[0] = '1';

    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    // Iterate for m from 2 to n
    for (int m = 2; m <= n; ++m) {
        // The number 'm' is at pos[m].
        // We need to expand the current segment [current_min_idx, current_max_idx]
        // to include 'm'.
        // The new segment will span from min(current_min_idx, pos[m]) to max(current_max_idx, pos[m]).

        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // For the segment p[current_min_idx ... current_max_idx]
        // The minimum value is 1 (because we started with 1 and only added larger numbers).
        // The maximum value is m (because we added numbers 2, 3, ..., m in order).
        // The length of this segment is current_max_idx - current_min_idx + 1.
        // If this length is equal to m, then it's a permutation of 1...m.
        if (current_max_idx - current_min_idx + 1 == m) {
            result[m - 1] = '1';
        } else {
            result[m - 1] = '0';
        }
    }

    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

