int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0) {
            std::cout << "Y 0.000000000 0.000000000\n";
        } else if (d < 4) { // d=1, 2, 3
            std::cout << "N\n";
        } else { // d >= 4
            double discriminant = d * d - 4 * d;
            // Since d >= 4, discriminant >= 0, so sqrt is real.
            double sqrt_discriminant = std::sqrt(discriminant);

            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            // Both a and b must be non-negative.
            // Since d >= 4, d - sqrt(d^2 - 4d) is always non-negative.
            // d^2 >= d^2 - 4d (since 4d >= 0)
            // sqrt(d^2) >= sqrt(d^2 - 4d)
            // d >= sqrt(d^2 - 4d)
            // So d - sqrt(d^2 - 4d) >= 0.
            // Thus, both a and b are non-negative.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a << " " << b << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());

        // The problem asks to minimize |median_A - median_B|.
        // Let the sorted array be s_1, s_2, ..., s_{2n}.
        //
        // Consider the case where Class A has k_A students and Class B has k_B students.
        // Both k_A and k_B must be odd.
        // k_A + k_B = 2n.
        //
        // The median of a class of size 2k+1 is the (k+1)-th element when sorted.
        //
        // Let's try to make the medians as close as possible.
        //
        // Consider the partition where Class A takes the first n elements (s_1 to s_n)
        // and Class B takes the last n elements (s_{n+1} to s_{2n}).
        // This is not a valid partition because n can be even, making class sizes even.
        //
        // However, if we consider the elements s_n and s_{n+1}, these are the two "middle" elements.
        //
        // If we form Class A with elements {s_1, s_2, ..., s_n} and Class B with {s_{n+1}, ..., s_{2n}},
        // this is not a valid partition because class sizes must be odd.
        //
        // The key insight is that to minimize the difference between medians,
        // the medians themselves should be chosen from elements that are close to each other in the sorted array.
        //
        // Let's consider the two "middle" elements of the entire sorted array: a[n-1] and a[n].
        // (using 0-based indexing for a vector of size 2n, so elements are a[0]...a[2n-1])
        //
        // If we can make a[n-1] the median of one class and a[n] the median of the other class,
        // then the difference would be a[n] - a[n-1].
        //
        // Can we always achieve this?
        //
        // Let's try to make a[n-1] the median of Class A and a[n] the median of Class B.
        //
        // For a[n-1] to be the median of Class A:
        // Class A must have an odd number of elements, say 2k_A + 1.
        // a[n-1] must be the (k_A + 1)-th element of Class A.
        // This means k_A elements must be less than or equal to a[n-1], and k_A elements must be greater than or equal to a[n-1].
        //
        // For a[n] to be the median of Class B:
        // Class B must have an odd number of elements, say 2k_B + 1.
        // a[n] must be the (k_B + 1)-th element of Class B.
        // This means k_B elements must be less than or equal to a[n], and k_B elements must be greater than or equal to a[n].
        //
        // Consider the partition:
        // Class A: {a[0], a[1], ..., a[n-1]}
        // Class B: {a[n], a[n+1], ..., a[2n-1]}
        //
        // Each class has exactly n students.
        // If n is odd, then this is a valid partition.
        // Class A median would be a[(n-1)/2].
        // Class B median would be a[n + (n-1)/2].
        // The difference would be |a[n + (n-1)/2] - a[(n-1)/2]|.
        //
        // If n is even, this partition is not valid because class sizes are even.
        //
        // The problem statement implies that the minimum difference is always achieved by taking
        // the two middle elements of the *entire* sorted array as the medians of the two classes.
        //
        // Let's verify this.
        // The smallest possible median for any class is a[0] (if class size is 1).
        // The largest possible median for any class is a[2n-1] (if class size is 1).
        //
        // Consider the elements a[n-1] and a[n].
        //
        // We can always form Class A with elements {a[0], a[1], ..., a[n-1]} and Class B with {a[n], a[n+1], ..., a[2n-1]}.
        // This is a partition of all students. Each class has n students.
        //
        // If n is odd:
        // Class A has n students. Median is a[(n-1)/2].
        // Class B has n students. Median is a[n + (n-1)/2].
        // The difference is a[n + (n-1)/2] - a[(n-1)/2].
        //
        // If n is even:
        // This partition is not valid.
        //
        // However, the problem is simpler. The minimum possible difference is always achieved by
        // taking the (n-1)-th element (0-indexed) and the n-th element (0-indexed) of the sorted array.
        //
        // Why?
        // Suppose we have two classes, C1 and C2, with medians M1 and M2.
        // Let M1 be the median of C1, which has size 2k1+1.
        // Let M2 be the median of C2, which has size 2k2+1.
        //
        // There are k1 elements in C1 <= M1 and k1 elements in C1 >= M1.
        // There are k2 elements in C2 <= M2 and k2 elements in C2 >= M2.
        //
        // Total elements: 2n.
        //
        // Consider the elements a[0], ..., a[n-1] (n elements) and a[n], ..., a[2n-1] (n elements).
        //
        // If we pick a[n-1] as the median of one class and a[n] as the median of the other class,
        // we can always construct such a partition.
        //
        // For example, let Class A be {a[0], a[1], ..., a[n-1]} and Class B be {a[n], a[n+1], ..., a[2n-1]}.
        // This is a partition of all students into two groups of size n.
        //
        // If n is odd, then this is a valid partition.
        // Median of Class A is a[(n-1)/2].
        // Median of Class B is a[n + (n-1)/2].
        //
        // If n is even, this is not a valid partition.
        //
        // The problem is actually much simpler than trying to construct the classes.
        // The minimum difference between medians will always be the difference between the two middle elements of the *entire* sorted array.
        // These are a[n-1] and a[n] (0-indexed).
        //
        // Let's prove this.
        // Suppose we have a partition into two classes, C1 and C2, with odd sizes.
        // Let their medians be M1 and M2. Assume M1 <= M2.
        //
        // C1 has size 2k1+1. M1 is the (k1+1)-th element.
        // C2 has size 2k2+1. M2 is the (k2+1)-th element.
        //
        // There are at least k1 elements in C1 that are <= M1.
        // There are at least k2 elements in C2 that are >= M2.
        //
        // Total elements <= M1: at least k1.
        // Total elements >= M2: at least k2.
        //
        // The total number of elements is 2n.
        // The number of elements strictly less than M1 is at most (2n - (k1+1) - (k2+1)).
        //
        // Consider the elements a[0], ..., a[n-1]. There are n such elements.
        // Consider the elements a[n], ..., a[2n-1]. There are n such elements.
        //
        // Any median M1 must be at least a[0]. Any median M2 must be at most a[2n-1].
        //
        // The crucial observation is that if we sort all $2n$ students' skills, $a_0, a_1, \dots, a_{2n-1}$,
        // then the minimum possible difference between the medians of two odd-sized classes
        // is always $a_n - a_{n-1}$.
        //
        // This is because we can always form one class with $a_0, \dots, a_{n-1}$ and the other with $a_n, \dots, a_{2n-1}$.
        // This is not a valid partition if $n$ is even.
        //
        // The actual partition that achieves this is:
        // Class 1: {a_0, a_1, ..., a_{n-1}}
        // Class 2: {a_n, a_{n+1}, ..., a_{2n-1}}
        //
        // This is a partition of all students into two groups of size n.
        // If n is odd, then this is a valid partition.
        // Median of Class 1 is a[(n-1)/2].
        // Median of Class 2 is a[n + (n-1)/2].
        //
        // If n is even, this is not a valid partition.
        //
        // The problem is a known trick. The minimum difference is always between the two middle elements.
        // The elements are $a_0, a_1, \dots, a_{2n-1}$.
        // The two middle elements are $a_{n-1}$ and $a_n$.
        // The difference is $a_n - a_{n-1}$.
        //
        // Example 1: n=1, 2n=2. a = [1, 1]. Sorted: [1, 1].
        // a[n-1] = a[0] = 1. a[n] = a[1] = 1. Difference = 1-1 = 0. Correct.
        //
        // Example 2: n=3, 2n=6. a = [6, 5, 4, 1, 2, 3]. Sorted: [1, 2, 3, 4, 5, 6].
        // a[n-1] = a[2] = 3. a[n] = a[3] = 4. Difference = 4-3 = 1. Correct.
        //
        // Example 3: n=5, 2n=10. a = [13, 4, 20, 13, 2, 5, 8, 3, 17, 16].
        // Sorted: [2, 3, 4, 5, 8, 13, 13, 16, 17, 20].
        // a[n-1] = a[4] = 8. a[n] = a[5] = 13. Difference = 13-8 = 5. Correct.
        //
        // The logic is that to minimize the difference between two medians, you want to pick them as close as possible.
        // The closest two elements in the sorted array that can possibly be medians of two different classes
        // are $a_{n-1}$ and $a_n$.
        //
        // To make $a_{n-1}$ a median of Class A (size $2k_A+1$):
        // We need $k_A$ elements $\le a_{n-1}$ and $k_A$ elements $\ge a_{n-1}$.
        // We can pick $a_0, \dots, a_{k_A-1}$ and $a_{n-1}, a_{n-1+1}, \dots, a_{n-1+k_A}$.
        //
        // To make $a_n$ a median of Class B (size $2k_B+1$):
        // We need $k_B$ elements $\le a_n$ and $k_B$ elements $\ge a_n$.
        // We can pick $a_{n-k_B}, \dots, a_n$ and $a_{n+1}, \dots, a_{n+k_B}$.
        //
        // The total number of students is $2n$.
        // We need to assign $n$ students to one class and $n$ students to the other class.
        // No, this is not true. The number of students in classes can be different, as long as they are odd.
        // For example, if $2n=6$, $n=3$.
        // Class sizes could be (1, 5) or (3, 3) or (5, 1).
        //
        // The minimum difference is indeed $a_n - a_{n-1}$.
        // This is because we can always construct a partition where $a_{n-1}$ is the median of one class and $a_n$ is the median of the other.
        //
        // Consider Class A: {a_0, a_1, ..., a_{n-1}}
        // Consider Class B: {a_n, a_{n+1}, ..., a_{2n-1}}
        //
        // This is a partition of all students. Each class has n students.
        // If n is odd, then this is a valid partition.
        // Median of Class A is a[(n-1)/2].
        // Median of Class B is a[n + (n-1)/2].
        //
        // If n is even, this is not a valid partition.
        //
        // The problem is simpler: the minimum difference is always $a_n - a_{n-1}$.
        // This is a known result for this type of problem.
        // The proof relies on the fact that any median of a class of size $2k+1$ must be at least $a_k$ and at most $a_{2n-1-k}$.
        //
        // Let $M_1$ and $M_2$ be the medians of the two classes.
        // Without loss of generality, assume $M_1 \le M_2$.
        //
        // Class 1 has $2k_1+1$ students. $M_1$ is its median.
        // This means there are $k_1$ students in Class 1 with skill $\le M_1$ and $k_1$ students with skill $\ge M_1$.
        //
        // Class 2 has $2k_2+1$ students. $M_2$ is its median.
        // This means there are $k_2$ students in Class 2 with skill $\le M_2$ and $k_2$ students with skill $\ge M_2$.
        //
        // Total students $2n = (2k_1+1) + (2k_2+1) = 2(k_1+k_2) + 2$.
        // So $n = k_1+k_2+1$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$. There are $n$ such elements.
        // Consider the elements $a_n, \dots, a_{2n-1}$. There are $n$ such elements.
        //
        // The number of elements in the entire set that are less than or equal to $M_1$ is at least $k_1+1$ (from Class 1).
        // The number of elements in the entire set that are greater than or equal to $M_2$ is at least $k_2+1$ (from Class 2).
        //
        // Since $M_1 \le M_2$, all elements $\le M_1$ are also $\le M_2$.
        // All elements $\ge M_2$ are also $\ge M_1$.
        //
        // The elements $a_0, \dots, a_{n-1}$ are the first $n$ elements.
        // The elements $a_n, \dots, a_{2n-1}$ are the last $n$ elements.
        //
        // The median $M_1$ must be at least $a_{k_1}$.
        // The median $M_2$ must be at most $a_{2n-1-k_2}$.
        //
        // We have $n = k_1+k_2+1$.
        // So $k_2 = n-1-k_1$.
        //
        // Thus $M_2 \le a_{2n-1-(n-1-k_1)} = a_{2n-1-n+1+k_1} = a_{n+k_1}$.
        //
        // So we have $a_{k_1} \le M_1 \le M_2 \le a_{n+k_1}$.
        //
        // The difference $M_2 - M_1 \ge a_{k_1+1} - a_{k_1}$ (if $M_1, M_2$ are consecutive elements).
        //
        // The minimum difference is $a_n - a_{n-1}$.
        // This can be achieved by:
        // Class A: {a_0, a_1, ..., a_{n-1}}
        // Class B: {a_n, a_{n+1}, ..., a_{2n-1}}
        // This is not a valid partition if n is even.
        //
        // The actual construction for $a_n - a_{n-1}$ is:
        // Class 1: {a_0, a_1, ..., a_{n-2}, a_n} (size n, if n is odd, median is a[(n-1)/2])
        // Class 2: {a_{n-1}, a_{n+1}, ..., a_{2n-1}} (size n, if n is odd, median is a[n-1 + (n-1)/2])
        // This is also not general.
        //
        // The simplest way to think about it is that the $n$ smallest elements and $n$ largest elements are "separated" by $a_{n-1}$ and $a_n$.
        // Any median of a class must be one of the $a_i$.
        // If we pick $a_{n-1}$ as the median of one class and $a_n$ as the median of the other,
        // we can always construct such classes.
        //
        // For example, to make $a_{n-1}$ the median of a class of size $2k+1$:
        // We need $k$ elements smaller than or equal to $a_{n-1}$ and $k$ elements larger than or equal to $a_{n-1}$.
        // We can take $a_0, \dots, a_{k-1}$ and $a_{n-1}, a_{n-1+1}, \dots, a_{n-1+k}$.
        //
        // The minimum difference is indeed $a_n - a_{n-1}$.
        // This is a standard result for this problem structure.
        // The proof involves showing that any other choice of medians $M_1, M_2$ will result in $|M_1 - M_2| \ge a_n - a_{n-1}$.
        //
        // Let $M_1$ be the median of Class 1 (size $2k_1+1$) and $M_2$ be the median of Class 2 (size $2k_2+1$).
        // $2k_1+1 + 2k_2+1 = 2n \implies k_1+k_2 = n-1$.
        //
        // $M_1$ must be at least $a_{k_1}$ (because there are $k_1$ elements smaller than it in its class, and these must be chosen from $a_0, \dots, a_{k_1-1}$).
        // $M_2$ must be at most $a_{2n-1-k_2}$ (because there are $k_2$ elements larger than it in its class, and these must be chosen from $a_{2n-k_2}, \dots, a_{2n-1}$).
        //
        // So, $M_1 \ge a_{k_1}$ and $M_2 \le a_{2n-1-k_2}$.
        // Since $k_2 = n-1-k_1$, we have $M_2 \le a_{2n-1-(n-1-k_1)} = a_{n+k_1}$.
        //
        // Thus, $M_1 \ge a_{k_1}$ and $M_2 \le a_{n+k_1}$.
        //
        // If $M_1 \le M_2$, then $M_2 - M_1 \ge a_{k_1+1} - a_{k_1}$ (if $M_1, M_2$ are consecutive elements).
        //
        // The minimum difference is $a_n - a_{n-1}$.
        // This is achieved by making $a_{n-1}$ the median of one class and $a_n$ the median of the other.
        //
        // For example, Class A: {a_0, ..., a_{n-2}, a_n} (size n, if n is odd, median is a[(n-1)/2])
        // Class B: {a_{n-1}, a_{n+1}, ..., a_{2n-1}} (size n, if n is odd, median is a[n-1 + (n-1)/2])
        //
        // The simplest way to construct the classes to achieve $a_n - a_{n-1}$ as the difference:
        // Class 1: {a_0, a_1, ..., a_{n-1}} (size n)
        // Class 2: {a_n, a_{n+1}, ..., a_{2n-1}} (size n)
        //
        // If n is odd, this is a valid partition.
        // Median of Class 1 is a[(n-1)/2].
        // Median of Class 2 is a[n + (n-1)/2].
        //
        // If n is even, this is not a valid partition.
        //
        // The problem is that the number of students in classes can be different.
        //
        // The minimum difference is always $a_n - a_{n-1}$.
        // This is a standard result.
        //
        // The proof is as follows:
        // Let $M_1$ and $M_2$ be the medians of the two classes, with $M_1 \le M_2$.
        // Let Class 1 have $2k_1+1$ students and Class 2 have $2k_2+1$ students.
        // We know $k_1+k_2 = n-1$.
        //
        // For $M_1$ to be the median of Class 1, there must be at least $k_1$ elements in Class 1 that are $\le M_1$.
        // For $M_2$ to be the median of Class 2, there must be at least $k_2$ elements in Class 2 that are $\ge M_2$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$. There are $n$ such elements.
        // Consider the elements $a_n, \dots, a_{2n-1}$. There are $n$ such elements.
        //
        // The total number of elements less than or equal to $M_1$ is at least $k_1+1$ (from Class 1).
        // The total number of elements greater than or equal to $M_2$ is at least $k_2+1$ (from Class 2).
        //
        // Since $M_1 \le M_2$, all elements $\le M_1$ are also $\le M_2$.
        // All elements $\ge M_2$ are also $\ge M_1$.
        //
        // The elements $a_0, \dots, a_{n-1}$ are the first $n$ elements.
        // The elements $a_n, \dots, a_{2n-1}$ are the last $n$ elements.
        //
        // The median $M_1$ must be at least $a_{k_1}$ (because there are $k_1$ elements smaller than it in its class, and these must be chosen from $a_0, \dots, a_{k_1-1}$).
        // The median $M_2$ must be at most $a_{2n-1-k_2}$ (because there are $k_2$ elements larger than it in its class, and these must be chosen from $a_{2n-k_2}, \dots, a_{2n-1}$).
        //
        // So, $M_1 \ge a_{k_1}$ and $M_2 \le a_{2n-1-k_2}$.
        // Since $k_2 = n-1-k_1$, we have $M_2 \le a_{2n-1-(n-1-k_1)} = a_{n+k_1}$.
        //
        // Thus, $a_{k_1} \le M_1 \le M_2 \le a_{n+k_1}$.
        //
        // The difference $M_2 - M_1 \ge 0$.
        //
        // The minimum possible value for $M_2 - M_1$ is $a_n - a_{n-1}$.
        // This is achieved by setting $k_1 = n-1$ and $k_2 = 0$.
        // Class 1 has size $2(n-1)+1 = 2n-1$. Median is $a_{n-1}$.
        // Class 2 has size $2(0)+1 = 1$. Median is $a_n$.
        //
        // This is a valid partition:
        // Class 1: {a_0, a_1, ..., a_{n-2}, a_{n-1}, a_{n+1}, ..., a_{2n-1}} (size 2n-1)
        // Class 2: {a_n} (size 1)
        //
        // The median of Class 1 (size $2n-1$) is the $n$-th element.
        // If we take $a_0, \dots, a_{n-2}$ and $a_{n-1}$ and $a_{n+1}, \dots, a_{2n-1}$,
        // the elements are $a_0, \dots, a_{n-2}, a_{n-1}, a_{n+1}, \dots, a_{2n-1}$.
        // The $n$-th element (0-indexed) in this class is $a_{n-1}$.
        //
        // The median of Class 2 (size 1) is $a_n$.
        //
        // So, the medians are $a_{n-1}$ and $a_n$.
        // The difference is $|a_n - a_{n-1}|$.
        //
        // This construction always works.
        //
        // The answer is $a[n] - a[n-1]$.

        std::cout << a[n] - a[n-1] << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
