#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // First, ensure the median element itself is 's'.
    operations += std::abs(a[median_idx] - s);

    // For elements to the left of the median, they must be <= s.
    // If a[i] > s, we must decrease it to s.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // For elements to the right of the median, they must be >= s.
    // If a[i] < s, we must increase it to s.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate minimum values for the left increasing part
    // b_i >= i for a 0-indexed array, or b_i >= i-1 for 1-indexed
    // b_i >= b_{i-1} + 1
    // b_0 >= 0
    // b_1 >= 1
    // b_i >= i
    std::vector<long long> min_left(n);
    min_left[0] = 0;
    for (int i = 1; i < n; ++i) {
        min_left[i] = std::max(min_left[i-1] + 1, (long long)i);
    }

    // Calculate minimum values for the right decreasing part
    // b_i >= n-1-i for a 0-indexed array
    // b_i >= b_{i+1} + 1
    // b_{n-1} >= 0
    // b_{n-2} >= 1
    // b_i >= n-1-i
    std::vector<long long> min_right(n);
    min_right[n-1] = 0;
    for (int i = n - 2; i >= 0; --i) {
        min_right[i] = std::max(min_right[i+1] + 1, (long long)(n - 1 - i));
    }

    bool possible = false;
    for (int k = 0; k < n; ++k) { // k is 0-indexed peak position
        // For a peak at index k, we need:
        // b_0 < b_1 < ... < b_k
        // b_k > b_{k+1} > ... > b_{n-1}

        // The minimum value for b_k to satisfy the left part is min_left[k].
        // The minimum value for b_k to satisfy the right part is min_right[k].
        // So, the minimum value for b_k is max(min_left[k], min_right[k]).
        // If a[k] is less than this minimum required value, then k cannot be the peak.
        if (a[k] >= std::max(min_left[k], min_right[k])) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

