    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    int count = 0;
    int j = 0; // Pointer for elements to be placed (the 'b' array elements)
    for (int i = 0; i < n; ++i) { // Pointer for original positions (the 'a' array elements)
        // We are trying to find an element a[j] such that a[j] > a[i]
        // Since both arrays are sorted, if a[j] > a[i], then any a[k] with k > j will also be > a[i] (or equal)
        // To maximize the count, we should use the smallest possible a[j] that satisfies a[j] > a[i]
        // This leaves larger elements available for later, potentially larger a[i] values.
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // Found an element a[j] such that a[j] > a[i]
            count++;
            j++; // Move to the next element for the 'b' array
        } else {
            // No more elements in 'a' (from index j onwards) are greater than a[i].
            // Since 'a' is sorted, no subsequent a[k] (k > i) will be able to find a greater element either.
            // So we can break.
            break;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

