struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i; // Not strictly needed for A, but good practice
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    // Create the result array A'
    std::vector<long long> a_prime(m);

    // The strategy is to pair the largest A_i with the largest B_i,
    // the second largest A_i with the second largest B_i, and so on.
    // This means A_i values are assigned to B_i values in a way that
    // if A_i is sorted and B_i is sorted, then A'_i = A_i.
    // However, the problem asks for A'_i to be placed at the original index of B_i.
    // So, if B_j (original index j) is the k-th smallest B value,
    // it should be paired with the k-th smallest A value.

    for (int i = 0; i < m; ++i) {
        // b_elements[i] is the i-th smallest B value (0-indexed)
        // Its original index is b_elements[i].original_index
        // It should be paired with a_elements[i].value (the i-th smallest A value)
        a_prime[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

