// Function to check if a specific box can be the final box
// target_box_idx: 0 for Box 1, 1 for Box 2, 2 for Box 3, 3 for Box 4
bool can_be_final(long long A, long long B, long long C, long long D, int target_box_idx) {
    long long total_toys = A + B + C + D;
    if (total_toys == 0) return false; // Should not happen based on constraints A+B+C+D > 0

    if (total_toys == 1) {
        if (A == 1 && target_box_idx == 0) return true;
        if (B == 1 && target_box_idx == 1) return true;
        if (C == 1 && target_box_idx == 2) return true;
        if (D == 1 && target_box_idx == 3) return true;
        return false;
    }

    // State: (num_neg_gt_1, num_neg_lt_1, num_pos_lt_1, num_pos_gt_1)
    // Corresponds to (A, B, C, D)
    // We need to find if there's a sequence of operations that leads to the target_box_idx.
    // This is a reachability problem on a state space.
    // The state space is defined by the counts of toys in each category.
    // The total number of toys decreases by 1 in each step.
    // The parity of negative toys is important.
    // The parity of toys with magnitude > 1 is important.

    // Let's simplify the state to (parity_neg, parity_gt_1)
    // parity_neg: 0 if even number of negative toys, 1 if odd
    // parity_gt_1: 0 if even number of toys with magnitude > 1, 1 if odd

    // Initial parities
    int initial_parity_neg = (A + B) % 2;
    int initial_parity_gt_1 = (A + D) % 2;

    // Case 1: Final toy is in Box 1 (negative, magnitude >= 1)
    // Requires: odd number of negative toys, odd number of magnitude > 1 toys
    if (target_box_idx == 0) {
        // If we want to end up in Box 1, the final toy must be negative and |val| >= 1.
        // This means the total number of negative factors must be odd.
        // And the total number of factors with |val| > 1 must be odd.
        // The parities of (A+B) and (A+D) must be odd.
        // (A+B)%2 == 1 and (A+D)%2 == 1
        // This is always possible if we can reach any state with these parities.
        // The parities of (A+B) and (A+D) are invariant under multiplication of two toys from the same box.
        // When we multiply two toys, say X and Y, to get Z:
        // - If X, Y are both negative: Z is positive. (A+B) decreases by 2, (A+B)%2 unchanged.
        // - If X, Y are both positive: Z is positive. (A+B) unchanged.
        // - If X is negative, Y is positive: Z is negative. (A+B) unchanged.
        // So, the parity of negative toys (A+B)%2 is invariant.
        // Similarly, the parity of (A+D)%2 is invariant.
        // So, if we want to end in Box 1, we must have (A+B)%2 == 1 and (A+D)%2 == 1 initially.
        return (initial_parity_neg == 1 && initial_parity_gt_1 == 1);
    }

    // Case 2: Final toy is in Box 2 (negative, magnitude < 1)
    // Requires: odd number of negative toys, even number of magnitude > 1 toys
    if (target_box_idx == 1) {
        // (A+B)%2 == 1 and (A+D)%2 == 0
        return (initial_parity_neg == 1 && initial_parity_gt_1 == 0);
    }

    // Case 3: Final toy is in Box 3 (positive, magnitude < 1)
    // Requires: even number of negative toys, even number of magnitude > 1 toys
    if (target_box_idx == 2) {
        // (A+B)%2 == 0 and (A+D)%2 == 0
        return (initial_parity_neg == 0 && initial_parity_gt_1 == 0);
    }

    // Case 4: Final toy is in Box 4 (positive, magnitude >= 1)
    // Requires: even number of negative toys, odd number of magnitude > 1 toys
    if (target_box_idx == 3) {
        // (A+B)%2 == 0 and (A+D)%2 == 1
        return (initial_parity_neg == 0 && initial_parity_gt_1 == 1);
    }

    return false; // Should not be reached
}


int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        std::string result[4];
        for (int i = 0; i < 4; ++i) {
            if (can_be_final(A, B, C, D, i)) {
                result[i] = "Ya";
            } else {
                result[i] = "Tidak";
            }
        }
        std::cout << result[0] << " " << result[1] << " " << result[2] << " " << result[3] << "\n";
    }
    return 0;
}

