void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor ^= a;
    }

    // We need current_sum + S_added = 2 * (current_xor ^ X_added)
    // Let's try to add at most 3 elements.
    // The problem statement guarantees a solution always exists.
    // A common strategy for "at most 3 elements" is to try to add 0, 1, 2, or 3 elements.
    // If current_sum == 2 * current_xor, we need to add 0 elements.
    if (current_sum == 2 * current_xor) {
        std::cout << 0 << std::endl << std::endl;
        return;
    }

    // Otherwise, we need to add elements.
    // Let's try to add two elements: current_xor and current_sum + current_xor.
    // Let b1 = current_xor
    // Let b2 = current_sum + current_xor
    // New sum S' = current_sum + b1 + b2
    // New xor X' = current_xor ^ b1 ^ b2
    //
    // S' = current_sum + current_xor + (current_sum + current_xor)
    // S' = 2 * current_sum + 2 * current_xor
    //
    // X' = current_xor ^ current_xor ^ (current_sum + current_xor)
    // X' = 0 ^ (current_sum + current_xor)
    // X' = current_sum + current_xor
    //
    // We need S' = 2 * X'
    // 2 * current_sum + 2 * current_xor = 2 * (current_sum + current_xor)
    // This identity holds true for any current_sum and current_xor.
    // So, adding these two specific elements always makes the array good.

    long long b1 = current_xor;
    long long b2 = current_sum + current_xor;

    std::cout << 2 << std::endl;
    std::cout << b1 << " " << b2 << std::endl;
}

