// Function to check if a subarray is a permutation
// This version checks if elements are distinct and max is equal to length
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) return true; // An empty sequence can be considered a permutation of length 0
    if (start_idx + len > arr.size()) return false; // Out of bounds

    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val < 1 || val > len || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<std::pair<int, int>> results;

    // Precompute prefix permutation checks
    std::vector<bool> is_prefix_perm(n + 1, false);
    if (n > 0) { // A sequence of length 0 is not a permutation in this context (lengths are non-zero)
        std::vector<bool> seen_prefix(n + 1, false);
        int current_max_prefix = 0;
        int distinct_count_prefix = 0;
        for (int l1 = 1; l1 <= n; ++l1) {
            int val = a[l1 - 1];
            if (val < 1 || val > l1 || seen_prefix[val]) {
                // This prefix cannot be a permutation, nor can any longer prefix starting from here
                // unless the max_val condition is met later.
                // But if val > l1, it can't be a permutation of length l1.
                // If seen_prefix[val], it's not distinct.
                // If val < 1, it's invalid.
                // So, if any of these, this prefix is not a permutation.
                // And if current_max_prefix is not l1, it's not a permutation.
                // We need to be careful here.
                // A prefix is a permutation of length L if it contains 1..L exactly once.
                // This means max element must be L, and all elements must be distinct and <= L.
                // Let's re-evaluate this check.
                // A prefix of length L is a permutation of 1..L if:
                // 1. All elements are distinct.
                // 2. All elements are <= L.
                // 3. The maximum element is L.
                // We can track distinct count and max value.
                // If a[l1-1] is already seen, or a[l1-1] > l1, then it's not a permutation.
                // Otherwise, update distinct count and max value.
                // If distinct_count == l1 and max_val == l1, then it's a permutation.
                is_prefix_perm[l1] = false; // Mark as false for now, will update if conditions met
            } else {
                seen_prefix[val] = true;
                distinct_count_prefix++;
                if (val > current_max_prefix) {
                    current_max_prefix = val;
                }
                if (distinct_count_prefix == l1 && current_max_prefix == l1) {
                    is_prefix_perm[l1] = true;
                }
            }
        }
    }

    // Precompute suffix permutation checks
    std::vector<bool> is_suffix_perm(n + 1, false);
    if (n > 0) {
        std::vector<bool> seen_suffix(n + 1, false);
        int current_max_suffix = 0;
        int distinct_count_suffix = 0;
        for (int l2 = 1; l2 <= n; ++l2) {
            int val = a[n - l2]; // Element at index n-l2 is the first element of the suffix of length l2
            if (val < 1 || val > l2 || seen_suffix[val]) {
                is_suffix_perm[l2] = false;
            } else {
                seen_suffix[val] = true;
                distinct_count_suffix++;
                if (val > current_max_suffix) {
                    current_max_suffix = val;
                }
                if (distinct_count_suffix == l2 && current_max_suffix == l2) {
                    is_suffix_perm[l2] = true;
                }
            }
        }
    }

    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

