// Function to convert a number to its parity pattern string
std::string get_parity_pattern(long long n) {
    if (n == 0) {
        return "0";
    }
    std::string pattern = "";
    while (n > 0) {
        if ((n % 10) % 2 == 0) {
            pattern += '0';
        } else {
            pattern += '1';
        }
        n /= 10;
    }
    std::reverse(pattern.begin(), pattern.end());
    return pattern;
}

// Function to normalize a pattern string to a fixed length (18)
// by padding with '0's from the left.
// This is crucial for map keys.
std::string normalize_pattern(const std::string& s) {
    std::string normalized_s = s;
    if (normalized_s.length() < 18) {
        normalized_s = std::string(18 - normalized_s.length(), '0') + normalized_s;
    }
    return normalized_s;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            counts[normalize_pattern(pattern)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            counts[normalize_pattern(pattern)]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            std::cout << counts[normalize_pattern(s)] << "\n";
        }
    }

    return 0;
}

