// Function to get prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x is a divisor of p and x is not divisible by q.
        // This means we need to remove some prime factors from p such that the resulting number is no longer divisible by q.
        // To maximize x, we should remove the minimum necessary factors.
        // Specifically, for each prime factor f of q, we need to reduce the power of f in p such that p/f^k is no longer divisible by q.

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 1;

        for (long long f : q_prime_factors) {
            // For each prime factor f of q, we want to find the largest divisor of p
            // that is not divisible by q, by "removing" f from p as much as needed.

            long long current_p = p;
            // Divide current_p by f until it's no longer divisible by q
            // Or until current_p is no longer divisible by f
            while (current_p % f == 0) {
                current_p /= f;
                if (current_p % q != 0) {
                    max_x = std::max(max_x, current_p);
                }
            }
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

