    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            if (f1 == 0) { // Cannot move left (x-1, y)
                // Must stay at or to the right of current x
                // So, target X must be >= x
                min_x = std::max(min_x, x);
            }
            if (f2 == 0) { // Cannot move up (x, y+1)
                // Must stay at or below current y
                // So, target Y must be <= y
                max_y = std::min(max_y, y);
            }
            if (f3 == 0) { // Cannot move right (x+1, y)
                // Must stay at or to the left of current x
                // So, target X must be <= x
                max_x = std::min(max_x, x);
            }
            if (f4 == 0) { // Cannot move down (x, y-1)
                // Must stay at or above current y
                // So, target Y must be >= y
                min_y = std::max(min_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
