}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    for (int pivot_digit = 0; pivot_digit <= 9; ++pivot_digit) {
        std::string colors(n, ' ');
        int last1 = -1;
        int last2 = -1;
        bool possible = true;

        for (int i = 0; i < n; ++i) {
            int current_digit = s[i] - '0';

            bool can_be_1 = (current_digit >= last1 && current_digit <= pivot_digit);
            bool can_be_2 = (current_digit >= last2 && current_digit >= pivot_digit);

            if (can_be_1 && can_be_2) {
                // Prefer coloring 2 if current_digit == pivot_digit to keep last1 as small as possible
                // This helps satisfy current_digit >= last1 for future digits.
                // If current_digit > pivot_digit, it must be 2.
                // If current_digit < pivot_digit, it must be 1.
                // So this case is only for current_digit == pivot_digit.
                // If current_digit == pivot_digit, we can put it in S1 (if last1 <= pivot_digit)
                // or in S2 (if last2 <= pivot_digit).
                // To maximize chances for future digits, we want last1 to be as small as possible.
                // So if current_digit == pivot_digit, we put it in S2.
                // This is equivalent to the logic: if current_digit > pivot_digit, it must be 2.
                // If current_digit < pivot_digit, it must be 1.
                // If current_digit == pivot_digit, we try to put it in S2 first.
                // This is implicitly handled by the order of checks below.
                // If current_digit == pivot_digit, and it can be 1 and 2:
                //   If we put it in 1: last1 becomes pivot_digit.
                //   If we put it in 2: last2 becomes pivot_digit.
                // The condition for S1 is current_digit <= pivot_digit.
                // The condition for S2 is current_digit >= pivot_digit.
                // If current_digit == pivot_digit, it satisfies both.
                // We want to make last1 as small as possible.
                // So if current_digit == pivot_digit, we put it in S2.
                // This is the key insight.
                colors[i] = '2';
                last2 = current_digit;
            } else if (can_be_1) {
                colors[i] = '1';
                last1 = current_digit;
            } else if (can_be_2) {
                colors[i] = '2';
                last2 = current_digit;
            } else {
                possible = false;
                break;
            }
        }

        if (possible) {
            std::cout << colors << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

