    return 0;
}

#include <iostream>

long long power(long long base, long long exp) {
    long long res = 1;
    base %= 1000000007;
    while (exp > 0) {
        if (exp % 2 == 1) res = (res * base) % 1000000007;
        base = (base * base) % 1000000007;
        exp /= 2;
    }
    return res;
}

long long modInverse(long long n) {
    return power(n, 1000000007 - 2);
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum_r = sum_{r=1 to b-1} r = (b-1) * b / 2
    long long sum_r_term = (b - 1);
    sum_r_term = (sum_r_term * b) % MOD;
    sum_r_term = (sum_r_term * modInverse(2)) % MOD;

    // Sum_k_b_plus_1 = sum_{k=1 to a} (k * b + 1)
    // = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // = b * (a * (a+1) / 2) + a
    long long sum_k_b_plus_1_term = (a * (a + 1)) % MOD;
    sum_k_b_plus_1_term = (sum_k_b_plus_1_term * modInverse(2)) % MOD;
    sum_k_b_plus_1_term = (sum_k_b_plus_1_term * (b % MOD)) % MOD;
    sum_k_b_plus_1_term = (sum_k_b_plus_1_term + a) % MOD;

    long long total_sum = (sum_r_term * sum_k_b_plus_1_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_score = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n == 1) {
                chanek_score += 1;
                n = 0;
            } else if (n % 2 == 1) { // N is odd
                chanek_score += 1;
                n -= 1;
            } else { // N is even
                // Option 1: Take 1
                // Remaining N-1 (odd). Opponent takes 1. N-2 (even).
                // This path is generally worse if N/2 is a good move.

                // Option 2: Take N/2
                // Remaining N/2.
                // If N/2 is odd, opponent takes 1. N/2-1 (even).
                // If N/2 is even, opponent can take N/4 or 1.

                // Consider the optimal strategy for Chanek:
                // If N is even, Chanek can take N/2.
                // If N/2 is odd, then after Chanek takes N/2, N becomes odd.
                // The opponent will be forced to take 1.
                // This means Chanek gets N/2, and the opponent gets 1.
                // This is generally good for Chanek.

                // If N is even and N/2 is even (i.e., N is a multiple of 4),
                // Chanek takes N/2. N becomes N/2 (even).
                // Opponent can take N/4.
                // This means Chanek gets N/2, opponent gets N/4.
                // This is also generally good for Chanek.

                // The only time Chanek might prefer taking 1 when N is even
                // is if taking N/2 leads to a state where the opponent gets
                // a disproportionately large share.
                // This happens when N is even, and N/2 is odd, AND N/2 > 1.
                // Example: N=6. Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 3+1=4. Opponent: 1+1=2.
                // If Chanek takes 1: N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                // Chanek: 1+2+1=4. Opponent: 1+1=2.
                // In this case, both lead to 4.

                // What if N is a power of 2? N = 2^k.
                // Chanek takes N/2. N becomes N/2.
                // Opponent takes N/4. N becomes N/4.
                // Chanek takes N/8. N becomes N/8.
                // ...
                // This continues until N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek's score: N/2 + N/8 + N/32 + ... + 1 (if k is odd)
                // Opponent's score: N/4 + N/16 + N/64 + ... + 1 (if k is even)
                // Total coins: N.
                // Chanek gets 2/3 of N if N is a power of 2.
                // Example N=4: Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                // Chanek: 2+1=3. Opponent: 1.
                // Example N=8: Chanek takes 4. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 4+1=5. Opponent: 2+1=3.

                // The only time taking 1 is better than N/2 for Chanek when N is even
                // is if N/2 is odd and N/2 > 1.
                // Example: N=6. N/2=3 (odd).
                // Chanek takes N/2 (3): N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 3+1=4. Opponent: 1+1=2.
                // Chanek takes 1: N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                // Chanek: 1+2+1=4. Opponent: 1+1=2.
                // Both give 4.

                // What if N is even, and N/2 is odd, and N/2 > 1?
