#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <numeric>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::vector<std::set<char>> adj(26);
    std::vector<bool> in_password(26, false);

    for (size_t i = 0; i < s.length(); ++i) {
        in_password[s[i] - 'a'] = true;
        if (i + 1 < s.length()) {
            char c1 = s[i];
            char c2 = s[i+1];

            adj[c1 - 'a'].insert(c2);
            adj[c2 - 'a'].insert(c1);
        }
    }

    for (int i = 0; i < 26; ++i) {
        if (adj[i].size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::vector<bool> visited(26, false);

    // Find a starting point for the path: a character with only one neighbor
    // or any character if all characters in password have 0 or 2 neighbors.
    char start_char = '\0';
    for (int i = 0; i < 26; ++i) {
        if (in_password[i] && adj[i].size() == 1) {
            start_char = (char)('a' + i);
            break;
        }
    }

    // If no char with 1 neighbor found among those in password,
    // it means all chars in password have 0 or 2 neighbors.
    // If there are chars in password, pick one with 0 or 2 neighbors as start.
    // If all chars in password have 2 neighbors, it forms a cycle.
    // If it forms a cycle, we can pick any char in the cycle as start.
    // If it forms multiple disjoint paths/cycles, we need to pick one.
    // The problem implies a single path for the required characters.
    // If all chars in password have 2 neighbors, and they form a single path,
    // this means the path is actually a cycle. This is fine, we can break it anywhere.
    // If it's a single path, it must have two endpoints with 1 neighbor.
    // If it's a cycle, all nodes have 2 neighbors.
    // If it's a single path, start_char will be found.
    // If it's a cycle, start_char will be '\0'. In this case, pick any char from password.
    if (start_char == '\0') {
        for (int i = 0; i < 26; ++i) {
            if (in_password[i]) {
                start_char = (char)('a' + i);
                break;
            }
        }
    }

    // If start_char is still '\0', it means the password was empty or contained only one unique character.
    // In this case, any layout is fine. We'll just append all letters.
    if (start_char != '\0') {
        char current_char = start_char;
        char prev_char = '\0'; // Sentinel for the first character

        while (current_char != '\0' && !visited[current_char - 'a']) {
            layout += current_char;
            visited[current_char - 'a'] = true;

            char next_char = '\0';
            for (char neighbor : adj[current_char - 'a']) {
                if (neighbor != prev_char) {
                    next_char = neighbor;
                    break;
                }
            }
            prev_char = current_char;
            current_char = next_char;
        }
    }

    // Append remaining unvisited characters
    for (int i = 0; i < 26; ++i) {
        if (!visited[i]) {
            layout += (char)('a' + i);
        }
    }

    // Check if the constructed layout covers all characters that were in the password
    // and if all required adjacencies are met.
    // The construction method ensures that if a path exists, it's built correctly.
    // The only remaining check is if the path covers all required characters.
    // If the graph formed by password characters is disconnected (multiple paths/cycles),
    // then it's impossible.
    // This can be checked by counting how many `in_password` characters are visited.
    int visited_in_password_count = 0;
    for(int i=0; i<26; ++i) {
        if (in_password[i] && visited[i]) {
            visited_in_password_count++;
        }
    }
    int total_in_password_count = 0;
    for(int i=0; i<26; ++i) {
        if (in_password[i]) {
            total_in_password_count++;
        }
    }

    if (visited_in_password_count != total_in_password_count) {
        std::cout << "NO\n";
        return;
    }

    std::cout << "YES\n" << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

