    std::cin >> s;
    int n = s.length();

    std::vector<std::vector<int>> pos_char(26);
    for (int i = 0; i < n; ++i) {
        pos_char[s[i] - 'a'].push_back(i);
    }

    double total_prob = 0.0;

    for (int char_code = 0; char_code < 26; ++char_code) {
        const std::vector<int>& k_indices = pos_char[char_code];
        if (k_indices.empty()) {
            continue;
        }

        if (k_indices.size() == 1) {
            total_prob += 1.0; // If only one k matches t[0], Vasya wins for sure.
            continue;
        }

        // For each possible second position p, calculate how many k_indices it helps distinguish.
        // Vasya chooses p that maximizes this count.
        int max_distinguishable_k = 0;

        for (int p = 1; p < n; ++p) {
            std::map<char, int> char_counts;
            for (int k_val : k_indices) {
                char_counts[s[(k_val + p) % n]]++;
            }

            int current_distinguishable_k = 0;
            for (auto const& [char_val, count] : char_counts) {
                if (count == 1) {
                    current_distinguishable_k++;
                }
            }
            max_distinguishable_k = std::max(max_distinguishable_k, current_distinguishable_k);
        }

        total_prob += static_cast<double>(max_distinguishable_k);
    }

    std::cout << std::fixed << std::setprecision(15) << total_prob / n << std::endl;

    return 0;
}

