#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial total counts
    int initial_s = 0;
    int initial_b = 0;
    for (int x : a) {
        if (x == 1) {
            initial_s++;
        } else {
            initial_b++;
        }
    }

    // Prefix sums for the left half (jars 1 to n)
    // diff_left[i] = (count of 1s in a[0...i-1]) - (count of 2s in a[0...i-1])
    // We are interested in jars 1 to n, which are indices 0 to n-1.
    // diff_left[k] will store the difference for the prefix of length k (jars 1 to k).
    // So diff_left[0] = 0 (empty prefix)
    // diff_left[1] = a[0] == 1 ? 1 : -1
    // ...
    // diff_left[n] = difference for jars 1 to n (indices 0 to n-1)
    std::vector<int> diff_left(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_left[i + 1] = diff_left[i] + (a[i] == 1 ? 1 : -1);
    }

    // Suffix sums for the right half (jars n+1 to 2n)
    // diff_right[i] = (count of 1s in a[i...2n-1]) - (count of 2s in a[i...2n-1])
    // We are interested in jars n+1 to 2n, which are indices n to 2n-1.
    // diff_right[k] will store the difference for the suffix of length k (jars 2n-k+1 to 2n).
    // So diff_right[0] = 0 (empty suffix)
    // diff_right[1] = a[2n-1] == 1 ? 1 : -1
    // ...
    // diff_right[n] = difference for jars n+1 to 2n (indices n to 2n-1)
    std::vector<int> diff_right(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_right[i + 1] = diff_right[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars eaten from the left to achieve a certain difference
    // key: difference (S-B), value: number of jars eaten from left (L)
    std::map<int, int> left_diff_to_L;
    for (int L = 0; L <= n; ++L) {
        int current_diff = diff_left[L];
        if (left_diff_to_L.find(current_diff) == left_diff_to_L.end()) {
            left_diff_to_L[current_diff] = L;
        }
    }

    int min_jars_eaten = 2 * n; // Initialize with maximum possible

    // Iterate through possible number of jars eaten from the right (R)
    for (int R = 0; R <= n; ++R) {
        int current_right_diff = diff_right[R];
        // We need (S_rem - B_rem) = 0
        // (S_total - S_eaten_L - S_eaten_R) - (B_total - B_eaten_L - B_eaten_R) = 0
        // (S_total - B_total) - (S_eaten_L - B_eaten_L) - (S_eaten_R - B_eaten_R) = 0
        // (initial_s - initial_b) - diff_left[L] - diff_right[R] = 0
        // So, we need diff_left[L] = (initial_s - initial_b) - diff_right[R]
        int target_left_diff = (initial_s - initial_b) - current_right_diff;

        if (left_diff_to_L.count(target_left_diff)) {
            int L = left_diff_to_L[target_left_diff];
            min_jars_eaten = std::min(min_jars_eaten, L + R);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_and_mask = 1023; // All bits set
    int current_or_mask = 0;    // All bits clear
    int current_xor_mask = 0;   // No change

    for (int i = 0; i < n; ++i) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        if (op_char == '&') {
            current_and_mask &= val;
            current_or_mask &= val;
            current_xor_mask &= val;
        } else if (op_char == '|') {
            current_and_mask |= val;
            current_or_mask |= val;
            current_xor_mask |= val;
        } else if (op_char == '^') {
            current_and_mask ^= val;
            current_or_mask ^= val;
            current_xor_mask ^= val;
        }
    }

    // The final transformation is: (x & current_and_mask) | current_or_mask ^ current_xor_mask
    // This can be simplified.
    // Let's find the equivalent AND, OR, XOR constants.
    // We need to find A, O, X such that for any x in [0, 1023]:
    // (x & A) | O ^ X == (x & current_and_mask) | current_or_mask ^ current_xor_mask

    // Consider the effect on an initial 0 and an initial 1 for each bit.
    // For an initial 0:
    // (0 & current_and_mask) | current_or_mask ^ current_xor_mask
    // = 0 | current_or_mask ^ current_xor_mask
    // = current_or_mask ^ current_xor_mask
    int val_if_input_is_0 = current_or_mask ^ current_xor_mask;

    // For an initial 1023 (all bits set):
    // (1023 & current_and_mask) | current_or_mask ^ current_xor_mask
    // = current_and_mask | current_or_mask ^ current_xor_mask
    int val_if_input_is_1023 = current_and_mask | current_or_mask ^ current_xor_mask;

    // Now, we want to find A, O, X such that:
    // (0 & A) | O ^ X = val_if_input_is_0  => O ^ X = val_if_input_is_0
    // (1023 & A) | O ^ X = val_if_input_is_1023 => A | O ^ X = val_if_input_is_1023

    // From these, we can deduce A, O, X.
    // O ^ X = val_if_input_is_0
    // A | (O ^ X) = val_if_input_is_1023
    // A | val_if_input_is_0 = val_if_input_is_1023

    // This means for each bit b:
    // If (val_if_input_is_0)_b is 0:
    //   (A)_b | 0 = (val_if_input_is_1023)_b => (A)_b = (val_if_input_is_1023)_b
    // If (val_if_input_is_0)_b is 1:
    //   (A)_b | 1 = (val_if_input_is_1023)_b => (val_if_input_is_1023)_b must be 1. (A)_b can be 0 or 1.
    //   To make A minimal (or rather, to ensure it's consistent with the original logic),
    //   we can say (A)_b = (val_if_input_is_1023)_b.
    //   This is equivalent to A = val_if_input_is_1023 & (~val_if_input_is_0)
    //   No, this is not quite right.
    //   A = val_if_input_is_1023 ^ val_if_input_is_0 is not correct either.

    // Let's use the property that for each bit `b`:
    // `f(0)_b` is the `b`-th bit of `val_if_input_is_0`.
    // `f(1)_b` is the `b`-th bit of `val_if_input_is_1023` (when considering only bit `b`).
    // More precisely, `f(1)_b` is the `b`-th bit of `val_if_input_is_1023` if we consider `x` to be `(1<<b)`.
    // Let's track `f(0)` and `f(1)` for each bit.
    // `f(0)` is the result if the input bit is 0.
    // `f(1)` is the result if the input bit is 1.

    // Initialize `f(0)` to 0 and `f(1)` to 1 for each bit.
    // `f(0)` for all bits is 0.
    // `f(1)` for all bits is 1023.
    int current_val_0 = 0;
    int current_val_1023 = 1023;

    // Re-simulate the operations on these two special values
    // This is equivalent to what we did with current_and_mask, current_or_mask, current_xor_mask
    // but it's more direct.
    // current_val_0 will become val_if_input_is_0
    // current_val_1023 will become val_if_input_is_1023
    current_val_0 = current_or_mask ^ current_xor_mask;
    current_val_1023 = current_and_mask | current_or_mask ^ current_xor_mask;

    // Now we have `current_val_0` (what 0 becomes) and `current_val_1023` (what 1023 becomes).
    // We need to find A, O, X such that:
    // (0 & A) | O ^ X = current_val_0
    // (1023 & A) | O ^ X = current_val_1023

    // From the first equation: O ^ X = current_val_0
    // From the second equation: A | (O ^ X) = current_val_1023
    // Substituting: A | current_val_0 = current_val_1023

    // Let's determine A, O, X bit by bit.
    // For each bit `b` from 0 to 9:
    // Let `v0_b` be the `b`-th bit of `current_val_0`.
    // Let `v1_b` be the `b`-th bit of `current_val_1023`.

    // We need to find `A_b`, `O_b`, `X_b` such that:
    // (0 & A_b) | O_b ^ X_b = v0_b  => O_b ^ X_b = v0_b
    // (1 & A_b) | O_b ^ X_b = v1_b  => A_b | (O_b ^ X_b) = v1_b
    // Substituting: A_b | v0_b = v1_b

    // Case 1: v0_b = 0
    //   O_b ^ X_b = 0  => O_b = X_b
    //   A_b | 0 = v1_b => A_b = v1_b
    //   If v1_b = 0: A_b=0, O_b=X_b=0 (e.g., &0, |0, ^0)
    //   If v1_b = 1: A_b=1, O_b=X_b=0 (e.g., &1, |0, ^0)
    //   In this case, we can use A_b = v1_b, O_b = 0, X_b = 0.
    //   This means the bit is `x_b & v1_b`.

    // Case 2: v0_b = 1
    //   O_b ^ X_b = 1  => O_b != X_b
    //   A_b | 1 = v1_b => v1_b must be 1. (If v1_b is 0, it's impossible, but this won't happen
    //                                      because current_val_0 is a submask of current_val_1023
    //                                      i.e., current_val_0 | current_val_1023 = current_val_1023)
    //   If v1_b = 1: A_b | 1 = 1. A_b can be 0 or 1.
    //   We can choose A_b = 0. Then O_b ^ X_b = 1.
    //   We can use A_b = 0, O_b = 1, X_b = 0.
    //   This means the bit is `x_b | 1`.
    //   Or we can use A_b = 0, O_b = 0, X_b = 1.
    //   This means the bit is `x_b ^ 1`.

    // Let's construct the final A, O, X constants.
    int final_A = 1023; // Initial AND mask
    int final_O = 0;    // Initial OR mask
    int final_X = 0;    // Initial XOR mask

    for (int b = 0; b < 10; ++b) {
        int v0_b = (current_val_0 >> b) & 1;
        int v1_b = (current_val_1023 >> b) & 1;

        if (v0_b == 0 && v1_b == 0) {
            // Input 0 -> 0, Input 1 -> 0
            // This means the bit is always 0.
            // We can achieve this with `& 0`.
            final_A &= ~(1 << b); // Set A_b to 0
            // O_b and X_b remain 0 for this bit.
        } else if (v0_b == 0 && v1_b == 1) {
            // Input 0 -> 0, Input 1 -> 1
            // This means the bit is unchanged.
            // We can achieve this with `& 1`, `| 0`, `^ 0`.
            // A_b remains 1. O_b remains 0. X_b remains 0.
        } else if (v0_b == 1 && v1_b == 0) {
            // Input 0 -> 1, Input 1 -> 0
            // This means the bit is flipped.
            // We can achieve this with `^ 1`.
            final_X |= (1 << b); // Set X_b to 1
            // A_b remains 1. O_b remains 0.
        } else if (v0_b == 1 && v1_b == 1) {
            // Input 0 -> 1, Input 1 -> 1
            // This means the bit is always 1.
            // We can achieve this with `| 1`.
            final_O |= (1 << b); // Set O_b to 1
            // A_b remains 1. X_b remains 0.
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_A != 1023) { // If any bit of A is 0, we need an AND operation
        result_ops.push_back({'&', final_A});
    }
    if (final_O != 0) { // If any bit of O is 1, we need an OR operation
        result_ops.push_back({'|', final_O});
    }
    if (final_X != 0) { // If any bit of X is 1, we need an XOR operation
        result_ops.push_back({'^', final_X});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_zeros(n, 0);
    std::vector<int> right_ones(n, 0);

    // Calculate left_zeros: length of consecutive zeros to the left of i (inclusive)
    // if a[i] == 1, left_zeros[i] is 0
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            left_zeros[i] = (i > 0 ? left_zeros[i - 1] : 0) + 1;
        } else {
            left_zeros[i] = 0;
        }
    }

    // Calculate right_ones: length of consecutive ones to the right of i (inclusive)
    // if a[i] == 0, right_ones[i] is 0
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 1) {
            right_ones[i] = (i < n - 1 ? right_ones[i + 1] : 0) + 1;
        } else {
            right_ones[i] = 0;
        }
    }

    int max_k = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) { // Find 0s that are part of a 01...10 pattern
            if (i > 0 && a[i-1] == 1) { // This 0 is preceded by a 1
                // Find the length of the block of 1s to its left
                int len_ones = right_ones[i-1];
                if (len_ones > 0) {
                    max_k = std::max(max_k, (len_ones + 1) / 2);
                }
            }
        } else { // Find 1s that are part of a 10...01 pattern
            if (i > 0 && a[i-1] == 0) { // This 1 is preceded by a 0
                // Find the length of the block of 0s to its left
                int len_zeros = left_zeros[i-1];
                if (len_zeros > 0) {
                    max_k = std::max(max_k, (len_zeros + 1) / 2);
                }
            }
        }
    }

    std::cout << max_k << std::endl;

    std::vector<int> result_a = a;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) { // 0s can turn into 1s
            // Check if this 0 is part of a 1...10...1 pattern where 1s are close enough
            // The 0 at index i will turn into 1 if it's within max_k distance from a 1 on both sides
            // More precisely, if it's part of a 1...10...01...1 pattern where the 0s block length is <= 2*max_k - 1
            // Or, if it's part of a 1...10 pattern where the 1s block length is >= 2*max_k
            // Or, if it's part of a 0...1 pattern where the 1s block length is >= 2*max_k

            // A 0 at index i changes to 1 if it's surrounded by 1s within max_k steps.
            // This means there's a 1 at index i-k' and a 1 at index i+k'' where k', k'' <= max_k.
            // The effective condition for a[i] to become 1 is if it's part of a 1...0...1 pattern
            // where the distance between the 1s is at most 2*max_k - 1.
            // This is equivalent to saying that the block of 0s it belongs to has length L,
            // and it's not one of the (L+1)/2 outermost 0s.

            // A 0 at index i will become 1 if it's part of a 1...0...0...0...1 pattern
            // where the block of 0s has length L, and its distance from either 1 is less than or equal to max_k.
            // This means its index relative to the start of the 0-block (0-indexed) is j,
            // and its index relative to the end of the 0-block (0-indexed) is L-1-j.
            // It will become 1 if min(j, L-1-j) < max_k.
            // This is equivalent to saying that the 0 is not one of the (L+1)/2 outermost 0s.

            // Let's find the block of 0s containing a[i].
            // Find the first 0 in this block: j_start
            // Find the last 0 in this block: j_end
            int j_start = i;
            while (j_start > 0 && a[j_start - 1] == 0) {
                j_start--;
            }
            int j_end = i;
            while (j_end < n - 1 && a[j_end + 1] == 0) {
                j_end++;
            }

            // If this block of 0s is surrounded by 1s (or boundaries)
            bool left_is_one = (j_start == 0 || a[j_start - 1] == 1);
            bool right_is_one = (j_end == n - 1 || a[j_end + 1] == 1);

            if (left_is_one && right_is_one) {
                int block_len = j_end - j_start + 1;
                if (block_len <= 2 * max_k - 1) {
                    result_a[i] = 1;
                }
            }
        } else { // 1s can turn into 0s
            // A 1 at index i will become 0 if it's part of a 0...1...0 pattern
            // where the block of 1s has length L, and its distance from either 0 is less than or equal to max_k.
            // This means its index relative to the start of the 1-block (0-indexed) is j,
            // and its index relative to the end of the 1-block (0-indexed) is L-1-j.
            // It will become 0 if min(j, L-1-j) < max_k.

            int j_start = i;
            while (j_start > 0 && a[j_start - 1] == 1) {
                j_start--;
            }
            int j_end = i;
            while (j_end < n - 1 && a[j_end + 1] == 1) {
                j_end++;
            }

            bool left_is_zero = (j_start == 0 || a[j_start - 1] == 0);
            bool right_is_zero = (j_end == n - 1 || a[j_end + 1] == 0);

            if (left_is_zero && right_is_zero) {
                int block_len = j_end - j_start + 1;
                if (block_len <= 2 * max_k - 1) {
                    result_a[i] = 0;
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << result_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n >= m by swapping if necessary.
        // This simplifies calculations as we can assume n is the larger coordinate.
        if (n < m) {
            std::swap(n, m);
        }

        // Case 1: k < n (or k < m, since n >= m).
        // It's impossible to reach (n, m) in k moves if k is less than the maximum coordinate.
        // This is because each move can change a coordinate by at most 1.
        if (k < n) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: k >= n.
        // We can always reach (n, m) in k moves.
        // The strategy is to make n diagonal moves to reach (n, n) or (n, m) if m=n,
        // then make m straight moves to reach (n, m) if m < n,
        // and then use remaining moves to oscillate.

        // Calculate the maximum number of diagonal moves possible.
        // This is limited by the smaller coordinate, m.
        // We can make m diagonal moves to reach (m, m) or (n, m) if n=m.
        // After m diagonal moves, we are at (x, y) where |x| <= m, |y| <= m.
        // To reach (n, m), we need to cover a distance of n in x and m in y.
        // The minimum number of moves to reach (n, m) is n (if n >= m).
        // This is achieved by m diagonal moves and n-m straight moves.
        // Total moves = m + (n-m) = n.
        // So, if k = n, the answer is m.

        // If k > n, we have k - n extra moves.
        // Each pair of extra moves can be used to oscillate (e.g., (x,y) -> (x+1,y) -> (x,y))
        // or (x,y) -> (x+1,y+1) -> (x,y) etc.
        // We want to maximize diagonal moves.
        // An oscillation like (x,y) -> (x+1,y+1) -> (x,y) uses 2 moves and 2 diagonal moves.
        // An oscillation like (x,y) -> (x+1,y) -> (x,y) uses 2 moves and 0 diagonal moves.
        // An oscillation like (x,y) -> (x+1,y) -> (x+1,y+1) -> (x,y+1) -> (x,y) uses 4 moves and 2 diagonal moves.

        // The parity of (n+m) must match the parity of k.
        // Each move changes the parity of (current_x + current_y).
