                current_y_offset += val_ax;
                current_x -= val_ax;
            }

            // Store results for all visited nodes in this path
            for (int j = 1; j <= n; ++j) {
                if (visited[j]) {
                    if (cycle_detected) {
                        dp_y[j] = -1;
                        dp_x[j] = 0; // Not relevant for infinite loop
                    } else {
                        dp_y[j] = current_y_offset;
                        dp_x[j] = current_x;
                    }
                }
            }
        }

        // Now simulate for a[1] = i
        int current_x = 1;
        long long current_y = 0;

        long long val_ax = a[current_x];

        // Step 2: x = x + a_x, y = y + a_x
        current_y += val_ax;
        current_x += val_ax;

        if (current_x < 1 || current_x > n) { // Terminated
            std::cout << current_y << "\n";
            continue;
        }

        // Step 3: x = x - a_x, y = y + a_x
        val_ax = a[current_x]; // a_x for the new x
        current_y += val_ax;
        current_x -= val_ax;

        if (current_x < 1 || current_x > n) { // Terminated
            std::cout << current_y << "\n";
            continue;
        }

        // Now we are at a state (current_x, current_y) where current_x >= 1 and current_x <= n.
        // We can use the precomputed DP values.
        if (dp_y[current_x] == -1) { // Infinite loop
            std::cout << -1 << "\n";
        } else { // Terminating path
            std::cout << current_y + dp_y[current_x] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <tuple>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n);
    std::vector<long long> max_val_constraint(n, 2000000000LL); // Initialize with a large value (larger than 10^9)

    // Process operations in reverse to determine initial_a constraints
    // For type 2 operations, max(a_j + delta_j) = m implies a_j + delta_j <= m for all j in [l, r].
    // This means a_j <= m - delta_j. We want the tightest upper bound for a_j.
    // delta_j here is the sum of d's from type 1 operations *after* this type 2 operation.
    // So, we need to track the *current* delta for each element.
    std::vector<long long> current_delta(n, 0);
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] -= ops[i].val; // Subtract d because we are going backwards
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_constraint[j] = std::min(max_val_constraint[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // Set initial_a based on the derived constraints
    for (int i = 0; i < n; ++i) {
        initial_a[i] = max_val_constraint[i];
    }

    // Verify the solution
    std::vector<long long> current_array_state = initial_a;
    std::vector<long long> prefix_diff(n + 1, 0);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            prefix_diff[ops[i].l] += ops[i].val;
            if (ops[i].r + 1 < n) {
                prefix_diff[ops[i].r + 1] -= ops[i].val;
            }
        } else { // type 2
            long long current_max = -3000000000000000000LL; // A very small number
            long long current_sum_delta = 0;
            for (int j = 0; j < n; ++j) {
                current_sum_delta += prefix_diff[j];
                if (j >= ops[i].l && j <= ops[i].r) {
                    current_max = std::max(current_max, initial_a[j] + current_sum_delta);
                }
            }
            if (current_max != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long count = 0;

    std::vector<int> next_one(n + 1, n);
    for (int i = n - 1; i >= 0; --i) {
        if (s[i] == '1') {
            next_one[i] = i;
        } else {
            next_one[i] = next_one[i + 1];
        }
    }

    for (int i = 0; i < n; ++i) {
        // Case 1: Substring starts with '1'
        // Iterate over possible lengths for substrings starting at i
        // The maximum length we need to check is limited by MAX_LEN_CHECK
        // because 2^k grows much faster than k.
        // For k=20, 2^20 = 1048576. For k=21, 2^21 = 2097152.
        // Max N is 2e5. So max length is N.
        // If len > 20, then 2^len is much larger than len.
        // Specifically, if len >= 20, then 2^len > 2*10^5.
        // So, if f(s_l...s_r) = len, then len must be small.
        // The maximum value of f(s_l...s_r) can be N.
        // If f(s_l...s_r) = N, then len must be around log2(N).
        // For N=2e5, log2(2e5) is about 17.6. So max len is around 18.
        // Let's use a safe upper bound like 20 or 21.
        // The problem states $r-l+1 = f(s_l \dots s_r)$.
        // If $s_l = '1'$, then $f(s_l \dots s_r) \ge 2^{r-l}$.
        // So $r-l+1 \ge 2^{r-l}$. This only holds for small $r-l$.
        // If $r-l=0$, $1 \ge 2^0=1$. True.
        // If $r-l=1$, $2 \ge 2^1=2$. True.
        // If $r-l=2$, $3 \ge 2^2=4$. False.
        // So if $s_l = '1'$, then $r-l$ can be at most 1.
        // This means $r-l+1$ can be at most 2.
        // If $r-l+1=1$, $s_i='1'$. $f('1')=1$. Good.
        // If $r-l+1=2$, $s_i s_{i+1} = '10'$. $f('10')=2$. Good.
        // If $s_i = '1'$, we only need to check $s_i$ and $s_i s_{i+1}$.
        // This is incorrect. $f(s_l \dots s_r)$ is the value of the binary string $s_l \dots s_r$.
        // The length is $len = r-l+1$.
        // If $s_l = '1'$, then $f(s_l \dots s_r) \ge 2^{len-1}$.
        // So we need $len = f(s_l \dots s_r) \ge 2^{len-1}$.
        // This inequality $k \ge 2^{k-1}$ holds only for $k=1, 2$.
        // For $k=1$: $1 \ge 2^0 = 1$. True.
        // For $k=2$: $2 \ge 2^1 = 2$. True.
        // For $k=3$: $3 \ge 2^2 = 4$. False.
        // So if $s_i = '1'$, the length $len$ can be at most 2.
        // This means $s_i$ itself (len=1) and $s_i s_{i+1}$ (len=2) are the only candidates.
        // This is also incorrect. The value $f(s_l \dots s_r)$ can be small even if $s_l='1'$
        // if there are many zeros after the first '1'.
        // Example: $s=100000$. $f(100000)=32$. Length is 6. $6 \ne 32$.
        // Example: $s=1011$. $s_1 \dots s_2 = '10'$. Length 2. $f('10')=2$. Good.
        // The maximum length of a substring we need to check is limited by $N$.
        // The maximum value of $f(s_l \dots s_r)$ is $N$.
        // If $s_l = '1'$, then $f(s_l \dots s_r)$ can be at most $N$.
        // The length of the binary string $s_l \dots s_r$ is $len = r-l+1$.
        // If $len > \log_2 N + 1$, then $f(s_l \dots s_r)$ will be greater than $N$
        // (assuming $s_l='1'$).
        // For $N=2 \cdot 10^5$, $\log_2(2 \cdot 10^5) \approx 17.6$.
        // So if $s_l='1'$, we only need to check substrings of length up to about 18-20.
        // Let's use a constant MAX_LEN_CHECK = 20.
        // This means for each starting position $i$, we check $j$ such that $j-i+1 \le 20$.
        // This is $O(N \cdot \text{MAX_LEN_CHECK})$.

        long long current_val = 0;
        for (int j = i; j < n; ++j) {
            int len = j - i + 1;
            if (len > 20) { // Optimization: if len is too large, current_val will exceed N
                            // if s[i] is '1'. If s[i] is '0', this loop is skipped.
                            // This is not quite right. current_val can be small if there are many leading zeros.
                            // But we are in the loop where s[i] is the first '1'.
                            // So current_val will be at least 2^(len-1).
                            // If len > 20, then 2^(len-1) > 2^19 = 524288 > N.
                            // So current_val will be > N.
                            // Thus, len cannot be equal to current_val.
                break;
            }

            current_val = (current_val << 1) | (s[j] - '0');

            if (s[i] == '0') { // Substring starts with '0'
                // This case is handled by the '0' prefix logic below.
                // We only need to check substrings starting with '1' in this loop.
                // If s[i] is '0', we skip this inner loop and go to the next i.
                // This is wrong. The outer loop iterates through all possible starting positions i.
                // If s[i] is '0', then current_val will be 0 for s[i...j] until a '1' is encountered.
                // Example: s = 0001000. i=0.
                // j=0: s[0]='0'. len=1. current_val=0. 1 != 0.
                // j=1: s[0..1]='00'. len=2. current_val=0. 2 != 0.
                // j=2: s[0..2]='000'. len=3. current_val=0. 3 != 0.
                // j=3: s[0..3]='0001'. len=4. current_val=1. 4 != 1.
                // This loop correctly calculates current_val for s[i...j].
                // The condition `if (s[i] == '0')` is not needed here.
                // The condition `if (current_val > n)` is a better optimization.
                // If current_val > n, then it cannot be equal to len, because len <= n.
                if (current_val > n) {
                    break; // current_val is already too large
                }
            } else { // Substring starts with '1'
                // If s[i] is '1', then current_val will grow quickly.
                // If current_val > n, then it cannot be equal to len.
                if (current_val > n) {
                    break;
                }
            }

            if (current_val == len) {
                count++;
            }
        }
    }

    // The above loop handles all substrings s[i...j] where s[i] is '1'.
    // It also handles substrings s[i...j] where s[i] is '0' but current_val is calculated.
    // However, the problem statement implies that $f(011)=3$, $f(00101)=5$.
    // This means leading zeros are part of the binary string for length calculation,
    // but they don't change the value.
    // Example: $s=0110$.
    // $s_1 \dots s_1 = '0'$. len=1. $f('0')=0$. $1 \ne 0$.
    // $s_1 \dots s_2 = '01'$. len=2. $f('01')=1$. $2 \ne 1$.
    // $s_1 \dots s_3 = '011'$. len=3. $f('011')=3$. $3 = 3$. Good.
    // $s_1 \dots s_4 = '0110'$. len=4. $f('0110')=6$. $4 \ne 6$.
    // The previous loop correctly handles these.
    // The issue is with substrings like $0001000$.
    // $s_1 \dots s_4 = '0001'$. len=4. $f('0001')=1$. $4 \ne 1$.
    // $s_1 \dots s_5 = '00010'$. len=5. $f('00010')=2$. $5 \ne 2$.
    // $s_1 \dots s_6 = '000100'$. len=6. $f('000100')=4$. $6 \ne 4$.
    // $s_1 \dots s_7 = '0001000'$. len=7. $f('0001000')=8$. $7 \ne 8$.

    // The problem is that if a substring starts with '0', say $s_i \dots s_j$,
    // its value $f(s_i \dots s_j)$ is the same as $f(s_k \dots s_j)$ where $s_k$ is the first '1'
    // in $s_i \dots s_j$, or 0 if all are '0'.
    // Let $k$ be the index of the first '1' in $s_i \dots s_j$.
    // If $s_i \dots s_j$ is all zeros, $f(s_i \dots s_j) = 0$.
    // If $s_i \dots s_j$ contains at least one '1', let $k$ be the index of the first '1'.
    // Then $f(s_i \dots s_j) = f(s_k \dots s_j)$.
    // The length is $len = j-i+1$.
    // The condition is $j-i+1 = f(s_k \dots s_j)$.
    // Let $len' = j-k+1$. This is the length of $s_k \dots s_j$.
    // The value $f(s_k \dots s_j)$ is at most $2^{len'} - 1$.
    // So we need $j-i+1 = f(s_k \dots s_j)$.
    // Also, $j-i+1 = (k-i) + (j-k+1) = (k-i) + len'$.
    // So we need $(k-i) + len' = f(s_k \dots s_j)$.
    // Since $f(s_k \dots s_j)$ is calculated from $s_k \dots s_j$, it is at most $2^{len'}-1$.
    // So $(k-i) + len' \le 2^{len'}-1$.
    // This means $k-i \le 2^{len'}-1-len'$.
    // The maximum value of $len'$ is about 20 (as discussed above, for $f(s_k \dots s_j) \le N$).
    // If $len' = 1$, $k-i \le 2^1-1-1 = 0$. So $k-i=0$, which means $i=k$. This is the case where $s_i='1'$.
    // If $len' = 2$, $k-i \le 2^2-1-2 = 1$. So $k-i=0$ or $k-i=1$.
    // If $len' = 3$, $k-i \le 2^3-1-3 = 4$.
    // If $len' = 4$, $k-i \le 2^4-1-4 = 11$.
    // If $len' = 5$, $k-i \le 2^5-1-5 = 26$.
    // If $len' = 6$, $k-i \le 2^6-1-6 = 57$.
    // If $len' = 7$, $k-i \le 2^7-1-7 = 120$.
    // If $len' = 8$, $k-i \le 2^8-1-8 = 247$.
    // If $len' = 9$, $k-i \le 2^9-1-9 = 502$.
    // If $len' = 10$, $k-i \le 2^{10}-1-10 = 1013$.
    // If $len' = 11$, $k-i \le 2^{11}-1-11 = 2036$.
    // If $len' = 12$, $k-i \le 2^{12}-1-12 = 4083$.
    // If $len' = 13$, $k-i \le 2^{13}-1-13 = 8174$.
    // If $len' = 14$, $k-i \le 2^{14}-1-14 = 16371$.
    // If $len' = 15$, $k-i \le 2^{15}-1-15 = 32752$.
    // If $len' = 16$, $k-i \le 2^{16}-1-16 = 65519$.
    // If $len' = 17$, $k-i \le 2^{17}-1-17 = 131054$.
    // If $len' = 18$, $k-i \le 2^{18}-1-18 = 262127$.
    // If $len' = 19$, $k-i \le 2^{19}-1-19 = 524268$.
    // If $len' = 20$, $k-i \le 2^{20}-1-20 = 1048555$.
    // The maximum value for $k-i$ is $N-1$.
    // So we need to iterate $len'$ from 1 to about 20.
    // For each $len'$, we find $f(s_k \dots s_j)$ where $j-k+1 = len'$.
    // Then we check if $k-i = f(s_k \dots s_j) - len'$.
    // The number of leading zeros $k-i$ must be non-negative.
    // So $f(s_k \dots s_j) - len' \ge 0$.
    // This means $f(s_k \dots s_j) \ge len'$. This is always true for $s_k='1'$ and $len' \ge 1$.

    // The strategy:
    // Iterate $k$ from $0$ to $n-1$. This $k$ is the starting position of the '1' part.
    // If $s[k] == '0'$, skip.
    // Now $s[k]$ is '1'.
    // Iterate $j$ from $k$ to $n-1$. This $j$ is the end of the '1' part.
    // Let $len' = j-k+1$.
    // Calculate $val = f(s_k \dots s_j)$.
    // If $len' > 20$ (or $val > n$), break from inner loop.
    // We are looking for $i$ such that $s_i \dots s_{k-1}$ are all '0's.
    // The length of $s_i \dots s_j$ is $len = (k-i) + len'$.
    // We need $len = val$.
    // So $(k-i) + len' = val$.
    // This means $k-i = val - len'$.
    // Let $num\_leading\_zeros = val - len'$.
    // If $num\_leading\_zeros < 0$, this is impossible.
    // If $num\_leading\_zeros = 0$, then $i=k$. This is the case where $s_k$ is the first char.
    // If $num\_leading\_zeros > 0$, then $i = k - num\_leading\_zeros$.
    // We need to check if $i \ge 0$ and $s_i \dots s_{k-1}$ are all '0's.
    // The condition $s_i \dots s_{k-1}$ are all '0's is equivalent to $next\_one[i] \ge k$.
    // (meaning the first '1' from index $i$ onwards is at or after $k$).
    // And $next\_one[i]$ must be exactly $k$ if $i < k$.
    // If $i < k$, then $s_i \dots s_{k-1}$ must be all zeros.
    // This means $next\_one[i]$ must be $k$.
    // If $i=k$, then $num\_leading\_zeros=0$. This is handled.

    // Let's refine the loop structure.
    // Iterate $k$ from $0$ to $n-1$.
    // If $s[k] == '0'$, continue.
    // Now $s[k]$ is '1'.
    // `current_val` will be $f(s_k \dots s_j)$.
    long long current_val_from_k = 0;
    for (int k = 0; k < n; ++k) {
        if (s[k] == '0') {
            continue;
        }

        current_val_from_k = 0;
        for (int j = k; j < n; ++j) {
            current_val_from_k = (current_val_from_k << 1) | (s[j] - '0');

            int len_prime = j - k + 1; // Length of substring s[k...j]

            // Optimization: if current_val_from_k is too large, it cannot be equal to len.
            // The maximum possible length of the full substring s[i...j] is N.
            // So current_val_from_k must be <= N.
            if (current_val_from_k > n + 20) { // A slightly larger bound to be safe, e.g., N + MAX_LEN_CHECK
                                               // because val - len' can be up to N.
                                               // If val is N, len' is ~18.
                                               // So val - len' is N-18.
                                               // If val is N+18, len' is ~19.
                                               // So val - len' is N-1.
                                               // If val is N+19, len' is ~20.
                                               // So val - len' is N-1.
                                               // The maximum value of val is $2^{20}-1 \approx 10^6$.
                                               // If $val > N + \text{MAX_LEN_CHECK}$, then $val - len'$ will be too large.
                                               // $val - len' \le N-1$.
                                               // So $val \le N-1+len'$.
                                               // Max $len'$ is 20. So $val \le N-1+20 = N+19$.
                                               // So if $val > N+19$, we can break.
                break;
            }

            long long num_leading_zeros = current_val_from_k - len_prime;

            if (num_leading_zeros < 0) {
                // This means current_val_from_k < len_prime.
                // Since s[k] is '1', current_val_from_k >= 2^(len_prime-1).
                // We need 2^(len_prime-1) < len_prime. This only happens for len_prime=1, 2.
                // If len_prime=1, current_val_from_k=1. num_leading_zeros = 1-1=0.
                // If len_prime=2, current_val_from_k=2. num_leading_zeros = 2-2=0.
                // So num_leading_zeros will never be negative here.
                // This check is technically redundant but harmless.
            } else {
                int i = k - (int)num_leading_zeros;
                if (i >= 0) {
                    // Check if s[i...k-1] are all '0's.
                    // This is true if next_one[i] == k.
                    if (next_one[i] == k) {
                        count++;
                    }
                }
            }
        }
    }

    std::cout << count << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string a, b;
    std::cin >> a >> b;

    int ones_a = 0;
    for (char c : a) {
        if (c == '1') {
            ones_a++;
        }
    }

    int ones_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_b++;
        }
    }

    // If ones_a is odd, we can append '1'. If even, we can append '0'.
    // So, if ones_a is odd, we can effectively increase the count of '1's by 1.
    // If ones_a is even, we can't increase the count of '1's by appending parity.
    // However, we can always append '0' if ones_a is even.
    // The maximum number of '1's we can achieve is ones_a + (ones_a % 2).
    // This is equivalent to (ones_a + 1) if ones_a is odd, and ones_a if ones_a is even.
    // This can be simplified to ones_a + (ones_a % 2).
    // This is the maximum number of '1's we can have in a string of length |a| or more,
    // assuming we only append parity.

    // The crucial part is that we can always make the string longer.
    // If we have `ones_a` ones, we can append `ones_a % 2`.
    // If `ones_a % 2 == 1`, we append '1', new ones count is `ones_a + 1`.
    // If `ones_a % 2 == 0`, we append '0', new ones count is `ones_a`.
    // So, the maximum number of ones we can achieve is `ones_a + (ones_a % 2)`.
    // Let's call this `max_ones_reachable_from_a`.

    int max_ones_reachable_from_a = ones_a + (ones_a % 2);

    // We need to check two conditions:
    // 1. The number of '1's in b must be less than or equal to the maximum '1's we can generate.
    // 2. The length of b must be less than or equal to the length of a plus any number of appended characters.
    //    Since we can remove characters from the front of 'a', we can effectively start with any suffix of 'a'.
    //    The shortest possible string we can start with is a single character.
    //    The longest possible string we can start with is 'a' itself.
    //    If |b| <= |a|, we can potentially form 'b' by just removing characters from 'a' and then appending.
    //    If |b| > |a|, we must append characters.
    //    The key is that we can always make the string longer by appending parity.
    //    So, the length constraint is effectively that |b| must be at least 1 (since b is not empty).
    //    The only real length constraint is that we must be able to reach `ones_b` '1's.
    //    If `ones_b` is 0, we need to be able to make a string of all '0's.
    //    If `ones_a` is 0, we can only make strings of all '0's.
    //    If `ones_a` is 0 and `ones_b` is 0, then it's possible if `|b| <= |a|` (by removing leading '0's)
    //    or if `|b| > |a|` (by appending '0's). So if `ones_a == 0` and `ones_b == 0`, it's always YES.

    if (ones_b <= max_ones_reachable_from_a) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v, d, p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false;

        long long current_v_cry = children[i].v;
        long long total_d_cry_from_leaving = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply crying from child i
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Apply crying from children who left earlier due to low confidence
            children[j].p -= total_d_cry_from_leaving;
        }

        // Chain reaction for children leaving due to low confidence
        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_cry_from_leaving += children[j].d; // Accumulate d_j for subsequent children
                // Re-check children after j, as their confidence might now be negative
                // This is handled by iterating j from i+1 to n and applying total_d_cry_from_leaving
                // The current loop structure ensures that if child j leaves, its d_j affects j+1, j+2, etc.
                // If j+1 then leaves, its d_j affects j+2, j+3, etc.
                // This means we need to re-evaluate children after j.
                // A simple way is to restart the inner loop from j, but that's inefficient.
                // A better way is to use a queue for children whose confidence drops below zero,
                // or simply iterate through the remaining children and apply the accumulated d_cry.
                // The current approach of accumulating total_d_cry_from_leaving and applying it
                // to all subsequent children in the same pass is correct.
                // If a child j leaves, its d_j is added to total_d_cry_from_leaving.
                // When we process child k > j, it will have total_d_cry_from_leaving (which includes d_j) applied.
                // If child k also leaves, its d_k is added to total_d_cry_from_leaving, affecting k+1, etc.
                // This is correct.
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    std::vector<int> partition(n);

    // Case 1: All elements in one subsequence (e.g., S1).
    // All f values are a_i + a_j.
    // Min f = a_0 + a_1
    // Max f = a_{n-2} + a_{n-1}
    // Goodness = (a_{n-2} + a_{n-1}) - (a_0 + a_1)
    long long goodness1 = (elements[n - 2].value + elements[n - 1].value) - (elements[0].value + elements[1].value);

    // Case 2: At least one element in S1 and at least one in S2.
    // This means there will be values of type a_i + a_j + h.
    // The minimum possible value of f is min(a_i + a_j, a_k + a_l + h).
    // The maximum possible value of f is max(a_i + a_j, a_k + a_l + h).

    // Consider a partition where elements[0] is in S1 and elements[1] is in S2.
    // Or more generally, elements[0] is in S1 and elements[n-1] is in S2.
    // The smallest possible sum a_i + a_j is elements[0].value + elements[1].value.
    // The largest possible sum a_i + a_j is elements[n-2].value + elements[n-1].value.
    // The smallest possible sum a_i + a_j + h is elements[0].value + elements[1].value + h.
    // The largest possible sum a_i + a_j + h is elements[n-2].value + elements[n-1].value + h.

    // Let's analyze the critical values for min/max f.
    // The minimum f value will always be a_0 + a_1 (if S1 or S2 has at least 2 elements)
    // or a_0 + a_k + h (if a_0 is in S1, a_k in S2).
    // The maximum f value will always be a_{n-2} + a_{n-1} (if S1 or S2 has at least 2 elements)
    // or a_{n-1} + a_k + h (if a_{n-1} is in S1, a_k in S2).

    // The key observation is that if we have elements in both subsequences,
    // the minimum value of f will be either elements[0].value + elements[1].value
    // (if elements[0] and elements[1] are in the same subsequence)
    // OR elements[0].value + elements[k].value + h for some k (if elements[0] is in one, elements[k] in other).
    // The maximum value of f will be either elements[n-2].value + elements[n-1].value
    // (if elements[n-2] and elements[n-1] are in the same subsequence)
    // OR elements[n-1].value + elements[k].value + h for some k (if elements[n-1] is in one, elements[k] in other).

    // Consider a partition where elements[0] is in S1, and elements[1], ..., elements[n-1] are in S2.
    // Min f:
    //   - elements[1].value + elements[2].value (from S2)
    //   - elements[0].value + elements[1].value + h (between S1 and S2)
    // Max f:
    //   - elements[n-2].value + elements[n-1].value (from S2)
    //   - elements[0].value + elements[n-1].value + h (between S1 and S2)

    // So, min_f = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    // max_f = std::max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h)
    // This is for n >= 3. If n=2, S2 has only one element, so no a_i+a_j in S2.
    // If n=2, elements[0] in S1, elements[1] in S2. Only f(a_0, a_1) = a_0 + a_1 + h. Min=Max=a_0+a_1+h. Goodness=0.
    // This is covered by the general logic if we consider the case where one subsequence has < 2 elements.

    // If n=2:
    // Case 1: Both in S1. f(a_0, a_1) = a_0 + a_1. Goodness = 0.
    // Case 2: a_0 in S1, a_1 in S2. f(a_0, a_1) = a_0 + a_1 + h. Goodness = 0.
    // So for n=2, minimal goodness is 0.
    if (n == 2) {
        std::cout << 0 << std::endl;
        std::cout << "1 1" << std::endl; // Or "1 2", doesn't matter.
        return 0;
    }

    // Consider the partition where elements[0] is in S1, and all others are in S2.
    // S1 = {elements[0]}, S2 = {elements[1], ..., elements[n-1]}
    long long min_f_case2_1;
    long long max_f_case2_1;

    // Values within S2: elements[1].value + elements[2].value to elements[n-2].value + elements[n-1].value
    // Values between S1 and S2: elements[0].value + elements[1].value + h to elements[0].value + elements[n-1].value + h

    min_f_case2_1 = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
    max_f_case2_1 = std::max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h);

    long long goodness2_1 = max_f_case2_1 - min_f_case2_1;

    // Consider the partition where elements[0], ..., elements[n-2] are in S1, and elements[n-1] is in S2.
    // S1 = {elements[0], ..., elements[n-2]}, S2 = {elements[n-1]}
    long long min_f_case2_2;
    long long max_f_case2_2;

    // Values within S1: elements[0].value + elements[1].value to elements[n-3].value + elements[n-2].value
    // Values between S1 and S2: elements[0].value + elements[n-1].value + h to elements[n-2].value + elements[n-1].value + h

    min_f_case2_2 = std::min(elements[0].value + elements[1].value, elements[0].value + elements[n-1].value + h);
    max_f_case2_2 = std::max(elements[n-3].value + elements[n-2].value, elements[n-2].value + elements[n-1].value + h);

    long long goodness2_2 = max_f_case2_2 - min_f_case2_2;

    // The optimal partition will be one of these three candidates.
    // Candidate 1: All in one group.
    // Candidate 2: One element (smallest) in one group, rest in other.
    // Candidate 3: One element (largest) in one group, rest in other.

    long long min_goodness = goodness1;
    int best_case = 1; // 1 for all in one group

    if (goodness2_1 < min_goodness) {
        min_goodness = goodness2_1;
        best_case = 2; // 2 for smallest element separated
    }
    if (goodness2_2 < min_goodness) {
        min_goodness = goodness2_2;
        best_case = 3; // 3 for largest element separated
    }

    std::cout << min_goodness << std::endl;

    if (best_case == 1) {
        for (int i = 0; i < n; ++i) {
            partition[elements[i].original_index] = 1;
        }
    } else if (best_case == 2) {
        partition[elements[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            partition[elements[i].original_index] = 2;
        }
    } else { // best_case == 3
        for (int i = 0; i < n - 1; ++i) {
            partition[elements[i].original_index] = 1;
        }
        partition[elements[n - 1].original_index] = 2;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
