// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k = 1
    // Try all possible single cuts
    for (int i = 1; i < n; ++i) { // Cut point i means s[0...i-1] and s[i...n-1]
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string new_s = s2 + s1;

        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k = 2
    // If k=1 didn't work, we check k=2.
    // The problem statement implies that if k=1 is not possible,
    // then k=2 is the next minimum.
    // We need to check if it's possible to form *any* new palindrome.
    // If all characters in s are the same (e.g., "aaaa"), then no new palindrome can be formed.
    // If s consists of only one distinct character, e.g., "aaaaa", then any permutation of its substrings
    // will result in "aaaaa". Since we need a new string, it's impossible.
    // We can check this by counting distinct characters in the first half of the string.
    // Since s is a palindrome, s[0...n/2-1] determines the distinct characters.

    bool all_same_char = true;
    if (n > 0) {
        char first_char = s[0];
        for (int i = 1; i < n / 2; ++i) { // Check up to n/2-1
            if (s[i] != first_char) {
                all_same_char = false;
                break;
            }
        }
    }

    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters in the first half are the same,
        // it's always possible to make a new palindrome with 2 cuts.
        // Example: "nolon" -> "no|l|on" -> "on|l|no"
        // Example: "abacaba" -> "ab|ac|aba" -> "aba|ac|ab"
        // The strategy is to cut off the first character, then the rest of the string,
        // then the last character.
        // For example, s = c_1 c_2 ... c_k ... c_2 c_1
        // Cut into c_1 | c_2 ... c_k ... c_2 | c_1
        // Rearrange to c_1 | c_2 ... c_k ... c_2 | c_1
        // This is not what the problem means.
        // The problem means we cut s into k+1 pieces, then rearrange.
        // If s is not all same characters, we can always find a cut that makes a new palindrome.
        // Consider s = "abacaba".
        // Cut at index 1: "a" | "bacaba". New string "bacabaa". Not palindrome.
        // Cut at index 2: "ab" | "acaba". New string "acabaab". Not palindrome.
        // Cut at index 3: "aba" | "caba". New string "cabaaba". Palindrome! And != s.
        // This is a k=1 solution.
        // The problem states "It can be shown that there is no solution with one cut" for "nolon".
        // "nolon" -> "no|l|on" -> "on|l|no". This is 2 cuts.
        // The logic for k=1 is correct. If it didn't find a solution, then 1 cut is not enough.
        // If the string is not composed of all identical characters, then it's always possible to make a new palindrome with 2 cuts.
        // For example, take s = "abacaba".
        // Cut into s[0...0] | s[1...n-2] | s[n-1...n-1]
        // "a" | "bacab" | "a"
        // Rearrange to s[n-1...n-1] | s[1...n-2] | s[0...0]
        // "a" | "bacab" | "a" -> "abacaba" (original)
        // This specific rearrangement doesn't work.
        //
        // Let's re-evaluate the "all_same_char" condition.
        // If s = "qqqq", all_same_char is true. Output "Impossible". Correct.
        // If s = "otto", all_same_char is false. Output 1. Correct.
        // If s = "nolon", all_same_char is false. Output 2. Correct.
        // If s = "kinnikkinnik", all_same_char is false. Output 1. Correct.
        //
        // The logic seems to be:
        // 1. Try k=1. If a solution is found, print 1.
        // 2. If no solution for k=1, check if all characters in the first half of `s` are the same.
        //    (This is equivalent to checking if `s` consists of only one distinct character, e.g., "aaaaa").
        //    If they are, print "Impossible".
        // 3. Otherwise (k=1 failed, but `s` has at least two distinct characters in its first half), print 2.
        //
        // Why is it always 2 if k=1 fails and not all chars are same?
        // Consider s = c_1 c_2 ... c_m ... c_2 c_1 where m = n/2.
        // If not all chars are same, there exists some c_i != c_1 for i < m.
        // We can cut s into s[0...i-1] | s[i...n-1-i] | s[n-i...n-1].
        // For example, s = "nolon". n=5.
        // s[0] = 'n', s[1] = 'o', s[2] = 'l'.
        // s[0] != s[1].
        // Cut "no|l|on". Pieces: "no", "l", "on".
        // Rearrange to "on" + "l" + "no" = "onlno". This is a palindrome and != "nolon".
        // This uses 2 cuts.
        //
        // The condition `all_same_char` should be checked for the entire string, not just the first half.
        // If `s` consists of only one distinct character (e.g., "aaaa", "bbbbb"), then any rearrangement of its substrings will result in the same string `s`.
        // So, if `s` is like "aaaa", it's impossible.
        //
        // Let's refine `all_same_char` check:
        bool all_chars_same_in_s = true;
        if (n > 0) {
            char first_char_s = s[0];
            for (int i = 1; i < n; ++i) {
                if (s[i] != first_char_s) {
                    all_chars_same_in_s = false;
                    break;
                }
            }
        }

        if (all_chars_same_in_s) {
            std::cout << "Impossible" << std::endl;
        } else {
            std::cout << 2 << std::endl;
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    std::vector<long long> head_reach_left(n);
    std::vector<long long> head_reach_right(n);
    for (int i = 0; i < n; ++i) {
        head_reach_left[i] = h[i] - T;
        head_reach_right[i] = h[i] + T;
    }

    std::vector<long long> dp_left(m); // dp_left[j] = minimum head index needed to cover p[0...j]
    std::vector<long long> dp_right(m); // dp_right[j] = minimum head index needed to cover p[j...m-1]

    // Calculate dp_left
    int current_head_idx = 0;
    for (int j = 0; j < m; ++j) {
        while (current_head_idx < n && head_reach_right[current_head_idx] < p[j]) {
            current_head_idx++;
        }
        if (current_head_idx == n) { // No head can reach p[j]
            return false; // Should not happen if T is large enough, but good for safety
        }
        dp_left[j] = current_head_idx;
    }

    // Calculate dp_right
    current_head_idx = n - 1;
    for (int j = m - 1; j >= 0; --j) {
        while (current_head_idx >= 0 && head_reach_left[current_head_idx] > p[j]) {
            current_head_idx--;
        }
        if (current_head_idx < 0) { // No head can reach p[j]
            return false; // Should not happen if T is large enough
        }
        dp_right[j] = current_head_idx;
    }

    // Check if all tracks can be covered
    // Case 1: All tracks covered by a single head
    for (int i = 0; i < n; ++i) {
        if (head_reach_left[i] <= p[0] && head_reach_right[i] >= p[m - 1]) {
            return true;
        }
    }

    // Case 2: Tracks covered by multiple heads
    // We need to find if there exist k heads h_i1, h_i2, ..., h_ik
    // such that h_i1 covers p_0...p_j1, h_i2 covers p_j1+1...p_j2, etc.
    // This is equivalent to finding a partition of p into k segments,
    // where each segment [p_a, p_b] is covered by some head h_i.
    // And the heads used are distinct and in increasing order of index.

    // Let's use a greedy approach for covering.
    // We iterate through the target tracks p.
    // `last_covered_p_idx` is the index of the rightmost track covered so far.
    // `current_head_idx` is the index of the head we are currently considering.
    // We try to cover as many tracks as possible with the current head.

    int p_idx = 0;
    int h_idx = 0;
    while (p_idx < m && h_idx < n) {
        // Find the first head that can reach p[p_idx]
        while (h_idx < n && head_reach_right[h_idx] < p[p_idx]) {
            h_idx++;
        }
        if (h_idx == n) { // No head can reach current p[p_idx]
            return false;
        }

        // This head h_idx can reach p[p_idx].
        // Now, find how far to the right this head can cover.
        long long current_head_max_reach = head_reach_right[h_idx];

        // Find the rightmost p_k that this head can cover.
        int next_p_idx = p_idx;
        while (next_p_idx < m && p[next_p_idx] <= current_head_max_reach) {
            next_p_idx++;
        }
        p_idx = next_p_idx; // Move to the next uncovered track
        h_idx++; // Use the next head for the remaining tracks
    }

    return p_idx == m; // All tracks covered
}


int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible distance: 10^10 (max coord) - 1 (min coord) + 10^10 (max coord) - 1 (min coord)
                               // A safe upper bound is max(p_m-1, h_n-1) - min(p_0, h_0)
                               // Max p_i is 10^10, min p_i is 1. So max diff is 10^10.
                               // A head might need to move from 1 to 10^10, so 10^10 is a good upper bound.
                               // 2e10 is a safe upper bound for T.

    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_val = 0;
    for (int i = 0; i < n; ++i) {
        int current_a = a[i];

        // Case 1: current_a >= prev_val
        // We need to ensure current_a remains >= prev_val.
        // If current_a + x < m and current_a + x < prev_val, then we must increment.
        // This means current_a + x (mod m) must be >= prev_val.
        // If current_a >= prev_val, we can potentially keep current_a as is.
        // If current_a < prev_val, we must increment current_a.

        if (current_a >= prev_val) {
            // We need to ensure a_i' becomes >= prev_val.
            // If current_a + x < m, then a_i' can be current_a or (current_a + 1) % m, ..., (current_a + x) % m.
            // If current_a + x < m, then the maximum value we can achieve without wrap-around is current_a + x.
            // If current_a + x >= m, then we can achieve any value from 0 to m-1.

            // If current_a + x < m:
            //   We can choose to increment current_a to any value up to current_a + x.
            //   To satisfy a_i' >= prev_val, we can just keep current_a as is, since current_a >= prev_val.
            //   So, we don't need to increment current_a.
            // If current_a + x >= m:
            //   We can choose to increment current_a to any value up to current_a + x (mod m), which covers all values [0, m-1].
            //   We can choose to keep current_a as is, since current_a >= prev_val.
            //   So, we don't need to increment current_a.

            // The only situation where we *must* increment current_a is if current_a itself is too small
            // AND current_a + x (mod m) is also too small.
            // This means if current_a < prev_val, we must increment.
            // But we are in the branch current_a >= prev_val.
            // So, if current_a >= prev_val, we can always choose to not increment current_a,
            // and it will satisfy a_i' >= prev_val.
            // The only exception is if current_a + x < m AND current_a + x < prev_val.
            // This means if we increment current_a by some amount, it might become less than prev_val.
            // Example: m=7, prev_val=3, current_a=5, x=1.
            // current_a >= prev_val. We can keep current_a=5. Next prev_val=5.
            // Example: m=7, prev_val=3, current_a=5, x=3.
            // current_a >= prev_val. We can keep current_a=5. Next prev_val=5.
            // Example: m=7, prev_val=3, current_a=5, x=5.
            // current_a >= prev_val. We can keep current_a=5. Next prev_val=5.

            // The condition is: can we make a_i' such that a_i' >= prev_val?
            // If current_a >= prev_val, we can always choose to not increment a_i.
            // Then a_i' = current_a, which is >= prev_val.
            // This is valid as long as 0 operations is within the allowed x operations.
            // So, if current_a >= prev_val, we set prev_val = current_a.
            // This is the greedy choice: make a_i' as small as possible (i.e., current_a)
            // while satisfying a_i' >= prev_val.

            // However, if current_a + x < m AND current_a + x < prev_val,
            // it means even if we increment current_a by x, it's still less than prev_val.
            // This implies that we *must* have wrapped around.
            // If current_a + x < m, then we can only achieve values in [current_a, current_a + x].
            // If current_a + x < prev_val, then we cannot satisfy a_i' >= prev_val.
            // This is a contradiction.
            // So, if current_a >= prev_val, we can always satisfy the condition by setting a_i' = current_a.
            // The only case where we *might* need to increment is if current_a < prev_val.

            // Let's re-evaluate. We want to find a value `val_i` for `a_i` such that `val_i >= prev_val`
            // and `val_i` can be obtained from `a_i` using at most `x` operations.
            // This means `val_i = (a_i + k) % m` for some `0 <= k <= x`.

            // If `a_i >= prev_val`:
            // We can choose `k=0`, so `val_i = a_i`. This satisfies `val_i >= prev_val`.
            // So we set `prev_val = a_i`.
            // This is the greedy choice: keep `a_i` as small as possible.
            // However, if `a_i + x < m` and `a_i + x < prev_val`, this logic is flawed.
            // Example: m=10, prev_val=8, a_i=9, x=1.
            // a_i >= prev_val. If we set prev_val = a_i = 9.
            // Next element a_{i+1} must be >= 9.
            // But what if we could have chosen a_i' = (a_i + k) % m such that a_i' < a_i?
            // This happens if a_i + k >= m.
            // Example: m=10, prev_val=8, a_i=9, x=2.
            // If we choose k=0, a_i' = 9. Next prev_val=9.
            // If we choose k=1, a_i' = (9+1)%10 = 0. This is < prev_val=8. Invalid.
            // If we choose k=2, a_i' = (9+2)%10 = 1. This is < prev_val=8. Invalid.
            // So, if a_i >= prev_val, we must keep a_i as is.
            // The only way we can make a_i' < a_i is if we increment it past m-1.
            // If we increment a_i by k, it becomes (a_i + k) % m.
            // If a_i + k >= m, then (a_i + k) % m will be < a_i.
            // If we choose to increment a_i such that it wraps around, say to `val_wrap = (a_i + k_wrap) % m`.
            // We need `val_wrap >= prev_val`.
            // This is only possible if `val_wrap` is in `[prev_val, m-1]`.
            // The smallest value we can get by wrapping around is `0`.
            // The largest value we can get by wrapping around is `(a_i + x) % m` if `a_i + x >= m`.
            // If `a_i + x < m`, we cannot wrap around.

            // Correct logic:
            // We need to find `k` such that `0 <= k <= x` and `(a_i + k) % m >= prev_val`.
            // We want to pick the smallest such `(a_i + k) % m` to be the new `prev_val`.

            // Option 1: Don't wrap around.
            // If `a_i >= prev_val`, we can choose `k=0`. Then `(a_i + 0) % m = a_i`.
            // This satisfies `a_i >= prev_val`. So we can set `prev_val = a_i`.
            // This is valid if `a_i` is reachable with `k=0` operations.

            // Option 2: Wrap around.
            // If we increment `a_i` by `k` such that `a_i + k >= m`.
            // The new value is `(a_i + k) % m`.
            // We need `(a_i + k) % m >= prev_val`.
            // The smallest `k` that causes a wrap-around is `m - a_i`.
            // If `m - a_i <= x`, then we can achieve `0` by incrementing `a_i` by `m - a_i`.
            // If `prev_val == 0`, then `0` is a valid value.
            // If `prev_val > 0`, then `0` is not a valid value.
            // We need to find `k` such that `a_i + k >= m` and `(a_i + k) % m >= prev_val`.
            // This means `(a_i + k) % m` must be in `[prev_val, m-1]`.
            // The values we can achieve by wrapping are `0, 1, ..., (a_i + x) % m` (if `a_i + x >= m`).
            // If `a_i + x >= m`:
            //   We can achieve any value in `[0, (a_i + x) % m]`.
            //   We can also achieve any value in `[a_i, m-1]` (by not wrapping).
            //   So, we can achieve any value in `[0, (a_i + x) % m]` union `[a_i, m-1]`.
            //   If `a_i >= prev_val`:
            //     We can choose `a_i` (by `k=0`). This is valid.
            //     We can also choose `(a_i + k) % m` if it's `>= prev_val`.
            //     If `(a_i + x) % m >= prev_val`, then we can choose `prev_val` to be `prev_val`.
            //     This is the case where we can make `a_i` smaller than its original value,
            //     but still greater than or equal to the previous element.
            //     Example: m=7, prev_val=0, a_i=6, x=1.
            //     a_i >= prev_val.
            //     If we don't increment, a_i'=6. Next prev_val=6.
            //     If we increment by 1, a_i'=(6+1)%7=0. Next prev_val=0.
            //     We want to choose the smallest possible `a_i'` that is `>= prev_val`.
            //     So if `a_i >= prev_val`:
            //       If `a_i + x >= m` AND `(a_i + x) % m >= prev_val`:
            //         Then we can potentially set `prev_val` to `prev_val` itself.
            //         This means we can make `a_i'` equal to `prev_val`.
            //         This is the best case.
            //       Else (if `a_i + x < m` OR `(a_i + x) % m < prev_val`):
            //         We cannot make `a_i'` equal to `prev_val` by wrapping around.
            //         So we must keep `a_i'` as `a_i`.
            //         Set `prev_val = a_i`.
            //   If `a_i < prev_val`:
            //     We *must* increment `a_i`.
            //     We need `(a_i + k) % m >= prev_val`.
            //     This means `a_i + k` must be at least `prev_val` (if no wrap) or `m + prev_val` (if one wrap), etc.
            //     The smallest `k` to achieve `prev_val` is `prev_val - a_i`.
            //     If `prev_val - a_i <= x`, then we can achieve `prev_val`.
            //     So we set `prev_val = prev_val`.
            //     If `prev_val - a_i > x`, then we cannot achieve `prev_val` without wrapping.
            //     We need to wrap around.
            //     The smallest `k` to wrap around and reach `prev_val` is `m - a_i + prev_val`.
            //     If `m - a_i + prev_val <= x`, then we can achieve `prev_val`.
            //     So we set `prev_val = prev_val`.
            //     If `m - a_i + prev_val > x`, then we cannot achieve `prev_val`.
            //     This means it's impossible. Return false.

            // Simplified logic:
            // We need to find `k` such that `0 <= k <= x` and `(a_i + k) % m >= prev_val`.
            // If such `k` exists, we update `prev_val` to the smallest `(a_i + k) % m` that satisfies the condition.

            // Case 1: `a_i >= prev_val`
            // We can always choose `k=0`, making `a_i' = a_i`. This satisfies `a_i' >= prev_val`.
            // So, `a_i` is a possible value for `a_i'`.
            // Can we achieve `prev_val` itself?
            // This would require `(a_i + k) % m = prev_val`.
            // This means `a_i + k = prev_val` (if no wrap) or `a_i + k = m + prev_val` (if one wrap).
            // If `a_i + x >= m` (meaning we can wrap around):
            //   We can potentially achieve `prev_val` by incrementing `a_i`.
            //   The number of operations needed to reach `prev_val` from `a_i` by wrapping is `m - a_i + prev_val`.
            //   If `m - a_i + prev_val <= x`, then we can make `a_i'` equal to `prev_val`.
            //   In this case, we choose `prev_val` as the new `prev_val`.
            //   Otherwise, we cannot make `a_i'` equal to `prev_val` by wrapping.
            //   So we must choose `a_i'` to be `a_i`.
            //   Set `prev_val = a_i`.
            // If `a_i + x < m` (meaning we cannot wrap around):
            //   We can only achieve values in `[a_i, a_i + x]`.
            //   Since `a_i >= prev_val`, we can choose `a_i'` to be `a_i`.
            //   Set `prev_val = a_i`.

            // Combining these:
            // If `a_i >= prev_val`:
            //   If `a_i + x >= m` AND `(m - a_i + prev_val) <= x`:
            //     We can make `a_i'` equal to `prev_val`.
            //     So, `prev_val` remains `prev_val`.
            //   Else:
            //     We must make `a_i'` equal to `a_i`.
            //     So, `prev_val` becomes `a_i`.

            // Case 2: `a_i < prev_val`
            // We *must* increment `a_i`.
            // We need `(a_i + k) % m >= prev_val`.
            // The smallest `k` to achieve `prev_val` is `prev_val - a_i`.
            // If `prev_val - a_i <= x`:
            //   We can achieve `prev_val` without wrapping.
            //   So, `prev_val` remains `prev_val`.
            // Else (`prev_val - a_i > x`):
            //   We cannot achieve `prev_val` without wrapping.
            //   This means we must wrap around.
            //   The smallest `k` to achieve `prev_val` by wrapping is `m - a_i + prev_val`.
            //   If `m - a_i + prev_val <= x`:
            //     We can achieve `prev_val` by wrapping.
            //     So, `prev_val` remains `prev_val`.
            //   Else (`m - a_i + prev_val > x`):
            //     We cannot achieve `prev_val` even by wrapping.
            //     It's impossible. Return `false`.

            // Let's simplify the conditions.
            // We need to find a `k` such that `0 <= k <= x` and `(a_i + k) % m >= prev_val`.
            // If `a_i >= prev_val`:
            //   We can choose `k=0`, so `a_i' = a_i`. This is valid.
            //   However, we want to make `a_i'` as small as possible, so if we can make `a_i' = prev_val`, that's better.
            //   Can we make `a_i' = prev_val`?
            //   This requires `(a_i + k) % m = prev_val`.
            //   If `a_i <= prev_val` (this is not the current branch, but for completeness):
            //     `k = prev_val - a_i`. If `k <= x`, then yes.
            //   If `a_i > prev_val`:
            //     `k = m - a_i + prev_val`. If `k <= x`, then yes.
            //   So, if `a_i >= prev_val`:
            //     If `m - a_i + prev_val <= x`: // Can reach prev_val by wrapping
            //       `prev_val` remains `prev_val`.
            //     Else: // Cannot reach prev_val by wrapping, must use a_i
            //       `prev_val` becomes `a_i`.
            // Else (`a_i < prev_val`):
            //   We must increment.
            //   If `prev_val - a_i <= x`: // Can reach prev_val without wrapping
            //     `prev_val` remains `prev_val`.
            //   Else: // Cannot reach prev_val without wrapping, must wrap
            //     If `m - a_i + prev_val <= x`: // Can reach prev_val by wrapping
            //       `prev_val` remains `prev_val`.
            //     Else: // Cannot reach prev_val at all
            //       return `false`.

            // This logic seems correct and covers all cases.
            // Let's test with examples.
            // 5 7, 0 6 1 3 2. x=1.
            // i=0, a[0]=0, prev_val=0.
            //   a[0] >= prev_val (0 >= 0).
            //   m - a[0] + prev_val = 7 - 0 + 0 = 7.
            //   7 > x=1. So, prev_val becomes a[0]=0.
            //   Current prev_val = 0.
            // i=1, a[1]=6, prev_val=0.
            //   a[1] >= prev_val (6 >= 0).
            //   m - a[1] + prev_val = 7 - 6 + 0 = 1.
            //   1 <= x=1. So, prev_val remains prev_val=0.
            //   Current prev_val = 0.
            // i=2, a[2]=1, prev_val=0.
            //   a[2] >= prev_val (1 >= 0).
            //   m - a[2] + prev_val = 7 - 1 + 0 = 6.
            //   6 > x=1. So, prev_val becomes a[2]=1.
            //   Current prev_val = 1.
            // i=3, a[3]=3, prev_val=1.
            //   a[3] >= prev_val (3 >= 1).
            //   m - a[3] + prev_val = 7 - 3 + 1 = 5.
            //   5 > x=1. So, prev_val becomes a[3]=3.
            //   Current prev_val = 3.
            // i=4, a[4]=2, prev_val=3.
            //   a[4] < prev_val (2 < 3).
            //   prev_val - a[4] = 3 - 2 = 1.
            //   1 <= x=1. So, prev_val remains prev_val=3.
            //   Current prev_val = 3.
            // All elements processed. Return true.
            // This matches example output.

            // 5 3, 0 0 0 1 2. x=0.
            // i=0, a[0]=0, prev_val=0.
            //   a[0] >= prev_val. m - a[0] + prev_val = 3 - 0 + 0 = 3. 3 > x=0. prev_val = a[0]=0.
            // i=1, a[1]=0, prev_val=0.
            //   a[1] >= prev_val. m - a[1] + prev_val = 3 - 0 + 0 = 3. 3 > x=0. prev_val = a[1]=0.
            // i=2, a[2]=0, prev_val=0.
            //   a[2] >= prev_val. m - a[2] + prev_val = 3 - 0 + 0 = 3. 3 > x=0. prev_val = a[2]=0.
            // i=3, a[3]=1, prev_val=0.
            //   a[3] >= prev_val. m - a[3] + prev_val = 3 - 1 + 0 = 2. 2 > x=0. prev_val = a[3]=1.
            // i=4, a[4]=2, prev_val=1.
            //   a[4] >= prev_val. m - a[4] + prev_val = 3 - 2 + 1 = 2. 2 > x=0. prev_val = a[4]=2.
            // All elements processed. Return true.
            // This matches example output.

            // Test case where it fails:
            // 3 10, 5 1 2. x=0.
            // i=0, a[0]=5, prev_val=0.
            //   a[0] >= prev_val. m - a[0] + prev_val = 10 - 5 + 0 = 5. 5 > x=0. prev_val = a[0]=5.
            // i=1, a[1]=1, prev_val=5.
            //   a[1] < prev_val (1 < 5).
            //   prev_val - a[1] = 5 - 1 = 4. 4 > x=0.
            //   m - a[1] + prev_val = 10 - 1 + 5 = 14. 14 > x=0.
            //   Return false. Correct.

            // Test case where it passes by wrapping:
            // 3 10, 5 1 2. x=5.
            // i=0, a[0]=5, prev_val=0.
            //   a[0] >= prev_val. m - a[0] + prev_val = 10 - 5 + 0 = 5. 5 <= x=5. prev_val remains 0.
            // i=1, a[1]=1, prev_val=0.
            //   a[1] >= prev_val. m - a[1] + prev_val = 10 - 1 + 0 = 9. 9 > x=5. prev_val = a[1]=1.
            // i=2, a[2]=2, prev_val=1.
            //   a[2] >= prev_val. m - a[2] + prev_val = 10 - 2 + 1 = 9. 9 > x=5. prev_val = a[2]=2.
            // Return true. Correct.

            // Test case where a_i < prev_val and needs to wrap to prev_val
            // 3 10, 8 1 2. x=3.
            // i=0, a[0]=8, prev_val=0.
            //   a[0] >= prev_val. m - a[0] + prev_val = 10 - 8 + 0 = 2. 2 <= x=3. prev_val remains 0.
            // i=1, a[1]=1, prev_val=0.
            //   a[1] >= prev_val. m - a[1] + prev_val = 10 - 1 + 0 = 9. 9 > x=3. prev_val = a[1]=1.
            // i=2, a[2]=2, prev_val=1.
            //   a[2] >= prev_val. m - a[2] + prev_val = 10 - 2 + 1 = 9. 9 > x=3. prev_val = a[2]=2.
            // Return true. Correct.

            // Test case where a_i < prev_val and needs to wrap to prev_val, but x is too small
            // 3 10, 8 1 2. x=1.
            // i=0, a[0]=8, prev_val=0.
            //   a[0] >= prev_val. m - a[0] + prev_val = 10 - 8 + 0 = 2. 2 > x=1. prev_val = a[0]=8.
            // i=1, a[1]=1, prev_val=8.
            //   a[1] < prev_val (1 < 8).
            //   prev_val - a[1] = 8 - 1 = 7. 7 > x=1.
            //   m - a[1] + prev_val = 10 - 1 + 8 = 17. 17 > x=1.
            //   Return false. Correct.

            if (current_a >= prev_val) {
                // Option 1: Keep current_a as is. This is valid since current_a >= prev_val.
                // Option 2: Increment current_a to wrap around and become prev_val.
                // This requires `k = m - current_a + prev_val` operations.
                // If `k <= x`, then we can achieve `prev_val`.
                // We prefer `prev_val` because it's smaller, making it easier for subsequent elements.
                if (m - current_a + prev_val <= x) {
                    // prev_val remains prev_val
                } else {
                    // Cannot achieve prev_val by wrapping, so we must keep current_a.
                    prev_val = current_a;
                }
            } else { // current_a < prev_val
                // We must increment current_a.
                // Option 1: Increment current_a to prev_val without wrapping.
                // This requires `k = prev_val - current_a` operations.
                // If `k <= x`, then we can achieve `prev_val`.
                if (prev_val - current_a <= x) {
                    // prev_val remains prev_val
                } else {
                    // Cannot achieve prev_val without wrapping.
                    // Option 2: Increment current_a to prev_val by wrapping.
                    // This requires `k = m - current_a + prev_val` operations.
                    // If `k <= x`, then we can achieve `prev_val`.
                    if (m - current_a + prev_val <= x) {
                        // prev_val remains prev_val
                    } else {
                        // Cannot achieve prev_val at all.
                        return false;
                    }
                }
            }
        }
    return true;
}

