int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // max_r_for_l[i] stores the maximum r such that the substring s[i...r]
    // does NOT contain any 3-AP.
    // If max_r_for_l[i] == i-1, it means s[i...i] already contains a 3-AP,
    // or no such r exists (e.g., if i > n).
    // Initialize with n, meaning s[i...n] is initially considered "bad-free"
    // until we find a 3-AP that forces an earlier end.
    std::vector<int> max_r_for_l(n + 1);
    std::iota(max_r_for_l.begin(), max_r_for_l.end(), 0); // max_r_for_l[i] = i initially
    for(int i = 0; i <= n; ++i) {
        max_r_for_l[i] = n; // Initialize to n, meaning s[i...n] is initially considered valid
    }

    // Iterate through all possible x and k to find 3-APs
    // s_x = s_{x+k} = s_{x+2k}
    // Indices are 0-based in string, 1-based in problem statement.
    // Let's use 0-based for string access: s[x], s[x+k], s[x+2k]
    // The problem statement uses 1-based indices for l, r, x, k.
    // So, if s[x_0] = s[x_0+k_0] = s[x_0+2k_0] for 0-based x_0, k_0,
    // then the 1-based indices are x = x_0+1, x+k = x_0+k_0+1, x+2k = x_0+2k_0+1.
    // The rightmost index of this 3-AP is x_0+2k_0.
    // This 3-AP "taints" any substring s[l...r] where l <= x_0+1 and r >= x_0+2k_0+1.

    // The maximum k can be (n-1)/2.
    // The maximum x can be n-1-2k.
    // The smallest k is 1.
    // The smallest x is 0.

    // For k=1: s[i], s[i+1], s[i+2]
    // For k=2: s[i], s[i+2], s[i+4]
    // For k=3: s[i], s[i+3], s[i+6]
    // For k=4: s[i], s[i+4], s[i+8]
    // For k=5: s[i], s[i+5], s[i+10]
    // For k=6: s[i], s[i+6], s[i+12]

    // The maximum k we need to check is 6.
    // Why? If k >= 7, then 2k >= 14.
    // If s[i] = s[i+k] = s[i+2k], then s[i] = s[i+k] and s[i+k] = s[i+2k].
    // If k >= 7, then i+k and i+2k are far apart.
    // Consider the condition s[x] = s[x+k] = s[x+2k].
    // This means that for any l, r such that l <= x+1 and r >= x+2k+1,
    // the pair (l, r) is "good".
    // We are counting "bad" pairs. A pair (l, r) is bad if no such x, k exists
    // within s[l...r].
    // This means for all x_0, k_0 such that l-1 <= x_0 and x_0+2k_0 <= r-1,
    // it's NOT true that s[x_0] = s[x_0+k_0] = s[x_0+2k_0].

    // Let's find the smallest r_prime such that s[l...r_prime] contains a 3-AP.
    // For each starting position l (1-based), we want to find the minimum r_prime (1-based)
    // such that there exists x, k with l <= x and x+2k <= r_prime and s_x=s_{x+k}=s_{x+2k}.
    // Let min_r_prime[l] be this value. If no such r_prime exists, min_r_prime[l] = n+1.
    // Then for a fixed l, any r such that l <= r < min_r_prime[l] is a "bad" pair.
    // The number of such r's is min_r_prime[l] - l.
    // The total number of bad pairs is sum_{l=1 to n} (min_r_prime[l] - l).

    // Initialize min_r_prime[l] = n+1 for all l.
    std::vector<int> min_r_prime(n + 2, n + 1);

    // Iterate through all possible 0-based x_0 and k_0.
    // The maximum value for k_0 is (n-1)/2.
    // However, the problem constraints on k are $1 \leq k \leq n$.
    // The condition $x < x+2k \leq r$ implies $x+2k \leq n$.
    // So $2k \leq n-x$. Since $x \geq 1$, $2k \leq n-1$. So $k \leq (n-1)/2$.
    // For $N=300000$, $k$ can be up to $150000$. This is too large for $O(N \cdot K)$ or $O(N \cdot \sqrt{N})$.

    // The key observation for this problem is that if $k$ is large, say $k \ge 7$,
    // then $s_x = s_{x+k} = s_{x+2k}$ implies $s_x = s_{x+k}$ and $s_{x+k} = s_{x+2k}$.
    // If $s_x = s_{x+k} = s_{x+2k}$ holds, then the rightmost index is $x+2k$.
    // This 3-AP makes all $(l, r)$ with $l \le x+1$ and $r \ge x+2k+1$ "good".
    // We are interested in the minimum $r$ for each $l$.
    // So, for each $x_0$ (0-based) and $k_0$ (1-based), if $s[x_0] = s[x_0+k_0] = s[x_0+2k_0]$,
    // then for any $l$ from $1$ to $x_0+1$, we can potentially update $min\_r\_prime[l]$
    // with $x_0+2k_0+1$.
    // Specifically, $min\_r\_prime[l] = \min(min\_r\_prime[l], x_0+2k_0+1)$.

    // The crucial insight is that we only need to check small values of k.
    // If $s_x = s_{x+k} = s_{x+2k}$ for some $k \ge 7$, then $x+2k \ge x+14$.
    // This means the "span" of the 3-AP is at least 14.
    // If there is such a 3-AP, it means $s_x = s_{x+k}$ and $s_{x+k} = s_{x+2k}$.
    // If $k$ is large, it's very unlikely to have $s_x = s_{x+k} = s_{x+2k}$.
    // More importantly, if such a 3-AP exists, it's likely that a "shorter" 3-AP
    // (with smaller $k$) also exists within the same range or a slightly larger range.
    // The maximum $k$ we need to check is small, typically around 6 or 7.
    // Let's verify this.
    // If $s_x = s_{x+k} = s_{x+2k}$ for $k \ge 7$.
    // The indices are $x, x+k, x+2k$.
    // The length of the segment is $2k+1$.
    // If $k=7$, length is 15.
    // If $k=8$, length is 17.
    // If $k=9$, length is 19.
    // If $k=10$, length is 21.
    // If $k=11$, length is 23.
    // If $k=12$, length is 25.
    // If $k=13$, length is 27.
    // If $k=14$, length is 29.
    // If $k=15$, length is 31.
    // If $k=16$, length is 33.

    // The maximum $k$ to check is 6.
    // For any $x, k$ such that $s_x = s_{x+k} = s_{x+2k}$, the interval $[x, x+2k]$ is "bad".
    // We want to find the smallest $r$ for each $l$ such that $[l, r]$ contains such an interval.
    // Let $R_0 = n+1$.
    // For $l = n$ down to $1$:
    //   $R_l = R_{l+1}$.
    //   For $k=1 \dots 6$:
    //     If $l-1+2k < n$ and $s[l-1] = s[l-1+k] = s[l-1+2k]$:
    //       $R_l = \min(R_l, l-1+2k+1)$.
    //   The number of bad pairs starting at $l$ is $R_l - l$.
    // This is the standard approach for this type of problem.

    // Iterate l from n down to 1 (1-based)
    // min_r_prime[l] stores the minimum r (1-based) such that s[l...r] contains a 3-AP.
    // Initialize min_r_prime[n+1] = n+1.
    // For l = n down to 1:
    //   min_r_prime[l] = min_r_prime[l+1] (inherit from right)
    //   For k = 1 to 6 (or up to (n-1)/2, but 6 is sufficient):
    //     Let x_0 = l-1 (0-based start of 3-AP)
    //     If x_0 + 2*k < n (i.e., x_0+2k is a valid 0-based index)
    //       If s[x_0] == s[x_0+k] && s[x_0+k] == s[x_0+2*k]:
    //         min_r_prime[l] = std::min(min_r_prime[l], x_0 + 2*k + 1);

    // The maximum k to check is 6.
    // This is a known property for problems involving arithmetic progressions in binary strings.
    // If a 3-AP exists with $k \ge 7$, then there must exist a 3-AP with $k' \le 6$
    // that "covers" the same or a smaller range.
    // This is related to results in Ramsey theory or specific properties of binary strings.
    // For example, if $s_x = s_{x+k} = s_{x+2k}$ for $k \ge 7$,
    // then consider the string $s[x \dots x+2k]$.
    // It's guaranteed that if $k \ge 7$, there must be a shorter 3-AP.
    // This is a non-trivial result. For competitive programming, it's often stated that
    // for binary strings, $k$ up to 6 or 7 is sufficient.
    // Let's use 6 as the limit for $k$.

    for (int l = n; l >= 1; --l) {
        min_r_prime[l] = min_r_prime[l+1]; // Inherit from the right
        for (int k = 1; k <= 6; ++k) { // Check k from 1 to 6
            int x0 = l - 1; // 0-based index for x
            if (x0 + 2 * k < n) { // Check if x0+2k is a valid 0-based index
                if (s[x0] == s[x0 + k] && s[x0 + k] == s[x0 + 2 * k]) {
                    min_r_prime[l] = std::min(min_r_prime[l], x0 + 2 * k + 1);
                }
            }
        }
        // If min_r_prime[l] is still n+1, it means no 3-AP starts at or after l
        // and ends within the string.
        // The number of bad pairs starting at l is (min_r_prime[l] - 1) - l + 1 = min_r_prime[l] - l.
        // For example, if min_r_prime[l] = n+1, then all r from l to n are bad.
        // Number of bad pairs: n - l + 1.
        // (n+1) - l = n - l + 1. This formula works.
        bad_pairs += (min_r_prime[l] - l);
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

