#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The reverse of a permutation has the same fingerprint.
    // If the original permutation is not a palindrome, its reverse is a different permutation.
    // For n >= 2, a permutation cannot be a palindrome unless n=1 (which is not allowed)
    // or it contains duplicate elements (which is not allowed).
    // Example: [1,2,1] is a palindrome but not a permutation of distinct elements.
    // Example: [1,2,3,2,1] is a palindrome but not a permutation of distinct elements.
    // The only way a permutation could be its own reverse is if p_i = p_{n-i+1} for all i.
    // But all elements must be distinct.
    // If n is odd, say n=3, p=[1,2,3]. Reverse is [3,2,1]. Different.
    // If n is even, say n=4, p=[1,2,3,4]. Reverse is [4,3,2,1]. Different.
    // So, reversing the permutation always yields a different permutation for n >= 2.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

