#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        long long d; // d can be up to 100, a_i up to 100. n up to 100.
                     // Max cost for one haybale is 99 days.
                     // Total haybales can be 100 * 100 = 10000.
                     // Total days needed could be 10000 * 99, which fits long long.
                     // However, d is only up to 100. So int is fine for d.
                     // But the sum of a_i can be 100*100 = 10000.
                     // The final a_1 can be 100 + 10000 = 10100.
                     // So a_1 should be int.
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        int initial_a1 = a[0];
        int added_to_a1 = 0;

        for (int i = 1; i < n; ++i) { // Iterate from pile 2 (index 1) to pile n
            int pile_index = i; // 0-indexed
            int haybales_in_pile = a[pile_index];
            int days_per_haybale = pile_index; // Cost to move one haybale to pile 1

            if (days_per_haybale == 0) { // This should only happen for pile 1 itself, which is skipped
                continue;
            }

            if (d >= days_per_haybale) {
                // Calculate how many haybales can be moved from this pile
                // based on available days.
                int haybales_movable_by_days = d / days_per_haybale;

                // We can move at most 'haybales_in_pile' haybales from this pile.
                // So, take the minimum of what's available and what can be afforded.
                int haybales_to_move = std::min(haybales_in_pile, haybales_movable_by_days);

                added_to_a1 += haybales_to_move;
                d -= (long long)haybales_to_move * days_per_haybale;
            } else {
                // Not enough days to move even one haybale from this pile.
                // Since we iterate from closest piles, we won't be able to move
                // haybales from any further piles either.
                break; 
            }
        }
        std::cout << initial_a1 + added_to_a1 << "\n";
    }
    return 0;
}

