#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << "\n";
        return;
    }

    // For n >= 2, we can construct a number that satisfies the conditions.
    // The strategy is to use '2' as the first digit and '3' for all subsequent digits.
    // This number will be 233...3 (n-1 times '3').
    // Let's check the conditions for s = 233...3:
    // 1. s > 0: True.
    // 2. s consists of n digits: True, by construction.
    // 3. No digit in s equals 0: True, all digits are 2 or 3.
    // 4. s is not divisible by any of its digits:
    //    The digits are 2 and 3.
    //    Divisibility by 2: The last digit is 3 (odd), so s is not divisible by 2.
    //    Divisibility by 3: The sum of digits is 2 + (n-1)*3.
    //    If n=2, s=23. Sum of digits = 2+3=5. Not divisible by 3.
    //    If n=3, s=233. Sum of digits = 2+3+3=8. Not divisible by 3.
    //    If n=4, s=2333. Sum of digits = 2+3+3+3=11. Not divisible by 3.
    //    In general, 2 + (n-1)*3 = 2 + 3n - 3 = 3n - 1.
    //    Since 3n is divisible by 3, 3n - 1 is never divisible by 3.
    //    Therefore, s is not divisible by 3.
    // Since s is not divisible by 2 and not divisible by 3, it is not divisible by any of its digits.

    std::cout << '2';
    for (int i = 0; i < n - 1; ++i) {
        std::cout << '3';
    }
    std::cout << "\n";
}

