#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    // Check a[0]
    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    // Iterate from right to left (n-1 down to 1)
    for (int i = n - 1; i >= 1; --i) {
        if (a[i] == b[i]) {
            // Already equal, no operation needed for this position
            // The presence of 1 or -1 before this index is still relevant for future checks
            // but not for this specific a[i] == b[i] condition.
            // We update has_pos_one and has_neg_one based on a[i] for subsequent iterations.
            if (a[i] == 1) has_pos_one = true;
            if (a[i] == -1) has_neg_one = true;
            continue;
        }

        if (b[i] > a[i]) {
            // Need to increase a[i]. This requires a '1' at some index j < i.
            if (!has_pos_one) {
                std::cout << "NO\n";
                return;
            }
        } else { // b[i] < a[i]
            // Need to decrease a[i]. This requires a '-1' at some index j < i.
            if (!has_neg_one) {
                std::cout << "NO\n";
                return;
            }
        }

        // Update has_pos_one and has_neg_one based on a[i] for subsequent iterations.
        // This is crucial because a[i] itself might be a 1 or -1 that could be used
        // for elements further to the left (smaller indices).
        if (a[i] == 1) has_pos_one = true;
        if (a[i] == -1) has_neg_one = true;
    }

    std::cout << "YES\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

