int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If n is 2, and the permutation is {1, 2} or {2, 1},
        // the max_val_in_row will be 1.
        // If p[i] is 1, then max_val_in_row will be 1.
        // If p[i] is 2, then max_val_in_row will be 1.
        // In general, if p[i] is the largest element (n), then max_val_in_row will be n-1.
        // If p[i] is not the largest element, then max_val_in_row will be p[i] (when compared with n).
        // So, p[i] is either max_val_in_row or n.
        // Since all values in the permutation are distinct and from 1 to n,
        // if max_val_in_row is n-1, then p[i] must be n.
        // Otherwise, p[i] must be max_val_in_row.
        if (max_val_in_row == n - 1 && n > 1) { // n > 1 check is for safety, problem states n >= 2
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        if (n <= 1) {
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        int min_suffix_price = a[n - 1]; // Initialize with the last price

        // Iterate from the second to last element backwards
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_suffix_price) {
                bad_prices_count++;
            } else {
                // If a[i] is not greater than min_suffix_price,
                // it means a[i] is less than or equal to the minimum price
                // found so far in the suffix a[i+1...n-1].
                // So, a[i] becomes the new minimum for the suffix a[i...n-1].
                min_suffix_price = a[i];
            }
        }
        std::cout << bad_prices_count << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_r_pos = -1, it means the frog is at cell 0.
                             // If last_r_pos = i, it means the frog is at cell i.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1 (1-indexed).
                // The previous 'R' or start was at last_r_pos (0-indexed).
                // The distance between the current 'R' cell and the previous 'R' cell (or start)
                // is (i+1) - (last_r_pos + 1) = i - last_r_pos.
                // If last_r_pos was -1 (start at 0), then the distance is (i+1) - 0 = i+1.
                // This can be simplified to (i+1) - (last_r_pos + 1) if we consider last_r_pos as -1 for cell 0.
                // Or, more simply, the distance from the previous safe point (last_r_pos + 1) to the current safe point (i + 1).
                // The gap is (current_cell_index) - (previous_cell_index).
                // Current cell index is i+1. Previous cell index is last_r_pos+1.
                // So, the gap is (i+1) - (last_r_pos+1) = i - last_r_pos.
                max_gap = std::max(max_gap, i - last_r_pos);
                last_r_pos = i;
            }
        }

        // After iterating through the string, we need to consider the gap from the last 'R'
        // to the target cell n+1.
        // The last 'R' was at index last_r_pos (0-indexed), which corresponds to cell last_r_pos + 1.
        // The target is cell n+1.
        // The gap is (n+1) - (last_r_pos + 1) = n - last_r_pos.
        max_gap = std::max(max_gap, n - last_r_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm> // For std::min

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        // The maximum number of teams is limited by three factors:
        // 1. The total number of coders available (each team needs at least one coder).
        // 2. The total number of mathematicians available (each team needs at least one mathematician).
        // 3. The total number of students available divided by 3 (each team needs 3 students).
        // So, the number of teams cannot exceed min(c, m, (c + m + x) / 3).
        // Let's call this potential maximum 'k_max'.
        // We need to find the largest 'k' such that k <= c, k <= m, and k <= (c + m + x) / 3.
        // This is equivalent to k <= min(c, m, (c + m + x) / 3).
        // The problem statement implies that if we have enough students of each type to form 'k' teams,
        // we can always arrange them.
        // For 'k' teams, we need at least 'k' coders and 'k' mathematicians.
        // The remaining 'c - k' coders, 'm - k' mathematicians, and 'x' non-specialized students
        // must fill the remaining 'k' slots (since each team has 3 members, and we've used 2 for C and M).
        // So, (c - k) + (m - k) + x must be at least 'k'.
        // This simplifies to c + m + x >= 3k, or k <= (c + m + x) / 3.
        // Thus, the maximum number of teams is indeed min(c, m, (c + m + x) / 3).
        long long result = std::min({c, m, (c + m + x) / 3});
        std::cout << result << "\n";
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_stair_cells = 1; // Cells for a staircase with 1 stair
        long long current_total_cells = 1; // Total cells for the first nice staircase (n=1)

        while (x >= current_total_cells) {
            count++;
            x -= current_total_cells;

            // Calculate cells for the next nice staircase
            // If current_stair_cells is for n, next is for 2n+1
            // Cells for n stairs: n*(n+1)/2
            // Cells for (2n+1) stairs: (2n+1)*(2n+2)/2 = (2n+1)*(n+1)
            // The number of cells for the staircase itself is (2*current_stair_cells + 1) * (current_stair_cells + 1)
            // This is not what we need. We need the number of cells for the next nice staircase.
            // The number of stairs for nice staircases are 1, 3, 7, 15, ... which is 2^k - 1.
            // Let n_k = 2^k - 1.
            // Cells for n_k stairs = n_k * (n_k + 1) / 2 = (2^k - 1) * (2^k) / 2 = (2^k - 1) * 2^(k-1).
            // The cost of the k-th nice staircase (with 2^k - 1 stairs) is (2^k - 1) * 2^(k-1).
            //
            // Let's re-evaluate the `current_total_cells` calculation.
            // The sequence of cells for nice staircases is:
            // k=1: n=1, cells = 1 * (1+1)/2 = 1
            // k=2: n=3, cells = 3 * (3+1)/2 = 6
            // k=3: n=7, cells = 7 * (7+1)/2 = 28
            // k=4: n=15, cells = 15 * (15+1)/2 = 120
            //
            // The pattern for `current_stair_cells` (which is `n` for the current nice staircase)
            // is `n_new = 2 * n_old + 1`.
            // So, `current_stair_cells` goes 1 -> 3 -> 7 -> 15 -> ...
            //
            // The cost of the next staircase is `n_new * (n_new + 1) / 2`.
            // `n_new = 2 * current_stair_cells + 1`.
            // `current_total_cells` should be updated to the cost of the *next* nice staircase.

            current_stair_cells = 2 * current_stair_cells + 1; // This is the 'n' for the next nice staircase
            current_total_cells = current_stair_cells * (current_stair_cells + 1) / 2; // This is the cost of that staircase
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int low = 1;
    int high = k + 1; // The largest number we'll use for the alternating part

    // Generate the first k+1 elements to produce k distinct differences
    // These differences will be k, k-1, ..., 1
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) {
            std::cout << low++;
        } else {
            std::cout << high--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // For the remaining n - (k+1) elements, just append them in increasing order
    // This will produce only difference 1, which is already covered by the first part
    // (since k >= 1, difference 1 is always generated by the alternating part)
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the triangle from the apex to the i-th cut (x_i)
        // should be i times the area of a single piece.
        // Total area of carrot = h/2
        // Area of one piece = (h/2) / n = h / (2n)
        // Area of triangle up to x_i = i * (h / (2n)) = i*h / (2n)
        //
        // For a triangle with height x_i, its base b_i is x_i / h (by similarity, b_i/x_i = 1/h).
        // Area of triangle up to x_i = (1/2) * b_i * x_i = (1/2) * (x_i/h) * x_i = x_i^2 / (2h)
        //
        // Equating the two expressions for the area:
        // x_i^2 / (2h) = i*h / (2n)
        // x_i^2 = (i*h / (2n)) * (2h)
        // x_i^2 = i * h^2 / n
        // x_i = sqrt(i * h^2 / n)
        // x_i = h * sqrt(i / n)

        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
