int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int target_open = k / 2;
    int target_close = k / 2;

    for (char c : s) {
        if (c == '(') {
            if (open_count < target_open) {
                result += '(';
                open_count++;
            }
        } else { // c == ')'
            if (close_count < target_close && open_count > close_count) {
                result += ')';
                close_count++;
            }
        }
        if (open_count == target_open && close_count == target_close) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long num_multiples = n / m;

        if (num_multiples == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Calculate the sum of last digits for one full cycle (10 terms)
        long long cycle_sum = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_sum += (m * i) % 10;
        }

        // Calculate how many full cycles are there
        long long full_cycles = num_multiples / 10;
        long long remaining_terms = num_multiples % 10;

        long long total_sum = full_cycles * cycle_sum;

        // Add the sum of last digits for the remaining terms
        for (long long i = 1; i <= remaining_terms; ++i) {
            total_sum += (m * i) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the index of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // For m > 1, we need to expand the segment to include 'm'.
        // The segment must contain all numbers from 1 to m.
        // This means the segment must span from the minimum index of {1..m-1}
        // to the maximum index of {1..m-1}, and also include 'm'.
        // So, the new min_idx will be min(old_min_idx, pos[m])
        // and the new max_idx will be max(old_max_idx, pos[m]).

        if (m > 1) {
            current_min_idx = std::min(current_min_idx, pos[m]);
            current_max_idx = std::max(current_max_idx, pos[m]);
        }

        // A number m is beautiful if the subsegment p[current_min_idx ... current_max_idx]
        // is a permutation of 1, 2, ..., m.
        // This means two conditions must be met:
        // 1. The length of the subsegment must be m.
        //    (current_max_idx - current_min_idx + 1 == m)
        // 2. The maximum value in the subsegment must be m.
        //    (This is implicitly handled by how current_max_idx and current_min_idx are updated.
        //     Since we are always expanding to include 'm', and we started with '1',
        //     the segment p[current_min_idx ... current_max_idx] will contain all numbers
        //     from 1 to m. If its length is also m, then it must be exactly 1..m.)

        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The median of the first class will be a[n-1]
        // The median of the second class will be a[n]
        // This is because the first class takes elements up to index n-1 (inclusive)
        // and the second class takes elements from index n (inclusive).
        // The smallest possible size for each class is 1.
        // If class 1 has size 1, it takes a[0]. Class 2 takes 2n-1 elements.
        // If class 1 has size 2n-1, it takes a[0]...a[2n-2]. Class 2 takes a[2n-1].
        // The optimal strategy is to split the sorted array into two halves.
        // The first class will contain elements from a[0] to a[n-1].
        // The second class will contain elements from a[n] to a[2n-1].
        // The median of the first class (size n) would be a[(n-1)/2] if n is odd.
        // The median of the second class (size n) would be a[n + (n-1)/2] if n is odd.
        // However, the problem states that the total number of students is 2n.
        // The median of an array of 2k+1 elements is the (k+1)-th element.
        // If we split the 2n students into two classes, say Class A and Class B,
        // each with an odd number of students.
        // Let Class A have $S_A$ students and Class B have $S_B$ students.
        // $S_A + S_B = 2n$. Both $S_A$ and $S_B$ are odd.
        // The smallest possible $S_A$ is 1, then $S_B = 2n-1$.
        // The largest possible $S_A$ is $2n-1$, then $S_B = 1$.
        //
        // Consider the sorted array $a_0, a_1, \dots, a_{2n-1}$.
        // The key insight is that to minimize the difference between medians,
        // the medians themselves should be as close as possible in the sorted array.
        // If we pick $a_{n-1}$ as the median of the first class and $a_n$ as the median of the second class,
        // this implies that the first class contains $n$ elements up to $a_{n-1}$ (inclusive)
        // and the second class contains $n$ elements from $a_n$ (inclusive).
        // This is a partition where each class has $n$ students.
        // If $n$ is odd, then $n = 2k+1$. The median is $a_k$.
        // The first class would be $a_0, \dots, a_{n-1}$. Its median would be $a_{(n-1)/2}$.
        // The second class would be $a_n, \dots, a_{2n-1}$. Its median would be $a_{n + (n-1)/2}$.
        // This is a valid partition if $n$ is odd.
        //
        // However, the problem states that each class must have an odd number of students.
        // If $n$ is even, then $n$ students in each class is not allowed.
        //
        // The crucial observation is that the two medians must be adjacent elements in the sorted full array.
        // Let the two medians be $M_1$ and $M_2$.
        // To minimize $|M_1 - M_2|$, we should choose $M_1$ and $M_2$ to be adjacent elements in the sorted array $a$.
        // The elements $a_{n-1}$ and $a_n$ are the two middle elements of the sorted array $a$.
        // If we can form two classes such that $a_{n-1}$ is the median of one class and $a_n$ is the median of the other,
        // then the difference will be $|a_n - a_{n-1}|$.
        //
        // Can we always do this?
        // Let Class 1 take $a_0, \dots, a_{n-1}$. This class has $n$ students.
        // Let Class 2 take $a_n, \dots, a_{2n-1}$. This class has $n$ students.
        // If $n$ is odd, then this is a valid partition. The median of Class 1 is $a_{(n-1)/2}$.
        // The median of Class 2 is $a_{n + (n-1)/2}$.
        // This is not necessarily $a_{n-1}$ and $a_n$.
        //
        // The problem is simpler:
        // We have $2n$ students. We sort their skill levels: $a_0, a_1, \dots, a_{2n-1}$.
        // We need to pick $S_1$ students for Class 1 and $S_2$ students for Class 2,
        // where $S_1, S_2$ are odd and $S_1+S_2=2n$.
        // Let $M_1$ be the median of Class 1 and $M_2$ be the median of Class 2.
        // We want to minimize $|M_1 - M_2|$.
        //
        // Consider the elements $a_{n-1}$ and $a_n$.
        // Can we always make $a_{n-1}$ the median of one class and $a_n$ the median of the other?
        // Yes.
        // Let Class 1 consist of $a_0, a_1, \dots, a_{n-1}$. This class has $n$ students.
        // Let Class 2 consist of $a_n, a_{n+1}, \dots, a_{2n-1}$. This class has $n$ students.
        //
        // If $n$ is odd:
        // Class 1 has $n$ students. Its median is $a_{(n-1)/2}$.
        // Class 2 has $n$ students. Its median is $a_{n + (n-1)/2}$.
        // This is a valid partition. The difference is $|a_{n + (n-1)/2} - a_{(n-1)/2}|$.
        //
        // If $n$ is even:
        // This partition is not allowed because $n$ is even.
        //
        // The problem is asking for the minimum possible absolute difference.
        // The crucial observation is that the two medians must be $a_{n-1}$ and $a_n$.
        // Why?
        // Suppose we have two classes, $C_1$ and $C_2$, with medians $M_1$ and $M_2$.
        // Let $M_1$ be the $k_1$-th element in $C_1$ (sorted) and $M_2$ be the $k_2$-th element in $C_2$ (sorted).
        // $C_1$ has $2k_1-1$ elements, $C_2$ has $2k_2-1$ elements.
        // Total elements $2k_1-1 + 2k_2-1 = 2(k_1+k_2-1) = 2n$.
        // So $k_1+k_2-1 = n$.
        // This means $k_1+k_2 = n+1$.
        //
        // In the combined sorted array $a_0, \dots, a_{2n-1}$:
        // $M_1$ must be at least $a_{k_1-1}$ (because there are $k_1-1$ elements smaller than or equal to $M_1$ in $C_1$).
        // $M_2$ must be at least $a_{k_2-1}$ (because there are $k_2-1$ elements smaller than or equal to $M_2$ in $C_2$).
        //
        // Also, $M_1$ must be at most $a_{2n-k_1}$ (because there are $k_1-1$ elements larger than or equal to $M_1$ in $C_1$).
        // $M_2$ must be at most $a_{2n-k_2}$ (because there are $k_2-1$ elements larger than or equal to $M_2$ in $C_2$).
        //
        // The total number of elements less than or equal to $M_1$ in $C_1$ is $k_1$.
        // The total number of elements less than or equal to $M_2$ in $C_2$ is $k_2$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$.
        // The minimum difference is always achieved by taking $a_{n-1}$ and $a_n$.
        // This is because we can always construct two classes such that $a_{n-1}$ is the median of one and $a_n$ is the median of the other.
        //
        // Let $S_1 = 1$ and $S_2 = 2n-1$.
        // Class 1: $\{a_0\}$. Median is $a_0$.
        // Class 2: $\{a_1, \dots, a_{2n-1}\}$. Median is $a_{1 + (2n-1-1)/2} = a_{1+n-1} = a_n$.
        // Difference: $|a_n - a_0|$. This is generally not minimal.
        //
        // Let $S_1 = 2n-1$ and $S_2 = 1$.
        // Class 1: $\{a_0, \dots, a_{2n-2}\}$. Median is $a_{(2n-1-1)/2} = a_{n-1}$.
        // Class 2: $\{a_{2n-1}\}$. Median is $a_{2n-1}$.
        // Difference: $|a_{2n-1} - a_{n-1}|$. This is also generally not minimal.
        //
        // The problem is asking for the minimum possible absolute difference.
        // The two medians must be $a_{n-1}$ and $a_n$.
        // This is a standard result for this type of problem.
