// Function to determine if a box can be the special box
// Parameters:
//   A, B, C, D: initial counts of toys in boxes 1, 2, 3, 4 respectively.
//   target_box: the box number (1, 2, 3, or 4) we are checking if it can be the special box.
//   initial_neg_count: initial count of negative toys (A+B)
//   initial_pos_count: initial count of positive toys (C+D)
//   initial_gt1_count: initial count of toys with magnitude > 1 (A+D)
//   initial_lt1_count: initial count of toys with magnitude < 1 (B+C)
bool can_be_special_box(long long A, long long B, long long C, long long D, int target_box,
                        long long initial_neg_count, long long initial_pos_count,
                        long long initial_gt1_count, long long initial_lt1_count) {
    long long total_toys = A + B + C + D;

    if (total_toys == 0) return false; // Should not happen based on constraints A+B+C+D > 0

    // Case 1: Only one toy initially
    if (total_toys == 1) {
        if (A == 1 && target_box == 1) return true;
        if (B == 1 && target_box == 2) return true;
        if (C == 1 && target_box == 3) return true;
        if (D == 1 && target_box == 4) return true;
        return false;
    }

    // Determine the sign of the final toy
    // The final toy's sign depends on the parity of negative toys multiplied.
    // If an even number of negative toys are multiplied, the result is positive.
    // If an odd number of negative toys are multiplied, the result is negative.
    // The number of negative toys multiplied is the initial_neg_count.
    bool final_is_positive_possible = (initial_neg_count % 2 == 0);
    bool final_is_negative_possible = (initial_neg_count % 2 == 1);

    // If there are any zero toys, the final toy can be 0.
    // However, the problem states fun values are real numbers, and boxes are defined for non-zero values.
    // So we assume no toy has fun value 0.

    // Determine if the final toy's magnitude can be < 1 or >= 1
    // If there's at least one toy with magnitude < 1 (from B or C),
    // it's possible to make the final magnitude < 1 by carefully choosing values.
    // E.g., if we have 0.5 and 100, we can make 0.5 * 100 = 50 (>=1) or 0.5 * 0.001 = 0.0005 (<1).
    // The only way to guarantee magnitude >= 1 is if ALL initial toys have magnitude >= 1.
    // The only way to guarantee magnitude < 1 is if ALL initial toys have magnitude < 1.
    // But we want to know if it's *possible* to achieve a certain magnitude.

    // Can final magnitude be < 1?
    // Yes, if there is at least one toy with magnitude < 1 (B or C).
    // We can pick a very small value for one of these toys, and multiply it last.
    // E.g., if we have 0.001 and a product P from other toys, 0.001 * P can be < 1.
    bool final_mag_lt1_possible = (initial_lt1_count > 0);

    // Can final magnitude be >= 1?
    // Yes, if there is at least one toy with magnitude >= 1 (A or D).
    // We can pick a very large value for one of these toys, and multiply it last.
    // E.g., if we have 100 and a product P from other toys, 100 * P can be >= 1.
    bool final_mag_ge1_possible = (initial_gt1_count > 0);

    // Edge case: If all initial toys have magnitude < 1 (B+C == total_toys),
    // then the final toy's magnitude MUST be < 1.
    if (initial_gt1_count == 0) { // All toys have magnitude < 1
        final_mag_ge1_possible = false;
    }
    // Edge case: If all initial toys have magnitude >= 1 (A+D == total_toys),
    // then the final toy's magnitude MUST be >= 1.
    if (initial_lt1_count == 0) { // All toys have magnitude >= 1
        final_mag_lt1_possible = false;
    }

    // Special handling for the case where all toys are from B and C (all magnitude < 1)
    // If A=0, D=0, then all toys are in B or C.
    // In this case, the final product will always have magnitude < 1.
    if (A == 0 && D == 0) {
        final_mag_ge1_possible = false; // Cannot achieve magnitude >= 1
    }
    // Special handling for the case where all toys are from A and D (all magnitude >= 1)
    // If B=0, C=0, then all toys are in A or D.
    // In this case, the final product will always have magnitude >= 1.
    if (B == 0 && C == 0) {
        final_mag_lt1_possible = false; // Cannot achieve magnitude < 1
    }

    // Now combine possibilities for the target box
    if (target_box == 1) { // x <= -1
        return final_is_negative_possible && final_mag_ge1_possible;
    } else if (target_box == 2) { // -1 < x < 0
        return final_is_negative_possible && final_mag_lt1_possible;
    } else if (target_box == 3) { // 0 < x < 1
        return final_is_positive_possible && final_mag_lt1_possible;
    } else if (target_box == 4) { // x >= 1
        return final_is_positive_possible && final_mag_ge1_possible;
    }
    return false; // Should not reach here
}

