#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_min_diff: minimum possible value for a[i] if it's part of an increasing sequence starting from 0
    // a[0] >= 0
    // a[1] >= 1
    // a[i] >= i
    // So, a[i] must be at least i.
    // If a[i] < i for any i, it's impossible to form the increasing part.
    // This is equivalent to checking if a[i] - i >= 0 for all i.
    // We need to find the minimum value of a[i] - i.
    // If min(a[i] - i) < 0, then it's impossible.
    // Let's call this `left_min_val_needed`.
    // `left_min_val_needed[i]` stores the minimum value `a[i]` can take if it's the `i`-th element (0-indexed)
    // of a strictly increasing sequence starting from 0.
    // So, `left_min_val_needed[i] = i`.
    // We need `a[i] >= left_min_val_needed[i]` for all `i` in the increasing part.

    // Calculate suffix_min_diff: minimum possible value for a[i] if it's part of a decreasing sequence ending at 0
    // a[n-1] >= 0
    // a[n-2] >= 1
    // a[i] >= (n-1) - i
    // So, a[i] must be at least (n-1) - i.
    // If a[i] < (n-1) - i for any i, it's impossible to form the decreasing part.
    // This is equivalent to checking if a[i] - ((n-1) - i) >= 0 for all i.
    // Let's call this `right_min_val_needed`.
    // `right_min_val_needed[i]` stores the minimum value `a[i]` can take if it's the `i`-th element (0-indexed)
    // of a strictly decreasing sequence ending at 0.
    // So, `right_min_val_needed[i] = (n-1) - i`.
    // We need `a[i] >= right_min_val_needed[i]` for all `i` in the decreasing part.

    // The condition for a sharpened array is that there exists a peak `k` (1-indexed)
    // such that `b_1 < ... < b_k` and `b_k > ... > b_n`.
    // This means `b_i` must be at least `i-1` for `i <= k` (0-indexed: `b_i >= i` for `i < k`).
    // And `b_i` must be at least `n-i` for `i >= k` (0-indexed: `b_i >= (n-1)-i` for `i >= k`).
    // The peak element `b_k` (0-indexed: `b_{k-1}`) must satisfy both:
    // `b_{k-1} >= (k-1)` and `b_{k-1} >= (n-1)-(k-1)`.
    // Also, `b_{k-1}` must be strictly greater than its neighbors if they exist.
    // `b_{k-1} > b_{k-2}` and `b_{k-1} > b_k`.
    // The minimum value for `b_{k-1}` is `max(k-1, (n-1)-(k-1))`.
    // But this is not quite right. The peak `b_{k-1}` must be `(k-1)` from the left and `(n-1)-(k-1)` from the right.
    // The actual value of `b_{k-1}` must be at least `(k-1)` and at least `(n-1)-(k-1)`.
    // So, `b_{k-1} >= max(k-1, (n-1)-(k-1))`.
    // And we must have `a_{k-1} >= b_{k-1}`.
    // So, we need `a_{k-1} >= max(k-1, (n-1)-(k-1))`.

    // Let's check the conditions for each possible peak `k` (0-indexed: `k_idx`).
    // For a given `k_idx` (from 0 to n-1) to be the peak:
    // 1. For `i` from `0` to `k_idx-1`: `a[i]` must be at least `i`.
    // 2. For `i` from `k_idx+1` to `n-1`: `a[i]` must be at least `(n-1) - i`.
    // 3. For the peak `a[k_idx]`: `a[k_idx]` must be at least `k_idx` AND `a[k_idx]` must be at least `(n-1) - k_idx`.
    //    This simplifies to `a[k_idx] >= k_idx` and `a[k_idx] >= (n-1) - k_idx`.
    //    The second part `a[k_idx] >= (n-1) - k_idx` is only relevant if `k_idx < n-1`.
    //    The first part `a[k_idx] >= k_idx` is only relevant if `k_idx > 0`.
    //    If `k_idx = 0`, the increasing part is empty. We need `a[0] >= (n-1) - 0`.
    //    If `k_idx = n-1`, the decreasing part is empty. We need `a[n-1] >= n-1`.
    //    In general, for any `k_idx`, we need `a[k_idx] >= k_idx` and `a[k_idx] >= (n-1) - k_idx`.
    //    This is because `b_{k_idx}` must be `k_idx` steps up from `b_0=0` and `(n-1)-k_idx` steps up from `b_{n-1}=0`.
    //    So, `a[k_idx] >= k_idx` and `a[k_idx] >= (n-1) - k_idx`.

    // Let's precompute the minimum required values for the left and right parts.
    // `left_req[i]` = minimum value `a[i]` must have if it's part of an increasing sequence starting from 0.
    // `left_req[i] = i`.
    // `right_req[i]` = minimum value `a[i]` must have if it's part of a decreasing sequence ending at 0.
    // `right_req[i] = (n-1) - i`.

    // We need to check if there exists a `k_idx` such that:
    // `a[i] >= i` for all `i` from `0` to `k_idx`.
    // `a[i] >= (n-1) - i` for all `i` from `k_idx` to `n-1`.

    // This can be simplified.
    // We need to find if there is *any* `k_idx` such that `a[k_idx]` can be the peak.
    // For `a[k_idx]` to be the peak, it must be possible to make `b_0, ..., b_{k_idx}` strictly increasing
    // and `b_{k_idx}, ..., b_{n-1}` strictly decreasing.
    // This means `a[i] >= i` for all `i` from `0` to `k_idx`.
    // And `a[i] >= (n-1) - i` for all `i` from `k_idx` to `n-1`.

    // Let's check the conditions for `a[0]` and `a[n-1]` first.
    // If `a[0] == 0`, then `b_0` must be 0.
    // If `a[n-1] == 0`, then `b_{n-1}` must be 0.

    // Consider the conditions for `a[i]` to be the peak.
    // For `a[i]` to be the peak, we need:
    // 1. `a[j] >= j` for all `j <= i`. (This ensures the left part can be formed)
    // 2. `a[j] >= (n-1) - j` for all `j >= i`. (This ensures the right part can be formed)

    // Let's find the leftmost index `L` such that `a[L] < L`. If no such `L` exists, `L = n`.
    // This means for all `i < L`, `a[i] >= i`.
    // Any peak `k_idx` must be less than `L`. If `k_idx >= L`, then `a[L] < L`, so `a[L]` cannot be `L` or more,
    // which is required for the increasing part `b_0 < ... < b_L`.
    // So, possible peaks `k_idx` are in `[0, L-1]`.

    // Let's find the rightmost index `R` such that `a[R] < (n-1) - R`. If no such `R` exists, `R = -1`.
    // This means for all `i > R`, `a[i] >= (n-1) - i`.
    // Any peak `k_idx` must be greater than `R`. If `k_idx <= R`, then `a[R] < (n-1) - R`, so `a[R]` cannot be `(n-1)-R` or more,
    // which is required for the decreasing part `b_R > ... > b_{n-1}`.
    // So, possible peaks `k_idx` are in `[R+1, n-1]`.

    // Combining these, a valid peak `k_idx` must be in the range `[R+1, L-1]`.
    // If this range is non-empty, i.e., `R+1 <= L-1`, then it's possible. Otherwise, it's not.

    int L = n; // First index from left where a[i] < i
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            L = i;
            break;
        }
    }

    int R = -1; // First index from right where a[i] < (n-1)-i
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] < (n - 1) - i) {
            R = i;
            break;
        }
    }

    // If L <= R, it means the "bad" regions overlap or touch, making no valid peak index.
    // Example: n=4, a = [0, 1, 1, 0]
    // i=0: a[0]=0, i=0. a[0] >= 0. OK.
    // i=1: a[1]=1, i=1. a[1] >= 1. OK.
    // i=2: a[2]=1, i=2. a[2] < 2. L=2.
    // So, possible peaks for left part: [0, 1].

    // i=3: a[3]=0, (n-1)-i = 0. a[3] >= 0. OK.
    // i=2: a[2]=1, (n-1)-i = 1. a[2] >= 1. OK.
    // i=1: a[1]=1, (n-1)-i = 2. a[1] < 2. R=1.
    // So, possible peaks for right part: [2, 3].

    // L=2, R=1.
    // Valid peak range: [R+1, L-1] = [1+1, 2-1] = [2, 1]. This is empty. So "No".

    // Example: n=6, a = [100, 11, 15, 9, 7, 8]
    // L calculation:
    // i=0: a[0]=100, i=0. 100 >= 0. OK.
    // i=1: a[1]=11, i=1. 11 >= 1. OK.
    // i=2: a[2]=15, i=2. 15 >= 2. OK.
    // i=3: a[3]=9, i=3. 9 >= 3. OK.
    // i=4: a[4]=7, i=4. 7 >= 4. OK.
    // i=5: a[5]=8, i=5. 8 >= 5. OK.
    // L = 6. Possible peaks for left part: [0, 5].

    // R calculation: (n-1)=5
    // i=5: a[5]=8, (n-1)-i = 0. 8 >= 0. OK.
    // i=4: a[4]=7, (n-1)-i = 1. 7 >= 1. OK.
    // i=3: a[3]=9, (n-1)-i = 2. 9 >= 2. OK.
    // i=2: a[2]=15, (n-1)-i = 3. 15 >= 3. OK.
    // i=1: a[1]=11, (n-1)-i = 4. 11 >= 4. OK.
    // i=0: a[0]=100, (n-1)-i = 5. 100 >= 5. OK.
    // R = -1. Possible peaks for right part: [0, 5].

    // L=6, R=-1.
    // Valid peak range: [R+1, L-1] = [0, 5]. This is non-empty. So "Yes".

    if (R + 1 <= L - 1) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

