    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long opponent_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (n % 2 == 1) { // N is odd
            if (chanek_turn) {
                chanek_coins += 1;
            } else {
                opponent_coins += 1;
            }
            n -= 1;
        } else { // N is even
            // If N is 2, taking 1 or N/2 gives the same result (1 coin).
            // Taking 1 leaves 1 for the opponent.
            // Taking N/2 leaves 1 for the opponent.
            // In this specific case, taking N/2 is fine.
            // For N > 2 and even:
            // Option 1: Take 1. N becomes N-1 (odd).
            // Option 2: Take N/2. N becomes N/2.

            // If N is a power of 2 (and N > 2), e.g., 4, 8, 16...
            // Taking N/2 is always optimal for the current player.
            // Example N=4:
            // Chanek takes 2. N=2. Chanek has 2.
            // Opponent takes 1. N=1. Opponent has 1.
            // Chanek takes 1. N=0. Chanek has 2+1=3.
            // Total: Chanek 3, Opponent 1.
            // If Chanek took 1: N=3. Chanek has 1.
            // Opponent takes 1. N=2. Opponent has 1.
            // Chanek takes 1. N=1. Chanek has 1+1=2.
            // Opponent takes 1. N=0. Opponent has 1+1=2.
            // Total: Chanek 2, Opponent 2.
            // So for N=4, Chanek takes N/2.

            // If N is even but not a power of 2, e.g., 6, 10, 12...
            // Example N=6:
            // Chanek takes N/2=3. N=3. Chanek has 3.
            // Opponent takes 1. N=2. Opponent has 1.
            // Chanek takes 1. N=1. Chanek has 3+1=4.
            // Opponent takes 1. N=0. Opponent has 1+1=2.
            // Total: Chanek 4, Opponent 2.
            // If Chanek took 1: N=5. Chanek has 1.
            // Opponent takes 1. N=4. Opponent has 1.
            // Chanek takes N/2=2. N=2. Chanek has 1+2=3.
            // Opponent takes N/2=1. N=1. Opponent has 1+1=2.
            // Chanek takes 1. N=0. Chanek has 3+1=4.
            // Total: Chanek 4, Opponent 2.
            // In this case, both options lead to the same result for Chanek.

            // The strategy is: if N is even, and N/2 is odd, taking N/2 might be bad
            // because it leaves an odd number for the opponent, who then has to take 1,
            // leaving an even number for us.
            // However, if N/2 is even, taking N/2 is good as it leaves an even number for the opponent.
            // The only case where taking 1 is better than taking N/2 is when N/2 is odd,
            // AND N/2 is not 1 (i.e., N > 2 and N/2 is odd).
            // This means N is even, and N/2 is odd. This implies N is of the form 2 * (odd number).
            // For example, N=6 (N/2=3), N=10 (N/2=5), N=14 (N/2=7), etc.
            // In these cases, if we take N/2, the opponent gets an odd number.
            // If we take 1, the opponent gets an odd number (N-1).

            // Let's re-evaluate the optimal strategy for an even N.
            // If N is even:
            // Option A: Take 1. N becomes N-1 (odd).
            // Option B: Take N/2. N becomes N/2.

            // If N/2 is odd and N/2 > 1 (i.e., N is even, N/2 is odd, N > 2):
            //   If current player takes N/2: they get N/2 coins. Remaining N/2 (odd).
            //   Next player takes 1. Remaining N/2 - 1 (even).
            //   If current player takes 1: they get 1 coin. Remaining N-1 (odd).
            //   Next player takes 1. Remaining N-2 (even).
            //   The goal is to leave an even number for the opponent if possible, or an odd number that is as small as possible.

            // Consider N = 2 * (odd number) where odd number > 1. E.g., N=6.
            // Chanek's turn, N=6.
            //   Option 1: Take 1. Chanek gets 1. N=5.
            //     Opponent's turn, N=5. Opponent takes 1. Opponent gets 1. N=4.
            //     Chanek's turn, N=4. Chanek takes 2. Chanek gets 2. N=2.
            //     Opponent's turn, N=2. Opponent takes 1. Opponent gets 1. N=1.
            //     Chanek's turn, N=1. Chanek takes 1. Chanek gets 1. N=0.
            //     Chanek total: 1+2+1 = 4. Opponent total: 1+1 = 2.
            //   Option 2: Take N/2 = 3. Chanek gets 3. N=3.
            //     Opponent's turn, N=3. Opponent takes 1. Opponent gets 1. N=2.
            //     Chanek's turn, N=2. Chanek takes 1. Chanek gets 1. N=1.
            //     Opponent's turn, N=1. Opponent takes 1. Opponent gets 1. N=0.
            //     Chanek total: 3+1 = 4. Opponent total: 1+1 = 2.
            // Both options yield 4 for Chanek.

            // It seems that taking N/2 is always optimal or equally good when N is even.
            // The only exception is when N is a power of 2, where taking N/2 is strictly better.
            // Let's check if N is a power of 2.
            // A number is a power of 2 if (n & (n - 1)) == 0.
            if ((n & (n - 1)) == 0) { // N is a power of 2
                if (chanek_turn) {
                    chanek_coins += n / 2;
                } else {
                    opponent_coins += n / 2;
                }
                n /= 2;
            } else { // N is even but not a power of 2
                // In this case, N/2 is not a power of 2, or N/2 is odd.
                // If N/2 is odd, taking N/2 leaves an odd number for the opponent.
                // If N/2 is even, taking N/2 leaves an even number for the opponent.
                // Taking 1 leaves an odd number for the opponent.
                // The key insight is that if N is even and not a power of 2, then N can be written as 2^k * M where M is odd and M > 1.
                // If we take N/2, we get N/2 coins, and the remaining is N/2.
                // If we take 1, we get 1 coin, and the remaining is N-1.
                // The opponent will then face N/2 or N-1. Both are odd.
                // The opponent will take 1 coin, leaving N/2-1 or N-2 (both even).
                // So, the current player gets N/2 or 1. The next player gets 1. The player after that gets an even number.
                // It seems taking N/2 is always better or equal.
                // The only time taking 1 is better is if taking N/2 leads to a worse outcome for the current player.
                // This happens if N/2 is odd, and the opponent can then take a large chunk.
                // But if N/2 is odd, the opponent can only take 1.
                // So, if N is even, taking N/2 is always the best move.
                if (chanek_turn) {
                    chanek_coins += n / 2;
                } else {
                    opponent_coins += n / 2;
                }
                n /= 2;
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

