#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << "\n\n";
    } else {
        // We need to find b1, b2 such that
        // (current_sum + b1 + b2) = 2 * (current_xor_sum ^ b1 ^ b2)
        // Let b1 = current_xor_sum.
        // Then current_xor_sum ^ b1 = current_xor_sum ^ current_xor_sum = 0.
        // The equation becomes (current_sum + current_xor_sum + b2) = 2 * (0 ^ b2)
        // (current_sum + current_xor_sum + b2) = 2 * b2
        // current_sum + current_xor_sum = b2
        // So, b2 = current_sum + current_xor_sum.

        // Let's verify this:
        // New sum = current_sum + current_xor_sum + (current_sum + current_xor_sum)
        //         = 2 * (current_sum + current_xor_sum)
        // New xor_sum = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
        //             = 0 ^ (current_sum + current_xor_sum)
        //             = current_sum + current_xor_sum
        // So, New sum = 2 * New xor_sum.
        // This strategy always works and adds 2 elements.

        long long b1 = current_xor_sum;
        long long b2 = current_sum + current_xor_sum;

        std::cout << 2 << "\n";
        std::cout << b1 << " " << b2 << "\n";
    }
}

