#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long a_count = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means all 'a's to its left
            // will eventually interact with this 'b'.
            // Each 'a' to its left will generate 'a_count' steps
            // when interacting with this 'b' (and the 'b's it creates).
            // The 'a_count' represents the number of 'a's that are currently
            // "active" and need to jump over 'b's.
            // When an 'a' jumps over a 'b', it creates a new 'b'.
            // So, the number of steps for this 'b' is equal to the current 'a_count'.
            total_steps = (total_steps + a_count) % mod;
            // After this 'b' has been "processed" by all 'a's to its left,
            // it effectively doubles the number of 'a's that will need to jump
            // over subsequent 'b's to its left.
            // This is because each 'a' that jumped over this 'b' also created a new 'b'.
            // So, the 'a_count' effectively doubles for the next 'b' to the left.
            a_count = (a_count * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' is now active
            // and will need to jump over any 'b's to its right.
            // Increment the count of active 'a's.
