// Function to convert a number to its 18-digit parity pattern string
std::string to_parity_pattern(long long n) {
    std::string pattern_str = "";
    if (n == 0) {
        pattern_str = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern_str += '0';
            } else {
                pattern_str += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the left to make it 18 digits long
    // Since we built it from right to left, we need to reverse and then pad
    std::reverse(pattern_str.begin(), pattern_str.end());
    while (pattern_str.length() < 18) {
        pattern_str = '0' + pattern_str;
    }
    return pattern_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's from the left to make it 18 digits long
            while (s.length() < 18) {
                s = '0' + s;
            }
            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left side
    // `i` represents the number of items taken from the left (0 to n)
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right side

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        // The sum of weights for items w_n, w_{n-1}, ..., w_{n-j+1}
        // is prefix_sum[n] - prefix_sum[n-j]
        current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;

        // Add extra energy based on the difference in counts
        if (i > j) { // More items from left than right
            if (i - 1 > j) { // At least two more items from left
                current_energy += (i - j - 1) * Ql;
            }
        } else if (j > i) { // More items from right than left
            if (j - 1 > i) { // At least two more items from right
                current_energy += (j - i - 1) * Qr;
            }
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w assuming all '1's

    // Step 1: If s[i] is '0', then w[i-x] and w[i+x] must be '0'.
    // Set corresponding positions in w to '0'.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Step 2: Verify if the constructed w can produce the given s.
    // Build a candidate s_prime from w and compare with s.
    std::string s_prime(n, '0');
    for (int i = 0; i < n; ++i) {
        bool is_one = false;
        // Check w[i-x]
        if (i - x >= 0 && w[i - x] == '1') {
            is_one = true;
        }
        // Check w[i+x]
        if (i + x < n && w[i + x] == '1') {
            is_one = true;
        }
        if (is_one) {
            s_prime[i] = '1';
        }
    }

    if (s_prime == s) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

