    for (int i = 0; i < n; ++i) {
        count_x[i + 1] = count_x[i];
        count_y[i + 1] = count_y[i];
        count_z[i + 1] = count_z[i];
        if (s[i] == 'x') {
            count_x[i + 1]++;
        } else if (s[i] == 'y') {
            count_y[i + 1]++;
        } else { // s[i] == 'z'
            count_z[i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        int num_x = count_x[r] - count_x[l - 1];
        int num_y = count_y[r] - count_y[l - 1];
        int num_z = count_z[r] - count_z[l - 1];

        int min_val = std::min({num_x, num_y, num_z});
        int max_val = std::max({num_x, num_y, num_z});

        if (max_val - min_val <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>
#include <numeric>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;

    // Find prime factors of q
    std::vector<long long> prime_factors_q;
    long long temp_q = q;
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            prime_factors_q.push_back(i);
            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }
    if (temp_q > 1) {
        prime_factors_q.push_back(temp_q);
    }

    for (long long factor_q : prime_factors_q) {
        long long current_p = p;
        while (current_p % factor_q == 0) {
            current_p /= factor_q;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

