void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (int k = 0; k <= 9; ++k) {
        std::string current_result(n, ' ');
        char last_c1 = '0';
        char last_c2 = '0';
        bool possible_for_k = true;

        for (int i = 0; i < n; ++i) {
            char digit = s[i];
            if (digit < (k + '0')) {
                // Must be color 1
                if (digit < last_c1) {
                    possible_for_k = false;
                    break;
                }
                current_result[i] = '1';
                last_c1 = digit;
            } else if (digit > (k + '0')) {
                // Must be color 2
                if (digit < last_c2) {
                    possible_for_k = false;
                    break;
                }
                current_result[i] = '2';
                last_c2 = digit;
            } else { // digit == (k + '0')
                // Can be color 1 or 2
                // Prioritize color 2 if it maintains sorted order for color 2
                if (digit >= last_c2) {
                    current_result[i] = '2';
                    last_c2 = digit;
                } else if (digit >= last_c1) {
                    current_result[i] = '1';
                    last_c1 = digit;
                } else {
                    possible_for_k = false;
                    break;
                }
            }
        }

        if (possible_for_k) {
            // Final check: last_c1 <= first_c2
            // This is implicitly handled by the logic:
            // If a digit is < k, it's color 1.
            // If a digit is > k, it's color 2.
            // If a digit is == k, it's color 1 if it can't be color 2, otherwise color 2.
            // This ensures that all color 1 digits are <= k, and all color 2 digits are >= k.
            // The only edge case is if last_c1 (from a digit == k) is > first_c2 (from a digit == k).
            // But our greedy choice for digits == k (prefer 2) ensures that if a k is colored 1,
            // it's because it couldn't be colored 2 (i.e., it was smaller than last_c2).
            // And if a k is colored 2, it's because it was >= last_c2.
            // The overall structure is: all digits < k are 1, then some k's are 1, then some k's are 2, then all digits > k are 2.
            // This structure guarantees the final sequence is sorted.

            result = current_result;
            found_solution = true;
            break; 
        }
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

