int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int char_code = 0; char_code < 26; ++char_code) {
        const std::vector<int>& K0_indices = char_indices[char_code];
        if (K0_indices.empty()) {
            continue;
        }

        double max_win_prob_for_c0 = 0.0;

        // If only one k matches t[0], Vasya wins immediately for this c0.
        if (K0_indices.size() == 1) {
            max_win_prob_for_c0 = 1.0;
        } else {
            // Iterate over all possible second positions p (from 1 to L-1)
            for (int p = 1; p < L; ++p) {
                std::map<char, std::vector<int>> k_by_c_p;
                for (int k_val : K0_indices) {
                    char c_p = s[(k_val + p) % L];
                    k_by_c_p[c_p].push_back(k_val);
                }

                double current_win_prob_for_p = 0.0;
                for (const auto& pair : k_by_c_p) {
                    if (pair.second.size() == 1) {
                        current_win_prob_for_p += 1.0;
                    }
                }
                max_win_prob_for_c0 = std::max(max_win_prob_for_c0, current_win_prob_for_p / K0_indices.size());
            }
        }
        total_win_prob += max_win_prob_for_c0 * K0_indices.size();
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // If b = 1, mod(x, 1) is always 0, so no nice integers.
    // The sum of r from 1 to b-1 would be 0.
    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This is sum_r = (b_minus_1 * b) / 2
    // We need to compute this modulo MOD.
    // Since b_minus_1 * b can be large, we do modulo at each step.
    // Also, division by 2 requires modular inverse if MOD is odd.
    // MOD = 10^9 + 7 is odd, so modular inverse of 2 is (MOD + 1) / 2.
    long long b_minus_1 = b - 1;
    long long sum_r_term = (b_minus_1 % MOD * (b % MOD)) % MOD;
    long long inv2 = (MOD + 1) / 2; // Modular inverse of 2 modulo 10^9 + 7
    sum_r_term = (sum_r_term * inv2) % MOD;

    // Sum of (k * b + 1) for k from 1 to a
    // This is sum_k = sum_{k=1 to a} (k * b + 1)
    // sum_k = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // sum_k = b * (a * (a+1) / 2) + a
    // We need to compute this modulo MOD.
    long long a_plus_1 = a + 1;
    long long sum_k_part1 = (a % MOD * (a_plus_1 % MOD)) % MOD;
    sum_k_part1 = (sum_k_part1 * inv2) % MOD; // (a * (a+1) / 2) % MOD
    sum_k_part1 = (sum_k_part1 * (b % MOD)) % MOD; // (b * a * (a+1) / 2) % MOD

    long long sum_k_part2 = a % MOD; // sum_{k=1 to a} 1 = a

    long long sum_k_term = (sum_k_part1 + sum_k_part2) % MOD;

    // Total sum = (sum_r_term * sum_k_term) % MOD
    long long total_sum = (sum_r_term * sum_k_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <algorithm>
#include <map>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (size_t i = 0; i < s.length() - 1; ++i) {
        adj[s[i]].insert(s[i+1]);
        adj[s[i+1]].insert(s[i]);
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::set<char> visited;
    char current_char = '\0';

    // Find a starting character for the layout.
    // It should be a character with degree 1 in the adjacency graph,
    // or any character if all have degree 2 (e.g., a cycle or a single character string).
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj.count(c) && adj[c].size() == 1) {
            current_char = c;
            break;
        }
    }

    // If no degree 1 character found, pick any character that appeared in 's'.
    // This handles cases like "abacaba" where 'c' has degree 1, or "abc" where 'a' has degree 1.
    // Also handles cases like "ab" where 'a' has degree 1.
    // If all characters in 's' have degree 2 (e.g., "abacaba" if we consider 'a' as degree 2, 'b' as degree 2, 'c' as degree 2),
    // this means it's a cycle or a path where we didn't find an endpoint.
    // The problem guarantees no adjacent equal characters, so 's' is not "aa".
    // If s is "ab", 'a' has degree 1, 'b' has degree 1.
    // If s is "abc", 'a' has degree 1, 'b' has degree 2, 'c' has degree 1.
    // If s is "abacaba", 'b' has neighbors 'a', 'a'. 'c' has neighbors 'a', 'a'. 'a' has neighbors 'b', 'c'.
    // This means 'a' has degree 2 (neighbors 'b', 'c'), 'b' has degree 1 (neighbor 'a'), 'c' has degree 1 (neighbor 'a').
    // So 'b' or 'c' would be chosen as current_char.
    if (current_char == '\0' && !s.empty()) {
        // If s is not empty and no degree 1 char found, it means all chars in s have degree 2.
        // This implies a cycle or a single character string.
        // A single character string "a" would have adj['a'] empty, so current_char would be '\0'.
        // In this case, we can just pick the first char of s.
        // If s is "a", adj['a'] is empty, size is 0.
        // If s is "ab", adj['a']={'b'}, adj['b']={'a'}. Both size 1.
        // If s is "abc", adj['a']={'b'}, adj['b']={'a','c'}, adj['c']={'b'}. 'a' and 'c' size 1.
        // So current_char will always be found if s.length() > 0 and there are valid adjacencies.
        // The only case current_char is '\0' here is if s is empty, but problem says |s| >= 1.
        // Or if s has only one character, e.g., "a". Then adj is empty.
        // In this case, we can just pick 'a'.
        current_char = s[0];
    } else if (s.empty()) { // Should not happen based on constraints
        std::cout << "YES\n";
        std::cout << "abcdefghijklmnopqrstuvwxyz\n";
        return;
    }


    // Build the layout path
    if (current_char != '\0') { // If we found a starting character
        char prev_char = '\0';
        while (current_char != '\0' && visited.find(current_char) == visited.end()) {
            layout += current_char;
            visited.insert(current_char);

            char next_char = '\0';
            if (adj.count(current_char)) {
                for (char neighbor : adj[current_char]) {
                    if (neighbor != prev_char) {
                        next_char = neighbor;
                        break;
                    }
                }
            }
            prev_char = current_char;
            current_char = next_char;
        }
    }

    // Check if all characters from 's' are included in the layout
    std::set<char> s_chars;
    for (char c : s) {
        s_chars.insert(c);
    }
    for (char c : s_chars) {
        if (visited.find(c) == visited.end()) {
            // This means there's a disconnected component or a cycle that wasn't traversed.
            // If it's a cycle, it would have all degrees 2.
            // If it's a path, it would have degree 1 endpoints.
            // The logic for finding current_char should have picked an endpoint of any path.
            // If there are multiple disconnected paths/cycles, this is impossible.
            // Example: s = "ab" and "cd". adj['a']={'b'}, adj['b']={'a'}, adj['c']={'d'}, adj['d']={'c'}.
            // We would pick 'a', traverse 'ab'. Then 'c' is left.
            // This implies that the graph formed by adjacent characters in 's' must be a single path.
            // If it's not a single path, it's impossible.
            std::cout << "NO\n";
            return;
        }
    }

    // Add remaining characters not in 's'
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited.find(c) == visited.end()) {
            layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

