#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (only endpoints)
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_zeros(n, 0); // left_zeros[i] = count of consecutive zeros to the left of i, including a[i]
    std::vector<int> right_zeros(n, 0); // right_zeros[i] = count of consecutive zeros to the right of i, including a[i]
    std::vector<int> left_ones(n, 0);   // left_ones[i] = count of consecutive ones to the left of i, including a[i]
    std::vector<int> right_ones(n, 0);  // right_ones[i] = count of consecutive ones to the right of i, including a[i]

    // Calculate left_zeros and left_ones
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            left_zeros[i] = (i > 0 ? left_zeros[i - 1] : 0) + 1;
            left_ones[i] = 0;
        } else { // a[i] == 1
            left_ones[i] = (i > 0 ? left_ones[i - 1] : 0) + 1;
            left_zeros[i] = 0;
        }
    }

    // Calculate right_zeros and right_ones
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 0) {
            right_zeros[i] = (i < n - 1 ? right_zeros[i + 1] : 0) + 1;
            right_ones[i] = 0;
        } else { // a[i] == 1
            right_ones[i] = (i < n - 1 ? right_ones[i + 1] : 0) + 1;
            right_zeros[i] = 0;
        }
    }

    int max_k = 0;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) { // a[i] is 0, it can become 1 if it's surrounded by 1s
            if (a[i - 1] == 1 && a[i + 1] == 1) {
                // This 0 is part of a 0-block surrounded by 1s.
                // It will flip to 1.
                // The number of steps depends on the distance to the nearest 1.
                // The distance is min(left_ones[i-1], right_ones[i+1]).
                // The 0 at index i will flip after min(left_ones[i-1], right_ones[i+1]) steps.
                max_k = std::max(max_k, std::min(left_ones[i - 1], right_ones[i + 1]));
            }
        } else { // a[i] is 1, it can become 0 if it's surrounded by 0s
            if (a[i - 1] == 0 && a[i + 1] == 0) {
                // This 1 is part of a 1-block surrounded by 0s.
                // It will flip to 0.
                // The number of steps depends on the distance to the nearest 0.
                // The distance is min(left_zeros[i-1], right_zeros[i+1]).
                // The 1 at index i will flip after min(left_zeros[i-1], right_zeros[i+1]) steps.
                max_k = std::max(max_k, std::min(left_zeros[i - 1], right_zeros[i + 1]));
            }
        }
    }

    std::cout << max_k << std::endl;

    std::vector<int> result = a;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) {
            if (a[i - 1] == 1 && a[i + 1] == 1) {
                if (std::min(left_ones[i - 1], right_ones[i + 1]) <= max_k) {
                    result[i] = 1;
                }
            }
        } else { // a[i] == 1
            if (a[i - 1] == 0 && a[i + 1] == 0) {
                if (std::min(left_zeros[i - 1], right_zeros[i + 1]) <= max_k) {
                    result[i] = 0;
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << result[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize the state for each bit.
    // For each bit position (0-9), we track what happens to an input bit '0' and '1'.
    // initial_val_for_0[i] = what bit i becomes if input bit i is 0
    // initial_val_for_1[i] = what bit i becomes if input bit i is 1
    // Initially, if input bit i is 0, it stays 0. If input bit i is 1, it stays 1.
    std::vector<int> initial_val_for_0(10); // All zeros
    std::vector<int> initial_val_for_1(10); // All ones
    for (int i = 0; i < 10; ++i) {
        initial_val_for_1[i] = 1;
    }

    for (int k = 0; k < n; ++k) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        for (int i = 0; i < 10; ++i) {
            int bit_val = (val >> i) & 1; // i-th bit of the constant 'val'

            if (op_char == '&') {
                initial_val_for_0[i] &= bit_val;
                initial_val_for_1[i] &= bit_val;
            } else if (op_char == '|') {
                initial_val_for_0[i] |= bit_val;
                initial_val_for_1[i] |= bit_val;
            } else if (op_char == '^') {
                initial_val_for_0[i] ^= bit_val;
                initial_val_for_1[i] ^= bit_val;
            }
        }
    }

    // Now, initial_val_for_0[i] and initial_val_for_1[i] store the final state
    // of bit i if the original input bit i was 0 or 1, respectively.

    // We want to find A, B, C such that:
    // (x & A | B) ^ C = final_state(x)
    // Or, more generally, a sequence of at most 5 operations.
    // The problem statement implies that 3 operations are sufficient: AND, OR, XOR.
    // Let's try to find A, B, C for (x & A | B) ^ C.

    // For each bit i:
    // If input bit i is 0: (0 & A_i | B_i) ^ C_i = B_i ^ C_i = initial_val_for_0[i]
    // If input bit i is 1: (1 & A_i | B_i) ^ C_i = (A_i | B_i) ^ C_i = initial_val_for_1[i]

    // Let's determine A, B, C bit by bit.
    int final_and_val = 1023; // All ones
    int final_or_val = 0;     // All zeros
    int final_xor_val = 0;    // All zeros

    for (int i = 0; i < 10; ++i) {
        int b0 = initial_val_for_0[i]; // Result if input bit i is 0
        int b1 = initial_val_for_1[i]; // Result if input bit i is 1

        // Case 1: b0 = 0, b1 = 0
        // (0 & A_i | B_i) ^ C_i = B_i ^ C_i = 0
        // (1 & A_i | B_i) ^ C_i = (A_i | B_i) ^ C_i = 0
        // This implies B_i = C_i.
        // Also, (A_i | B_i) ^ B_i = 0. This means A_i | B_i = B_i.
        // This is true if A_i = 0.
        // So, A_i = 0, B_i = 0, C_i = 0 works.
        // (x & 0 | 0) ^ 0 = 0.
        if (b0 == 0 && b1 == 0) {
            final_and_val &= ~(1 << i); // Set A_i to 0
            final_or_val &= ~(1 << i);  // Set B_i to 0
            final_xor_val &= ~(1 << i); // Set C_i to 0
        }
        // Case 2: b0 = 0, b1 = 1
        // B_i ^ C_i = 0  => B_i = C_i
        // (A_i | B_i) ^ C_i = 1 => (A_i | B_i) ^ B_i = 1
        // This means A_i | B_i = 1 ^ B_i.
        // If B_i = 0: A_i | 0 = 1 => A_i = 1. So A_i=1, B_i=0, C_i=0 works.
        // (x & 1 | 0) ^ 0 = x.
        // If B_i = 1: A_i | 1 = 0 (impossible).
        // So, A_i = 1, B_i = 0, C_i = 0 works.
        // (x & 1 | 0) ^ 0 = x.
        if (b0 == 0 && b1 == 1) {
            final_and_val |= (1 << i);  // Set A_i to 1
            final_or_val &= ~(1 << i);  // Set B_i to 0
            final_xor_val &= ~(1 << i); // Set C_i to 0
        }
        // Case 3: b0 = 1, b1 = 0
        // B_i ^ C_i = 1 => B_i != C_i
        // (A_i | B_i) ^ C_i = 0 => A_i | B_i = C_i
        // If B_i = 0: C_i = 1. Then A_i | 0 = 1 => A_i = 1.
        // So, A_i = 1, B_i = 0, C_i = 1 works.
        // (x & 1 | 0) ^ 1 = x ^ 1.
        // If B_i = 1: C_i = 0. Then A_i | 1 = 0 (impossible).
        // So, A_i = 1, B_i = 0, C_i = 1 works.
        // (x & 1 | 0) ^ 1 = x ^ 1.
        if (b0 == 1 && b1 == 0) {
            final_and_val |= (1 << i);  // Set A_i to 1
            final_or_val &= ~(1 << i);  // Set B_i to 0
            final_xor_val |= (1 << i);  // Set C_i to 1
        }
        // Case 4: b0 = 1, b1 = 1
        // B_i ^ C_i = 1 => B_i != C_i
        // (A_i | B_i) ^ C_i = 1
        // If B_i = 0: C_i = 1. Then (A_i | 0) ^ 1 = 1 => A_i ^ 1 = 1 => A_i = 0.
        // So, A_i = 0, B_i = 0, C_i = 1 works.
        // (x & 0 | 0) ^ 1 = 1.
        // If B_i = 1: C_i = 0. Then (A_i | 1) ^ 0 = 1 => 1 ^ 0 = 1. This is always true.
        // So, A_i = 0, B_i = 1, C_i = 0 works.
        // (x & 0 | 1) ^ 0 = 1.
        // We can choose A_i=0, B_i=1, C_i=0.
        if (b0 == 1 && b1 == 1) {
            final_and_val &= ~(1 << i); // Set A_i to 0
            final_or_val |= (1 << i);   // Set B_i to 1
            final_xor_val &= ~(1 << i); // Set C_i to 0
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_val != 1023) { // If A is not all ones
        result_ops.push_back({'&', final_and_val});
    }
    if (final_or_val != 0) { // If B is not all zeros
        result_ops.push_back({'|', final_or_val});
    }
    if (final_xor_val != 0) { // If C is not all zeros
        result_ops.push_back({'^', final_xor_val});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
