int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n >= m by swapping if necessary.
        // This simplifies calculations as we always deal with the larger coordinate first.
        if (n < m) {
            std::swap(n, m);
        }

        // Calculate the minimum number of moves required to reach (n,m) using only diagonal and straight moves.
        // This is equivalent to max(abs(n), abs(m)) if we can only move to adjacent cells (8 directions).
        // The number of diagonal moves will be m (to cover the smaller coordinate).
        // The remaining n-m moves will be straight moves along the x-axis.
        // So, min_moves = m (diagonal) + (n-m) (straight) = n.
        long long min_moves_to_reach = n;

        // If k is less than the minimum moves required, it's impossible.
        if (k < min_moves_to_reach) {
            std::cout << -1 << "\n";
            continue;
        }

        // Now we know k >= n. We have k - n extra moves.
        // Each extra move must be paired with a "return" move to cancel out its displacement,
        // effectively consuming two moves without changing the final position.
        // For example, (x,y) -> (x+1,y) -> (x,y) or (x,y) -> (x+1,y+1) -> (x,y).
        // The parity of the total number of moves (k) must match the parity of the minimum moves (n)
        // to reach the target. If k and n have different parities, we need at least one more move
        // to adjust the parity.
        // (k - n) represents the number of "extra" moves beyond the minimum path.
        // If (k - n) is odd, it means we have an odd number of extra moves.
        // Each pair of extra moves (e.g., (0,0)->(1,0)->(0,0)) consumes 2 moves and keeps parity.
        // If (k - n) is odd, we need to make one move that changes the parity of the total displacement.
        // This can be done by making a move like (x,y) -> (x+1,y) and then (x+1,y) -> (x,y+1)
        // or (x,y) -> (x+1,y+1) and then (x+1,y+1) -> (x,y+2).
        // The key is that each move changes the sum of coordinates (x+y) by an odd amount.
        // So, the parity of (x+y) changes with each move.
        // The parity of (n+m) must match the parity of k.
        // If (n+m) % 2 != k % 2, it's impossible.
        // This is equivalent to checking if (k - (n+m)) is odd.
        // Or, more simply, if (k - n) is odd, we need to adjust.

        long long ans;
        if ((k - n) % 2 == 0) {
            // If (k - n) is even, we can use all k moves efficiently.
            // We make m diagonal moves to cover the smaller coordinate.
            // We make n-m straight moves to cover the remaining larger coordinate.
            // This uses n moves.
            // The remaining k-n moves are even. We can use them by moving back and forth.
            // For example, (x,y) -> (x+1,y) -> (x,y). This uses 2 moves and doesn't change position.
            // These back-and-forth moves are always straight moves if we want to maximize diagonal moves.
            // So, the maximum diagonal moves would be m.
            // However, we can also make diagonal back-and-forth moves.
            // (x,y) -> (x+1,y+1) -> (x,y). This uses 2 diagonal moves.
            // To maximize diagonal moves, we should use diagonal back-and-forth moves for the (k-n) extra moves.
            // Each such pair adds 2 diagonal moves.
            // So, total diagonal moves = m (initial diagonal moves) + (k-n) (extra diagonal moves).
            ans = m + (k - n);
        } else {
            // If (k - n) is odd, we have an odd number of extra moves.
            // This means we cannot simply use back-and-forth pairs.
            // We need to "waste" one move's parity.
            // Consider the path of n moves: m diagonal, n-m straight.
            // We have k-n extra moves. Since k-n is odd, we need to make one move that changes the parity.
            // This means we cannot end up at (n,m) if we only use moves that preserve parity.
            // The parity of (x+y) changes with each move.
            // So, (n+m) must have the same parity as k.
