#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n, 0);
    std::vector<long long> current_a(n, 0);

    // Step 1: Determine upper bounds for initial_a[j]
    // For each type 2 query (l, r, m_i), we know that for any j in [l, r],
    // a_j(0) + delta_j(k) <= m_i.
    // This implies a_j(0) <= m_i - delta_j(k).
    // We want to find the tightest upper bound for each a_j(0).
    // Initialize initial_a[j] to a very large value (effectively infinity)
    // and then take the minimum of all derived upper bounds.
    for (int j = 0; j < n; ++j) {
        initial_a[j] = std::numeric_limits<long long>::max();
    }

    std::vector<long long> current_deltas(n, 0);
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_deltas[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_deltas[j]);
            }
        }
    }

    // Step 2: Verify the solution
    // Use the derived initial_a and re-simulate all operations.
    // For type 2 queries, check if the maximum is exactly m_i.
    // If it's less than m_i, then no solution exists.
    // If it's greater than m_i, then initial_a[j] was too large for some j,
    // which contradicts how initial_a was constructed (it's an upper bound).
    // So we only need to check if max_val == m_i.

    // Reset current_deltas for re-simulation
    std::fill(current_deltas.begin(), current_deltas.end(), 0);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_deltas[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val_in_range = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_in_range = std::max(max_val_in_range, initial_a[j] + current_deltas[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int j = 0; j < n; ++j) {
        // If initial_a[j] was never constrained by a type 2 query, it remains max_long_long.
        // In this case, any value within [-10^9, 10^9] is valid. We can pick 0.
        // The problem statement says "all numbers in his array didn't exceed 10^9 in their absolute value".
        // So we should ensure the output values are within this range.
        // Since m_i is up to 5*10^7 and d_i up to 10^4, current_deltas can be up to 5000 * 10^4 = 5*10^7.
        // So m_i - current_deltas[j] can be around 5*10^7 - (-5*10^7) = 10^8.
        // This is well within 10^9. So initial_a[j] will be within bounds if constrained.
        // If not constrained, it's max_long_long, so we should output 0.
        if (initial_a[j] == std::numeric_limits<long long>::max()) {
            std::cout << 0 << (j == n - 1 ? "" : " ");
        } else {
            std::cout << initial_a[j] << (j == n - 1 ? "" : " ");
        }
    }
    std::cout << "\n";

    return 0;
