            // If `a[i] >= prev_val`:
            //   We can choose `v = a[i]`. The cost is 0. This is always <= x.
            //   So, `prev_val` for the next element becomes `a[i]`.
            //   However, we can also choose `v` such that `v < a[i]` but `v >= prev_val` by wrapping around.
            //   Example: a[i]=6, prev_val=0, m=7, x=1.
            //   If we choose `v=6`, cost is 0. `prev_val` becomes 6.
            //   If we choose `v=0` (by incrementing 6 to 0), cost is 1. `prev_val` becomes 0.
            //   This is the crucial part. If `a[i] >= prev_val`, we have two choices for `prev_val` for the next element:
            //   1. `a[i]` (cost 0 for `a[i]`)
            //   2. `prev_val` (cost `(prev_val - a[i] + m) % m` for `a[i]`)
            //   We must pick the one that is valid (cost <= x) and allows the smallest `prev_val` for the next element.
            //   If `(prev_val - a[i] + m) % m <= x`, then we can make `a[i]` become `prev_val`.
            //   In this case, we keep `prev_val` as `prev_val`.
            //   Otherwise, we must make `a[i]` become `a[i]`. So `prev_val` becomes `a[i]`.
            //   This logic is for when `a[i] >= prev_val`.

            // Let's re-evaluate the `if (current_a >= prev_val)` block.
            // If `current_a >= prev_val`:
            // We have two options for the value of `a[i]` to pass to `prev_val` for the next iteration:
            // Option A: Keep `a[i]` as `current_a`. This costs 0 operations for `a[i]`.
            //           The new `prev_val` for `a[i+1]` would be `current_a`.
            // Option B: Increment `a[i]` to `prev_val` (by wrapping around).
            //           This costs `(prev_val - current_a + m) % m` operations.
            //           The new `prev_val` for `a[i+1]` would be `prev_val`.
            // We want to choose the option that results in a smaller `prev_val` for the next element,
            // provided the cost is <= `x`.
            // If `(prev_val - current_a + m) % m <= x`, it means we can afford to increment `current_a`
            // to `prev_val` (by wrapping). In this case, we prefer `prev_val` because it's smaller.
            // So, `prev_val` remains `prev_val`.
            // Otherwise (if `(prev_val - current_a + m) % m > x`), we cannot afford to increment `current_a`
            // to `prev_val`. We must keep `current_a` as `current_a`.
            // So, `prev_val` becomes `current_a`.
            // This is the correct logic for `current_a >= prev_val`.

            // If `current_a < prev_val`:
            // We MUST increment `current_a` to be at least `prev_val`.
            // The smallest value `current_a` can become that is `>= prev_val` is `prev_val` itself.
            // The number of operations to make `current_a` become `prev_val` is `prev_val - current_a`.
            // If `prev_val - current_a <= x`, then we can achieve `prev_val`.
            // So, `prev_val` for the next element remains `prev_val`.
            // If `prev_val - current_a > x`, it means we cannot make `current_a` become `prev_val`
            // without exceeding `x` operations.
            // In this case, it's impossible to satisfy the condition `a[i] >= prev_val`.
            // So, return `false`.

            // Combining these:
            // If `current_a >= prev_val`:
            //   If `(prev_val - current_a + m) % m <= x`: // Can we make current_a become prev_val?
            //     `prev_val` remains `prev_val`. (We choose to increment current_a to prev_val)
            //   Else: // Cannot make current_a become prev_val, must keep current_a
            //     `prev_val` becomes `current_a`.
            // Else (`current_a < prev_val`):
            //   If `prev_val - current_a <= x`: // Can we make current_a become prev_val?
            //     `prev_val` remains `prev_val`.
            //   Else: // Cannot make current_a become prev_val
            //     Return `false`.

            // This can be simplified.
            // We need to find the smallest `v` such that `v >= prev_val` and `(v - current_a + m) % m <= x`.
            // If such `v` exists, we update `prev_val` to `v`.
            // Otherwise, it's impossible.

            // Let `diff = (prev_val - current_a + m) % m`. This is the number of increments
            // needed to change `current_a` to `prev_val` (possibly wrapping).
            // If `diff <= x`:
            //   This means we can make `current_a` become `prev_val`.
            //   So, we can keep `prev_val` as `prev_val` for the next iteration.
            // Else (`diff > x`):
            //   This means we cannot make `current_a` become `prev_val` by incrementing it `diff` times.
            //   We can only increment `current_a` by at most `x`.
            //   The maximum value `current_a` can become is `(current_a + x) % m`.
            //   If `current_a >= prev_val`:
            //     We cannot make `current_a` become `prev_val` (because `diff > x`).
            //     So we must keep `current_a` as `current_a`.
            //     `prev_val` for the next iteration becomes `current_a`.
            //   If `current_a < prev_val`:
            //     We cannot make `current_a` become `prev_val` (because `diff > x`).
            //     And `current_a` itself is already less than `prev_val`.
            //     So it's impossible to satisfy `a[i] >= prev_val`.
            //     Return `false`.

            // Let's try this simplified logic:
            long long diff = (prev_val - current_a + m) % m;
            if (diff <= x) {
                // We can make current_a become prev_val.
                // So, prev_val for the next element remains prev_val.
                // No change to prev_val.
            } else { // diff > x
                // We cannot make current_a become prev_val.
                // If current_a is already >= prev_val, we must use current_a.
                // If current_a < prev_val, it's impossible.
                if (current_a < prev_val) {
                    return false; // Cannot satisfy a[i] >= prev_val
                }
                // If current_a >= prev_val, we must use current_a.
                // prev_val for the next element becomes current_a.
                prev_val = current_a;
            }
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric> // For std::iota

struct Child {
    long long v, d, p;
    int original_index;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_index = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> treated_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        treated_children_indices.push_back(children[i].original_index);
        children[i].in_line = false; // Child i is now treated

        long long current_v_cry = children[i].v;
        long long accumulated_d_cry = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_cry from previous children who ran away
            children[j].p -= accumulated_d_cry;

            // Apply v_cry from the child currently in the office
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Check if child j runs away
            if (children[j].p < 0) {
                children[j].in_line = false;
                accumulated_d_cry += children[j].d;
            }
        }
    }

    std::cout << treated_children_indices.size() << "\n";
    for (size_t i = 0; i < treated_children_indices.size(); ++i) {
        std::cout << treated_children_indices[i] << (i == treated_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

