// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Check for k=1
    // A single cut divides s into s_left and s_right.
    // We can rearrange them to s_right + s_left.
    // This new string must be a palindrome and not equal to s.
    // We iterate through all possible cut positions.
    for (int i = 1; i < n; ++i) { // i is the length of s_left
        std::string s_left = s.substr(0, i);
        std::string s_right = s.substr(i);
        std::string s_prime = s_right + s_left;

        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // If k=1 didn't work, check for k=2.
    // If a solution exists with k=2, it must be possible to form a new palindrome.
    // The only case where k=2 is the minimum is if all characters in s are the same,
    // or if s is of the form "ababa" where 'a' and 'b' are distinct characters,
    // and all characters except the middle one are the same.
    // For example, "nolon" -> no|l|on -> on|l|no.
    // If all characters are the same (e.g., "aaaa"), then any rearrangement of pieces
    // will result in the same string "aaaa". In this case, it's impossible.
    // We can check this by counting distinct characters.

    // Count distinct characters
    std::vector<bool> seen(26, false);
    int distinct_chars = 0;
    for (char c : s) {
        if (!seen[c - 'a']) {
            seen[c - 'a'] = true;
            distinct_chars++;
        }
    }

    if (distinct_chars <= 1) { // All characters are the same (e.g., "aaaa")
        std::cout << "Impossible" << std::endl;
    } else {
        // If there are at least two distinct characters, and k=1 didn't work,
        // then k=2 must be the answer.
        // This is because if s is a palindrome and not all characters are the same,
        // and no 1-cut rearrangement works, then a 2-cut rearrangement will always work.
        // For example, take s = "abacaba".
        // Cut 1: "a" | "bacaba" -> "bacaba" + "a" = "bacabaa" (not palindrome)
        // Cut 2: "ab" | "acaba" -> "acaba" + "ab" = "acabaab" (not palindrome)
        // ...
        // If s is not all same characters, it means there's at least one character
        // different from the first character.
        // Consider s = "nolon". First char 'n'. 'o' is different.
        // Cut "n" | "olo" | "n". Rearrange to "n" | "olo" | "n" (same)
        // Cut "no" | "l" | "on". Rearrange to "on" | "l" | "no" = "onlno" (palindrome, not s).
        // This requires 2 cuts.
        // The problem statement guarantees that if a solution exists, k=2 is the maximum needed
        // if k=1 doesn't work and not all characters are the same.
        std::cout << 2 << std::endl;
    }

    return 0;
}

