// Function to calculate parity of a 01-string
// Returns 1 if odd number of '1's, 0 otherwise
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    // Calculate initial parity of string a
    int parity_a = calculate_parity(a);

    // If parity_a is 1 (odd number of '1's), we can append a '1' to make it even.
    // This effectively means we can always make the number of '1's even if we want to.
    // So, the maximum number of '1's we can achieve in string 'a' (or any string derived from it
    // by appending parity bits) is its current count of '1's, plus one if its current parity is odd.
    // This is equivalent to (count_ones(a) + parity_a).

    int max_ones_a = 0;
    for (char c : a) {
        if (c == '1') {
            max_ones_a++;
        }
    }
    max_ones_a += parity_a; // If initial 'a' has odd ones, we can append '1' to make it even.
                            // This effectively increases the max_ones_a by 1.

    // Calculate the number of '1's in string b
    int ones_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_b++;
        }
    }

    // Condition 1: The number of '1's in b must be less than or equal to the maximum
    // number of '1's we can achieve in a (after potentially one parity append).
    // If ones_b > max_ones_a, it's impossible.
    if (ones_b > max_ones_a) {
        std::cout << "NO\n";
        return 0;
    }

    // Condition 2: The length of b must be less than or equal to the length of a.
    // If |b| > |a|, we need to append parity bits to 'a' until its length is at least |b|.
    // The maximum length we can achieve is effectively infinite, but we only care if it can reach |b|.
    // The 'remove first character' operation allows us to effectively "shift" the string.
    // So, if we can generate a string `a_prime` of length `|b|` such that `a_prime` has `ones_b` ones,
    // and `a_prime` is a suffix of some `a_extended` (which is `a` plus parity bits), then it's possible.
    // The crucial insight is that we can always extend `a` to any length `L >= |a|` by appending parity bits.
    // And we can always remove leading characters.
    // So, the only constraints are the number of '1's.

    // If we can reach `ones_b` '1's in `a` (or an extended version of `a`),
    // and `ones_b` has the same parity as `max_ones_a` (which is always even if `max_ones_a` is > 0,
    // or 0 if `max_ones_a` is 0), then it's possible.
    //
    // Let's re-evaluate `max_ones_a`.
    // `count_ones(a)` is the initial count.
    // If `count_ones(a)` is odd, we can append '1'. New count is `count_ones(a) + 1` (even).
    // If `count_ones(a)` is even, we can append '0'. New count is `count_ones(a)` (even).
    // So, after *at most one* parity append, the number of '1's in the string becomes even.
    // Let `current_ones` be the number of '1's in the string.
    // If `current_ones` is even, appending parity '0' keeps it even.
    // If `current_ones` is odd, appending parity '1' makes it even.
    // Once the count of '1's is even, any subsequent parity append will be '0' (if count is even)
    // or '1' (if count is odd, which won't happen if we always keep it even).
    //
    // This means that if we can reach `ones_b` '1's, and `ones_b` has the same parity as `max_ones_a`,
    // then it's possible.
    // `max_ones_a` is `count_ones(a)` if `count_ones(a)` is even, or `count_ones(a) + 1` if `count_ones(a)` is odd.
    // In both cases, `max_ones_a` is the smallest even number of ones that is >= `count_ones(a)`.
    //
    // So, the condition is:
    // 1. `ones_b <= max_ones_a`
    // 2. `(max_ones_a - ones_b)` must be an even number.
    // This is because we can only reduce the number of '1's by pairs (by appending '0's and then removing '1's,
    // or by appending '1's and then removing '0's, but the total count of '1's in the string we are working with
    // can only change by 0 or 1 at a time, and we can always make it even).
    //
    // More simply:
    // We can always make the number of '1's in `a` even by appending at most one parity bit.
    // Let this new count be `current_ones_in_a`.
    // If `current_ones_in_a` is less than `ones_b`, it's impossible.
    // Otherwise, we have `current_ones_in_a` '1's. We need `ones_b` '1's.
    // The difference `current_ones_in_a - ones_b` must be an even number.
    // This is because each time we append a '0' (which happens when the current string has an even number of '1's),
    // the number of '1's remains the same.
    // If we need to reduce the number of '1's, we must remove '1's from the front.
    // We can always extend the string `a` to be long enough to contain `b` as a suffix.
    // The only constraint is the number of '1's.

    // Let's re-calculate `max_ones_a` as the maximum number of '1's we can have in a string
    // that is derived from `a` and has an even number of '1's.
    // If `calculate_parity(a)` is 1 (odd), we can append '1', making `count_ones(a) + 1` '1's (even).
    // If `calculate_parity(a)` is 0 (even), we can append '0', making `count_ones(a)` '1's (even).
    // So, `max_ones_a_even = count_ones(a) + calculate_parity(a)`.
    // This `max_ones_a_even` is the maximum number of '1's we can have in a string that is
    // derived from `a` and has an even number of '1's.
    // Any string we generate by repeatedly appending parity bits (after the first one that makes it even)
    // will always have an even number of '1's.

    int initial_ones_a = 0;
    for (char c : a) {
        if (c == '1') {
            initial_ones_a++;
        }
    }

    int effective_max_ones_a = initial_ones_a;
    if (initial_ones_a % 2 != 0) { // If initial 'a' has odd '1's, we can append '1'
        effective_max_ones_a++;
    }
    // Now, effective_max_ones_a is the smallest even number of '1's that is >= initial_ones_a.
    // This is the maximum number of '1's we can have in a string derived from 'a' that has an even number of '1's.

    if (ones_b > effective_max_ones_a) {
        std::cout << "NO\n";
    } else {
        // If ones_b <= effective_max_ones_a, it means we can potentially reach the target number of '1's.
        // Since effective_max_ones_a is always even, and any subsequent parity append keeps the count even,
        // the number of '1's in any string we can form (after the first potential '1' append) will always be even.
        // Therefore, ones_b must also be even.
        // No, this is not entirely correct. We can remove characters.
        //
        // Let's trace the example: 01011 -> 0110
        // a = 01011, ones_a = 3 (odd)
        // b = 0110, ones_b = 2 (even)
        //
        // effective_max_ones_a = 3 + 1 = 4 (even)
        // ones_b = 2 (even)
        //
        // 2 <= 4 is true.
        // (4 - 2) = 2, which is even. So YES.
        //
        // Example 2: 0011 -> 1110
        // a = 0011, ones_a = 2 (even)
        // b = 1110, ones_b = 3 (odd)
        //
        // effective_max_ones_a = 2 (even)
        // ones_b = 3 (odd)
        //
        // 3 <= 2 is false. So NO.
        //
        // This logic seems to hold.
        // The key is that after at most one parity append, the string will have an even number of '1's.
        // From that point on, appending parity will always append '0' (because the count of '1's is even),
        // thus maintaining an even number of '1's.
        // So, any string `a_prime` that we can form by appending parity bits will have an even number of '1's,
        // *unless* `a` initially had an odd number of '1's and we chose *not* to append a '1' (i.e., we only appended '0's).
        // But we can always choose to append '1' if `a` has odd '1's.
        //
        // The number of '1's in `b` must be achievable.
        // The maximum number of '1's we can have in any string derived from `a` is `initial_ones_a` if `initial_ones_a` is even,
        // or `initial_ones_a + 1` if `initial_ones_a` is odd. Let's call this `max_possible_ones`.
        //
        // If `ones_b > max_possible_ones`, then it's impossible.
        // Otherwise, `ones_b <= max_possible_ones`.
        //
        // Now, consider the parity of `ones_b` and `max_possible_ones`.
        // `max_possible_ones` is always even.
        // If `ones_b` is odd, and `max_possible_ones` is even, then `max_possible_ones - ones_b` is odd.
        // This means we cannot reach `ones_b` from `max_possible_ones` by only removing pairs of '1's.
        //
        // The number of '1's in the string can only change by 0 or 1 at a time (append parity).
        // Once the count of '1's becomes even, it stays even if we only append parity bits.
        // So, if `ones_b` is odd, it must be that we never made the count of '1's even.
        // This means `initial_ones_a` must have been odd, and `ones_b` must be `initial_ones_a`.
        // But we can always append '1' to make it even.
        //
        // The logic is:
        // 1. Calculate `initial_ones_a`.
        // 2. Calculate `ones_b`.
        // 3. If `initial_ones_a` is odd, we can choose to append '1' to `a`, making its '1's count `initial_ones_a + 1` (even).
        //    Or we can choose to append '0' (if we somehow made it even earlier, which is not the case here).
        //    The crucial point is that we can always reach a state where the number of '1's is `initial_ones_a` (if even)
        //    or `initial_ones_a + 1` (if odd), and this count is always even.
        //    Let `target_ones_a = initial_ones_a` if `initial_ones_a` is even, else `initial_ones_a + 1`.
        //    This `target_ones_a` is the maximum number of '1's we can have in an even-parity string derived from `a`.
        //
        // 4. If `ones_b > target_ones_a`, then it's impossible.
        // 5. If `ones_b <= target_ones_a`, then it's possible if and only if `(target_ones_a - ones_b)` is even.
        //    This is because `target_ones_a` is even. If `ones_b` is also even, their difference is even.
        //    If `ones_b` is odd, their difference is odd, meaning we can't reach `ones_b` from `target_ones_a`
        //    by only removing pairs of '1's (which is what effectively happens when we consider the "even" state).
        //
        // This logic seems sound.

        if ((effective_max_ones_a - ones_b) % 2 == 0) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current index for tracks to read
    int h_idx = 0; // Current index for heads

    while (p_idx < m && h_idx < n) {
        // Find the first head h_idx that can reach p[p_idx]
        // A head h_idx can reach p[p_idx] if p[p_idx] is within [h[h_idx] - T, h[h_idx] + T]
        // This means h[h_idx] - T <= p[p_idx] <= h[h_idx] + T
        // Or, equivalently, abs(h[h_idx] - p[p_idx]) <= T
        // Since p is sorted, we want to use the leftmost head that can cover p[p_idx]
        // and potentially cover subsequent tracks.

        // Skip heads that are too far to the left to reach p[p_idx]
        // i.e., h[h_idx] + T < p[p_idx]
        while (h_idx < n && h[h_idx] + T < p[p_idx]) {
            h_idx++;
        }

        if (h_idx == n) {
            // No more heads available to cover p[p_idx]
            return false;
        }

        // Now, h[h_idx] is the first head that *might* be able to cover p[p_idx].
        // It satisfies h[h_idx] + T >= p[p_idx].
        // We also need h[h_idx] - T <= p[p_idx].
        // If h[h_idx] - T > p[p_idx], this head is too far to the right to cover p[p_idx].
        // In this case, we cannot cover p[p_idx] with any remaining head, because
        // all subsequent heads h[h_idx+1], ... are even further to the right.
        if (h[h_idx] - T > p[p_idx]) {
            return false;
        }

        // If we reach here, h[h_idx] can cover p[p_idx].
        // We use this head to cover as many subsequent tracks as possible.
        long long current_head_reach_right = h[h_idx] + T;
        long long current_head_reach_left = h[h_idx] - T;

        // The head can cover tracks in the range [current_head_reach_left, current_head_reach_right].
        // We need to cover p[p_idx].
        // The actual range covered by this head is [max(p[p_idx], current_head_reach_left), current_head_reach_right].
        // No, this is not correct. The head can move to any point X in [h[h_idx]-T, h[h_idx]+T].
        // From X, it can cover [X-T, X+T].
        // The total range a head can cover is [h[h_idx] - T - T, h[h_idx] + T + T] if it moves optimally.
        // This is not how it works. A head at h_i can reach any point X such that |h_i - X| <= T.
        // Once it reaches X, it has "read" X.
        // The problem states "A track is considered read if at least one head has visited this track."
        // "During the operation each head's movement does not affect the movement of the other heads: the heads can change their relative order; there can be multiple reading heads above any of the tracks."
        // "For each of the reading heads, the hard drive's firmware can move the head exactly one track to the right or to the left, or leave it on the current track."
        // This means in T time, a head at h_i can visit any track X such that |h_i - X| <= T.
        // So, the range covered by head h_idx is [h[h_idx] - T, h[h_idx] + T].

        // We use h[h_idx] to cover p[p_idx] and all subsequent tracks that fall within its range.
        long long max_covered_by_this_head = h[h_idx] + T;
        while (p_idx < m && p[p_idx] <= max_covered_by_this_head) {
            p_idx++;
        }
        h_idx++; // Move to the next head
    }

    return p_idx == m; // All tracks covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10; // Max possible difference between any p_i and h_j is ~10^10.
                           // A head might need to move 10^10 units.
                           // A safe upper bound for T.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    int value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all in subsequence 1)
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value
    // goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    long long goodness1 = (long long)a[n - 2].value + a[n - 1].value - ((long long)a[0].value + a[1].value);
    std::vector<int> partition1(n, 1);

    // Case 2: Partition into two non-empty subsequences.
    // The strategy is to put a[0] into one subsequence (say, 1) and a[1] into the other (say, 2).
    // All other elements a[2]...a[n-1] are put into subsequence 2.
    // This ensures that a[0] is always in a different subsequence from a[1], a[2], ..., a[n-1].
    // And a[1] is in the same subsequence as a[2], ..., a[n-1].
    //
    // Possible f values:
    // 1. a[0] with any other a[j] (j > 0): f = a[0].value + a[j].value + h (different subsequences)
    //    Min: a[0].value + a[1].value + h
    //    Max: a[0].value + a[n-1].value + h
    // 2. a[i] with a[j] (i, j > 0): f = a[i].value + a[j].value (same subsequence)
    //    Min: a[1].value + a[2].value (if n > 2, otherwise this case might not exist or be trivial)
    //    Max: a[n-2].value + a[n-1].value
    //
    // Overall min_f: min(a[0].value + a[1].value + h, a[1].value + a[2].value (if n>2))
    // Overall max_f: max(a[0].value + a[n-1].value + h, a[n-2].value + a[n-1].value)

    long long min_f_case2;
    long long max_f_case2;

    // Minimum possible f value
    min_f_case2 = (long long)a[0].value + a[1].value + h; // a[0] and a[1] are in different groups

    if (n > 2) {
        // If there are at least 3 elements, a[1] and a[2] can be in the same group.
        min_f_case2 = std::min(min_f_case2, (long long)a[1].value + a[2].value);
    } else { // n == 2
        // If n=2, only a[0] and a[1] exist. They are in different groups.
        // The only f value is a[0].value + a[1].value + h.
        // min_f_case2 and max_f_case2 will both be this value.
    }

    // Maximum possible f value
    max_f_case2 = std::max((long long)a[0].value + a[n - 1].value + h, (long long)a[n - 2].value + a[n - 1].value);

    long long goodness2 = max_f_case2 - min_f_case2;
    std::vector<int> partition2(n);
    partition2[a[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[a[i].original_index] = 2;
    }

    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for sums to prevent overflow, as a_i can be up to 10^9
// and y can accumulate many such values.
// n can be up to 2*10^5.
// Max y could be roughly n * max(a_i) * 2, which is 2*10^5 * 10^9 * 2 = 4*10^14,
// fitting in long long.

// Memoization table for results:
// dp[x_start][parity] stores the pair {final_x, final_y_increment}
// when starting at x_start, with the given parity of step (0 for step 2, 1 for step 3).
// We only care about starting at x_start and performing the first operation.
// The parity here refers to whether the first operation is x+a_x or x-a_x.
// For our problem, the first operation is always x+a_x, so we can simplify.
// Let dp[x_start] store {final_x, total_y_increment} for a full cycle starting at x_start.
// A full cycle means: x_start -> x_start + a[x_start] -> x_start + a[x_start] - a[x_start + a[x_start]]
// This is not quite right. The problem states:
// 1. x = x + a_x, y = y + a_x
// 2. x = x - a_x, y = y + a_x
// These two steps form a pair.
// Let's define `solve(current_x, current_y_offset, is_first_step_plus)`
// `is_first_step_plus` indicates if the current `a_x` should be added to `x` (true) or subtracted (false).
// This is equivalent to `parity` in the thought process.

// We need to store results for `dp[x][parity]`.
// `dp[x][0]` for when the next operation is `x += a[x]`
// `dp[x][1]` for when the next operation is `x -= a[x]`

// The problem structure is:
// Start with x=1, y=0.
// Loop:
//   val = a[x]
//   x = x + val
//   y = y + val
//   val = a[x] (new x)
//   x = x - val
//   y = y + val
// This means the first operation is always `x += a[x]`.
// So, for each `i` from `1` to `n-1`, we set `a_1 = i`.
// Then we start the simulation.
// The state for memoization should be `(current_x, current_y_offset, is_plus_step)`.
// `is_plus_step` is true if the next operation is `x += a_x`, false if `x -= a_x`.

// Let `memo[x][0]` store the result if the next step is `x += a[x]`.
// Let `memo[x][1]` store the result if the next step is `x -= a[x]`.
// The result will be a pair: `{final_x, total_y_increment}`.
// `final_x` is the x value when the program terminates.
// `total_y_increment` is the sum of `a_x` values added to `y` from this point until termination.

std::vector<long long> a_orig; // Stores a_2, ..., a_n
int N;

// Memoization table:
// dp[x][0] stores {final_x, total_y_increment} if starting at x and next op is x += a[x]
// dp[x][1] stores {final_x, total_y_increment} if starting at x and next op is x -= a[x]
// -1 for final_x indicates non-termination.
std::vector<std::vector<std::pair<long long, long long>>> memo;

// Visited table to detect cycles during DFS
std::vector<std::vector<bool>> visited;

// Function to get a_val for a given x.
// Note: a_orig stores a_2...a_n. So a_orig[k-2] is a_k.
// For a_1, we use the input `start_a1_val`.
long long get_a_val(int x, long long start_a1_val) {
    if (x == 1) {
        return start_a1_val;
    }
    return a_orig[x - 2];
}

// Recursive function to calculate {final_x, total_y_increment}
// current_x: current value of x
// is_plus_step: true if next operation is x += a_x, false if x -= a_x
// start_a1_val: the value of a_1 for the current run
std::pair<long long, long long> calculate_path(int current_x, bool is_plus_step, long long start_a1_val) {
    // Check for termination conditions
    if (current_x <= 0 || current_x > N) {
        return {current_x, 0}; // Terminated, no further y increment
    }

    int parity_idx = is_plus_step ? 0 : 1;

    // Check memoization table
    if (memo[current_x][parity_idx].first != 0 || memo[current_x][parity_idx].second != 0) {
        // If memo[current_x][parity_idx] is {0,0}, it means it's either uncomputed or a cycle.
        // We need a better way to distinguish uncomputed from {0,0} result.
        // Let's use a special value for uncomputed, e.g., {-2, -2}.
        if (memo[current_x][parity_idx].first != -2) {
            return memo[current_x][parity_idx];
        }
    }

    // Detect cycle
    if (visited[current_x][parity_idx]) {
        return {-1, -1}; // Cycle detected, indicates non-termination
    }

    // Mark as visited
    visited[current_x][parity_idx] = true;

    long long val_ax = get_a_val(current_x, start_a1_val);
    long long next_x;
    bool next_is_plus_step;

    if (is_plus_step) {
        next_x = current_x + val_ax;
        next_is_plus_step = false; // After x += a_x, next is x -= a_x
    } else {
        next_x = current_x - val_ax;
        next_is_plus_step = true; // After x -= a_x, next is x += a_x
    }

    // Recursively calculate the rest of the path
    std::pair<long long, long long> res = calculate_path(next_x, next_is_plus_step, start_a1_val);

    // Unmark as visited (backtrack)
    visited[current_x][parity_idx] = false;

    // If non-terminating path found, propagate it
    if (res.first == -1) {
        memo[current_x][parity_idx] = {-1, -1};
        return {-1, -1};
    }

    // Add current a_x value to the total y increment
    memo[current_x][parity_idx] = {res.first, res.second + val_ax};
    return memo[current_x][parity_idx];
}

