            // `memo_run_id[x][parity]` stores the `run_id` for which `memo[x][parity]` is valid.

            // Global variables for memoization and cycle detection
            static std::vector<std::vector<std::pair<long long, long long>>> memo_results;
            static std::vector<std::vector<int>> memo_run_id; // Stores the run_id for which memo_results is valid
            static std::vector<std::vector<int>> visited_run_id; // Stores the run_id if currently in recursion stack

            // Initialize these once
            if (memo_results.empty()) {
                memo_results.resize(N + 1, std::vector<std::pair<long long, long long>>(2));
                memo_run_id.resize(N + 1, std::vector<int>(2, 0));
                visited_run_id.resize(N + 1, std::vector<int>(2, 0));
            }

            // Recursive function with run_id
            auto calculate_path_optimized =
                [&](auto self, int current_x, bool is_plus_step, long long start_a1_val, int current_run_id)
                -> std::pair<long long, long long> {
                if (current_x <= 0 || current_x > N) {
                    return {current_x, 0};
                }

                int parity_idx = is_plus_step ? 0 : 1;

                // Check memoization table for current run_id
                if (memo_run_id[current_x][parity_idx] == current_run_id) {
                    return memo_results[current_x][parity_idx];
                }

                // Detect cycle for current run_id
                if (visited_run_id[current_x][parity_idx] == current_run_id) {
                    return {-1, -1}; // Cycle detected
                }

                // Mark as visited for current run_id
                visited_run_id[current_x][parity_idx] = current_run_id;

                long long val_ax = get_a_val(current_x, start_a1_val);
                long long next_x;
                bool next_is_plus_step;

                if (is_plus_step) {
                    next_x = current_x + val_ax;
                    next_is_plus_step = false;
                } else {
                    next_x = current_x - val_ax;
                    next_is_plus_step = true;
                }

                std::pair<long long, long long> res = self(self, next_x, next_is_plus_step, start_a1_val, current_run_id);

                // Unmark from visited (backtrack)
                visited_run_id[current_x][parity_idx] = 0; // Or some other value indicating not in current path

                // Store result in memo table for current run_id
                if (res.first == -1) {
                    memo_results[current_x][parity_idx] = {-1, -1};
                } else {
                    memo_results[current_x][parity_idx] = {res.first, res.second + val_ax};
                }
                memo_run_id[current_x][parity_idx] = current_run_id;

                return memo_results[current_x][parity_idx];
            }; // End of lambda

            // For each i, this is a new run.
            // The `current_run_id` will be `i`.
            // Initial state: x=1, y=0. First step is x += a_x.
            long long current_a1_val = i;
            std::pair<long long, long long> result = calculate_path_optimized(calculate_path_optimized, 1, true, current_a1_val, i);

            if (result.first == -1) {
                std::cout << -1 << "\n";
            } else {
                // The total y is the sum of a_x values.
                // The `result.second` already contains the sum of `a_x` values.
                std::cout << result.second << "\n";
            }
        }
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    if (n < 3) { // Minimum length for s[x] == s[x+k] == s[x+2k] is 3 (k=1, x=0)
        std::cout << 0 << std::endl;
        return 0;
    }

    std::vector<int> min_r_for_l(n + 1, n + 1); // min_r_for_l[l] stores the minimum r such that [l, r] contains a triple.
                                                // Initialize with n+1 (invalid r)

    // Iterate through all possible starting positions x (0-indexed)
    for (int x = 0; x < n; ++x) {
        // Iterate through possible k values.
        // The maximum index is x + 2k, which must be < n.
        // So, 2k < n - x => k < (n - x) / 2.
        // Also, k must be at least 1.
        // The problem statement says 1 <= k <= n, but practically k is limited by string length.
        // The maximum k for a triple is when x=0, x+2k = n-1, so 2k = n-1, k = (n-1)/2.
        // The maximum k for a triple is 8.
        // If k > 8, then 2k > 16. If s[x] == s[x+k] == s[x+2k], then s[x] must be equal to s[x+k] and s[x+2k].
        // If k > 8, then x+k and x+2k are far apart.
        // The maximum k we need to check is small.
        // If k > 8, then x+2k - x = 2k > 16.
        // If s[x] == s[x+k] == s[x+2k], then the distance between x and x+2k is 2k.
        // If 2k > 16, then there must be at least 16 characters between s[x] and s[x+2k].
        // This means that if we have a triple s[i] == s[i+k] == s[i+2k] with k > 8,
        // then we must also have a triple s[i'] == s[i'+k'] == s[i'+2k'] with k' <= 8
        // that covers a smaller or equal range.
        // This is because any sequence of 17 characters must contain a triple with k <= 8.
        // For example, if we have 000, 01010, 0110110, 011101110, etc.
        // The maximum k for which a triple can be "minimal" (not covered by a smaller k triple) is 8.
        // For example, 00000000000000000 (17 zeros) has 0_0_0 for k=1, k=2, ..., k=8.
        // Consider a string of length 17. If it contains a triple, it must contain one with k <= 8.
        // If s[x] == s[x+k] == s[x+2k] for k > 8, then the range [x, x+2k] is at least 17 characters long.
        // Any substring of length 17 or more must contain a triple with k <= 8.
        // This is a known property for binary strings.
        // So, we only need to check k up to 8.
        for (int k = 1; k <= 8; ++k) {
            if (x + 2 * k < n) { // Check if x+2k is within bounds
                if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                    // Found a triple (x, x+k, x+2k)
                    // The 1-indexed range for this triple is [x+1, x+2k+1]
                    int l_val = x + 1;
                    int r_val = x + 2 * k + 1;

                    // For any l' from 1 to l_val, this triple makes [l', r_val] valid.
                    // We want to find the minimum r_val for each l'.
                    // So, for l' = 1, ..., l_val, update min_r_for_l[l'] = min(min_r_for_l[l'], r_val).
                    // This can be done efficiently by iterating l' downwards from l_val.
                    // However, a simpler approach is to just update min_r_for_l[l_val]
                    // and then propagate the minimums.
                    min_r_for_l[l_val] = std::min(min_r_for_l[l_val], r_val);
                }
            }
        }
    }

    // Propagate minimum r values:
    // If min_r_for_l[l] is valid, then min_r_for_l[l-1] can be at most min_r_for_l[l].
    // This ensures that if a triple exists for [l, r], it also exists for [l-1, r].
    for (int l = n - 1; l >= 1; --l) {
        min_r_for_l[l] = std::min(min_r_for_l[l], min_r_for_l[l + 1]);
    }

    long long count = 0;
    // Iterate through all possible l (1-indexed)
    for (int l = 1; l <= n; ++l) {
        // If min_r_for_l[l] is still n+1, it means no triple can start at or before l.
        // So, no valid r exists for this l.
        if (min_r_for_l[l] <= n) {
            // For a given l, any r from min_r_for_l[l] to n is valid.
            // The number of such r's is n - min_r_for_l[l] + 1.
            count += (n - min_r_for_l[l] + 1);
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

// Function to check if a subarray is a permutation of length 'len'
// It uses a frequency array (or boolean array) and checks max value.
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) {
        return true; // An empty sequence can be considered a permutation of length 0, though problem constraints imply len >= 1
    }
    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val <= 0 || val > len || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute max prefix values
    std::vector<int> max_prefix(n);
    max_prefix[0] = a[0];
    for (int i = 1; i < n; ++i) {
        max_prefix[i] = std::max(max_prefix[i - 1], a[i]);
    }

    // Precompute max suffix values
    std::vector<int> max_suffix(n);
    max_suffix[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        max_suffix[i] = std::max(max_suffix[i + 1], a[i]);
    }

    // Precompute prefix distinct counts
    std::vector<bool> seen_prefix(n + 1, false);
    std::vector<int> distinct_prefix_count(n);
    int current_distinct_prefix = 0;
    for (int i = 0; i < n; ++i) {
        if (!seen_prefix[a[i]]) {
            seen_prefix[a[i]] = true;
            current_distinct_prefix++;
        }
        distinct_prefix_count[i] = current_distinct_prefix;
    }

    // Precompute suffix distinct counts
    std::vector<bool> seen_suffix(n + 1, false);
    std::vector<int> distinct_suffix_count(n);
    int current_distinct_suffix = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (!seen_suffix[a[i]]) {
            seen_suffix[a[i]] = true;
            current_distinct_suffix++;
        }
        distinct_suffix_count[i] = current_distinct_suffix;
    }

    std::vector<std::pair<int, int>> results;

    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Check p1 conditions
        bool p1_is_perm = (max_prefix[l1 - 1] == l1) && (distinct_prefix_count[l1 - 1] == l1);

        // Check p2 conditions
        bool p2_is_perm = (max_suffix[l1] == l2) && (distinct_suffix_count[l1] == l2);

        if (p1_is_perm && p2_is_perm) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

