    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        long long diff = std::abs(a - b);

        long long count = 0;

        // Use 5s as much as possible
        count += diff / 5;
        diff %= 5;

        // Remaining diff can be 0, 1, 2, 3, 4
        if (diff == 0) {
            // No additional presses needed
        } else if (diff == 1) {
            // Can be achieved by +1 (1 press)
            // Or by +2 then -1 (2 presses)
            // Or by +5 then -2 then -2 then -1 (4 presses)
            // Or by +5 then -2 then -2 (3 presses)
            // Or by +5 then -2 then -1 then -1 (4 presses)
            // Or by +5 then -2 then -1 (3 presses)
            // Or by +5 then -5 then +1 (3 presses)
            // The simplest is 1 press (+1 or -1)
            count += 1;
        } else if (diff == 2) {
            // Can be achieved by +2 (1 press)
            // Or by +5 then -2 then -1 (3 presses)
            // The simplest is 1 press (+2 or -2)
            count += 1;
        } else if (diff == 3) {
            // Can be achieved by +1 then +2 (2 presses)
            // Or by +5 then -2 (2 presses)
            // Or by +5 then -1 then -1 (3 presses)
            // The simplest is 2 presses
            count += 2;
        } else if (diff == 4) {
            // Can be achieved by +2 then +2 (2 presses)
            // Or by +5 then -1 (2 presses)
            // The simplest is 2 presses
            count += 2;
        }

        std::cout << count << "\n";
    }
    return 0;
}

