#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        // The reverse of a permutation has the same set of adjacent sums.
        // F(p) = sort([p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n])
        // Let p' be the reverse of p: p' = [p_n, p_{n-1}, ..., p_1]
        // F(p') = sort([p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1])
        // This is the same set of sums, just in reverse order, so their sorted versions are identical.
        // The only case where p' might be equal to p is if p is a palindrome.
        // However, a permutation of distinct integers from 1 to n cannot be a palindrome
        // unless n=1 (which is not allowed, n>=2) or n=0.
        // For n >= 2, p_1 != p_n (since p_1=p_n would imply p_1 is repeated if n>1, or n=1).
        // If p_1 = p_n, then p is not a permutation of distinct integers from 1 to n.
        // For example, if p = [1, 2, 1], it's not a permutation.
        // If p = [1, 2, 3, 2, 1], it's not a permutation.
        // A permutation [p_1, ..., p_n] is a palindrome if p_i = p_{n-i+1} for all i.
        // If p is a permutation of distinct integers from 1 to n, then p_1 must be different from p_n
        // unless n=1. Since n >= 2, p_1 != p_n.
        // Therefore, reversing the permutation always yields a different permutation.

        for (int i = n - 1; i >= 0; --i) {
            std::cout << p[i] << (i == 0 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

