#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    int current_a1 = a[0];
    int days_left = d;

    // Iterate through piles from 2 to n (index 1 to n-1)
    for (int i = 1; i < n; ++i) {
        // Cost to move one haybale from pile i+1 (0-indexed i) to pile 1 (0-indexed 0)
        // is i days.
        int cost_per_haybale = i; 

        // If we don't have enough days to move even one haybale from this pile, stop.
        if (days_left < cost_per_haybale) {
            break;
        }

        // Calculate how many haybales we can move from this pile.
        // We have a[i] haybales in this pile.
        // We have days_left days.
        // Each haybale costs cost_per_haybale days.
        int haybales_to_move = std::min(a[i], days_left / cost_per_haybale);

        // Add these haybales to pile 1.
        current_a1 += haybales_to_move;

        // Deduct the days spent.
        days_left -= haybales_to_move * cost_per_haybale;
    }

    std::cout << current_a1 << std::endl;
}

