void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) {
            counts[s_val]++;
        }
    }

    long long current_sum = 0;
    for (auto const& [val, count] : counts) {
        // Add the total value contributed by this power of two
        // but cap it at 2048. For example, if we have three 1024s,
        // two of them can form 2048, and the third one is left over.
        // The total value contributed to the sum is 2048.
        // If we have one 1024, it contributes 1024.
        // This is equivalent to saying:
        // current_sum += val * count;
        // but we need to be careful not to exceed 2048 for any individual combination.
        // A simpler way is to just add the values directly.
        // The problem states we can combine any two equal integers.
        // This means we can effectively sum up all numbers less than or equal to 2048.
        // If the sum reaches 2048 or more, we can form 2048.
        // Example: {1024, 512, 512} -> {1024, 1024} -> {2048}
        // Sum = 1024 + 512 + 512 = 2048.
        // Example: {1, 1, 1, 1, ..., 1} (2048 times) -> sum = 2048.
        // This is because any two 2^k can form 2^(k+1).
        // So, if we have enough '1's to form a '2', and enough '2's to form a '4', etc.,
        // up to '1024's to form a '2048', then we can win.
        // The total "value" that can be combined into 2048 is simply the sum of all numbers
        // that are less than or equal to 2048.
        current_sum += static_cast<long long>(val) * count;
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

