#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = n - 1; i >= 1; --i) {
        if (a[i] == b[i]) {
            // No operation needed for this element, or it's already correct.
            // The flags for has_pos_one and has_neg_one should reflect elements
            // from index 0 to i-1.
            if (a[i] == 1) {
                has_pos_one = true; // This element was 1, but it's at index i, so it doesn't affect elements before it.
                                    // The flags are for elements *available* to modify current a[i].
                                    // So, we need to update flags for elements from 0 to i-1.
            } else if (a[i] == -1) {
                has_neg_one = true;
            }
            continue;
        }

        if (b[i] > a[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                std::cout << "NO\n";
                return;
            }
        } else { // b[i] < a[i], need to decrease a[i]
            if (!has_neg_one) {
                std::cout << "NO\n";
                return;
            }
        }

        // Update flags for elements from 0 to i-1
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }

    std::cout << "YES\n";
}

