    int bad_prices_count = 0;
    int min_suffix = a[n - 1]; // Initialize with the last element

    // Iterate from right to left, excluding the last element
    // The last element can never be a bad price by definition
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix) {
