    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_r_pos = -1, it means the frog is at cell 0.
                             // If last_r_pos = i, it means the frog is at cell i.
                             // The distance to the next 'R' or n+1 is calculated from last_r_pos + 1.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1 (1-indexed).
                // The distance from the previous 'R' (or 0) to this 'R' is (i+1) - (last_r_pos + 1) + 1
                // which simplifies to i - last_r_pos.
                // Example: last_r_pos = -1 (at 0), current 'R' at s[0] (cell 1). Gap is 1 - (-1) = 2.
                // Example: last_r_pos = 0 (at cell 1), current 'R' at s[2] (cell 3). Gap is 2 - 0 = 2.
                max_gap = std::max(max_gap, i - last_r_pos);
                last_r_pos = i;
            }
        }

        // After iterating through the string, calculate the gap from the last 'R' to n+1.
        // The last 'R' was at index `last_r_pos` (cell `last_r_pos + 1`).
        // The target is cell `n + 1`.
        // The distance is (n + 1) - (last_r_pos + 1) = n - last_r_pos.
        max_gap = std::max(max_gap, n - last_r_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

