int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    // The total area of the carrot is (1/2) * base * height = (1/2) * 1 * h = h/2.
    // Each of the n pieces must have an area of (h/2) / n = h / (2n).

    // Consider the triangle formed by the apex and the i-th cut.
    // Let x_i be the distance from the apex to the i-th cut.
    // This smaller triangle is similar to the original carrot.
    // If its height is x_i, its base will be (x_i / h) * 1 = x_i / h.
    // The area of this smaller triangle is (1/2) * (x_i / h) * x_i = x_i^2 / (2h).

    // The area of the first piece (from apex to x_1) is A_1.
    // A_1 = x_1^2 / (2h).
    // Since A_1 must be equal to the area of one piece, A_1 = h / (2n).
    // So, x_1^2 / (2h) = h / (2n)
    // x_1^2 = h^2 / n
    // x_1 = sqrt(h^2 / n) = h / sqrt(n)

    // In general, the area of the triangle from the apex to the i-th cut (at x_i)
    // must be equal to the sum of the areas of the first i pieces.
    // This means the area of the triangle up to x_i is i * (h / (2n)).
    // So, x_i^2 / (2h) = i * (h / (2n))
    // x_i^2 = i * h^2 / n
    // x_i = sqrt(i * h^2 / n) = h * sqrt(i / n)

    // We need to calculate x_1, x_2, ..., x_{n-1}.
    std::cout << std::fixed << std::setprecision(12);
    for (int i = 1; i < n; ++i) {
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

