#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 0;
        long long k = 1; // Represents 2^0, 2^1, 2^2, ...
        while (true) {
            // Cost for a staircase with (2^k - 1) stairs
            // This is (2^k - 1) * (2^k) / 2
            // Which simplifies to (2^k - 1) * 2^(k-1)
            // Or, using the formula (2^k - 1) * (2^k + 1) / 2 for the sum of squares
            // No, the formula is (2^k - 1) * (2^k) / 2 for the number of cells.
            // The cost for a nice staircase with (2^k - 1) stairs is (2^k - 1) * (2^k) / 2.
            // Let's use the derived formula: 2^(k+1) * (2^k - 1) / 2 = 2^k * (2^k - 1)
            // This is the sum of cells for a staircase with (2^k - 1) stairs.
            // The actual cost for a nice staircase with (2^k - 1) stairs is (2^k - 1) * (2^k) / 2.
            // Let's re-derive the cost for a nice staircase with (2^k - 1) stairs.
            // The number of cells for a staircase with N stairs is N*(N+1)/2.
            // For N = 2^k - 1, the number of cells is (2^k - 1) * (2^k - 1 + 1) / 2
            // = (2^k - 1) * 2^k / 2
            // = (2^k - 1) * 2^(k-1)
            // This is the cost for a staircase with (2^k - 1) stairs.
            // The sequence of costs for nice staircases is:
            // n=1: 1*(1+1)/2 = 1
            // n=3: 3*(3+1)/2 = 6
            // n=7: 7*(7+1)/2 = 28
            // n=15: 15*(15+1)/2 = 120
            // These are (2^k - 1) * 2^(k-1) for k=1, 2, 3, 4...
            // For k=1, (2^1 - 1) * 2^(1-1) = 1 * 1 = 1
            // For k=2, (2^2 - 1) * 2^(2-1) = 3 * 2 = 6
            // For k=3, (2^3 - 1) * 2^(3-1) = 7 * 4 = 28
            // For k=4, (2^4 - 1) * 2^(4-1) = 15 * 8 = 120

            // The cost of the next smallest nice staircase is (2*k - 1) * k.
            // Where k here is 2^(i-1) for the i-th nice staircase.
            // Let's use `val` to represent the number of stairs `2^i - 1`.
            // Let `power_of_2` be `2^i`.
            // The number of stairs is `power_of_2 - 1`.
            // The cost is `(power_of_2 - 1) * power_of_2 / 2`.

            long long num_stairs = (k << 1) - 1; // 2^(i+1) - 1
            long long cost_of_this_staircase = num_stairs * (num_stairs + 1) / 2;

            if (current_cost + cost_of_this_staircase <= x) {
                current_cost += cost_of_this_staircase;
                count++;
                k = k << 1; // k becomes 2*k for the next iteration
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
