#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::vector<long long> cycle_sum(10);
    for (int i = 0; i < 10; ++i) {
        cycle_sum[i] = (i * 1LL) % 10;
    }

    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        if (m > n) {
            std::cout << 0 << "\n";
            continue;
        }

        long long k = n / m; // Number of terms in the sequence m, 2m, ..., km

        long long sum_of_first_10_last_digits = 0;
        for (int i = 1; i <= 10; ++i) {
            sum_of_first_10_last_digits += (i * m) % 10;
        }

        long long num_full_cycles = k / 10;
        long long remaining_terms = k % 10;

        long long total_sum = num_full_cycles * sum_of_first_10_last_digits;

        for (long long i = 1; i <= remaining_terms; ++i) {
            total_sum += (i * m) % 10;
        }

        std::cout << total_sum << "\n";
    }

    return 0;
}

