#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << std::fixed << std::setprecision(9) << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            double discriminant = d * d - 4.0 * d;
            // Since d >= 4, discriminant will be non-negative.
            // d^2 - 4d = d(d-4). If d=4, disc=0. If d>4, disc>0.
            double sqrt_discriminant = std::sqrt(discriminant);

            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = (d - sqrt_discriminant) / 2.0;

            // We need a and b to be non-negative.
            // Since d >= 4, d is positive.
            // sqrt_discriminant = sqrt(d(d-4)).
            // If d=4, sqrt_discriminant=0, a1=b1=2. Both non-negative.
            // If d>4, d-4 > 0, so sqrt_discriminant > 0.
            // d + sqrt_discriminant > 0. So a1 > 0.
            // d - sqrt_discriminant:
            // We know d^2 - 4d >= 0 => d^2 >= 4d.
            // Since d > 0, d >= 4.
            // So d >= sqrt(4d).
            // d >= sqrt(d^2 - (d^2 - 4d))
            // d >= sqrt(d^2 - discriminant)
            // d >= sqrt(d^2 - (d^2 - 4d)) = sqrt(4d)
            // d >= sqrt(4d) is true for d >= 4.
            // So d - sqrt(d^2 - 4d) >= 0.
            // Thus, b1 is also non-negative.

            std::cout << std::fixed << std::setprecision(9) << "Y " << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Find the longest possible strictly increasing prefix
    // a_1 < a_2 < ... < a_k
    // This implies a_i >= i-1 for i=1 to k
    // We can achieve this if a_i_original >= i-1
    int left_reach = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) { // a[i] must be at least i-1 for 1-indexed, or i for 0-indexed
            left_reach = i;
        } else {
            break;
        }
    }

    // Find the longest possible strictly decreasing suffix
    // a_k > a_{k+1} > ... > a_n
    // This implies a_i >= n-i for i=k to n
    // We can achieve this if a_i_original >= n-i
    int right_reach = n - 1;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1) - i) { // a[i] must be at least n-i for 1-indexed, or (n-1)-i for 0-indexed
            right_reach = i;
        } else {
            break;
        }
    }

    // If there is any k such that a_1 < ... < a_k and a_k > ... > a_n
    // This means there must be an overlap or touch point between the
    // achievable strictly increasing prefix and strictly decreasing suffix.
    // The index 'left_reach' is the largest index 'i' such that a[0...i] can form a strictly increasing sequence.
    // The index 'right_reach' is the smallest index 'i' such that a[i...n-1] can form a strictly decreasing sequence.
    // If left_reach >= right_reach, it means there's at least one index 'k'
    // that can serve as the peak.
    if (left_reach >= right_reach) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

