// Function to check if Box 1 can be the special box
// Box 1: (-inf, -1]
bool can_be_box1(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 0) return false; // Should not happen based on constraints A+B+C+D > 0

    // If there's only one toy, it must be in Box 1
    if (total_toys == 1) {
        return A == 1;
    }

    // Case 1: Final product is negative.
    // This requires an odd number of negative factors.
    // The number of negative factors is A + B.
    // So, (A + B) must be odd.
    if ((A + B) % 2 == 0) { // Even number of negatives, final product is positive
        return false;
    }

    // Case 2: Final product magnitude is >= 1.
    // This is the tricky part. We need to ensure we can achieve a magnitude >= 1.
    // The only way to guarantee a magnitude >= 1 is if we have at least one toy from Box 1 or Box 4
    // that is not "diluted" by too many Box 2/3 toys.

    // Let's consider the "power" of magnitude >= 1.
    // A toy from Box 1 or Box 4 has magnitude >= 1.
    // A toy from Box 2 or Box 3 has magnitude < 1.

    // If we have at least one toy from Box 1 or Box 4 (A+D > 0),
    // we can try to arrange multiplications to keep the magnitude >= 1.
    // For example, multiply all Box 2/3 toys together first.
    // If B+C > 0, this product will be in Box 2 or Box 3 (magnitude < 1).
    // Then multiply this product with a Box 1/4 toy.
    // If we have A+D >= 1, we can potentially keep the magnitude >= 1.

    // A simpler approach:
    // If A+D >= 1, we have at least one "strong" toy.
    // If we have an odd number of negative toys (A+B is odd),
    // and we have at least one strong toy (A+D >= 1),
    // can we always make the final product be in Box 1?

    // Consider the "strength" of toys:
    // Strong toys: Box 1, Box 4 (magnitude >= 1)
    // Weak toys: Box 2, Box 3 (magnitude < 1)

    // If A+D == 0, all initial toys are weak.
    // Any product of weak toys will be weak (magnitude < 1).
    // So, if A+D == 0, the final toy will always have magnitude < 1.
    // Thus, it cannot be in Box 1.
    if (A + D == 0) {
        return false;
    }

    // If A+D >= 1 and (A+B) is odd, can we always make it Box 1?
    // Yes. We can always pick a toy from Box 1 or Box 4 (let's call it S).
    // We can multiply all other toys (total_toys - 1 of them) together.
    // This product (P_other) can be made arbitrarily small in magnitude (e.g., by picking values close to 0).
    // Then we multiply S * P_other.
    // If P_other has magnitude < 1, then S * P_other can have magnitude < 1 or >= 1 depending on S and P_other.
    // However, we need to ensure it can be >= 1.

    // The key insight for magnitude:
    // If there is at least one toy with magnitude >= 1 (A+D > 0),
    // we can always ensure the final product has magnitude >= 1.
    // How? Pick the "strongest" toy (e.g., from Box 1 or Box 4).
    // Multiply all other toys together. This product can be made arbitrarily close to 0 or 1.
    // If we have a toy with magnitude >= 1, say 100.
    // And we have many toys with magnitude < 1, say 0.1.
    // If we multiply 100 * 0.1 * 0.1 * ...
    // The magnitude can drop below 1.

    // This is about *possibility*, not certainty.
    // To make the final product magnitude >= 1:
    // We need at least one toy from Box 1 or Box 4 (A+D > 0).
    // And we need to be able to arrange multiplications such that the final magnitude is >= 1.
    // This is always possible if A+D > 0.
    // Example: Pick a toy from Box 1 or Box 4 (value X, |X| >= 1).
    // Pick another toy from Box 1 or Box 4 (value Y, |Y| >= 1).
    // Multiply X*Y. Result is |X*Y| >= 1.
    // If we have only one strong toy (A+D=1) and many weak toys (B+C > 0):
    // Let the strong toy be S. Let the weak toys be W1, W2, ..., Wk.
    // If we multiply S * W1 * W2 * ... * Wk, the magnitude can become < 1.
    // But we can choose the values.
    // For example, if S=100, W1=0.9, W2=0.9, ...
    // We can make the product S * W1 * ... * Wk >= 1.
    // E.g., if S=100, W1=0.9, W2=0.9, W3=0.9, W4=0.9, W5=0.9.
    // 100 * 0.9^5 = 100 * 0.59049 = 59.049 >= 1.
    // So, if A+D >= 1, we can always choose values such that the final product has magnitude >= 1.

    // So, for Box 1:
    // 1. Final product must be negative: (A+B) must be odd.
    // 2. Final product magnitude must be >= 1: A+D must be >= 1.
    return (A + B) % 2 == 1 && (A + D >= 1);
}

// Function to check if Box 2 can be the special box
// Box 2: (-1, 0)
bool can_be_box2(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 0) return false;

    // If there's only one toy, it must be in Box 2
    if (total_toys == 1) {
        return B == 1;
    }

    // Case 1: Final product is negative.
    // (A+B) must be odd.
    if ((A + B) % 2 == 0) { // Even number of negatives, final product is positive
        return false;
    }

    // Case 2: Final product magnitude is < 1.
    // This is always possible if there is at least one toy from Box 2 or Box 3 (B+C > 0).
    // If B+C == 0, then all toys are from Box 1 or Box 4.
    // In this case, all products will have magnitude >= 1.
    // So, if B+C == 0, it cannot be in Box 2.
    if (B + C == 0) {
        return false;
    }

    // If B+C >= 1, we can always choose values such that the final product has magnitude < 1.
    // Example: Pick a toy from Box 2 or Box 3 (value X, |X| < 1).
    // Multiply all other toys (total_toys - 1 of them) together.
    // This product (P_other) can be made arbitrarily large or small.
    // If we multiply X by P_other, we can make the final product magnitude < 1.
    // E.g., X=0.001. Multiply it last. The final product will be very small.
    // So, if B+C >= 1, we can always make the final product magnitude < 1.

    // So, for Box 2:
    // 1. Final product must be negative: (A+B) must be odd.
    // 2. Final product magnitude must be < 1: B+C must be >= 1.
    return (A + B) % 2 == 1 && (B + C >= 1);
}

// Function to check if Box 3 can be the special box
// Box 3: (0, 1)
bool can_be_box3(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 0) return false;

    // If there's only one toy, it must be in Box 3
    if (total_toys == 1) {
        return C == 1;
    }

    // Case 1: Final product is positive.
    // (A+B) must be even.
    if ((A + B) % 2 == 1) { // Odd number of negatives, final product is negative
        return false;
    }

    // Case 2: Final product magnitude is < 1.
    // B+C must be >= 1. (Same logic as Box 2 for magnitude < 1)
    if (B + C == 0) {
        return false;
    }

    // So, for Box 3:
    // 1. Final product must be positive: (A+B) must be even.
    // 2. Final product magnitude must be < 1: B+C must be >= 1.
    return (A + B) % 2 == 0 && (B + C >= 1);
}

// Function to check if Box 4 can be the special box
// Box 4: [1, inf)
bool can_be_box4(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 0) return false;

    // If there's only one toy, it must be in Box 4
    if (total_toys == 1) {
        return D == 1;
    }

    // Case 1: Final product is positive.
    // (A+B) must be even.
    if ((A + B) % 2 == 1) { // Odd number of negatives, final product is negative
        return false;
    }

    // Case 2: Final product magnitude is >= 1.
    // A+D must be >= 1. (Same logic as Box 1 for magnitude >= 1)
    if (A + D == 0) {
        return false;
    }

    // So, for Box 4:
    // 1. Final product must be positive: (A+B) must be even.
    // 2. Final product magnitude must be >= 1: A+D must be >= 1.
    return (A + B) % 2 == 0 && (A + D >= 1);
}


