#include <iostream>
#include <string>
#include <vector>
#include <map>
#include <algorithm>

char get_winning_move(char bot_move) {
    if (bot_move == 'R') return 'P';
    if (bot_move == 'S') return 'R';
    if (bot_move == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        std::map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        char most_frequent_bot_move = ' ';
        int max_count = -1;

        // Check 'R'
        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_bot_move = 'R';
        }
        // Check 'S'
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_bot_move = 'S';
        }
        // Check 'P'
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_bot_move = 'P';
        }
        // If counts are equal, any choice is fine. The order of if statements
        // implicitly prioritizes R, then S, then P if counts are equal.
        // For example, if R=5, S=5, P=3, it will pick R.
        // If R=5, S=3, P=5, it will pick P.
        // This is fine as any of the most frequent will yield the same max_count.

        char our_optimal_move = get_winning_move(most_frequent_bot_move);

        for (int i = 0; i < n; ++i) {
            std::cout << our_optimal_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, m;
    std::cin >> n >> m;
    std::vector<bool> row_has_one(n, false);
    std::vector<bool> col_has_one(m, false);

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            int val;
            std::cin >> val;
            if (val == 1) {
                row_has_one[i] = true;
                col_has_one[j] = true;
            }
        }
    }

    int available_rows = 0;
    for (bool b : row_has_one) {
        if (!b) {
            available_rows++;
        }
    }

    int available_cols = 0;
    for (bool b : col_has_one) {
        if (!b) {
            available_cols++;
        }
    }

    int moves_possible = std::min(available_rows, available_cols);

    if (moves_possible % 2 == 1) {
        std::cout << "Ashish\n";
    } else {
        std::cout << "Vivek\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it can potentially form 'ab' with any 'a' to its left.
            // Each 'a' to its left will eventually interact with this 'b'.
            // When an 'a' interacts with this 'b' (i.e., 'ab' -> 'bba'),
            // that 'a' effectively "jumps over" this 'b' and becomes 'a' followed by two 'b's.
            // The number of 'a's currently accumulated (count_a) represents
            // the number of 'a's that are to the left of the current 'b'
            // and have not yet been processed (i.e., have not formed 'ab' with a 'b' further right).
            // Each of these 'count_a' 'a's will eventually form an 'ab' with this 'b'.
            // When 'ab' -> 'bba', the 'a' effectively moves past the 'b'.
            // The number of steps for this 'b' is equal to the number of 'a's to its left.
            // After this 'b' is processed, it effectively doubles the number of 'a's
            // that will interact with subsequent 'b's to its left.
            // This is because each 'a' that passes this 'b' (count_a)
            // will generate a new 'b' (from 'ab' -> 'bba').
            // So, for the next 'b' to the left, it will see the original 'a's
            // plus the new 'b's generated by the current 'b'.
            // The number of 'a's that will interact with the next 'b' to the left
            // effectively doubles for each 'b' encountered.
            // So, count_a becomes (count_a * 2) % mod.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it adds to the count of 'a's that are
            // available to form 'ab' with 'b's to its left.
            // This 'a' itself is one such 'a'.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <map>
#include <utility> // For std::pair

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::map<int, long long> x_counts;
    std::map<int, long long> y_counts;
    std::map<std::pair<int, int>, long long> xy_counts;

    for (int i = 0; i < n; ++i) {
        int x, y;
        std::cin >> x >> y;
        x_counts[x]++;
        y_counts[y]++;
        xy_counts[{x, y}]++;
    }

    long long total_pairs = 0;

    // Pairs with same x-coordinate
    for (auto const& [x_coord, count] : x_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Pairs with same y-coordinate
    for (auto const& [y_coord, count] : y_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Subtract pairs with same (x, y) coordinates (counted twice)
    for (auto const& [coords, count] : xy_counts) {
        if (count >= 2) {
            total_pairs -= count * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number to use for generating k distinct differences

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between the smallest available and largest available numbers
    // from the range [1, k+1].
    // Example: k=2. Range [1, 3].
    // p[0] = 1 (left)
    // p[1] = 3 (right) -> diff |1-3|=2
    // p[2] = 2 (left) -> diff |3-2|=1
    // Permutation: 1 3 2. Differences: 2, 1. Count = 2.
    //
    // Example: k=3. Range [1, 4].
    // p[0] = 1 (left)
    // p[1] = 4 (right) -> diff |1-4|=3
    // p[2] = 2 (left) -> diff |4-2|=2
    // p[3] = 3 (right) -> diff |2-3|=1
    // Permutation: 1 4 2 3. Differences: 3, 2, 1. Count = 3.

    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index, take from left (ascending)
            p[i] = left++;
        } else { // Odd index, take from right (descending)
            p[i] = right--;
        }
    }

    // The remaining n - (k + 1) elements should not introduce new distinct differences.
    // The simplest way to do this is to append the remaining numbers in increasing order.
    // These numbers are k+2, k+3, ..., n.
    // The last number placed was either `left-1` or `right+1`.
    // If `left-1` was placed, then `left` is the next available number from the small end.
    // If `right+1` was placed, then `right` is the next available number from the large end.
    // In either case, `left` will be `(k+1)/2 + 1` if `k` is odd, or `k/2 + 1` if `k` is even.
    // `right` will be `(k+1)/2 + 1` if `k` is even, or `k/2 + 1` if `k` is odd.
    // The numbers used are `1, ..., k+1`.
    // The next number to append should be `k+2`.
    // The difference `|p[k] - (k+2)|` will be `| (k+1)/2 + 1 - (k+2) |` or `| k/2 + 1 - (k+2) |`.
    // These differences will be `k/2 + 1` or `(k+1)/2 + 1`.
    // These values are already within the range `1, ..., k`.
    // For example, if k=2, p = 1 3 2. left=2, right=3.
    // Next number is 4. p[2]=2. |2-4|=2. This is already in {1,2}.
    // Next number is 5. p[3]=4. |4-5|=1. This is already in {1,2}.
    // So, just append numbers from `k+2` to `n` in increasing order.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // This is equivalent to `p[i] = p[i-1] + 1` if p[i-1] was `i`.
                      // More precisely, it's `p[i] = (k+1) + (i - (k+1)) + 1 = i+1`.
                      // The numbers used for the first k+1 elements are 1 to k+1.
                      // So the next available number is k+2.
                      // The last element of the first part is either `left-1` or `right+1`.
                      // The smallest unused number from 1 to k+1 is `left` if k is even, or `right` if k is odd.
                      // The largest unused number from 1 to k+1 is `right` if k is even, or `left` if k is odd.
                      // The numbers from `k+2` to `n` are appended.
                      // The difference `|p[i-1] - p[i]|` will be `1` for `i > k+1`.
                      // The difference `|p[k] - p[k+1]|` will be `|p[k] - (k+2)|`.
                      // `p[k]` is either `left-1` or `right+1`.
                      // If `k` is even, `p[k] = right+1 = k/2 + 1`. Then `|k/2 + 1 - (k+2)| = |-k/2 - 1| = k/2 + 1`.
                      // If `k` is odd, `p[k] = left-1 = (k+1)/2`. Then `|(k+1)/2 - (k+2)| = |-(k+3)/2| = (k+3)/2`.
                      // Both `k/2 + 1` and `(k+3)/2` are <= `k` for `k >= 1`.
                      // For k=1, (1+3)/2 = 2. This is > k.
                      // Let's re-evaluate the remaining part.
                      // The numbers used are 1 to k+1.
                      // The remaining numbers are k+2, ..., n.
                      // We should just append them in increasing order.
                      // The last element of the first part is `p[k]`.
                      // The next element is `k+2`.
                      // The difference `|p[k] - (k+2)|` will be `|p[k] - (k+2)|`.
                      // If `k` is even, `p[k]` is `k/2 + 1`. Difference is `|k/2 + 1 - (k+2)| = |-k/2 - 1| = k/2 + 1`.
                      // If `k` is odd, `p[k]` is `(k+1)/2`. Difference is `|(k+1)/2 - (k+2)| = |(k+1-2k-4)/2| = |(-k-3)/2| = (k+3)/2`.
                      // For k=1, p[0]=1, p[1]=2. (k+1)/2 = 1. (1+3)/2 = 2.
                      // The differences generated are 1.
                      // If k=1, p = 1 2 3 ... n. Differences are all 1. Count = 1.
                      // My construction for k=1: p[0]=1, p[1]=2. Then append 3, 4, ... n.
                      // This gives 1 2 3 ... n. Differences are all 1. Correct.
                      // For k=2, p = 1 3 2. Then append 4, 5, ... n.
                      // p = 1 3 2 4 5 ... n.
                      // Differences: |1-3|=2, |3-2|=1, |2-4|=2, |4-5|=1, ...
                      // Distinct differences are {1, 2}. Count = 2. Correct.
                      // The logic seems sound.
        p[i] = i + 1;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

