void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1]. Its length is 1. min is 1, max is 1.
        // For m > 1, we need to expand the segment to include 'm'.
        // The segment must contain all numbers from 1 to m.
        // This means the segment must span from the minimum index of {1..m} to the maximum index of {1..m}.
        // We maintain current_min_idx and current_max_idx for the numbers {1..m-1}.
        // When considering 'm', we update these indices to include pos[m].

        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number m is beautiful if the subsegment p[current_min_idx ... current_max_idx]
        // contains exactly the numbers 1, 2, ..., m.
        // This implies two conditions:
        // 1. The length of the subsegment must be m.
        // 2. The minimum value in the subsegment must be 1, and the maximum value must be m.
        // Our current_min_idx and current_max_idx are defined such that they span all numbers from 1 to m.
        // So, the minimum value in p[current_min_idx ... current_max_idx] is 1, and the maximum is m.
        // We only need to check the length.
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

