long long solve() {
    long long p, q;
    std::cin >> p >> q;

    if (p % q != 0) {
        return p;
    }

    // p is divisible by q. We need to find a divisor x of p such that x is not divisible by q.
    // We want the largest such x.
    // This means we need to remove factors from p such that the resulting number is no longer divisible by q,
    // but we want to remove the minimum possible value.
    // This is equivalent to finding a prime factor f of q, and dividing p by f until it's no longer divisible by q,
    // or until it's no longer divisible by q^k where q^k is the highest power of f that divides q.

    long long max_x = 1;

    // Find prime factors of q
    long long temp_q = q;
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            // i is a prime factor of q
            long long current_p = p;
            while (current_p % q == 0) {
                current_p /= i;
            }
            max_x = std::max(max_x, current_p);

            // Remove all occurrences of i from temp_q
            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }
    // If temp_q is still greater than 1, it means temp_q itself is a prime factor
    if (temp_q > 1) {
        long long current_p = p;
        while (current_p % q == 0) {
            current_p /= temp_q;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

