                if (d[i] >= last_color2_digit) {
                    current_coloring[i] = '2';
                    last_color2_digit = d[i];
                } else if (d[i] >= last_color1_digit) {
                    current_coloring[i] = '1';
                    last_color1_digit = d[i];
                } else {
