#include <iostream>
#include <string>
#include <vector>
#include <map>
#include <algorithm> // For std::reverse

// Function to convert a number to its parity pattern string
std::string to_parity_pattern(long long n) {
    if (n == 0) {
        return "0";
    }
    std::string pattern = "";
    while (n > 0) {
        if ((n % 10) % 2 == 0) {
            pattern += '0';
        } else {
            pattern += '1';
        }
        n /= 10;
    }
    // The pattern is built from right to left, so it's already in the correct order
    // for comparison (e.g., 123 -> "101" where 1 is parity of 3, 0 of 2, 1 of 1)
    // However, for map keys, we want a canonical form.
    // The problem states "parity of the i-th from the right digit in decimal notation matches the i-th from the right digit of the pattern."
    // And "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
    // "Similarly, if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
    // This means we need to pad both to a common length (e.g., 18 digits) with '0's.
    // A simpler approach is to always store patterns of length 18.
    // The pattern generated here is already reversed (rightmost digit's parity is first char).
    // Example: 241 -> 101 (1 for 1, 0 for 4, 1 for 2).
    // If we pad this to 18, it would be "101000000000000000".
    // The problem states "0 stands for the even digits, while 1 stands for the odd."
    // "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
    // This means if the number is 92, its pattern is "10" (9 is odd, 2 is even).
    // If the query pattern is "010", it's "010".
    // To compare, we align from the right.
    // 92: ...00000000000000010
    // 010: ...000000000000000010
    // This means the canonical form should be padded with '0's on the left to a fixed length.
    // The `pattern` string built here has the rightmost digit's parity at index 0.
    // So, if we pad it to 18 characters with '0's, it should be `pattern + "00..."`.
    // Example: 92 -> "10". Padded to 18: "100000000000000000".
    // Example: 241 -> "101". Padded to 18: "101000000000000000".
    // This is the correct canonical form for map keys.
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;
        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern to 18 characters with '0's on the right
            // because the `to_parity_pattern` function also pads on the right.
            // This ensures consistent key generation.
            while (s.length() < 18) {
                s += '0';
            }
            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}

