void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj_map;
    for (char c = 'a'; c <= 'z'; ++c) {
        adj_map[c] = {};
    }

    for (size_t i = 0; i < s.length() - 1; ++i) {
        char c1 = s[i];
        char c2 = s[i+1];
        adj_map[c1].insert(c2);
        adj_map[c2].insert(c1);
    }

    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj_map[c].size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::set<char> visited_in_layout;

    // Find a starting point for a chain: a character with only one required neighbor
    char start_char = '\0';
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj_map[c].size() == 1) {
            start_char = c;
            break;
        }
    }

    // If no char has 1 neighbor, it means all chars in password have 2 neighbors (a cycle)
    // Or, the password is a single character.
    // Or, the password is empty (not possible by constraints).
    if (start_char == '\0' && !s.empty()) {
        // If all characters in the password have 2 neighbors, it implies a cycle.
        // We can pick any character from the password as a starting point.
        // If s is "ab", adj_map['a']={b}, adj_map['b']={a}. Both have size 1.
        // If s is "abc", adj_map['a']={b}, adj_map['b']={a,c}, adj_map['c']={b}. 'a' and 'c' have size 1.
        // If s is "abacaba", adj_map['a']={b,c}, adj_map['b']={a}, adj_map['c']={a}. 'b' and 'c' have size 1.
        // The only case where all chars in password have 2 neighbors is if the password forms a cycle, e.g., "abcb" (not allowed by problem statement, no adjacent equal chars).
        // Or if the password is just one character, e.g., "a".
        // If s is "a", adj_map['a'] is empty. start_char will be '\0'.
        // If s is "ab", start_char will be 'a' or 'b'.
        // So, if start_char is '\0' and s is not empty, it means all characters in the password have 0 or 2 neighbors.
        // If there's any character from the password with 2 neighbors, it must be part of a cycle.
        // If there are no characters with 1 neighbor, and there are characters with 2 neighbors, it means we have a cycle.
        // Example: s = "abcda" -> 'a'={b,d}, 'b'={a,c}, 'c'={b,d}, 'd'={a,c}. All have 2 neighbors. This is a NO case.
        // The only way to have a valid layout with all password chars having 2 neighbors is if the password itself forms a single chain that uses all 26 letters, which is highly unlikely.
        // More generally, if all characters involved in the password have 2 neighbors, it means they form one or more cycles.
        // A keyboard layout is a single linear chain. It cannot contain cycles.
        // So, if start_char is still '\0' and s is not empty, it means all characters in `s` have 2 neighbors (forming cycles) or 0 neighbors.
        // If there's any character in `s` that has 2 neighbors, it implies a cycle, which is impossible for a linear layout.
        // If all characters in `s` have 0 neighbors (i.e., `s` has length 1), then `start_char` would be `s[0]`.
        // So, if `start_char` is `\0` and `s` is not empty, it means there's a character in `s` with 2 neighbors, and no character in `s` with 1 neighbor. This implies a cycle.
        // Example: s = "abcda". 'a' has {b,d}, 'b' has {a,c}, 'c' has {b,d}, 'd' has {a,c}. All have 2 neighbors. This is a NO.
        // The only exception is if s is a single character, e.g., "a". Then adj_map['a'] is empty, start_char would be 'a'.
        // So, if start_char is '\0' here, it means there's a cycle.
        bool has_two_neighbor_char_in_s = false;
        for(char c : s) {
            if (adj_map[c].size() == 2) {
                has_two_neighbor_char_in_s = true;
                break;
            }
        }
        if (has_two_neighbor_char_in_s) {
            std::cout << "NO\n";
            return;
        }
        // If s is "a", adj_map['a'] is empty. start_char will be 'a'.
        // If s is "ab", adj_map['a']={b}, adj_map['b']={a}. start_char will be 'a'.
        // So, if start_char is '\0' here, it means s is empty, which is not allowed by constraints.
        // Or, it means all characters in s have 0 neighbors, which means s has length 1.
        // If s has length 1, say "a", then adj_map['a'] is empty. start_char would be 'a'.
        // So, this `if (start_char == '\0' && !s.empty())` block should only be reached if there's a cycle.
        // The logic for finding start_char needs to be robust for single-char passwords.
        // If s is "a", adj_map['a'] is empty. The loop for start_char will find 'a' if it's the first char with 0 neighbors.
        // Let's refine start_char logic:
        // If s is "a", adj_map['a'] is empty.
        // If s is "ab", adj_map['a']={b}, adj_map['b']={a}.
        // If s is "abc", adj_map['a']={b}, adj_map['b']={a,c}, adj_map['c']={b}.
        // A character with 0 neighbors (if it's in `s`) or 1 neighbor (if it's in `s`) can be a start.
        // If all characters in `s` have 2 neighbors, then it's a cycle.
        // Let's find a starting character for the layout.
        // It must be a character that is part of the password.
        // If s is "a", start_char should be 'a'.
        // If s is "ab", start_char should be 'a' or 'b'.
        // If s is "abc", start_char should be 'a' or 'c'.
        // So, start_char should be any character from `s` that has 0 or 1 required neighbors.
        // If all characters in `s` have 2 required neighbors, then it's a cycle, and impossible.
        start_char = '\0';
        for (char c : s) {
            if (adj_map[c].size() <= 1) { // 0 for single char password, 1 for end of chain
                start_char = c;
                break;
            }
        }
        if (start_char == '\0' && !s.empty()) { // All chars in s have 2 neighbors, implies cycle
            std::cout << "NO\n";
            return;
        }
    }

    if (s.empty()) { // Should not happen based on constraints (1 <= |s|)
        // Handle empty string case if needed, but problem says |s| >= 1
        std::cout << "YES\n";
        std::cout << "abcdefghijklmnopqrstuvwxyz\n";
        return;
    }

    // If s is "a", start_char will be 'a'. adj_map['a'] is empty.
    // If s is "ab", start_char will be 'a'. adj_map['a']={b}.
    // If s is "abc", start_char will be 'a'. adj_map['a']={b}.

    if (start_char == '\0') { // This means s was not empty, but no char in s had 0 or 1 neighbors.
                              // This implies s contains only characters that have 2 neighbors, forming a cycle.
                              // This case should have been caught by the previous `if (start_char == '\0' && !s.empty())` block.
                              // The only way start_char is still '\0' here is if s was empty, which is not allowed.
                              // Or if s has length 1, e.g., "a", then adj_map['a'] is empty, so start_char would be 'a'.
                              // So, this branch should not be reached.
        // Fallback for single character password, e.g., "a"
        start_char = s[0];
    }


    char current_char = start_char;
    char prev_char = '\0'; // Sentinel for the first character

    while (current_char != '\0' && visited_in_layout.find(current_char) == visited_in_layout.end()) {
        layout += current_char;
        visited_in_layout.insert(current_char);

        char next_char = '\0';
        for (char neighbor : adj_map[current_char]) {
            if (neighbor != prev_char) {
                next_char = neighbor;
                break;
            }
        }
        prev_char = current_char;
        current_char = next_char;
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

