    // If we remove `k` jars from the left (jars 1 to k), the remaining left jars are `k+1` to `n`.
    // The difference of these remaining jars is `diff_left_prefix[n] - diff_left_prefix[k]`.
    // Let's rephrase: `left_diff_map[d]` stores the minimum number of jars removed from the left
    // to achieve a difference `d` among the remaining left jars.
    // The jars are 0-indexed: a[0]...a[n-1] are left, a[n]...a[2n-1] are right.
    // If we remove `k` jars from the left, we remove a[0]...a[k-1].
    // The remaining left jars are a[k]...a[n-1].
    // The difference of these remaining jars is `current_left_total_diff - current_left_removed_diff`.
    // Let's compute `diff_left_suffix[k]` = sum(a[k]...a[n-1])
    // `diff_left_suffix[k]` is the difference of jars remaining on the left if we remove `k` jars from the left.
    std::map<int, int> left_diff_to_removed_count; // map<diff, removed_count>
    int current_left_diff = 0;
    left_diff_to_removed_count[0] = 0; // If 0 jars removed from left, diff is 0 (empty set)
                                        // This is for the case where we remove all n jars from left.
                                        // The actual meaning is: if we remove `k` jars from the left,
                                        // the remaining `n-k` jars have a certain difference.
                                        // Let's compute the difference of the *remaining* left jars.
                                        // `left_diff_to_removed_count[d]` stores the minimum `k` such that
                                        // the suffix `a[k...n-1]` has difference `d`.

    // Calculate suffix differences for the left side (jars a[k]...a[n-1])
    // Iterate from right to left for the left half
    // `current_left_diff` will be the difference of `a[i...n-1]`
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 1) {
            current_left_diff++;
        } else {
            current_left_diff--;
        }
        int removed_count = n - i; // Number of jars removed from a[0]...a[i-1]
                                   // No, this is the number of jars remaining from a[i]...a[n-1]
                                   // The number of jars removed from the left is `i`.
                                   // If we keep jars `a[i]` to `a[n-1]`, we removed `i` jars.
        left_diff_to_removed_count[current_left_diff] = n - i; // `n-i` is the number of jars removed from the left (a[0]...a[i-1])
                                                                // No, `n-i` is the number of jars remaining.
                                                                // The number of jars removed is `i`.
                                                                // Let's use `k` as the number of jars removed from the left.
                                                                // If `k` jars are removed, we keep `a[k...n-1]`.
                                                                // `current_left_diff` is the diff of `a[i...n-1]`.
                                                                // So, `k = i`.
        left_diff_to_removed_count[current_left_diff] = i; // `i` jars removed from left (a[0]...a[i-1])
    }
    // Add the case where all `n` jars are removed from the left.
    // The remaining left jars are 0, so their difference is 0.
    // This corresponds to `i=n`, so `n` jars removed.
    left_diff_to_removed_count[0] = std::min(left_diff_to_removed_count.count(0) ? left_diff_to_removed_count[0] : n, n);


    // Calculate prefix sums for the right side (jars n+1 to 2n)
    // `right_diff_to_removed_count[d]` stores the minimum `k` such that
    // the prefix `a[n...n+k-1]` has difference `d`.
    std::map<int, int> right_diff_to_removed_count; // map<diff, removed_count>
    int current_right_diff = 0;
    right_diff_to_removed_count[0] = 0; // If 0 jars removed from right, diff is 0 (empty set)
                                        // This is for the case where we remove all n jars from right.

    // Iterate from left to right for the right half
    // `current_right_diff` will be the difference of `a[n...i]`
    for (int i = n; i < 2 * n; ++i) {
        if (a[i] == 1) {
            current_right_diff++;
        } else {
            current_right_diff--;
        }
        int removed_count = i - n + 1; // Number of jars remaining from a[n]...a[i]
                                       // The number of jars removed from the right is `n - (i - n + 1)`.
                                       // No, this is the number of jars removed from the right.
                                       // If we keep jars `a[n]` to `a[i]`, we removed `2n-1 - i` jars from the right.
                                       // Let `k` be the number of jars removed from the right.
                                       // If `k` jars are removed, we keep `a[n...2n-1-k]`.
                                       // `current_right_diff` is the diff of `a[n...i]`.
                                       // So, `k = (2n-1) - i`.
        right_diff_to_removed_count[current_right_diff] = (2 * n - 1) - i; // `(2n-1)-i` jars removed from right (a[i+1]...a[2n-1])
    }
    // Add the case where all `n` jars are removed from the right.
    // The remaining right jars are 0, so their difference is 0.
    // This corresponds to `i=n-1` (conceptually), so `n` jars removed.
    right_diff_to_removed_count[0] = std::min(right_diff_to_removed_count.count(0) ? right_diff_to_removed_count[0] : n, n);


    int min_removed_jars = 2 * n; // Max possible removed jars

    // Iterate through all possible differences for the left side
    for (auto const& [left_rem_diff, left_removed_count] : left_diff_to_removed_count) {
        // We want (initial_diff - left_rem_diff - right_rem_diff) = 0
        // So, right_rem_diff = initial_diff - left_rem_diff
        int target_right_rem_diff = initial_diff - left_rem_diff;

        if (right_diff_to_removed_count.count(target_right_rem_diff)) {
            int right_removed_count = right_diff_to_removed_count[target_right_rem_diff];
            min_removed_jars = std::min(min_removed_jars, left_removed_count + right_removed_count);
        }
    }

    std::cout << min_removed_jars << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to apply median smoothing once
std::vector<int> apply_median_smoothing(const std::vector<int>& a) {
    int n = a.size();
    if (n < 3) { // Should not happen based on constraints (n >= 3)
        return a;
    }
    std::vector<int> b(n);
    b[0] = a[0];
    b[n - 1] = a[n - 1];
    for (int i = 1; i < n - 1; ++i) {
        int sum = a[i - 1] + a[i] + a[i + 1];
        b[i] = (sum >= 2) ? 1 : 0;
    }
    return b;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Constraints say n >= 3, but good to be robust
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    // Find the first 0-1 transition from left
    int first_one_idx = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            first_one_idx = i;
            break;
        }
    }

    // Find the last 1-0 transition from right
    int last_zero_idx = -1;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 0) {
            last_zero_idx = i;
            break;
        }
    }

    if (first_one_idx == -1 || last_zero_idx == -1 || first_one_idx > last_zero_idx) {
        // Sequence is all 0s or all 1s, or already stable (e.g., 000111)
        // In these cases, the sequence is already stable.
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    // Calculate max_k
    int max_k = 0;
    int current_len = 0;
    for (int i = first_one_idx; i <= last_zero_idx; ++i) {
        if (a[i] == 0) {
            current_len++;
        } else {
            max_k = std::max(max_k, (current_len + 1) / 2);
            current_len = 0;
        }
    }
    max_k = std::max(max_k, (current_len + 1) / 2); // For the last segment of zeros

    // Apply smoothing max_k times
    std::vector<int> current_seq = a;
    for (int k = 0; k < max_k; ++k) {
        current_seq = apply_median_smoothing(current_seq);
    }

    std::cout << max_k << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << current_seq[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

