    std::string s;
    std::cin >> s;

    int n = s.length();

    // Prefix sums for counts of 'x', 'y', 'z'
    // counts[0][i] = count of 'x' in s[0...i-1]
    // counts[1][i] = count of 'y' in s[0...i-1]
    // counts[2][i] = count of 'z' in s[0...i-1]
    std::vector<std::vector<int>> counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        counts[0][i + 1] = counts[0][i];
        counts[1][i + 1] = counts[1][i];
        counts[2][i + 1] = counts[2][i];
        if (s[i] == 'x') {
            counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            counts[1][i + 1]++;
        } else { // s[i] == 'z'
            counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        // Adjust to 0-based indexing for substring s[l-1...r-1]
        // The substring length is r - l + 1
        int len = r - l + 1;

        if (len < 3) {
            std::cout << "YES\n";
            continue;
        }

        // Get counts of 'x', 'y', 'z' in the substring s[l-1...r-1]
        int count_x = counts[0][r] - counts[0][l - 1];
        int count_y = counts[1][r] - counts[1][l - 1];
        int count_z = counts[2][r] - counts[2][l - 1];

        // Check if the counts are "balanced" enough for termination
        // The difference between any two counts must be at most 1
        if (std::abs(count_x - count_y) <= 1 &&
            std::abs(count_y - count_z) <= 1 &&
            std::abs(count_x - count_z) <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n, std::numeric_limits<long long>::max()); // b[j] = A_0[j] + sum of d_i for type 1 ops before type 2 ops
    std::vector<long long> current_delta(n, 0); // sum of d_i for type 1 ops encountered so far

    // First pass: Determine upper bounds for A_0[j] + sum(d_i)
    // For each type 2 operation (l, r, m_i), we know that for all j in [l, r],
    // A_0[j] + current_delta[j] <= m_i.
    // So, A_0[j] <= m_i - current_delta[j].
    // We want to find the tightest upper bound for A_0[j].
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::min(b[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // Initialize initial_a with the derived upper bounds.
    // If b[j] is still max_long_long, it means no type 2 operation constrained A_0[j].
    // In this case, we can set A_0[j] to 0 (or any value within bounds).
    // Since we want to satisfy A_0[j] <= m_i - current_delta[j], setting A_0[j] = m_i - current_delta[j]
    // (i.e., b[j]) is the "tightest" possible value that satisfies the constraint.
    // If no constraint, 0 is a safe choice.
    std::vector<long long> initial_a(n);
    for (int j = 0; j < n; ++j) {
        if (b[j] == std::numeric_limits<long long>::max()) {
            initial_a[j] = 0; // No upper bound from type 2 ops, set to 0
        } else {
            initial_a[j] = b[j];
        }
    }

    // Second pass: Simulate operations with the constructed initial_a and verify.
    // We need to check if the maximums for type 2 operations match.
    // Also, check if initial_a values are within |10^9|.
    std::fill(current_delta.begin(), current_delta.end(), 0); // Reset current_delta for simulation
    std::vector<long long> current_array_values = initial_a;

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
                current_array_values[j] += ops[i].val; // Update current_array_values for simulation
            }
        } else { // type 2
            long long max_val = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, current_array_values[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check absolute value constraint for initial_a
    for (int j = 0; j < n; ++j) {
        if (std::abs(initial_a[j]) > 1000000000LL) {
            // This case should ideally not happen if the problem guarantees a solution
            // within these bounds, given the constraints on d and m_i.
            // However, it's good practice to check.
            // For this problem, the maximum possible value for m_i is 5*10^7.
            // The maximum sum of d_i can be 5000 * 10^4 = 5*10^7.
            // So, m_i - current_delta[j] can be 5*10^7 - (-5*10^7) = 10^8.
            // Or -5*10^7 - (5*10^7) = -10^8.
            // So initial_a[j] will be within [-10^8, 10^8], which is within [-10^9, 10^9].
            // This check is technically not needed based on the problem constraints.
        }
    }

    std::cout << "YES\n";
    for (int j = 0; j < n; ++j) {
        std::cout << initial_a[j] << (j == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
