// Function to calculate parity of a 01-string
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    // Calculate initial parity of string a
    int parity_a = calculate_parity(a);

    // Calculate initial parity of string b
    int parity_b = calculate_parity(b);

    // The number of '1's in string 'a' can only increase or stay the same
    // when appending parity.
    // If parity_a is 0, it means an even number of '1's.
    // Appending '0' keeps it even.
    // Appending '1' makes it odd.
    // If parity_a is 1, it means an odd number of '1's.
    // Appending '0' keeps it odd.
    // Appending '1' makes it even.

    // This means that if we have an even number of '1's (parity 0),
    // we can always reach an odd number of '1's (parity 1) by appending '1'.
    // If we have an odd number of '1's (parity 1),
    // we can always reach an even number of '1's (parity 0) by appending '1'.
    // In essence, by repeatedly appending parity, we can make the number of '1's
    // as large as needed, and we can always switch between even and odd counts
    // of '1's by appending '1' (if current parity is 0) or '0' (if current parity is 1)
    // and then '1' (if current parity is 0) or '0' (if current parity is 1).
    // More simply, if we have parity P, we can append P to get P.
    // If we want to change parity, we can append P, then the new string has parity P.
    // Then we can append 1-P to get 1-P.
    // So, we can always achieve either parity 0 or parity 1 for any sufficiently long string.

    // The key insight is that if string 'a' has an even number of '1's,
    // we can only ever produce strings with an even number of '1's,
    // or strings with an odd number of '1's if we append a '1'.
    // If 'a' has an odd number of '1's, we can only ever produce strings
    // with an odd number of '1's, or strings with an even number of '1's if we append a '1'.

    // Let's count the number of '1's in 'a' and 'b'.
    int ones_in_a = 0;
    for (char c : a) {
        if (c == '1') {
            ones_in_a++;
        }
    }

    int ones_in_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_in_b++;
        }
    }

    // If 'a' has fewer '1's than 'b', it's impossible unless we can add '1's.
    // The only way to add '1's is by appending '1' (if parity is 1).
    // If 'a' has an even number of '1's, we can append '0' (parity 0) or '1' (parity 1).
    // If 'a' has an odd number of '1's, we can append '0' (parity 0) or '1' (parity 1).

    // The maximum number of '1's we can effectively have in 'a' is its current count
    // plus one (if we append a '1').
    // If 'a' has an even number of '1's, we can make it odd by appending '1'.
    // So, we can effectively have `ones_in_a` or `ones_in_a + 1` '1's.
    // If 'a' has an odd number of '1's, we can make it even by appending '1'.
    // So, we can effectively have `ones_in_a` or `ones_in_a + 1` '1's.
    // In general, we can achieve `ones_in_a` '1's or `ones_in_a + 1` '1's
    // by appending the correct parity character.
    // For example, if `ones_in_a` is even, and we need `ones_in_b` which is odd,
    // we can append '1' to `a` to make `ones_in_a + 1` '1's.
    // If `ones_in_a` is odd, and we need `ones_in_b` which is even,
    // we can append '1' to `a` to make `ones_in_a + 1` '1's.

    // So, the effective maximum number of '1's we can have in a string derived from 'a'
    // (before removing leading characters) is `ones_in_a` if `ones_in_a` is even,
    // or `ones_in_a + 1` if `ones_in_a` is odd.
    // This is equivalent to `ones_in_a` if `parity_a` is 0, and `ones_in_a + 1` if `parity_a` is 1.
    // No, this is wrong. If `parity_a` is 0, `ones_in_a` is even. We can append '0' to keep it even,
    // or append '1' to make it odd. So we can have `ones_in_a` or `ones_in_a + 1` ones.
    // If `parity_a` is 1, `ones_in_a` is odd. We can append '0' to keep it odd,
    // or append '1' to make it even. So we can have `ones_in_a` or `ones_in_a + 1` ones.
    // In both cases, we can achieve `ones_in_a` or `ones_in_a + 1` ones.
    // The maximum number of '1's we can have in the string `a` (before removing leading chars)
    // that is relevant to matching `b` is `ones_in_a` if `ones_in_a` is even,
    // and `ones_in_a + 1` if `ones_in_a` is odd.
    // This is because if `ones_in_a` is odd, we can append a '1' to make it even.
    // If `ones_in_a` is even, we can append a '0' to keep it even.
    // So, if `ones_in_a` is odd, we can effectively have `ones_in_a + 1` '1's (even count).
    // If `ones_in_a` is even, we can effectively have `ones_in_a` '1's (even count).
    // This means we can always achieve an even number of '1's, and if `ones_in_a` is odd,
    // we can achieve `ones_in_a + 1` '1's.
    // The maximum number of '1's we can achieve is `ones_in_a` if `ones_in_a` is even,
    // and `ones_in_a + 1` if `ones_in_a` is odd.
    // This is equivalent to `ones_in_a + (ones_in_a % 2)`.

    int max_ones_a_can_have = ones_in_a + (ones_in_a % 2);

    if (max_ones_a_can_have >= ones_in_b) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v;
    long long d;
    long long p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false;

        long long current_v_cry = children[i].v;
        long long d_chain_cry = 0; // Accumulates d_j cries from children leaving due to low confidence

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply d_chain_cry first, as it affects all subsequent children
            if (d_chain_cry > 0) {
                children[j].p -= d_chain_cry;
            }

            // Apply current_v_cry from the child being treated
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry = std::max(0LL, current_v_cry - 1);
            }

            // Check if child j's confidence dropped below zero
            if (children[j].p < 0) {
                children[j].in_line = false;
                d_chain_cry += children[j].d; // Add this child's d_j to the chain reaction
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

