int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1; // Max possible operations for any element is m-1 (e.g., 0 -> m-1)
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // All f(a_i, a_j) = a_i + a_j.
    // min_f = elements[0].value + elements[1].value
    // max_f = elements[n-1].value + elements[n-2].value
    // Goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)
    long long goodness1 = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);
    std::vector<int> partition1(n, 1);

    // Case 2: Partition into two non-empty subsequences.
    // The strategy is to put elements[0] and elements[1] in different subsequences.
    // This ensures that elements[0] + elements[1] + h is one of the f values.
    // To minimize max_f, we want elements[n-1] and elements[n-2] to be in the same subsequence.
    // This makes max_f = elements[n-1].value + elements[n-2].value.
    // The minimum f value will be elements[0].value + elements[1].value + h.
    // The maximum f value will be elements[n-1].value + elements[n-2].value.
    // The other f values are:
    //   - elements[0].value + elements[k].value + h (k > 1)
    //   - elements[1].value + elements[k].value + h (k > 1)
    //   - elements[i].value + elements[j].value (i,j > 1)
    //   - elements[0].value + elements[k].value (k > 1, if in same group)
    //   - elements[1].value + elements[k].value (k > 1, if in same group)
    //
    // The critical observation is that if elements[0] and elements[1] are in different groups,
    // then f(elements[0], elements[1]) = elements[0].value + elements[1].value + h.
    // This is the smallest possible sum involving h.
    // The smallest possible sum not involving h is elements[0].value + elements[2].value (if elements[0] and elements[2] are in the same group).
    // Or elements[1].value + elements[2].value (if elements[1] and elements[2] are in the same group).
    //
    // Let's try a specific partition:
    // elements[0] in S1, elements[1] in S2.
    // All other elements (elements[2] to elements[n-1]) in S2.
    //
    // S1: {elements[0]}
    // S2: {elements[1], elements[2], ..., elements[n-1]}
    //
    // Possible f values:
    // 1. Pairs within S1: None (S1 has only 1 element).
    // 2. Pairs within S2: elements[i].value + elements[j].value for 1 <= i < j <= n-1.
    //    Min of these: elements[1].value + elements[2].value
    //    Max of these: elements[n-1].value + elements[n-2].value
    // 3. Pairs across S1 and S2: elements[0].value + elements[j].value + h for 1 <= j <= n-1.
    //    Min of these: elements[0].value + elements[1].value + h
    //    Max of these: elements[0].value + elements[n-1].value + h
    //
    // Overall min_f for this partition:
    // min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    //
    // Overall max_f for this partition:
    // max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)
    //
    // Goodness for this partition: max_f - min_f.
    //
    // This partition is: elements[0] in group 1, all others in group 2.
    // min_f_candidate = elements[0].value + elements[1].value + h;
    // max_f_candidate = elements[n-1].value + elements[n-2].value;
    //
    // If elements[0].value + elements[1].value + h > elements[n-1].value + elements[n-2].value,
    // then the minimum f value is elements[0].value + elements[1].value + h.
    // The maximum f value is elements[0].value + elements[n-1].value + h.
    // Goodness = (elements[0].value + elements[n-1].value + h) - (elements[0].value + elements[1].value + h)
    //          = elements[n-1].value - elements[1].value.
    // This is the case where h is very large.
    //
    // If elements[0].value + elements[1].value + h <= elements[n-1].value + elements[n-2].value,
    // then the minimum f value is elements[0].value + elements[1].value + h.
    // The maximum f value is elements[n-1].value + elements[n-2].value.
    // Goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value + h).
    // This is the case where h is not too large.

    long long min_f_val_case2;
    long long max_f_val_case2;

    // The smallest sum without h is elements[1].value + elements[2].value (from S2).
    // The smallest sum with h is elements[0].value + elements[1].value + h (across S1 and S2).
    min_f_val_case2 = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);

    // The largest sum without h is elements[n-1].value + elements[n-2].value (from S2).
    // The largest sum with h is elements[0].value + elements[n-1].value + h (across S1 and S2).
    max_f_val_case2 = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h);

    long long goodness2 = max_f_val_case2 - min_f_val_case2;
    std::vector<int> partition2(n);
    partition2[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[elements[i].original_index] = 2;
    }

    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k = 1 (2 pieces)
    // Try all possible single cuts
    for (int i = 1; i < n; ++i) { // i is the length of the first piece
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);

        std::string new_s = s2 + s1;

        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k = 2 (3 pieces)
    // The problem statement guarantees s is a palindrome.
    // If all characters in s are the same (e.g., "qqqq"), then no matter how we cut and reorder,
    // the resulting string will always be the same as s.
    // In this specific case, it's impossible to form a new palindrome.
    // We can check this by counting distinct characters.

    // Count distinct characters in the first half of the string (or first half + middle for odd length)
    // Since s is a palindrome, if all chars are same, s[0] == s[1] == ... == s[n-1].
    // If there's at least one character different from s[0], then we can potentially form a new palindrome.

    bool all_same_char = true;
    if (n > 0) { // Ensure string is not empty, though constraints say 1 <= |s|
        char first_char = s[0];
        for (int i = 1; i < n / 2; ++i) { // Check up to n/2 - 1
            if (s[i] != first_char) {
                all_same_char = false;
                break;
            }
        }
    }

    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work, then k=2 is always possible.
        // Example: "nolon" -> "no|l|on" -> "on|l|no" (k=2)
        // The strategy is to cut off the first character, the last character, and leave the middle.
        // For example, s = c_1 c_2 ... c_k ... c_2 c_1
        // Cut into s[0], s[1...n-2], s[n-1]
        // Pieces: s[0], s.substr(1, n-2), s[n-1]
        // Reorder to: s[n-1] + s.substr(1, n-2) + s[0]
        // Since s is a palindrome, s[0] == s[n-1].
        // This reordering results in the original string.
        //
        // A different strategy for k=2:
        // Consider the string s. Since not all characters are the same, there must be some s[i] != s[0] for i < n/2.
        // Let's take s = "abacaba". n=7. s[0]='a'. s[1]='b'.
        // Cut into s[0...i-1] | s[i] | s[i+1...n-1]
        // This is not what the problem means by k=2.
        //
        // The problem states: "cut the paper minimum number of times k, so they got k+1 pieces of paper with substrings of the initial string, and then unite those pieces together to get a new string."
        //
        // If k=1 doesn't work, it means for any split s = s1 + s2, s2 + s1 is either s or not a palindrome.
        //
        // Consider the string s. If it's not all same characters, then there exists at least one character s[i] such that s[i] != s[0] for i < n/2.
        //
        // Let's take the example "nolon". n=5.
        // k=1:
        // n|olon -> olonn (not pal)
        // no|lon -> lonno (not pal)
        // nol|on -> onnol (not pal)
        // nolo|n -> nnolo (not pal)
        //
        // k=2:
        // "no|l|on" -> pieces: "no", "l", "on"
        // Reorder to "on" + "l" + "no" = "onlno". This is a palindrome and != "nolon".
        // So k=2 is possible.
        //
        // The logic is: if not all characters are the same, then there must be at least two distinct characters.
        // Since s is a palindrome, if s[i] != s[0] for some i < n/2, then s[n-1-i] != s[n-1].
        //
        // If k=1 fails, it means for any split s = A + B, the string B + A is either s itself or not a palindrome.
        //
        // If s is not composed of all identical characters, then it's always possible to achieve k=2.
        // Consider the string s. Since it's a palindrome and not all characters are the same,
        // there must be at least one character `c` such that `c != s[0]` and `c` appears in `s`.
        //
        // Let's take the first character `s[0]`.
        // If `s` is not all same characters, then there exists some `i` such that `s[i] != s[0]`.
        // Since `s` is a palindrome, `s[i] == s[n-1-i]`.
        //
        // Consider cutting `s` into `s[0]`, `s.substr(1, n-2)`, `s[n-1]`.
        // Pieces: `s[0]`, `s_middle = s.substr(1, n-2)`, `s[n-1]`.
        // Since `s` is a palindrome, `s[0] == s[n-1]`.
        // If we reorder them as `s[n-1] + s_middle + s[0]`, this is `s[0] + s_middle + s[n-1]`, which is `s`.
        // This doesn't work.
        //
        // The example "nolon" -> "no|l|on" -> "onlno" works.
        // This is `s.substr(0,2)`, `s.substr(2,1)`, `s.substr(3,2)`.
        // Pieces: `s[0...1]`, `s[2]`, `s[3...4]`.
        // Reorder: `s[3...4] + s[2] + s[0...1]`.
        // This is `s[n-2...n-1] + s[n/2] + s[0...1]`.
        //
        // This is a general strategy for k=2:
        // Take `s_prefix = s.substr(0, i)` and `s_suffix = s.substr(n-i, i)` for some `i`.
        // The middle part is `s.substr(i, n-2*i)`.
        //
        // If `s` is not all same characters, then there exists an `i` such that `s.substr(0, i)` is not equal to `s.substr(n-i, i)` when reversed.
        //
        // The problem statement implies that if k=1 doesn't work and not all characters are the same, then k=2 is the answer.
        // This is a common pattern in competitive programming problems where if a simpler case fails, a slightly more complex one is guaranteed.
        //
        // The only case where it's impossible is when all characters are the same.
        // If `s` is "aaaaa", then any permutation of its substrings will result in "aaaaa".
        // If `s` is "ababa", k=1:
        // a|baba -> babaa (not pal)
        // ab|aba -> abaab (not pal)
        // aba|ba -> baaba (pal) but baaba != ababa. So k=1.
        //
        // The logic for "Impossible" is correct: only if all characters are the same.
        // If not all characters are the same, and k=1 didn't yield a solution, then k=2 must be the answer.
        // This is because we can always find a split that works for k=2.
        // For example, take `s = s[0] + s[1...n-2] + s[n-1]`.
        // Since `s` is a palindrome, `s[0] == s[n-1]`.
        // If `s` is not all same characters, then `s[1...n-2]` is not all same characters (unless `n=1` or `n=2` and `s[0]!=s[1]`).
        //
        // The problem statement implies that if k=1 doesn't work, and it's not "qqqq" case, then k=2 is the answer.
        // This is a strong hint.
        //
        // Let's re-verify the "all_same_char" check.
        // If `s = "qqqq"`, `n=4`. `first_char = 'q'`. Loop `i=1` to `n/2-1 = 1`. `s[1] == 'q'`. `all_same_char` remains true. Output "Impossible". Correct.
        // If `s = "otto"`, `n=4`. `first_char = 'o'`. Loop `i=1` to `1`. `s[1] == 't'`. `all_same_char` becomes false.
        // But for "otto", k=1 works: "ot|to" -> "toot".
        // So the `all_same_char` check should only be performed if k=1 fails.
        //
        // The current structure is:
        // 1. Try k=1. If found, print 1 and exit.
        // 2. If k=1 not found, then check if all characters are the same.
        //    If all characters are the same, print "Impossible".
        // 3. Otherwise (k=1 failed, but not all characters are the same), print 2.
        // This logic seems to match the examples and problem constraints.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current index for target tracks
    for (int i = 0; i < n; ++i) { // Iterate through heads
        if (p_idx == m) { // All target tracks covered
            return true;
        }

        long long head_pos = h[i];
        long long min_reach = head_pos - T;
        long long max_reach = head_pos + T;

        // If the current head cannot reach the current target track p[p_idx],
        // it means this head is too far to the left.
        // We need to find a head that can cover p[p_idx].
        // If p[p_idx] is outside [min_reach, max_reach], this head might be useful for later tracks.
        // But for p[p_idx], it must be covered.

        // If p[p_idx] is to the left of what this head can reach, this head cannot cover it.
        // We need to advance to the next head.
        if (p[p_idx] > max_reach) {
            continue;
        }

        // If p[p_idx] is within reach of this head, or to its left but still reachable
        // (i.e., p[p_idx] <= max_reach), this head can potentially cover p[p_idx]
        // and subsequent tracks.

        // The head can start at h[i] and move to cover tracks.
        // It can cover tracks from max(p[p_idx], h[i] - T) up to h[i] + T.
        // Or, it can cover tracks from h[i] - T up to min(p[p_idx], h[i] + T).
        // The key is that if a head covers p[p_idx], it can also cover a contiguous range
        // of tracks starting from p[p_idx] up to some point.

        // If p[p_idx] is covered by this head, we need to determine the furthest track
        // this head can cover to the right, given that it must cover p[p_idx].
        long long current_head_coverage_right_limit;

        // Case 1: Head moves right to cover p[p_idx]
        // It starts at h[i], moves to p[p_idx]. Time taken: p[p_idx] - h[i].
        // Remaining time: T - (p[p_idx] - h[i]).
        // Furthest right it can reach: p[p_idx] + (T - (p[p_idx] - h[i])) = h[i] + T.
        // This is valid if p[p_idx] >= h[i].

        // Case 2: Head moves left to cover p[p_idx]
        // It starts at h[i], moves to p[p_idx]. Time taken: h[i] - p[p_idx].
        // Remaining time: T - (h[i] - p[p_idx]).
        // Furthest right it can reach: p[p_idx] + (T - (h[i] - p[p_idx])) = 2*p[p_idx] - h[i] + T.
        // This is valid if p[p_idx] < h[i].

        if (p[p_idx] >= h[i]) { // Head moves right or stays
            // The head is at h[i]. It needs to reach p[p_idx]. This takes p[p_idx] - h[i] time.
            // If p[p_idx] - h[i] > T, this head cannot reach p[p_idx].
            // We already checked p[p_idx] > max_reach, which is p[p_idx] > h[i] + T,
            // so p[p_idx] - h[i] > T is already covered.
            // So if we are here, p[p_idx] <= h[i] + T.
            // The head can reach p[p_idx] and then continue to h[i] + T.
            current_head_coverage_right_limit = h[i] + T;
        } else { // p[p_idx] < h[i]. Head moves left.
            // The head is at h[i]. It needs to reach p[p_idx]. This takes h[i] - p[p_idx] time.
            // If h[i] - p[p_idx] > T, this head cannot reach p[p_idx].
            // This is equivalent to p[p_idx] < h[i] - T, which means p[p_idx] < min_reach.
            // If p[p_idx] < min_reach, this head cannot cover p[p_idx].
            // We should not be here if p[p_idx] < min_reach.
            // So if we are here, p[p_idx] >= h[i] - T.
            // The head moves to p[p_idx]. Time spent: h[i] - p[p_idx].
            // Remaining time: T - (h[i] - p[p_idx]).
            // From p[p_idx], it can move right by this remaining time.
            current_head_coverage_right_limit = p[p_idx] + (T - (h[i] - p[p_idx]));
        }

        // Now, advance p_idx as long as target tracks are covered by this head.
        while (p_idx < m && p[p_idx] <= current_head_coverage_right_limit) {
            p_idx++;
        }
    }
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible distance between any h_i and p_j is ~10^10.
                               // A single head might need to cover a range of 2*10^10.
                               // So T can be up to 2*10^10.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    // Precompute suffix array and LCP array for efficient string comparisons
    // This is a standard suffix array construction using doubling algorithm
    // and LCP array construction using Kasai's algorithm.
    // It's not strictly necessary for this problem's constraints (L=5000)
    // but provides a robust way to compare substrings.
    // For L=5000, O(L^2) string comparisons would be too slow.
    // O(L log L) or O(L log^2 L) for SA/LCP is fine.

    std::vector<int> sa(L);
    std::vector<int> rank(L);
    std::vector<int> new_rank(L);
    std::vector<int> cnt(std::max(L, 256)); // For counting sort

    // Initial ranking based on first character
    for (int i = 0; i < L; ++i) {
        sa[i] = i;
        rank[i] = s[i];
    }

    for (int k = 1; k < L; k <<= 1) {
        // Sort by (rank[i], rank[i+k])
        // Counting sort for pairs
        // First sort by second component (rank[i+k])
        std::fill(cnt.begin(), cnt.end(), 0);
        for (int i = 0; i < L; ++i) {
            cnt[i + k < L ? rank[i + k] : 0]++;
        }
        for (int i = 1; i < cnt.size(); ++i) {
            cnt[i] += cnt[i - 1];
        }
        std::vector<int> tmp_sa(L);
        for (int i = L - 1; i >= 0; --i) {
            tmp_sa[--cnt[sa[i] + k < L ? rank[sa[i] + k] : 0]] = sa[i];
        }
        sa = tmp_sa;

        // Then sort by first component (rank[i])
        std::fill(cnt.begin(), cnt.end(), 0);
        for (int i = 0; i < L; ++i) {
            cnt[rank[i]]++;
        }
        for (int i = 1; i < cnt.size(); ++i) {
            cnt[i] += cnt[i - 1];
        }
        for (int i = L - 1; i >= 0; --i) {
            tmp_sa[--cnt[rank[sa[i]]]] = sa[i];
        }
        sa = tmp_sa;

        // Update ranks
        new_rank[sa[0]] = 0;
        for (int i = 1; i < L; ++i) {
            int prev_idx = sa[i - 1];
            int curr_idx = sa[i];
            bool same_first = rank[prev_idx] == rank[curr_idx];
            bool same_second = (prev_idx + k < L ? rank[prev_idx + k] : -1) == (curr_idx + k < L ? rank[curr_idx + k] : -1);
            new_rank[curr_idx] = new_rank[prev_idx] + !(same_first && same_second);
        }
        rank = new_rank;
        if (rank[sa[L - 1]] == L - 1) break;
    }

    // LCP array construction (Kasai's algorithm)
    std::vector<int> lcp(L);
    std::vector<int> pos(L); // pos[i] = rank of suffix starting at i
    for (int i = 0; i < L; ++i) {
        pos[sa[i]] = i;
    }

    int k_lcp = 0;
    for (int i = 0; i < L; ++i) {
        if (pos[i] == L - 1) {
            k_lcp = 0;
            continue;
        }
        int j = sa[pos[i] + 1];
        while (i + k_lcp < L && j + k_lcp < L && s[i + k_lcp] == s[j + k_lcp]) {
            k_lcp++;
        }
        lcp[pos[i]] = k_lcp;
        if (k_lcp > 0) {
            k_lcp--;
        }
    }

    // Function to compare two cyclic shifts s_i and s_j
    // Returns 1 if s_i > s_j, -1 if s_i < s_j, 0 if s_i == s_j
    auto compare_cyclic_shifts = [&](int i, int j) {
        if (i == j) return 0;
        int r_i = rank[i];
        int r_j = rank[j];
        if (r_i == r_j) return 0; // Should not happen for distinct i,j unless L=1

        int common_len;
        if (r_i < r_j) { // s[i...] comes before s[j...] in SA
            common_len = lcp[r_i];
        } else { // s[j...] comes before s[i...] in SA
            common_len = lcp[r_j];
        }

        if (common_len >= L) return 0; // Full string match, implies i=j

        // If one suffix is a prefix of another, the shorter one comes first
        // But here we are comparing cyclic shifts of same length L
        // So if common_len is L, they are identical.
        // Otherwise, the character at common_len determines order.
        // If s[i+common_len] != s[j+common_len], then rank comparison is correct.
        // If common_len is L, they are identical.
        // The rank comparison already gives the correct order for suffixes.
        // For cyclic shifts, if rank[i] < rank[j], then s[i...] < s[j...].
        // Since they are cyclic shifts of the same length, this means s_i < s_j.
        return (r_i < r_j) ? -1 : 1;
    };

    double total_win_prob = 0.0;

    // Group indices by their character s[k]
    std::vector<std::vector<int>> indices_by_char(26);
    for (int i = 0; i < L; ++i) {
        indices_by_char[s[i] - 'a'].push_back(i);
    }

    for (int char_code = 0; char_code < 26; ++char_code) {
        const auto& current_k_candidates = indices_by_char[char_code];
        if (current_k_candidates.empty()) {
            continue;
        }

        int num_k_candidates = current_k_candidates.size();

        // If only one k candidate, Vasya wins for sure for this t[0]
        if (num_k_candidates == 1) {
            total_win_prob += 1.0;
            continue;
        }

        // Vasya needs to choose an optimal p
        int max_wins_for_this_t0 = 0;

        // Iterate over all possible positions p (1 to L-1)
        for (int p = 1; p < L; ++p) {
            // For a fixed p, group k candidates by t[p]
            // t[p] = s[(k + p) % L]
            std::map<char, std::vector<int>> k_candidates_by_t_p;
            for (int k_val : current_k_candidates) {
                k_candidates_by_t_p[s[(k_val + p) % L]].push_back(k_val);
            }

            int wins_for_this_p = 0;
            for (auto const& [t_p_char, group] : k_candidates_by_t_p) {
                if (group.size() == 1) {
                    wins_for_this_p++;
                } else {
                    // If multiple k values lead to the same (t[0], t[p]) pair,
                    // Vasya needs to check if they produce identical strings t.
                    // If all strings t are identical, Vasya loses.
                    // If they are not identical, Vasya loses.
                    // Vasya only wins if there's exactly one k that produces the observed (t[0], t[p])
                    // AND that k produces a unique string t among all possible k's.
                    // The problem statement says: "if there are at least two cyclic shifts of s that fit the information Vasya knowns, Vasya loses."
                    // This means if group.size() > 1, Vasya loses for this (t[0], t[p]) pair.
                    // So, we only count wins if group.size() == 1.
                }
            }
            max_wins_for_this_t0 = std::max(max_wins_for_this_t0, wins_for_this_p);
        }
        total_win_prob += static_cast<double>(max_wins_for_this_t0) / num_k_candidates;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

