#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2; // Total possible (l, r) pairs

    // Find the minimum r_prime such that for any l, if l <= r_prime,
    // then the pair (l, r_prime) does not contain any pattern.
    // This is equivalent to finding the smallest r_prime such that
    // all patterns (x, k) have x+2k > r_prime.
    // Or, find the maximum x+2k over all patterns.
    // Let max_pattern_end be the maximum value of x+2k for any pattern.
    // If no pattern exists, max_pattern_end will remain 0.
    int max_pattern_end = 0;

    // Iterate through all possible starting positions x (0-indexed)
    // and all possible steps k.
    // x+2k must be less than n.
    // So x can go from 0 to n-1.
    // k can go from 1 up to (n-1-x)/2.
    for (int x = 0; x < n; ++x) {
        // The maximum possible k for a given x is such that x + 2k < n.
        // So 2k < n - x, k < (n - x) / 2.
        // k starts from 1.
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a pattern. The end index is x + 2k (0-indexed).
                // We need to store the 1-indexed end position for the problem's definition.
                // So, x+2k+1.
                max_pattern_end = std::max(max_pattern_end, x + 2 * k + 1);
                // Optimization: For a fixed x, if we find a pattern,
                // we don't need to check larger k's for this x.
                // The smallest k for a given x that forms a pattern is sufficient
                // to determine if x is part of *any* pattern.
                // However, we need the *maximum* x+2k over all patterns.
                // So we must continue checking all k's.
                // The problem statement implies that k can be up to n.
                // But the condition x+2k <= r <= n limits k.
                // The maximum k is such that x+2k < n.
                // The problem statement $1 \leq x, k \leq n$ is for the original problem.
                // Here, $x$ is 0-indexed, $k$ is step.
                // $x+1$ is the 1-indexed start. $k$ is the step.
                // $x+1+2k$ is the 1-indexed end.
                // So $x+2k < n$ (0-indexed) means $x+1+2k \leq n$ (1-indexed).
                // The loop condition `x + 2 * k < n` correctly handles this.
            }
        }
    }

    // If max_pattern_end is 0, no patterns were found.
    // In this case, all (l, r) pairs are "bad" (do not contain a pattern).
    // The answer is 0.
    if (max_pattern_end == 0) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // The pairs (l, r) that DO NOT satisfy the condition are those where
    // r < max_pattern_end.
    // For any r < max_pattern_end, no pattern can be fully contained in s[l..r].
    // The number of such "bad" pairs (l, r) is the sum of (r - l + 1) for 1 <= l <= r < max_pattern_end.
    // This is equivalent to summing r for r from 1 to max_pattern_end - 1.
    // Sum of 1 to M is M * (M + 1) / 2.
    // Here M = max_pattern_end - 1.
    long long bad_pairs = (long long)(max_pattern_end - 1) * max_pattern_end / 2;

    // The number of "good" pairs is total_pairs - bad_pairs.
    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

