// Using long long for y to prevent overflow, as a_i can be up to 10^9 and n up to 2*10^5.
// In the worst case, y could accumulate many a_x values.
// For example, if x always stays within bounds and a_x is always 1, y could reach n * (some large number of steps).
// A path could be up to N steps long. If each a_x is 10^9, y could be N * 10^9.
// N is 2*10^5. So y could be 2*10^5 * 10^9 = 2*10^14, which fits in long long.

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // a_values stores a_2, a_3, ..., a_n
    // We will use a 1-indexed array for convenience in simulation.
    // A[0] will be unused. A[1] will be set to 'i' for each run.
    // A[k] for k >= 2 will be read from input.
    std::vector<long long> A(n + 1);
    for (int k = 2; k <= n; ++k) {
        std::cin >> A[k];
    }

    // Memoization tables for results and visited states
    // dp_y[x_start][step_type] stores the final y value if starting from x_start
    // and the next step is step_type (0 for add, 1 for subtract).
    // dp_y[x_start] will store the result for the initial (x=x_start, y=0) state.
    // We need to store results for (x, y_accumulated) pairs.
    // However, the problem structure is that a_x depends only on x.
    // The path taken depends only on x. The accumulated y depends on the path.
    // We can precompute for each x (from 2 to n) what happens if we start at x
    // and the next operation is either add or subtract.

    // Let's define states as (current_x, current_y_offset, next_op_type)
    // where next_op_type is 0 for add, 1 for subtract.
    // This is getting complicated. A simpler approach is to precompute for each x_i (from 2 to n)
    // what happens if we start at x_i with y=0 and the next operation is 'add a_i' then 'subtract a_i'.
    // This is not quite right because the 'add' and 'subtract' operations are interleaved.

    // Let's define a state as (current_x, current_y_offset, is_add_step).
    // is_add_step = true means the next operation is x += A[x], y += A[x].
    // is_add_step = false means the next operation is x -= A[x], y += A[x].

    // We need to compute for each starting x_1 (from 1 to n-1)
    // what happens if A[1] = x_1.
    // The simulation starts with x=1, y=0.
    // Then it performs (x += A[x], y += A[x]), then (x -= A[x], y += A[x]), and so on.

    // Let's define a function `solve(current_x, current_y_offset, is_add_step)`
    // This function returns a pair {final_x, final_y_offset} or {0, -1} for infinite loop.
    // The `current_y_offset` is the sum of `a_x` values encountered so far.

    // The problem is that `A[1]` changes for each run.
    // For `x >= 2`, `A[x]` is fixed.
    // For `x = 1`, `A[1]` is `i`.

    // We can use dynamic programming/memoization for states where `x >= 2`.
    // `memo[x][0]` will store {final_x, final_y_offset} if we start at `x` and the next step is `x += A[x]`.
    // `memo[x][1]` will store {final_x, final_y_offset} if we start at `x` and the next step is `x -= A[x]`.
    // `visited[x][0]` and `visited[x][1]` will detect cycles.

    std::vector<std::vector<std::pair<long long, long long>>> memo(n + 1, std::vector<std::pair<long long, long long>>(2, {0, 0}));
    std::vector<std::vector<bool>> visiting(n + 1, std::vector<bool>(2, false)); // To detect cycles
    std::vector<std::vector<bool>> computed(n + 1, std::vector<bool>(2, false)); // To check if memoized

    // Function to simulate from a given state (x, y_offset, is_add_step)
    // Returns {final_x, final_y_offset} or {0, -1} for infinite loop.
    // Note: y_offset is the sum of a_values encountered *from this point*.
    // The total y will be initial_y + y_offset.
    auto simulate = [&](auto self, int current_x, long long current_y_offset, bool is_add_step) -> std::pair<long long, long long> {
        // Termination conditions
        if (current_x <= 0 || current_x > n) {
            return {current_x, current_y_offset};
        }

        // Check memoization for x >= 2
        if (current_x >= 2 && computed[current_x][is_add_step]) {
            return {memo[current_x][is_add_step].first, current_y_offset + memo[current_x][is_add_step].second};
        }

        // Cycle detection for x >= 2
        if (current_x >= 2 && visiting[current_x][is_add_step]) {
            return {0, -1}; // Indicate infinite loop
        }

        // Mark as visiting
        if (current_x >= 2) {
            visiting[current_x][is_add_step] = true;
        }

        long long val = A[current_x];
        long long next_x;
        long long next_y_offset = current_y_offset + val;

        if (is_add_step) {
            next_x = current_x + val;
        } else {
            next_x = current_x - val;
        }

        // Recursive call for the next step
        std::pair<long long, long long> result = self(self, next_x, next_y_offset, !is_add_step);

        // Unmark visiting
        if (current_x >= 2) {
            visiting[current_x][is_add_step] = false;
        }

        // Memoize if not an infinite loop and x >= 2
        if (current_x >= 2 && result.second != -1) {
            memo[current_x][is_add_step] = {result.first, result.second - current_y_offset};
            computed[current_x][is_add_step] = true;
        }

        return result;
    };

    // For each i from 1 to n-1
    for (int i = 1; i < n; ++i) {
        A[1] = i; // Set a_1 for this run

        // Start simulation from x=1, y=0, next step is add
        std::pair<long long, long long> final_state = simulate(simulate, 1, 0, true);

        if (final_state.second == -1) {
            std::cout << -1 << "\n";
        } else {
            std::cout << final_state.second << "\n";
        }
    }

    return 0;
}

