        // Now diff can be 0, 1, 2, 3, 4
        if (diff == 0) {
            // No more presses needed
        } else if (diff == 1) {
            // Can be 1 (+1 or -1)
            presses += 1;
        } else if (diff == 2) {
            // Can be 1 (+2 or -2)
            presses += 1;
        } else if (diff == 3) {
            // Can be 2 (+1, +2 or -1, -2)
            presses += 2;
        } else if (diff == 4) {
            // Can be 2 (+2, +2 or -2, -2)
            presses += 2;
        }

        std::cout << presses << "\n";
    }
    return 0;
}

