#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The reverse of a permutation p, p_rev, will have the same set of adjacent sums
    // as p, just in reverse order. Therefore, F(p_rev) will be equal to F(p).
    // We need to ensure p_rev is different from p.
    // A permutation p is equal to its reverse p_rev if and only if p is a palindrome.
    // For a permutation of distinct integers from 1 to n, p can only be a palindrome
    // if n=1 (trivial, not allowed by constraints n>=2) or if it's not a permutation
    // (e.g., [1,2,1] is a palindrome but not a permutation).
    // A permutation of distinct integers from 1 to n cannot be a palindrome for n >= 2.
    // For example, if p_1 = p_n, then p_1 and p_n are the same element, but they must be distinct.
    // Wait, this reasoning is flawed. p_1 and p_n are values, not indices.
    // A permutation p is a palindrome if p_i = p_{n-1-i} for all i.
    // For example, if n=4, p=[1,2,3,4]. p_rev=[4,3,2,1]. These are different.
    // If n=5, p=[1,2,3,4,5]. p_rev=[5,4,3,2,1]. These are different.
    //
    // The only way p_rev could be equal to p is if p_i = p_{n-1-i} for all i.
    // For example, if n=2, p=[1,2]. p_rev=[2,1]. Different.
    // If n=3, p=[1,2,3]. p_rev=[3,2,1]. Different.
    //
    // A permutation p of distinct integers from 1 to n cannot be a palindrome
    // unless n=1 (which is not allowed by constraints).
    // If p is a palindrome, then p_1 = p_n, p_2 = p_{n-1}, etc.
    // But p_1 and p_n must be distinct values if n > 1.
    // This is incorrect. p_1 and p_n are values. They must be distinct if they are at different positions.
    // For example, if p = [1, 2, 3, 2, 1], this is a palindrome, but not a permutation because 1 and 2 appear twice.
    //
    // A permutation of distinct integers from 1 to n cannot be a palindrome for n >= 2.
    // Proof: Assume p is a permutation and a palindrome.
    // Then p_i = p_{n-1-i} for all i from 0 to n-1.
    // Consider p_0 and p_{n-1}. If p is a palindrome, p_0 = p_{n-1}.
    // But p is a permutation, so all elements are distinct.
    // This implies that if p_0 = p_{n-1}, then the elements at index 0 and n-1 must be the same element.
    // This is only possible if 0 = n-1, which means n=1.
    // Since n >= 2, p_0 and p_{n-1} must be distinct elements.
    // Therefore, p_0 cannot be equal to p_{n-1}.
    // This contradicts the assumption that p is a palindrome.
    // Thus, for n >= 2, a permutation cannot be a palindrome.
    //
    // Since p cannot be a palindrome for n >= 2, p_rev will always be different from p.
    // So, reversing the permutation is a valid solution.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

