    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 0;
        long long k = 1; // Represents the number of stairs in the current staircase (1, 3, 7, 15, ...)
        while (true) {
            // Calculate the number of cells for a staircase with k stairs
            // This is k * (k + 1) / 2
            // However, k here is 2^p - 1.
            // The actual number of stairs is (2^p - 1).
            // The cost for a staircase with (2^p - 1) stairs is (2^p - 1) * (2^p) / 2.
            // Let m = 2^p - 1. Then the cost is m * (m + 1) / 2.
            // The sequence of costs for nice staircases is:
            // p=1, k=1: cost = 1 * 2 / 2 = 1
            // p=2, k=3: cost = 3 * 4 / 2 = 6
            // p=3, k=7: cost = 7 * 8 / 2 = 28
            // p=4, k=15: cost = 15 * 16 / 2 = 120
            // The cost for the next nice staircase is (2*k + 1) * (2*k + 2) / 2.
            // This is (2k+1)(k+1).
            // Let's use the formula for the cost of a nice staircase with (2^p - 1) stairs.
            // Cost_p = (2^p - 1) * (2^p) / 2.
            // The sequence of k values is 1, 3, 7, 15, ...
            // The sequence of costs is 1, 6, 28, 120, ...
            // The next k is 2*k + 1.
            // The cost for the staircase with k stairs is k * (k + 1) / 2.
            long long cost_for_k_stairs = k * (k + 1) / 2;

            if (current_cost + cost_for_k_stairs <= x) {
                current_cost += cost_for_k_stairs;
                count++;
                // Calculate the next k.
                // k_next = 2 * k_current + 1.
                // Check for overflow before multiplying.
                // k_current can be up to 2^62 - 1 (approx 4.6e18).
                // 2 * k_current + 1 can exceed long long max if k_current > LLONG_MAX / 2.
                // LLONG_MAX is approx 9e18.
                // If k is around 4.5e18, 2*k+1 will overflow.
                // The maximum x is 10^18.
                // The costs are 1, 6, 28, 120, 496, 2016, 8128, 32640, 130816, 523776, 2096128, 8386560, 33550336, 134209536, 536854528, 2147450880, 8589869056, 34359607296, 137438691328, 549755681280, 2199022800896, 8796091877376, 35184366086144, 140737479009280, 562949949532672, 2251799813685248, 9007199194004480, 36028797018963968, 144115187000000000 (approx 1.44e17).
                // The next cost would be for k = 2 * (3.6e17) + 1, which is approx 7.2e17.
                // The sum of costs can reach x = 10^18.
                // The largest k for which cost_for_k_stairs <= 10^18 is when k * (k+1)/2 <= 10^18.
                // k^2/2 approx 10^18 => k^2 approx 2*10^18 => k approx sqrt(2)*10^9 approx 1.4 * 10^9.
                // The k values are 1, 3, 7, ..., 2^p - 1.
                // If k is 1.4 * 10^9, then 2*k+1 is 2.8 * 10^9, which fits in long long.
                // The cost for k=2^p-1 is (2^p-1)*2^p/2.
                // If 2^p-1 is approx 1.4*10^9, then 2^p is approx 1.4*10^9.
                // p is approx log2(1.4*10^9) approx log2(10^9) + log2(1.4) approx 9*log2(10) + 0.5 approx 9*3.32 + 0.5 approx 29.88 + 0.5 approx 30.38.
                // So p can go up to around 30.
                // 2^30 - 1 is approx 10^9.
                // The next k would be 2*(2^30-1)+1 = 2^31-1. This is fine.
                // The cost for 2^31-1 stairs is (2^31-1)*2^31/2. This is approx (2*10^9)*(2*10^9)/2 = 2*10^18.
                // This cost alone might exceed x.
                // So k will not overflow.
                k = 2 * k + 1;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams 'k' is limited by three factors:
        // 1. The number of coders available (each team needs at least one coder).
        // 2. The number of mathematicians available (each team needs at least one mathematician).
        // 3. The total number of students available (each team needs exactly three members).
        // So, k <= c, k <= m, and 3*k <= c + m + x.
        // This means k <= min(c, m, (c + m + x) / 3).
        // Let's call this upper bound 'max_possible_teams'.
        long long max_possible_teams = std::min({c, m, (c + m + x) / 3});

        // This 'max_possible_teams' is the answer because if we can form 'k' teams,
        // we use 'k' coders, 'k' mathematicians, and 'k' other students.
        // The 'k' other students can be drawn from the remaining coders (c-k),
        // remaining mathematicians (m-k), and students with no specialization (x).
        // The total number of students available for these 'k' "flexible" slots is (c-k) + (m-k) + x.
        // We need to ensure that (c-k) + (m-k) + x >= k.
        // This simplifies to c + m + x >= 3k, which is already covered by the third condition.
        // Since we pick k <= c and k <= m, we always have enough coders and mathematicians
        // to satisfy the "at least one" requirement for k teams.
        // The remaining c-k coders and m-k mathematicians, along with x non-specialized students,
        // are sufficient to fill the remaining k slots because their sum is (c+m+x) - 2k,
        // and we know (c+m+x) >= 3k, so (c+m+x) - 2k >= k.

        std::cout << max_possible_teams << "\n";
    }
    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks to minimize the absolute difference between the medians of two classes.
        // Each class must have an odd number of students.
        // Let the sorted skill levels be a_0, a_1, ..., a_{2n-1}.
        //
        // Consider the case where one class has size 1 and the other has size 2n-1.
        // If class 1 has size 1, its median is just the single element.
        // If class 2 has size 2n-1, its median is the (n)-th element (0-indexed) after sorting its elements.
        //
        // It can be proven that the optimal strategy is to split the sorted array
        // into two halves: the first n elements and the last n elements.
        // The first class will consist of elements a_0, ..., a_{n-1}.
        // The second class will consist of elements a_n, ..., a_{2n-1}.
        //
        // This is not a valid partition because each class would have n students.
        // If n is odd, this is a valid partition.
        // If n is even, this is not a valid partition.
        //
        // The key insight for this problem is that the minimum difference is achieved
        // by taking the median of the first n elements and the median of the last n elements
        // if we were to split the sorted array into two groups of n elements.
        //
        // More precisely, if we sort the array a_0, a_1, ..., a_{2n-1},
        // the minimum possible difference between the medians of two odd-sized classes
        // will be |a_{n-1} - a_n|.
        //
        // Let's verify this.
        // Consider the partition where Class 1 takes students a_0, ..., a_{n-1} and a_n.
        // This class has n+1 students. If n+1 is odd, this is a valid size.
        // The median would be a_n.
        // The remaining students are a_{n+1}, ..., a_{2n-1}. This class has n-1 students.
        // If n-1 is odd, this is a valid size.
        // The median would be a_{n + (n-1)/2}.
        // This doesn't seem to lead to |a_{n-1} - a_n|.
        //
        // The problem statement implies that we can choose any odd sizes $S_1, S_2$ such that $S_1+S_2=2n$.
        // The smallest possible median for any class will be $a_0$.
        // The largest possible median for any class will be $a_{2n-1}$.
        //
        // Let's consider the sorted array $a_0, a_1, \dots, a_{2n-1}$.
        // We need to pick $S_1$ students for class 1 and $S_2$ students for class 2, where $S_1, S_2$ are odd.
        // $S_1 + S_2 = 2n$.
        //
        // The median of a class of size $2k+1$ is the $k$-th element (0-indexed) after sorting its members.
        //
        // Consider the two elements $a_{n-1}$ and $a_n$.
        // Can we make $a_{n-1}$ the median of one class and $a_n$ the median of another class?
        //
        // To make $a_{n-1}$ the median of a class of size $2k_1+1$:
        // We need $k_1$ elements smaller than or equal to $a_{n-1}$ and $k_1$ elements greater than or equal to $a_{n-1}$.
        // We have $n-1$ elements $a_0, \dots, a_{n-2}$ that are $\le a_{n-1}$.
        // We have $n$ elements $a_n, \dots, a_{2n-1}$ that are $\ge a_n \ge a_{n-1}$.
        //
        // To make $a_n$ the median of a class of size $2k_2+1$:
        // We need $k_2$ elements smaller than or equal to $a_n$ and $k_2$ elements greater than or equal to $a_n$.
        // We have $n$ elements $a_0, \dots, a_{n-1}$ that are $\le a_n$.
        // We have $n-1$ elements $a_{n+1}, \dots, a_{2n-1}$ that are $\ge a_n$.
        //
        // The crucial observation is that the $n$-th element (0-indexed $a_{n-1}$) and the $(n+1)$-th element (0-indexed $a_n$)
        // are the "middle" two elements of the entire sorted array of $2n$ students.
        //
        // It is always possible to form two classes such that $a_{n-1}$ is the median of one class and $a_n$ is the median of the other.
        //
        // Consider Class 1: students $a_0, a_1, \dots, a_{n-1}$. This class has $n$ students.
        // Consider Class 2: students $a_n, a_{n+1}, \dots, a_{2n-1}$. This class has $n$ students.
        //
        // If $n$ is odd, then this is a valid partition.
        // Median of Class 1 (size $n=2k+1$): $a_k = a_{(n-1)/2}$.
        // Median of Class 2 (size $n=2k+1$): $a_{n+k} = a_{n+(n-1)/2}$.
        // This is not $a_{n-1}$ and $a_n$.
        //
        // The problem is simpler than trying to construct specific classes.
        // The minimum difference between medians will always be $a_n - a_{n-1}$ (after sorting).
        //
        // Why?
        // Let $M_1$ and $M_2$ be the medians of the two classes.
        // Suppose $M_1 < M_2$.
        // $M_1$ must be some $a_i$ and $M_2$ must be some $a_j$ where $i < j$.
        //
        // Consider the $n$ smallest elements $a_0, \dots, a_{n-1}$ and the $n$ largest elements $a_n, \dots, a_{2n-1}$.
        //
        // Any class with median $M_1$ must contain at least one element from $a_0, \dots, a_{n-1}$.
        // Any class with median $M_2$ must contain at least one element from $a_n, \dots, a_{2n-1}$.
        //
        // More strongly, if $M_1$ is the median of a class of size $2k_1+1$, then there are $k_1$ elements in that class $\le M_1$ and $k_1$ elements $\ge M_1$.
        // If $M_2$ is the median of a class of size $2k_2+1$, then there are $k_2$ elements in that class $\le M_2$ and $k_2$ elements $\ge M_2$.
        //
        // The total number of students is $2n$.
        // The $n$-th student (0-indexed $a_{n-1}$) and the $(n+1)$-th student (0-indexed $a_n$) are the two "middle" students.
        //
        // It is always possible to construct two classes such that $a_{n-1}$ is the median of one class and $a_n$ is the median of the other.
        //
        // Consider Class 1: $a_0, a_1, \dots, a_{n-1}$. This class has $n$ students.
        // Consider Class 2: $a_n, a_{n+1}, \dots, a_{2n-1}$. This class has $n$ students.
        //
        // If $n$ is odd, then both classes have odd size.
        // Median of Class 1 is $a_{(n-1)/2}$.
        // Median of Class 2 is $a_{n + (n-1)/2}$.
        // The difference is $a_{n+(n-1)/2} - a_{(n-1)/2}$. This is not $a_n - a_{n-1}$.
        //
        // The problem is a known result: for $2n$ elements, the minimum difference between medians of two odd-sized partitions is $a_n - a_{n-1}$ after sorting.
        //
        // Let's try to prove this.
        // Let the sorted array be $A = [a_0, a_1, \dots, a_{2n-1}]$.
        // We partition $A$ into two sets $C_1$ and $C_2$, with $|C_1|=S_1$ and $|C_2|=S_2$, where $S_1, S_2$ are odd and $S_1+S_2=2n$.
        // Let $m_1$ be the median of $C_1$ and $m_2$ be the median of $C_2$. We want to minimize $|m_1 - m_2|$.
        //
        // Without loss of generality, assume $m_1 \le m_2$.
        //
        // Consider the element $a_{n-1}$. It is the $n$-th element.
        // Consider the element $a_n$. It is the $(n+1)$-th element.
        //
        // Case 1: $a_{n-1}$ and $a_n$ are in the same class, say $C_1$.
        // Then $C_1$ contains at least $n+1$ elements (since it contains $a_0, \dots, a_n$ or some other $n+1$ elements).
        // If $a_{n-1}$ and $a_n$ are in $C_1$, then $m_1$ must be $\ge a_{n-1}$ and $\le a_n$.
        // This is because $m_1$ is the middle element of $C_1$. If $m_1 < a_{n-1}$, then $C_1$ would have at least $n+1$ elements greater than $m_1$ (namely $a_{n-1}, \dots, a_{2n-1}$ if they are in $C_1$, or some subset of them).
        // If $m_1 > a_n$, then $C_1$ would have at least $n+1$ elements smaller than $m_1$ (namely $a_0, \dots, a_n$ if they are in $C_1$, or some subset of them).
        // So if $a_{n-1}, a_n \in C_1$, then $a_{n-1} \le m_1 \le a_n$.
        //
        // Case 2: $a_{n-1}$ and $a_n$ are in different classes.
        // Say $a_{n-1} \in C_1$ and $a_n \in C_2$.
        // Then $m_1$ must be $\le a_{n-1}$ and $m_2$ must be $\ge a_n$.
        // This is because if $m_1 > a_{n-1}$, then $C_1$ would have at least $n$ elements smaller than $m_1$ (all elements $a_0, \dots, a_{n-1}$ are $\le a_{n-1}$).
        // If $m_2 < a_n$, then $C_2$ would have at least $n$ elements greater than $m_2$ (all elements $a_n, \dots, a_{2n-1}$ are $\ge a_n$).
        // So if $a_{n-1} \in C_1$ and $a_n \in C_2$, then $m_1 \le a_{n-1}$ and $m_2 \ge a_n$.
        // In this case, $m_2 - m_1 \ge a_n - a_{n-1}$.
        //
        // Combining both cases, we always have $m_2 - m_1 \ge a_n - a_{n-1}$.
        //
        // Now we need to show that $a_n - a_{n-1}$ is achievable.
        // We need to construct a partition where $m_1 = a_{n-1}$ and $m_2 = a_n$.
        //
        // Let $C_1 = \{a_0, a_1, \dots, a_{n-1}\}$ and $C_2 = \{a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // Both $C_1$ and $C_2$ have $n$ elements.
        // If $n$ is odd, then this is a valid partition.
        // Median of $C_1$ is $a_{(n-1)/2}$.
        // Median of $C_2$ is $a_{n + (n-1)/2}$.
        // This does not give $a_{n-1}$ and $a_n$ as medians.
        //
        // The construction that achieves $a_n - a_{n-1}$ is as follows:
        // Class 1: $a_0, a_1, \dots, a_{n-1}$ (these are $n$ elements).
        // Class 2: $a_n, a_{n+1}, \dots, a_{2n-1}$ (these are $n$ elements).
        //
        // This is not a valid partition if $n$ is even.
        //
        // The actual construction is:
        // Class 1: $a_0, a_1, \dots, a_{n-1}$ and $a_{2n-1}$. (n+1 elements)
        // Class 2: $a_n, a_{n+1}, \dots, a_{2n-2}$. (n-1 elements)
        //
        // If $n$ is odd:
        // $n+1$ is even. $n-1$ is even. This is not a valid partition.
        //
        // If $n$ is even:
        // $n+1$ is odd. $n-1$ is odd. This is a valid partition.
        //
        // Let's analyze this partition when $n$ is even.
        // $C_1 = \{a_0, \dots, a_{n-1}, a_{2n-1}\}$. Sorted: $a_0, \dots, a_{n-1}, a_{2n-1}$. Size $n+1$.
        // Median of $C_1$: $( (n+1)-1 ) / 2 = n/2$-th element (0-indexed).
        // This is $a_{n/2}$.
        //
        // $C_2 = \{a_n, \dots, a_{2n-2}\}$. Sorted: $a_n, \dots, a_{2n-2}$. Size $n-1$.
        // Median of $C_2$: $( (n-1)-1 ) / 2 = (n-2)/2$-th element (0-indexed) within $C_2$.
        // This corresponds to $a_{n + (n-2)/2} = a_{3n/2 - 1}$.
        //
        // The difference is $a_{3n/2 - 1} - a_{n/2}$. This is not $a_n - a_{n-1}$.
        //
        // The problem statement is a standard competitive programming problem.
        // The minimum difference is indeed $a_n - a_{n-1}$.
        //
        // Let's re-evaluate the proof that $m_2 - m_1 \ge a_n - a_{n-1}$.
        // Let $C_1$ and $C_2$ be the two classes with medians $m_1$ and $m_2$ respectively.
        // Assume $m_1 \le m_2$.
        //
        // $C_1$ has $S_1 = 2k_1+1$ elements. $m_1$ is the $k_1$-th element in sorted $C_1$.
        // This means $C_1$ has $k_1$ elements $\le m_1$ and $k_1$ elements $\ge m_1$.
        // $C_2$ has $S_2 = 2k_2+1$ elements. $m_2$ is the $k_2$-th element in sorted $C_2$.
        // This means $C_2$ has $k_2$ elements $\le m_2$ and $k_2$ elements $\ge m_2$.
        //
        // Total elements $2n = S_1+S_2 = 2k_1+1 + 2k_2+1 = 2(k_1+k_2+1)$.
        // So $n = k_1+k_2+1$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$. There are $n$ such elements.
        // Consider the elements $a_n, \dots, a_{2n-1}$. There are $n$ such elements.
        //
        // The total number of elements $\le m_1$ is at most $n-1$ (if $m_1 < a_n$).
        // The total number of elements $\ge m_2$ is at most $n-1$ (if $m_2 > a_{n-1}$).
        //
        // Let $N_{\le x}$ be the count of elements in $A$ that are $\le x$.
        // Let $N_{\ge x}$ be the count of elements in $A$ that are $\ge x$.
        //
        // For $C_1$, $m_1$ is its median. So $N_{\le m_1}(C_1) \ge k_1+1$ and $N_{\ge m_1}(C_1) \ge k_1+1$.
        // For $C_2$, $m_2$ is its median. So $N_{\le m_2}(C_2) \ge k_2+1$ and $N_{\ge m_2}(C_2) \ge k_2+1$.
        //
        // Since $m_1 \le m_2$:
        // The total number of elements $\le m_1$ in $A$ is $N_{\le m_1}(A) = N_{\le m_1}(C_1) + N_{\le m_1}(C_2)$.
        // $N_{\le m_1}(A) \ge (k_1+1) + N_{\le m_1}(C_2)$.
        // Since $m_1 \le m_2$, $N_{\le m_1}(C_2)$ could be 0.
        //
        // The total number of elements $\ge m_2$ in $A$ is $N_{\ge m_2}(A) = N_{\ge m_2}(C_1) + N_{\ge m_2}(C_2)$.
        // $N_{\ge m_2}(A) \ge N_{\ge m_2}(C_1) + (k_2+1)$.
        // Since $m_1 \le m_2$, $N_{\ge m_2}(C_1)$ could be 0.
        //
        // We know that $a_{n-1}$ is the $n$-th element (0-indexed). So $N_{\le a_{n-1}}(A) \ge n$.
        // We know that $a_n$ is the $(n+1)$-th element (0-indexed). So $N_{\ge a_n}(A) \ge n$.
        //
        // If $m_1 < a_{n-1}$, then $N_{\le m_1}(A) < n$.
        // If $m_2 > a_n$, then $N_{\ge m_2}(A) < n$.
        //
        // Suppose $m_1 < a_{n-1}$.
        // Then $N_{\le m_1}(A) \le n-1$.
        // We have $N_{\le m_1}(C_1) \ge k_1+1$.
        // $N_{\le m_1}(C_2)$ can be 0.
        // So $k_1+1 \le n-1$.
        //
        // Suppose $m_2 > a_n$.
        // Then $N_{\ge m_2}(A) \le n-1$.
        // We have $N_{\ge m_2}(C_2) \ge k_2+1$.
        // $N_{\ge m_2}(C_1)$ can be 0.
        // So $k_2+1 \le n-1$.
        //
        // Summing these: $(k_1+1) + (k_2+1) \le 2n-2$.
        // $k_1+k_2+2 \le 2n-2$.
        // Since $n = k_1+k_2+1$, we have $n+1 \le 2n-2$, which implies $3 \le n$.
        // This means for $n=1,2$, this argument might not hold.
        //
        // For $n=1$: $2n=2$ students. $a_0, a_1$.
        // $S_1=1, S_2=1$. $C_1=\{a_0\}, C_2=\{a_1\}$. Medians $m_1=a_0, m_2=a_1$.
        // Difference is $a_1 - a_0$. Here $n-1=0, n=1$. So $a_n - a_{n-1} = a_1 - a_0$. Correct.
        //
        // The general proof relies on the fact that if $m_1 < a_{n-1}$ and $m_2 > a_n$, then the total number of elements
        // that are "between" $m_1$ and $m_2$ (exclusive) is too small to satisfy the median conditions.
        //
        // The simplest argument is that $a_{n-1}$ and $a_n$ are the two "middle" elements.
        // Any median $m_1$ of a class $C_1$ must be $\le a_{n-1}$ or $\ge a_n$ if $C_1$ contains $a_{n-1}$ or $a_n$ respectively.
        //
        // The minimum difference is indeed $a_n - a_{n-1}$.
        // This is a known result for this type of problem.
        //
        // Example 2: n=3, 2n=6. a = [1, 2, 3, 4, 5, 6]
        // n-1 = 2, n = 3.
        // a_{n-1} = a_2 = 3.
        // a_n = a_3 = 4.
        // Difference = 4 - 3 = 1.
        // The example output is 1.
        //
        // Example 3: n=5, 2n=10. a = [2, 3, 4, 5, 8, 13, 13, 16, 17, 20]
        // n-1 = 4, n = 5.
        // a_{n-1} = a_4 = 8.
        // a_n = a_5 = 13.
        // Difference = 13 - 8 = 5.
        // The example output is 5.
        //
        // The solution is to sort the array and output a[n] - a[n-1].
        // The indices are 0-based for vector. So $a[n]$ and $a[n-1]$.
        //
        // The sum of n over all test cases does not exceed $10^5$.
        // Sorting takes $O(N \log N)$ where $N=2n$.
        // Total time complexity will be $\sum (2n \log (2n))$, which is fine.

        std::cout << a[n] - a[n - 1] << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    // The total area of the carrot is (1/2) * base * height = (1/2) * 1 * h = h/2.
    // Each of the n pieces should have an area of (h/2) / n = h / (2n).

    // Consider a cut at distance x from the apex. This forms a smaller triangle.
    // By similar triangles, if the original base is 1 and height is h,
    // then for a smaller triangle with height x, its base b_x will be x/h.
    // The area of this smaller triangle is (1/2) * b_x * x = (1/2) * (x/h) * x = x^2 / (2h).

    // We want the area from the apex up to the i-th cut (x_i) to be i times the area of one piece.
    // Area_up_to_x_i = i * (h / (2n))
    // So, x_i^2 / (2h) = i * (h / (2n))
    // x_i^2 = i * (h / (2n)) * (2h)
    // x_i^2 = i * h^2 / n
    // x_i = sqrt(i * h^2 / n)
    // x_i = h * sqrt(i / n)

    for (int i = 1; i < n; ++i) {
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << std::fixed << std::setprecision(12) << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
