int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest value we will use for the "zigzag" part

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between left and right pointers
    // The values used will be 1, 2, ..., k+1
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) {
            p[i] = left;
            left++;
        } else {
            p[i] = right;
            right--;
        }
    }

    // Fill the rest of the permutation (from index k+1 to n-1)
    // with the remaining numbers in increasing order.
    // These numbers are k+2, k+3, ..., n.
    // This ensures that the differences introduced here are all 1,
    // which is already one of the k distinct differences (since k >= 1).
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // The values are 1-indexed, so p[k+1] = k+2, p[k+2] = k+3, etc.
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

