}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_min_ops
    // prefix_min_ops[i] stores the minimum value a[i] can take
    // to satisfy a[0] < a[1] < ... < a[i]
    // This is equivalent to a[i] >= i
    std::vector<long long> prefix_min_val(n);
    prefix_min_val[0] = 0; // a[0] must be >= 0
    for (int i = 1; i < n; ++i) {
        prefix_min_val[i] = std::max(prefix_min_val[i-1] + 1, (long long)i);
    }

    // Calculate suffix_min_ops
    // suffix_min_ops[i] stores the minimum value a[i] can take
    // to satisfy a[i] > a[i+1] > ... > a[n-1]
    // This is equivalent to a[i] >= (n-1) - i
    std::vector<long long> suffix_min_val(n);
    suffix_min_val[n-1] = 0; // a[n-1] must be >= 0
    for (int i = n - 2; i >= 0; --i) {
        suffix_min_val[i] = std::max(suffix_min_val[i+1] + 1, (long long)(n - 1 - i));
    }

    for (int k = 0; k < n; ++k) {
        // For a[k] to be the peak, it must satisfy both conditions:
        // 1. a[0] < ... < a[k]
        // 2. a[k] > ... > a[n-1]
        // This means a[k] must be at least prefix_min_val[k] AND at least suffix_min_val[k].
        // So, a[k] must be at least max(prefix_min_val[k], suffix_min_val[k]).
        // If the original a[k] is less than this required minimum, it's impossible for this k.
        if (a[k] >= std::max(prefix_min_val[k], suffix_min_val[k])) {
            std::cout << "Yes\n";
            return;
        }
    }

    std::cout << "No\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

