#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long s;
    std::cin >> n >> s;

    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Step 1: Make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // Step 2: Adjust elements to the left of the median
    // These elements must be <= s. If any a[i] < s, it's fine.
    // If any a[i] > s, it must be decreased to s.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Step 3: Adjust elements to the right of the median
    // These elements must be >= s. If any a[i] > s, it's fine.
    // If any a[i] < s, it must be increased to s.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int left_ptr = 0; // Pointer for the "original" elements (smaller values)
    int right_ptr = 0; // Pointer for the "permuted" elements (larger values)

    while (right_ptr < n) {
        // If the element at right_ptr is strictly greater than the element at left_ptr,
        // we can form a pair (a[left_ptr], a[right_ptr]) where a[right_ptr] > a[left_ptr].
        // This contributes to our count.
        // We then advance both pointers, as a[left_ptr] has been "covered" and a[right_ptr] has been "used".
        if (a[right_ptr] > a[left_ptr]) {
            count++;
            left_ptr++;
            right_ptr++;
        } else {
            // If a[right_ptr] is not greater than a[left_ptr], it means a[right_ptr] is
            // either equal to or smaller than a[left_ptr].
            // In this case, a[right_ptr] cannot be placed at the position of a[left_ptr]
            // to satisfy the condition.
            // We need to find a larger element for a[left_ptr], so we advance right_ptr
            // to look for a potentially larger value. left_ptr remains the same.
            right_ptr++;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    // Create the result array A'
    // The i-th element of the sorted A (a_elements[i].value)
    // should be paired with the (m-1-i)-th element of the sorted B (b_elements[m-1-i].value)
    // This pairing maximizes F(A'_i, B_i) because F(n, k) is increasing in n and decreasing in k.
    // So, largest A values should be paired with smallest B values.
    // The original index of b_elements[m-1-i] tells us where this pair should go in the output.
    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        // The value a_elements[i].value (which is the i-th smallest A value)
        // should be placed at the position corresponding to b_elements[m-1-i].original_index
        // because b_elements[m-1-i] is the (m-1-i)-th smallest B value,
        // which means it's the i-th largest B value.
        result_a_prime[b_elements[m - 1 - i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <numeric> // For std::accumulate (though not strictly needed for this approach)
#include <map>     // For std::map

void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    long long current_sum = 0; // Use long long to prevent overflow if sum exceeds int max, though 2048 is small.

    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) {
            counts[s_val]++;
        }
    }

    // Simulate the merging process
    // We only care about numbers up to 2048.
    // Iterate through powers of two from smallest to largest.
    // If we have two 'x's, they combine to '2x'.
    // This means we can effectively add the value of 'x' to a running sum
    // as long as we have enough 'x's to form larger numbers.
    // The most straightforward way is to sum up all numbers <= 2048.
    // If this sum is >= 2048, we can always form 2048.
    // Why? Because any number 'x' can be thought of as contributing 'x' to the total sum.
    // When two 'x's combine to '2x', the total sum remains the same.
    // The operation only changes the distribution of values, not the total sum.
    // If the total sum of numbers <= 2048 is at least 2048, it means we have enough
    // "material" to form 2048. Since all numbers are powers of two, and we can always
    // combine two equal powers of two into the next higher power, we can always
    // consolidate the sum into a single number (or a few numbers) up to the total sum.
    // For example, if we have {1, 1, 1, 1}, sum is 4. We can make {2, 1, 1} -> {2, 2} -> {4}.
    // If we have {1024, 512, 512}, sum is 2048. We can make {1024, 1024} -> {2048}.
    // The only constraint is that we can't break down larger numbers.
    // But since we only care about forming 2048, numbers > 2048 are irrelevant.
    // Numbers <= 2048 can always be combined to form their sum, up to 2048.

    for (auto const& [val, count] : counts) {
        current_sum += static_cast<long long>(val) * count;
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

