void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::map<char, int> counts;
    for (char ch : s) {
        counts[ch]++;
    }

    char most_frequent_bot_move = ' ';
    int max_count = -1;

    // Check 'R'
    if (counts['R'] > max_count) {
        max_count = counts['R'];
        most_frequent_bot_move = 'R';
    }
    // Check 'P'
    if (counts['P'] > max_count) {
        max_count = counts['P'];
        most_frequent_bot_move = 'P';
    }
    // Check 'S'
    if (counts['S'] > max_count) {
        max_count = counts['S'];
        most_frequent_bot_move = 'S';
    }
    // If counts are equal, any choice is fine. The order R, P, S ensures a consistent tie-breaking.

    char our_winning_move;
    if (most_frequent_bot_move == 'R') {
        our_winning_move = 'P';
    } else if (most_frequent_bot_move == 'P') {
        our_winning_move = 'S';
    } else { // most_frequent_bot_move == 'S'
        our_winning_move = 'R';
    }

    for (int i = 0; i < n; ++i) {
        std::cout << our_winning_move;
    }
    std::cout << std::endl;
}

