#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        // The frog starts at cell 0.
        // It needs to reach cell n+1.
        // It can only jump right from cell 0.
        // To reach n+1, the frog must always make progress towards n+1.
        // This means it should only jump right.
        // If it encounters an 'L' character at cell i (s[i-1]), it means
        // from cell i, it can only jump left. This is a dead end for progress
        // towards n+1.
        // Therefore, the frog must jump over any 'L' cells.
        // The frog must jump from a cell 'R' or cell 0 to another cell 'R' or cell n+1.
        // The critical path is defined by consecutive 'R' cells.
        // The frog must be able to jump from the last 'R' cell before an 'L' block
        // to the first 'R' cell after that 'L' block, or from cell 0 to the first 'R' cell,
        // or from the last 'R' cell to n+1.

        // Let's consider the positions of 'R' characters.
        // The frog starts at 0.
        // It needs to reach n+1.
        // The 'R' characters are at indices i where s[i] == 'R'.
        // These correspond to cells i+1.
        // The frog can jump from cell 0.
        // The frog can jump from cell i+1 if s[i] == 'R'.

        // We are looking for the maximum distance between any two consecutive
        // 'R' cells (or 0 and the first 'R', or the last 'R' and n+1).
        // This maximum distance will be the minimum 'd' required.

        std::vector<int> r_positions;
        r_positions.push_back(0); // Represents the starting cell
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                r_positions.push_back(i + 1); // Cell number is index + 1
            }
        }
        r_positions.push_back(n + 1); // Represents the target cell

        int max_gap = 0;
        for (size_t i = 0; i < r_positions.size() - 1; ++i) {
            max_gap = std::max(max_gap, r_positions[i+1] - r_positions[i]);
        }

        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need to find b1, b2, ..., bs such that
    // (current_sum + sum(b_i)) = 2 * (current_xor_sum ^ xor(b_i))

    // Strategy: Append at most 3 elements.
    // It's always possible to append 2 elements.
    // Let's try to append two elements, say X and Y.
    // We want (current_sum + X + Y) = 2 * (current_xor_sum ^ X ^ Y)

    // A simple choice for X and Y that often works is:
    // X = current_xor_sum
    // Y = current_sum + current_xor_sum
    // Let's check this:
    // New XOR sum: current_xor_sum ^ X ^ Y
    //            = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
    //            = 0 ^ (current_sum + current_xor_sum)
    //            = current_sum + current_xor_sum
    // New SUM: current_sum + X + Y
    //        = current_sum + current_xor_sum + (current_sum + current_xor_sum)
    //        = 2 * (current_sum + current_xor_sum)

    // So, if we append X = current_xor_sum and Y = current_sum + current_xor_sum,
    // the new sum is 2 * (current_sum + current_xor_sum)
    // and the new XOR sum is current_sum + current_xor_sum.
    // The condition (new_sum = 2 * new_xor_sum) is satisfied.

    // This strategy always works and uses exactly 2 elements.
    // The problem statement says "at most 3 elements" and "you don't have to minimize the number of added elements".
    // So, appending 2 elements is fine.

    // The values can be large, up to 10^9 for initial elements.
    // current_sum can be up to 10^5 * 10^9 = 10^14.
    // current_xor_sum can be up to 2^30 - 1 (approx 10^9).
    // So, Y = current_sum + current_xor_sum can be up to 10^14 + 10^9, which fits in long long.
    // The problem states b_i can be up to 10^18, so this is well within limits.

    long long b1 = current_xor_sum;
    long long b2 = current_sum + current_xor_sum;

    std::cout << 2 << std::endl;
    std::cout << b1 << " " << b2 << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long MOD = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a's to its left
            // will eventually interact with this 'b' (or its descendants).
            // Each 'a' to its left will cause this 'b' to duplicate.
            // The number of 'a's currently to the left (count_a)
            // determines how many times this 'b' will be involved in an 'ab' -> 'bba' operation.
            // Each such operation adds 1 to total_steps.
            total_steps = (total_steps + count_a) % MOD;

            // After all 'a's to its left have processed this 'b',
            // this 'b' effectively doubles itself for future 'a's further left.
            // This is because 'ab' -> 'bba'. The original 'b' is still there,
            // and a new 'b' is created. So, for any 'a's to the left of this 'b',
            // they will eventually interact with *two* 'b's for every original 'b'
            // that was to their right.
            count_a = (count_a * 2) % MOD;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' is now available
            // to interact with any 'b's to its right.
            // We increment the count of 'a's that are "active" and
            // waiting to interact with 'b's.
            count_a = (count_a + 1) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <map>
#include <utility> // For std::pair

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::map<int, long long> x_counts;
    std::map<int, long long> y_counts;
    std::map<std::pair<int, int>, long long> xy_counts;

    for (int i = 0; i < n; ++i) {
        int x, y;
        std::cin >> x >> y;
        x_counts[x]++;
        y_counts[y]++;
        xy_counts[{x, y}]++;
    }

    long long total_pairs = 0;

    // Pairs with same x-coordinate
    for (auto const& [x_coord, count] : x_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Pairs with same y-coordinate
    for (auto const& [y_coord, count] : y_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Subtract pairs that have both same x and same y (i.e., are identical points)
    // These pairs were counted twice (once for same x, once for same y)
    // but should only be counted once.
    for (auto const& [coords, count] : xy_counts) {
        if (count >= 2) {
            total_pairs -= count * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long opponent_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 == 1) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                // Option 1: Take 1 coin
                // Remaining N-1. Opponent gets to play on N-1.
                // If N-1 is odd, opponent takes 1. N-2 remains.
                // If N-1 is even, this path is not taken.
                // This path is generally worse for Chanek if N/2 is a good move.

                // Option 2: Take N/2 coins
                // Remaining N/2. Opponent gets to play on N/2.
                // This is usually the better move for Chanek if N/2 is odd.
                // If N/2 is odd, Chanek takes N/2, opponent takes 1, Chanek takes 1, etc.
                // If N/2 is even, Chanek takes N/2, opponent takes N/4, etc.

                // Strategy:
                // If N is even:
                //   If N is a power of 2 (e.g., 2, 4, 8, 16, ...):
                //     Taking N/2 is always optimal. Chanek takes N/2, opponent takes N/4, Chanek takes N/8, etc.
                //     Chanek gets N/2 + N/8 + N/32 + ...
                //     Opponent gets N/4 + N/16 + N/64 + ...
                //     Chanek gets 2/3 of total, opponent gets 1/3.
                //     But this is not true if N/2 is odd.
                //     Example: N=6.
                //       Chanek takes 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                //       Chanek: 1+2+1 = 4. Opponent: 1+1 = 2.
                //       Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                //       Chanek: 3+1 = 4. Opponent: 1+1 = 2.
                //     In this case, both moves lead to 4.

                // Let's consider the parity of N/2.
                // If N/2 is odd:
                //   Chanek takes N/2. Remaining N/2 (odd).
                //   Opponent's turn on N/2 (odd). Opponent must take 1. Remaining N/2 - 1 (even).
                //   This seems good for Chanek, as opponent is forced to take 1.
                // If N/2 is even:
                //   Chanek takes N/2. Remaining N/2 (even).
                //   Opponent's turn on N/2 (even). Opponent can take N/4.
                //   This means opponent also gets a large chunk.

                // The optimal strategy for Chanek when N is even:
                // If N/2 is odd: Chanek takes N/2. This leaves an odd number for the opponent, forcing them to take 1.
                // If N/2 is even:
                //   If N is a power of 2 (N = 2^k, k > 1):
                //     Taking N/2 is optimal. Chanek gets N/2, opponent gets N/4, Chanek gets N/8, etc.
                //     Chanek gets 2/3 of N, opponent gets 1/3 of N.
                //   If N is even but not a power of 2 (N = 2^k * M, where M > 1 and M is odd):
                //     Example: N=12. N/2=6 (even).
                //       Chanek takes 1. N=11. Opponent takes 1. N=10. Chanek takes 5. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                //       Chanek: 1+5+2+1 = 9. Opponent: 1+1+1 = 3.
                //       Chanek takes 6. N=6. Opponent takes 3. N=3. Chanek takes 1. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                //       Chanek: 6+1+1 = 8. Opponent: 3+1 = 4.
                //     In this case, taking 1 is better.

                // So, the rule for Chanek when N is even:
                // If N/2 is odd (i.e., N = 2 * (odd number)): Chanek takes N/2.
                // If N/2 is even (i.e., N = 2 * (even number) = 4 * (any number)):
                //   Chanek takes 1. This leaves N-1 (odd) for the opponent. Opponent takes 1. N-2 (even) remains.
                //   This seems to be the general strategy to avoid giving opponent a large even number.
                //   However, if N is a power of 2, taking N/2 is better.
                //   How to distinguish N=2^k from N=4*M (M odd)?
                //   N=2^k: N/2 is even until N=2.
                //   N=4*M (M odd): N/2 is even, N/4 is odd.
                //   So, if N is even and N/2 is even, we need to check if N is a power of 2.
                //   A number is a power of 2 if (N & (N-1)) == 0.

                if ((n / 2) % 2 == 1) { // N/2 is odd (e.g., N=6, N=10, N=14, ...)
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N/2 is even (e.g., N=4, N=8, N=12, N=16, ...)
                    if ((n & (n - 1)) == 0) { // N is a power of 2
                        chanek_coins += n / 2;
                        n /= 2;
                    } else { // N is even, N/2 is even, but N is not a power of 2
                        chanek_coins += 1;
                        n -= 1;
                    }
                }
            }
        } else { // Opponent's turn
            if (n % 2 == 1) { // N is odd
                opponent_coins += 1;
                n -= 1;
            } else { // N is even
                // Opponent wants to maximize their coins.
                // Same logic as Chanek, but for opponent.
                if ((n / 2) % 2 == 1) { // N/2 is odd
                    opponent_coins += n / 2;
                    n /= 2;
                } else { // N/2 is even
                    if ((n & (n - 1)) == 0) { // N is a power of 2
                        opponent_coins += n / 2;
                        n /= 2;
                    } else { // N is even, N/2 is even, but N is not a power of 2
                        opponent_coins += 1;
                        n -= 1;
                    }
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

