#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Prefix sums for 'x', 'y', 'z' counts
    // counts[0][i] = count of 'x' in s[0...i-1]
    // counts[1][i] = count of 'y' in s[0...i-1]
    // counts[2][i] = count of 'z' in s[0...i-1]
    std::vector<std::vector<int>> counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        counts[0][i + 1] = counts[0][i];
        counts[1][i + 1] = counts[1][i];
        counts[2][i + 1] = counts[2][i];

        if (s[i] == 'x') {
            counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            counts[1][i + 1]++;
        } else { // s[i] == 'z'
            counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        // Adjust to 0-based indexing for prefix sums
        // Substring is s[l-1 ... r-1]
        // Count of 'x' in s[l-1 ... r-1] is counts[0][r] - counts[0][l-1]
        int count_x = counts[0][r] - counts[0][l - 1];
        int count_y = counts[1][r] - counts[1][l - 1];
        int count_z = counts[2][r] - counts[2][l - 1];

        // The algorithm works correctly if the counts of 'x', 'y', 'z'
        // in the substring s[l-1 ... r-1] are "balanced enough".
        // This means the difference between the maximum and minimum count
        // of any character ('x', 'y', 'z') should not exceed 1.
        // If it exceeds 1, it's always possible to form a 3-char substring
        // that is not "zyx", "xzy", or "yxz" and thus rearrange it.
        // For example, if counts are (5, 2, 1), we can always find 'xxy' or 'xxz' etc.
        // and rearrange it.
        // If counts are (3, 3, 2), we can always find 'xxy' or 'xxz' etc.
        // The only way to terminate is if all 3-char substrings are permutations of 'xyz'.
        // This implies that the total counts of 'x', 'y', 'z' in the substring
        // must be as close as possible.

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;
    long long temp_q = q;

    // Find prime factors of q
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            // i is a prime factor of q
            long long current_p = p;
            while (current_p % i == 0 && current_p % q == 0) {
                current_p /= i;
            }
            max_x = std::max(max_x, current_p);

            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }

    if (temp_q > 1) { // temp_q is now a prime factor itself
        long long current_p = p;
        long long i = temp_q; // The remaining prime factor
        while (current_p % i == 0 && current_p % q == 0) {
            current_p /= i;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;
        std::cout << get_max_x(p, q) << "\n";
    }
    return 0;
}

