            // f3: can move right (x+1, y)
            // If f3 == 0, robot cannot move right.
            // If X > x, it would need to move right.
            // So, if f3 == 0, then X must be <= x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }

            // f4: can move down (x, y-1)
            // If f4 == 0, robot cannot move down.
            // If Y < y, it would need to move down.
            // So, if f4 == 0, then Y must be >= y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
