    }

    // Find the first index `i` from the right such that a[i] > a[i+1]
    // This marks the end of the non-decreasing suffix
    int i = n - 2;
    while (i >= 0 && a[i] <= a[i+1]) {
        i--;
    }
    // Now, a[i+1 ... n-1] is non-decreasing.
    // If i < 0, the whole array is non-decreasing.

    // Find the first index `j` from the right such that a[j] < a[j+1]
    // This marks the end of the non-increasing suffix
    int j = i; // Start searching from where the non-decreasing suffix ended
    while (j >= 0 && a[j] >= a[j+1]) {
        j--;
    }
    // Now, a[j+1 ... n-1] is a "good" array.
    // The prefix to remove is a[0 ... j].
    // The length of this prefix is j + 1.

    std::cout << j + 1 << std::endl;
}

