        // This is (k*b + 1) * sum(r from 1 to b-1)
        // sum(r from 1 to b-1) = (b-1)*b/2

        long long kb_plus_1 = (k * b + 1) % MOD;
        long long term_sum_for_k = (kb_plus_1 * sum_r_term) % MOD;

