void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> all_chars_in_s;

    for (size_t i = 0; i < s.length(); ++i) {
        all_chars_in_s.insert(s[i]);
        if (i > 0) {
            adj[s[i]].insert(s[i-1]);
            adj[s[i-1]].insert(s[i]);
        }
    }

    bool possible = true;
    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    std::string layout_prefix = "";
    std::set<char> visited_in_layout;

    // Find a starting point for the layout: a character with only one required neighbor
    char start_char = '\0';
    for (char c : all_chars_in_s) {
        if (adj[c].size() == 1) {
            start_char = c;
            break;
        }
    }

    // If all characters in s have two required neighbors (e.g., "abacaba" forms a cycle a-b-c-a),
    // or if s has only one character, pick the first character of s as a starting point.
    if (start_char == '\0' && !all_chars_in_s.empty()) {
        start_char = s[0];
    }

    if (start_char != '\0') {
        char current_char = start_char;
        char prev_char = '\0'; // To keep track of the previous character in the path

        while (visited_in_layout.find(current_char) == visited_in_layout.end()) {
            layout_prefix += current_char;
            visited_in_layout.insert(current_char);

            char next_char = '\0';
            for (char neighbor : adj[current_char]) {
                if (neighbor != prev_char) {
                    next_char = neighbor;
                    break;
                }
            }
            prev_char = current_char;
            current_char = next_char;
            if (current_char == '\0' && visited_in_layout.size() < all_chars_in_s.size()) {
                // This means we've reached an end of a path, but not all chars from s are included.
                // This implies a disconnected graph or a cycle that wasn't fully traversed.
                // For this problem, it means it's impossible.
                possible = false;
                break;
            }
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Check if all characters from s are included in the generated layout_prefix
    for (char c : all_chars_in_s) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            // This means there's a character in 's' that wasn't part of the main path.
            // This can happen if 's' implies multiple disconnected components, which is impossible for a single row.
            // Or if we started from a char with degree 2 and traversed a cycle, but other chars were left out.
            // Example: s = "abacaba", all_chars_in_s = {a,b,c}. adj[a]={b,c}, adj[b]={a}, adj[c]={a}.
            // If we start at 'b', path is b-a-c. All chars covered.
            // If s = "ab", all_chars_in_s = {a,b}. adj[a]={b}, adj[b]={a}. Path a-b.
            // If s = "abc", all_chars_in_s = {a,b,c}. adj[a]={b}, adj[b]={a,c}, adj[c]={b}. Path a-b-c.
            // The only case where this check should fail is if the graph is not a single path.
            // The logic for `start_char` and `while` loop should handle this.
            // If `start_char` is picked from `s[0]` and it has degree 2, and it leads to a cycle,
            // then `current_char` will eventually be `start_char` again, and `visited_in_layout` will contain it.
            // If `visited_in_layout.size() < all_chars_in_s.size()` after the loop, it means not all chars from `s`
            // were part of the single path/cycle we traced. This implies multiple components or a non-path/cycle structure.
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Add remaining characters not in 's' to the layout
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            layout_prefix += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout_prefix << "\n";
}

