        // So, total diagonal moves: `(n-1) + (k-m-1) = n + k - m - 2`.
        // This seems to be the correct logic for `k-m` odd.

        long long ans;
        if ((k - m) % 2 == 0) { // k and m have same parity
            ans = n + (k - m);
        } else { // k and m have different parities
            ans = n + (k - m) - 2;
        }
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 2) {
            a[i] = -1;
        }
    }

    // Calculate prefix sums for the right side (from n to 2n-1)
    // Suffix sums for the right side, but calculated as prefix sums from n to 2n-1
    // right_sums[k] = sum of a[n]...a[n+k-1]
    // This means right_sums[0] = 0 (no jars removed from right)
    // right_sums[1] = a[n] (jar n+1 in 1-indexed)
    // right_sums[k] = sum of a[n]...a[n+k-1]
    std::vector<int> right_sums(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        right_sums[i + 1] = right_sums[i] + a[n + i];
    }

    // Store the first occurrence of each sum value for the right side
    // map: sum_value -> number of jars removed from right (k)
    std::map<int, int> right_sum_to_k;
    for (int k = 0; k <= n; ++k) {
        if (right_sum_to_k.find(right_sums[k]) == right_sum_to_k.end()) {
            right_sum_to_k[right_sums[k]] = k;
        }
    }

    // Calculate prefix sums for the left side (from n-1 down to 0)
    // left_sums[j] = sum of a[n-1]...a[n-j]
    // This means left_sums[0] = 0 (no jars removed from left)
    // left_sums[1] = a[n-1] (jar n in 1-indexed)
    // left_sums[j] = sum of a[n-1]...a[n-j]
    std::vector<int> left_sums(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        left_sums[i + 1] = left_sums[i] + a[n - 1 - i];
    }

    int min_removed = 2 * n; // Initialize with maximum possible jars removed

    // Iterate through all possible numbers of jars removed from the left (j)
    for (int j = 0; j <= n; ++j) {
        int current_left_sum = left_sums[j];
        // We need the remaining jars to have a sum of -current_left_sum
        // This means the sum of jars from the right side (right_sums[k]) should be -current_left_sum
        int target_right_sum = -current_left_sum;

        if (right_sum_to_k.count(target_right_sum)) {
            int k = right_sum_to_k[target_right_sum];
            min_removed = std::min(min_removed, j + k);
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

