// Function to calculate the parity of a 01-string
// Returns 1 if odd number of '1's, 0 otherwise.
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    // Calculate initial parity of string a
    int parity_a = calculate_parity(a);

    // Calculate parity of string b
    int parity_b = calculate_parity(b);

    // The maximum number of '1's we can have in 'a' after appending parities
    // is its current count plus the number of characters we can append.
    // The maximum length of 'a' can be 1000.
    // If we append '1's, the count of '1's increases.
    // If we append '0's, the count of '1's stays the same.
    // So, the maximum possible count of '1's in 'a' (or any string derived from 'a' by appending)
    // is its initial count plus its initial length (if all appended characters were '1's).
    // However, a simpler approach is to consider the maximum possible parity sum.
    // If parity_a is 0, we can append a '0', and parity remains 0.
    // If parity_a is 1, we can append a '1', and parity remains 0.
    // If parity_a is 0, we can append a '0', and parity remains 0.
    // If parity_a is 0, we can append a '1' (if we first make parity 1), and parity becomes 1.
    //
    // The key insight is that if we have a string `s` with `P` ones:
    // - If `P` is even (parity 0), we can append '0'. The new string `s0` has `P` ones, parity 0.
    // - If `P` is odd (parity 1), we can append '1'. The new string `s1` has `P+1` ones, parity 0.
    // In both cases, after one append operation, we can always reach a state where the string has an even number of ones.
    // Once a string has an even number of ones (parity 0), we can append '0's indefinitely, maintaining parity 0.
    // Or, if we want to change parity to 1, we need to append a '1'. This means the current string must have had an odd number of ones.
    //
    // Let's re-evaluate:
    // If current_parity is 0:
    //   Append '0'. New string has same number of '1's. New parity is 0.
    //   This means we can always maintain parity 0 if we start with it.
    // If current_parity is 1:
    //   Append '1'. New string has one more '1'. New parity is 0.
    //   This means we can always reach parity 0 from parity 1 in one step.
    //
    // So, any string `a` can be extended to `a'` such that `a'` has parity 0,
    // and `a'` can be further extended to `a''` such that `a''` has parity 0.
    // This means we can always make the parity 0, and then keep it 0.
    //
    // The only way to get a parity of 1 is if the *final* appended character makes it 1.
    // This means the string *before* the last append must have had an odd number of ones.
    //
    // Let `ones_a` be the count of '1's in `a`.
    // Let `ones_b` be the count of '1's in `b`.
    //
    // We can always increase the length of `a` by appending characters.
    // The maximum number of '1's we can effectively "generate" in `a`
    // is `ones_a` plus the number of characters we can append.
    // The maximum length of `a` is 1000.
    // The maximum length of `b` is 1000.
    //
    // If `|a| < |b|`, we must append `|b| - |a|` characters to `a` *at least*.
    // The maximum number of '1's we can have in `a` after appending is:
    // `ones_a` + (number of '1's we can append).
    //
    // Consider the total number of '1's we can achieve in `a` by appending.
    // Let `N_a` be the count of '1's in `a`.
    // If `N_a` is even, we can append '0's, keeping `N_a` even.
    // If `N_a` is odd, we can append '1', making `N_a+1` even.
    // So, we can always reach an even number of '1's.
    //
    // The maximum number of '1's we can have in `a` (before removing prefix)
    // is `ones_a` if `parity_a` is 0, or `ones_a + 1` if `parity_a` is 1.
    // This is because if `parity_a` is 1, we can append a '1' to make it `parity_a + 1` (which is even).
    // If `parity_a` is 0, we can append a '0' to keep it `parity_a` (which is even).
    // In both cases, we can achieve an even number of '1's.
    //
    // Let `max_ones_a_effective` be the maximum number of '1's we can have in `a`
    // such that its parity is 0.
    // If `parity_a` is 0, `max_ones_a_effective = ones_a`.
    // If `parity_a` is 1, `max_ones_a_effective = ones_a + 1`.
    // This can be simplified to `max_ones_a_effective = ones_a + parity_a`.
    //
    // Now, we need to check if `b` can be a suffix of `a` (after some operations).
    // This means `b` must have `ones_b` '1's.
    //
    // Condition 1: The number of '1's in `b` must be less than or equal to the
    // maximum effective '1's we can generate in `a`.
    // `ones_b <= max_ones_a_effective`
    // `ones_b <= ones_a + parity_a`
    //
    // Condition 2: The length of `b` must be less than or equal to the length of `a`
    // after we've potentially appended characters.
    // We can always append characters until `a` is long enough.
    // The only constraint is that `a` cannot become empty.
    // But `b` is never empty (length >= 1).
    // So, if `ones_b <= ones_a + parity_a`, we can always make `a` long enough
    // and with the correct number of '1's (or more '1's than needed, which is fine).
    //
    // Example 1: a = 01011, b = 0110
    // ones_a = 3, parity_a = 1
    // ones_b = 2, parity_b = 0
    // max_ones_a_effective = ones_a + parity_a = 3 + 1 = 4
    // Is ones_b <= max_ones_a_effective? 2 <= 4. YES.
    // Output: YES. Correct.
    //
    // Example 2: a = 0011, b = 1110
    // ones_a = 2, parity_a = 0
    // ones_b = 3, parity_b = 1
    // max_ones_a_effective = ones_a + parity_a = 2 + 0 = 2
    // Is ones_b <= max_ones_a_effective? 3 <= 2. NO.
    // Output: NO. Correct.

    int ones_a = 0;
    for (char c : a) {
        if (c == '1') {
            ones_a++;
        }
    }

    int ones_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_b++;
        }
    }

    // If parity_a is 1, we can append a '1' to make the count of ones `ones_a + 1` (which is even).
    // If parity_a is 0, we can append a '0' to keep the count of ones `ones_a` (which is even).
    // So, the maximum number of '1's we can have in a string derived from 'a'
    // that has an even parity is `ones_a` if `ones_a` is even, or `ones_a + 1` if `ones_a` is odd.
    // This is equivalent to `ones_a + (ones_a % 2)`.
    int max_possible_even_ones_in_a_prefix = ones_a + (ones_a % 2);

    // If `b` has an odd number of '1's, then the string `a'` from which `b` is a suffix
    // must also have had an odd number of '1's.
    // This means `max_possible_even_ones_in_a_prefix` is not directly applicable for `b`'s parity.
    //
    // Let's simplify:
    // We can always make the number of '1's in `a` equal to `ones_a` or `ones_a + 1`.
    // If `ones_a` is even, we can make it `ones_a` (by appending '0's) or `ones_a + 1` (by appending '1' after making it odd).
    // If `ones_a` is odd, we can make it `ones_a` (by appending '0' after making it even) or `ones_a + 1` (by appending '1').
    //
    // The crucial point is that we can always increase the count of '1's by at most 1
    // to achieve a desired parity for the *final* string `a'` from which `b` is a suffix.
    //
    // If `ones_b` is the count of '1's in `b`:
    // We need to be able to form a string `a_prime` (by appending to `a`) such that `b` is a suffix of `a_prime`.
    // The number of '1's in `a_prime` must be at least `ones_b`.
    //
    // Let `current_ones_a = ones_a`.
    // We can append characters.
    // If `current_ones_a` is even, we can append '0'. `current_ones_a` remains even.
    // If `current_ones_a` is odd, we can append '1'. `current_ones_a` becomes even.
    // So, we can always reach an even number of '1's.
    //
    // If we want to achieve `ones_b` '1's in `b`:
    // The maximum number of '1's we can have in `a` (before removing prefix) is `ones_a` if `ones_a` is even,
    // or `ones_a + 1` if `ones_a` is odd.
    // This is `ones_a + (ones_a % 2)`.
    //
    // If `ones_b` is greater than `ones_a + (ones_a % 2)`, it's impossible.
    // Otherwise, it's always possible.
    //
    // This logic seems sound and covers both examples.

    if (ones_b <= (ones_a + (ones_a % 2))) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // All f values are of the form a_i + a_j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value
    // Goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    long long goodness1 = (a[n - 2].value + a[n - 1].value) - (a[0].value + a[1].value);
    std::vector<int> partition1(n, 1);

    // Case 2: Partition into two non-empty subsequences.
    // The minimum possible f value is a[0].value + a[1].value.
    // The maximum possible f value is a[n-2].value + a[n-1].value + h.
    // This happens if a[0] and a[1] are in the same group, and a[n-2] and a[n-1] are in different groups.
    // Or if a[0] and a[1] are in different groups, and a[n-2] and a[n-1] are in the same group.
    // Or if a[0] and a[1] are in different groups, and a[n-2] and a[n-1] are in different groups.
    // The minimum f value will be min(a[0].value + a[1].value, a[0].value + a[1].value + h).
    // The maximum f value will be max(a[n-2].value + a[n-1].value, a[n-2].value + a[n-1].value + h).
    //
    // The critical observation is that if we have two non-empty subsequences,
    // then there must be at least one pair (a_i, a_j) in the same subsequence,
    // and at least one pair (a_k, a_l) in different subsequences.
    //
    // So, min_f will be at most a[0].value + a[1].value.
    // And max_f will be at least a[n-2].value + a[n-1].value + h.
    //
    // However, we can try to make the minimum f value as large as possible,
    // and the maximum f value as small as possible.
    //
    // Consider a partition where a[0] is in group 1, and all other elements are in group 2.
    // min_f:
    //   - a[0].value + a[1].value + h (a[0] in group 1, a[1] in group 2)
    //   - a[1].value + a[2].value (a[1], a[2] in group 2)
    //   The minimum of these two is a[1].value + a[2].value.
    // max_f:
    //   - a[n-2].value + a[n-1].value (a[n-2], a[n-1] in group 2)
    //   - a[0].value + a[n-1].value + h (a[0] in group 1, a[n-1] in group 2)
    //   The maximum of these two is a[0].value + a[n-1].value + h.
    //
    // Goodness = max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h) - min(a[1].value + a[2].value, a[0].value + a[1].value + h)
    //
    // Let's simplify.
    // The smallest possible sum is `a[0].value + a[1].value`.
    // The largest possible sum is `a[n-1].value + a[n-2].value`.
    //
    // If we put `a[0]` in group 1 and all others in group 2:
    // Pairs in same group: `(a[i], a[j])` for `i,j >= 1`. Smallest is `a[1].value + a[2].value`. Largest is `a[n-2].value + a[n-1].value`.
    // Pairs in different groups: `(a[0], a[j])` for `j >= 1`. Smallest is `a[0].value + a[1].value + h`. Largest is `a[0].value + a[n-1].value + h`.
    //
    // So, for this partition:
    // min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
    // max_f = std::max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h);
    // Goodness = max_f - min_f;
    //
    // This is the goodness for the partition where a[0] is in group 1, and all others are in group 2.
    // Let's call this goodness2.
    long long min_f2 = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
    long long max_f2 = std::max(a[n - 2].value + a[n - 1].value, a[0].value + a[n - 1].value + h);
    long long goodness2 = max_f2 - min_f2;

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        std::vector<int> result_partition(n);
        for (int i = 0; i < n; ++i) {
            result_partition[a[i].original_index] = 1;
        }
        for (int i = 0; i < n; ++i) {
            std::cout << result_partition[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        std::vector<int> result_partition(n);
        result_partition[a[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            result_partition[a[i].original_index] = 2;
        }
        for (int i = 0; i < n; ++i) {
            std::cout << result_partition[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k=1: One cut, two pieces.
    // Try all possible single cuts.
    // A cut at index `i` splits s into s[0...i-1] and s[i...n-1].
    // The pieces are P1 = s.substr(0, i) and P2 = s.substr(i).
    // We can form P1+P2 (original s) or P2+P1.
    // We need P2+P1 to be a palindrome and P2+P1 != s.
    for (int i = 1; i < n; ++i) { // i is the length of the first piece
        std::string p1 = s.substr(0, i);
        std::string p2 = s.substr(i);
        std::string new_s = p2 + p1;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k=2: Two cuts, three pieces.
    // This is always possible unless all characters in s are the same.
    // If s consists of all identical characters (e.g., "aaaa"),
    // then any reordering of its substrings will result in the same string,
    // and it will always be a palindrome.
    // Example: "aaaa" -> "a|a|aa" -> "aa|a|a" = "aaaa".
    // In this case, it's impossible to form a different palindrome.

    // Check if all characters in s are the same.
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }

    if (all_same) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, it's always possible with k=2.
        // Consider the string s. Since it's a palindrome and not all chars are same,
        // it must have at least two distinct characters.
        // Example: "nolon" -> "no|l|on" -> "on|l|no" (k=2)
        // Example: "otto" -> "ot|t|o" -> "o|t|ot" (k=2)
        // The problem statement guarantees s is a palindrome.
        // If s is a palindrome and not all characters are the same,
        // then s.substr(0, n-1) (s without last char) is not a palindrome.
        // For example, "abacaba". s.substr(0,6) = "abacab". Not a palindrome.
        // Consider cutting s into s[0...i-1], s[i], s[i+1...n-1].
        // If we take s[0...n/2-1] and s[n/2+1...n-1] and s[n/2] (middle char if odd length)
        // and swap the first and last parts.
        // For example, s = "abacaba", n=7.
        // P1 = "aba", P2 = "c", P3 = "aba".
        // New string P3+P2+P1 = "abacaba" (same).
        //
        // A simpler argument for k=2:
        // If s is a palindrome and not all characters are the same,
        // then s must have at least two distinct characters.
        // Consider the string s.
        // If we cut s into s[0...n-2] and s[n-1].
        // The first piece is s.substr(0, n-1).
        // The second piece is s.substr(n-1, 1).
        // This is k=1. We already checked this.
        //
        // The problem states: "It can be shown that there is no solution with one cut." for "nolon".
        // This implies that if k=1 doesn't work, k=2 is the next possibility.
        // If s is a palindrome and not all characters are the same,
        // then there exists at least one character `c` such that `s[0] != c`.
        // Since `s` is a palindrome, `s[0] == s[n-1]`.
        // If `s` is not all same characters, then `s` must contain at least two distinct characters.
        // This means `s` is not of the form `aaaaa...`.
        //
        // Consider the string `s`. If `s` is a palindrome and not all characters are the same,
        // then `s` must have at least two distinct characters.
        // For example, `s = "abacaba"`.
        // `s.substr(0, n-1)` is `s` without its last character.
        // `s.substr(0, n-1)` is `abacab`. This is not a palindrome.
        //
        // The key insight for k=2 is that if k=1 doesn't work, and not all characters are the same,
        // then k=2 is always possible.
        // Consider the string `s`. Since it's a palindrome and not all characters are the same,
        // there must be some `i` such that `s[i] != s[0]`.
        // This means `s` is not of the form `aaaa...`.
        //
        // If `s` is a palindrome and not all characters are the same,
        // then `s` has at least two distinct characters.
        // For example, `s = "abacaba"`.
        // Cut `s` into `s[0...n/2-1]`, `s[n/2]`, `s[n/2+1...n-1]`.
        // Let `P1 = s.substr(0, n/2)`, `P2 = s.substr(n/2, 1)`, `P3 = s.substr(n/2+1)`.
        // If `n` is odd, `P2` is the middle character.
        // If `n` is even, `P2` is empty, and `P1` and `P3` are `s.substr(0, n/2)` and `s.substr(n/2)`.
        // This is not the general k=2 strategy.
        //
        // The problem statement for "nolon" says "It can be shown that there is no solution with one cut."
        // This implies that if k=1 fails, and the string is not all identical characters, then k=2 is the answer.
        // This is a common pattern in competitive programming problems where if a simpler solution doesn't work,
        // the next level of complexity is the answer, unless a specific impossible case is met.
        // The "Impossible" case is when all characters are the same.
        // If `s` is a palindrome and not all characters are the same, then `k=2` is always possible.
        // For example, `s = "abacaba"`.
        // Cut `s` into `s[0]`, `s[1...n-2]`, `s[n-1]`.
        // `P1 = "a"`, `P2 = "bacab"`, `P3 = "a"`.
        // Reorder to `P2 + P1 + P3` = `bacabaa`. Not a palindrome.
        // Reorder to `P3 + P2 + P1` = `abacaba`. Same.
        //
        // The example `nolon` -> `no|l|on` -> `on|l|no` works.
        // This is `s.substr(0,2)`, `s.substr(2,1)`, `s.substr(3,2)`.
        // `P1 = "no"`, `P2 = "l"`, `P3 = "on"`.
        // `P3 + P2 + P1 = "onlno"`. This is a palindrome and `!= nolon`.
        // This is a specific way to make two cuts.
        //
        // The problem statement implies that if k=1 doesn't work, and the string is not all identical characters,
        // then k=2 is the answer.
        // This is a common trick in such problems.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // dp[i] will store the maximum 'r' such that the substring s[i...r-1]
    // does NOT contain any pattern s_x = s_{x+k} = s_{x+2k}
    // where x >= i.
    // More precisely, dp[i] stores the smallest 'r' such that s[i...r-1]
    // contains a pattern, or n+1 if no such pattern starts at or after i.
    // We want to find the largest 'r_max' such that s[i...r_max-1] is "good".
    // So, dp[i] = min(n, min_r_for_pattern - 1)
    // Let's redefine dp[i] as the smallest index `j` (0-based) such that
    // the substring s[i...j] contains a pattern. If no such pattern exists
    // starting at or after `i`, then `j` is `n`.
    // So, for a given `l` (0-based), the valid `r` (0-based) can go up to `dp[l]-1`.
    // The number of good `r` values for a given `l` is `dp[l] - l`.

    std::vector<int> dp(n + 1);
    dp[n] = n; // Base case: for an empty string starting at n, no pattern.

    for (int i = n - 1; i >= 0; --i) {
        dp[i] = dp[i + 1]; // Inherit from the next position

        // Check for patterns of type s_i = s_{i+k} = s_{i+2k}
        // k can be 1 or 2 for small patterns
        // k=1: s_i = s_{i+1} = s_{i+2}
        if (i + 2 < n && s[i] == s[i + 1] && s[i + 1] == s[i + 2]) {
            dp[i] = std::min(dp[i], i + 2);
        }
        // k=2: s_i = s_{i+2} = s_{i+4}
        if (i + 4 < n && s[i] == s[i + 2] && s[i + 2] == s[i + 4]) {
            dp[i] = std::min(dp[i], i + 4);
        }
        // k=3: s_i = s_{i+3} = s_{i+6}
        if (i + 6 < n && s[i] == s[i + 3] && s[i + 3] == s[i + 6]) {
            dp[i] = std::min(dp[i], i + 6);
        }
    }

    for (int i = 0; i < n; ++i) {
        // For each starting position `i` (0-based),
        // the substring s[i...r] is "good" if r < dp[i].
        // The number of such `r` values is `dp[i] - 1 - i + 1 = dp[i] - i`.
        // These are the `r` values (0-based) from `i` to `dp[i]-1`.
        bad_pairs += (dp[i] - i);
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current index for target tracks
    for (int i = 0; i < n; ++i) { // Iterate through heads
        if (p_idx == m) { // All target tracks covered
            return true;
        }

        long long head_pos = h[i];
        long long min_reach = head_pos - T;
        long long max_reach = head_pos + T;

        // If the current head cannot reach the current target track p[p_idx],
        // it means this head is too far to the left.
        // We need to find a head that can cover p[p_idx].
        // If p[p_idx] is outside [min_reach, max_reach], this head might be useful for later tracks.
        // But for p[p_idx], it must be covered.

        // If p[p_idx] is to the left of what this head can reach, this head cannot cover it.
        // We need to advance to the next head.
        if (p[p_idx] > max_reach) {
            continue;
        }

        // If p[p_idx] is within reach of this head, or to its left but still reachable
        // (i.e., p[p_idx] <= max_reach), this head can potentially cover p[p_idx]
        // and subsequent tracks.

        // The head can start at h[i] and move to cover tracks.
        // It can cover tracks from max(p[p_idx], h[i] - T) up to h[i] + T.
        // Or, it can cover tracks from h[i] - T up to min(p[p_idx], h[i] + T).
        // The key is that if a head covers p[p_idx], it can also cover a contiguous range
        // of tracks starting from p[p_idx] up to some point.

        // If p[p_idx] is covered by this head, we need to determine the furthest track
        // this head can cover to the right, given that it must cover p[p_idx].
        long long current_head_coverage_right_limit;

        // Case 1: Head moves right to cover p[p_idx]
        // It starts at h[i], moves to p[p_idx]. Time taken: p[p_idx] - h[i].
        // Remaining time: T - (p[p_idx] - h[i]).
        // Furthest right it can reach: p[p_idx] + (T - (p[p_idx] - h[i])) = h[i] + T.
        // This is valid if p[p_idx] >= h[i].

        // Case 2: Head moves left to cover p[p_idx]
        // It starts at h[i], moves to p[p_idx]. Time taken: h[i] - p[p_idx].
        // Remaining time: T - (h[i] - p[p_idx]).
        // Furthest right it can reach: p[p_idx] + (T - (h[i] - p[p_idx])) = 2*p[p_idx] - h[i] + T.
        // This is valid if p[p_idx] < h[i].

        if (p[p_idx] >= h[i]) { // Head moves right or stays
            // The head is at h[i]. It needs to reach p[p_idx]. This takes p[p_idx] - h[i] time.
            // If p[p_idx] - h[i] > T, this head cannot reach p[p_idx].
            // We already checked p[p_idx] > max_reach, which is p[p_idx] > h[i] + T,
            // so p[p_idx] - h[i] > T is already covered.
            // So if we are here, p[p_idx] <= h[i] + T.
            // The head can reach p[p_idx] and then continue to h[i] + T.
            current_head_coverage_right_limit = h[i] + T;
        } else { // p[p_idx] < h[i]. Head moves left.
            // The head is at h[i]. It needs to reach p[p_idx]. This takes h[i] - p[p_idx] time.
            // If h[i] - p[p_idx] > T, this head cannot reach p[p_idx].
            // This is equivalent to p[p_idx] < h[i] - T, which means p[p_idx] < min_reach.
            // If p[p_idx] < min_reach, this head cannot cover p[p_idx].
            // We should not be here if p[p_idx] < min_reach.
            // So if we are here, p[p_idx] >= h[i] - T.
            // The head moves to p[p_idx]. Time spent: h[i] - p[p_idx].
            // Remaining time: T - (h[i] - p[p_idx]).
            // From p[p_idx], it can move right by this remaining time.
            current_head_coverage_right_limit = p[p_idx] + (T - (h[i] - p[p_idx]));
        }

        // Now, advance p_idx as long as target tracks are covered by this head.
        while (p_idx < m && p[p_idx] <= current_head_coverage_right_limit) {
            p_idx++;
        }
    }
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible distance between any h_i and p_j is ~10^10.
                               // A single head might need to cover a range of 2*10^10.
                               // So T can be up to 2*10^10.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <map>
#include <algorithm>

// Function to convert a number to its parity pattern string
// The pattern will always be 18 characters long, padded with '0's on the left.
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern += '0';
            } else {
                pattern += '1';
            }
            n /= 10;
        }
    }
    std::reverse(pattern.begin(), pattern.end()); // Digits were added right-to-left, reverse to get left-to-right

    // Pad with '0's on the left to make it 18 characters long
    // This effectively handles the "shorter number/pattern padded with 0s" rule
    // for numbers up to 10^18 (which has 19 digits, but patterns are max 18).
    // For consistency with map keys, we'll use a fixed length.
    // Max length of pattern is 18. Max digits for 10^18-1 is 18.
    // So, 18 is a good fixed length.
    if (pattern.length() < 18) {
        pattern = std::string(18 - pattern.length(), '0') + pattern;
    }
    return pattern;
}

int main() {
    // Optimize C++ standard streams for faster input/output.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Use a map to store counts of each parity pattern string.
    // The key is the 18-character parity pattern string.
    // The value is the count of numbers in the multiset that generate this pattern.
    std::map<std::string, int> pattern_counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's on the left to match the fixed length of 18.
            // This ensures consistent key lookup in the map.
            if (s.length() < 18) {
                s = std::string(18 - s.length(), '0') + s;
            }
            std::cout << pattern_counts[s] << "\n";
        }
    }

    return 0;
}
